CREATE FUNCTION public.activate_tenant(p_tenant_id uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
BEGIN
    UPDATE tenants
    SET status = 'active',
        suspended_at = NULL,
        suspended_reason = NULL
    WHERE id = p_tenant_id;
    
    -- تسجيل الحدث
    INSERT INTO saas_events (tenant_id, event_type, event_data, actor_type)
    VALUES (p_tenant_id, 'tenant_activated', '{}', 'admin');
    
    RETURN jsonb_build_object('success', true);
END;
$$;


--
-- Name: activate_white_label(uuid, uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.activate_white_label(p_agent_id uuid, p_payment_id uuid, p_approved_by uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_agent RECORD;
    v_payment RECORD;
    v_config_id UUID;
BEGIN
    -- الحصول على الوكيل
    SELECT * INTO v_agent FROM agents WHERE id = p_agent_id;
    IF NOT FOUND THEN
        RETURN jsonb_build_object('success', false, 'error', 'الوكيل غير موجود');
    END IF;
    
    -- الحصول على الدفعة
    SELECT * INTO v_payment FROM white_label_payments WHERE id = p_payment_id AND agent_id = p_agent_id;
    IF NOT FOUND THEN
        RETURN jsonb_build_object('success', false, 'error', 'الدفعة غير موجودة');
    END IF;
    
    IF v_payment.status != 'completed' THEN
        RETURN jsonb_build_object('success', false, 'error', 'الدفعة غير مكتملة');
    END IF;
    
    -- تحديث الوكيل
    UPDATE agents
    SET has_white_label = true,
        white_label_status = 'active',
        white_label_payment_amount = v_payment.amount,
        white_label_payment_date = v_payment.paid_at,
        white_label_payment_reference = v_payment.payment_reference,
        white_label_commission_percent = 50,  -- 50% للوكلاء بـ White Label
        white_label_activated_at = NOW(),
        white_label_expires_at = v_payment.valid_to,
        white_label_approved_at = NOW(),
        white_label_approved_by = p_approved_by,
        commission_percent = 50,  -- تحديث نسبة العمولة الأساسية
        recurring_commission_percent = 50  -- تحديث نسبة العمولة المتكررة
    WHERE id = p_agent_id;
    
    -- إنشاء إعدادات White Label افتراضية
    INSERT INTO white_label_configs (agent_id, brand_name, is_active)
    VALUES (p_agent_id, v_agent.name, true)
    ON CONFLICT DO NOTHING
    RETURNING id INTO v_config_id;
    
    -- تسجيل الحدث
    INSERT INTO agent_events (agent_id, event_type, event_data)
    VALUES (p_agent_id, 'white_label_activated', jsonb_build_object(
        'payment_id', p_payment_id,
        'amount', v_payment.amount,
        'approved_by', p_approved_by
    ));
    
    RETURN jsonb_build_object(
        'success', true,
        'agent_id', p_agent_id,
        'config_id', v_config_id,
        'message', 'تم تفعيل White Label بنجاح'
    );
END;
$$;


--
-- Name: add_bank_account(uuid, character varying, character varying, character varying, character varying, character varying, numeric); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.add_bank_account(p_company_id uuid, p_bank_name_ar character varying, p_bank_name_en character varying, p_currency character varying DEFAULT 'UAH'::character varying, p_account_number character varying DEFAULT NULL::character varying, p_fop_group character varying DEFAULT NULL::character varying, p_annual_limit numeric DEFAULT NULL::numeric) RETURNS uuid
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_tenant_id UUID;
    v_bank_group_id UUID;
    v_next_code VARCHAR(10);
    v_new_account_id UUID;
    v_account_type_id UUID;
BEGIN
    -- Get tenant_id
    SELECT tenant_id INTO v_tenant_id 
    FROM companies 
    WHERE id = p_company_id;
    
    IF v_tenant_id IS NULL THEN
        RAISE EXCEPTION 'Company not found';
    END IF;
    
    -- Get bank group account (112)
    SELECT id INTO v_bank_group_id
    FROM chart_of_accounts
    WHERE company_id = p_company_id 
      AND account_code = '112'
      AND is_group = true;
    
    IF v_bank_group_id IS NULL THEN
        RAISE EXCEPTION 'Bank group account (112) not found. Please create unified chart first.';
    END IF;
    
    -- Get account type ID
    SELECT id INTO v_account_type_id
    FROM account_types
    WHERE code = 'CURRENT_ASSET';
    
    -- Generate next code (1121, 1122, ...)
    SELECT COALESCE(
        '112' || (MAX(SUBSTRING(account_code FROM 4)::INTEGER) + 1)::TEXT,
        '1121'
    ) INTO v_next_code
    FROM chart_of_accounts
    WHERE company_id = p_company_id 
      AND account_code LIKE '112%'
      AND LENGTH(account_code) = 4;
    
    -- Create new bank account
    INSERT INTO chart_of_accounts (
        tenant_id, company_id, account_code,
        name_ar, name_en,
        account_type_id, parent_id,
        is_group, is_detail, is_bank_account,
        currency, external_code, is_system
    ) VALUES (
        v_tenant_id, p_company_id, v_next_code,
        p_bank_name_ar, p_bank_name_en,
        v_account_type_id, v_bank_group_id,
        false, true, true,
        p_currency, p_account_number, false
    )
    RETURNING id INTO v_new_account_id;
    
    -- Add FOP limit if specified
    IF p_fop_group IS NOT NULL AND p_annual_limit IS NOT NULL THEN
        INSERT INTO bank_account_limits (
            tenant_id, company_id, account_id,
            fop_group, annual_limit,
            last_reset_date
        ) VALUES (
            v_tenant_id, p_company_id, v_new_account_id,
            p_fop_group, p_annual_limit,
            DATE_TRUNC('year', CURRENT_DATE)::DATE
        );
    END IF;
    
    RAISE NOTICE 'Bank account created: % (%) with code %', p_bank_name_ar, p_currency, v_next_code;
    
    RETURN v_new_account_id;
END;
$$;


