--
-- Name: add_module_to_plan(uuid, uuid, boolean); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.add_module_to_plan(p_plan_id uuid, p_module_id uuid, p_is_core boolean DEFAULT false) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_module_exists BOOLEAN;
BEGIN
    -- التحقق من وجود الموديول
    SELECT EXISTS (
        SELECT 1 FROM system_modules WHERE id = p_module_id
    ) INTO v_module_exists;
    
    IF NOT v_module_exists THEN
        RETURN jsonb_build_object(
            'success', false,
            'error', 'module_not_found',
            'message', 'الموديول غير موجود'
        );
    END IF;
    
    -- إضافة الموديول
    INSERT INTO plan_modules (plan_id, module_id, is_enabled, is_core)
    VALUES (p_plan_id, p_module_id, true, p_is_core)
    ON CONFLICT (plan_id, module_id) DO UPDATE SET
        is_enabled = true,
        is_core = EXCLUDED.is_core,
        updated_at = NOW();
    
    RETURN jsonb_build_object(
        'success', true,
        'message', 'تمت إضافة الموديول بنجاح'
    );
    
EXCEPTION
    WHEN OTHERS THEN
        RETURN jsonb_build_object(
            'success', false,
            'error', 'exception',
            'message', SQLERRM
        );
END;
$$;


