--
-- Name: add_pending_leave_on_insert(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.add_pending_leave_on_insert() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
BEGIN
    IF NEW.status = 'pending' THEN
        UPDATE leave_balances
        SET pending_days = pending_days + NEW.total_days
        WHERE employee_id = NEW.employee_id
        AND leave_type_id = NEW.leave_type_id
        AND year = EXTRACT(YEAR FROM NEW.start_date);
    END IF;
    RETURN NEW;
END;
$$;


--
-- Name: add_product_image(uuid, uuid, text, boolean, text, integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.add_product_image(p_tenant_id uuid, p_product_id uuid, p_image_url text, p_is_primary boolean DEFAULT false, p_alt_text text DEFAULT NULL::text, p_display_order integer DEFAULT NULL::integer) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_current_images JSONB;
    v_new_image JSONB;
    v_updated_images JSONB;
    v_max_order INT;
BEGIN
    -- 1. الحصول على الصور الحالية
    SELECT COALESCE(images, '[]'::jsonb)
    INTO v_current_images
    FROM products
    WHERE id = p_product_id AND tenant_id = p_tenant_id;
    
    -- 2. تحديد display_order إذا لم يُحدد
    IF p_display_order IS NULL THEN
        SELECT COALESCE(MAX((img->>'display_order')::int), 0) + 1
        INTO v_max_order
        FROM jsonb_array_elements(v_current_images) AS img;
        
        p_display_order := v_max_order;
    END IF;
    
    -- 3. إنشاء كائن الصورة الجديدة
    v_new_image := jsonb_build_object(
        'url', p_image_url,
        'is_primary', p_is_primary,
        'alt_text', COALESCE(p_alt_text, ''),
        'display_order', p_display_order,
        'uploaded_at', NOW()
    );
    
    -- 4. إذا كانت primary، اجعل الصور الأخرى غير primary
    IF p_is_primary THEN
        v_updated_images := (
            SELECT jsonb_agg(
                jsonb_set(img, '{is_primary}', 'false'::jsonb)
            )
            FROM jsonb_array_elements(v_current_images) AS img
        );
        v_current_images := COALESCE(v_updated_images, '[]'::jsonb);
    END IF;
    
    -- 5. إضافة الصورة الجديدة
    v_updated_images := v_current_images || v_new_image;
    
    -- 6. تحديث المنتج
    UPDATE products
    SET images = v_updated_images,
        updated_at = NOW()
    WHERE id = p_product_id AND tenant_id = p_tenant_id;
    
    RETURN v_new_image;
END;
$$;


