--
-- Name: add_product_review(uuid, uuid, uuid, uuid, integer, character varying, text, uuid, jsonb); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.add_product_review(p_tenant_id uuid, p_company_id uuid, p_product_id uuid, p_customer_id uuid, p_rating integer, p_title character varying, p_review_text text, p_order_id uuid DEFAULT NULL::uuid, p_images jsonb DEFAULT '[]'::jsonb) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_review_id UUID;
    v_is_verified BOOLEAN := false;
    v_result JSONB;
BEGIN
    -- التحقق من صحة التقييم
    IF p_rating < 1 OR p_rating > 5 THEN
        RETURN jsonb_build_object(
            'success', false,
            'error', 'التقييم يجب أن يكون من 1 إلى 5'
        );
    END IF;
    
    -- التحقق من شراء المنتج
    IF p_order_id IS NOT NULL THEN
        IF EXISTS (
            SELECT 1 FROM order_items oi
            INNER JOIN orders o ON o.id = oi.order_id
            WHERE oi.order_id = p_order_id
              AND oi.product_id = p_product_id
              AND o.customer_id = p_customer_id
              AND o.status IN ('delivered', 'confirmed')
        ) THEN
            v_is_verified := true;
        END IF;
    END IF;
    
    -- إضافة التقييم
    INSERT INTO product_reviews (
        tenant_id, company_id, product_id, customer_id, order_id,
        rating, title, review_text, images,
        is_verified_purchase, status
    )
    VALUES (
        p_tenant_id, p_company_id, p_product_id, p_customer_id, p_order_id,
        p_rating, p_title, p_review_text, p_images,
        v_is_verified, 'pending'
    )
    RETURNING id INTO v_review_id;
    
    -- إرجاع النتيجة
    v_result := jsonb_build_object(
        'success', true,
        'review_id', v_review_id,
        'is_verified_purchase', v_is_verified,
        'status', 'pending',
        'message', 'تم إرسال التقييم بنجاح. سيتم مراجعته قريباً'
    );
    
    RETURN v_result;
END;
$$;


