--
-- Name: add_to_cart(uuid, uuid, uuid, numeric, uuid, character varying, uuid, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.add_to_cart(p_tenant_id uuid, p_company_id uuid, p_product_id uuid, p_quantity numeric DEFAULT 1, p_customer_id uuid DEFAULT NULL::uuid, p_session_id character varying DEFAULT NULL::character varying, p_product_variant_id uuid DEFAULT NULL::uuid, p_notes text DEFAULT NULL::text) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_cart_id UUID;
    v_item_id UUID;
    v_unit_price DECIMAL;
    v_original_price DECIMAL;
    v_discount_percent DECIMAL;
    v_product_name VARCHAR;
    v_available_qty DECIMAL;
BEGIN
    -- ═══════════════════════════════════════════════════════════════
    -- 1. الحصول على أو إنشاء السلة
    -- ═══════════════════════════════════════════════════════════════
    v_cart_id := get_or_create_cart(p_tenant_id, p_company_id, p_customer_id, p_session_id);
    
    -- ═══════════════════════════════════════════════════════════════
    -- 2. حساب السعر (حسب العميل)
    -- ═══════════════════════════════════════════════════════════════
    SELECT 
        customer_price,
        base_price,
        discount_percent,
        name_ar
    INTO 
        v_unit_price,
        v_original_price,
        v_discount_percent,
        v_product_name
    FROM get_products_for_store(
        p_tenant_id,
        p_customer_id,
        NULL, NULL, NULL, NULL, NULL,
        'created_at', 'DESC',
        999, 0
    )
    WHERE product_id = p_product_id
    LIMIT 1;
    
    IF v_unit_price IS NULL THEN
        RETURN jsonb_build_object(
            'success', false,
            'error', 'product_not_found',
            'message', 'المنتج غير متاح'
        );
    END IF;
    
    -- ═══════════════════════════════════════════════════════════════
    -- 3. التحقق من التوفر
    -- ═══════════════════════════════════════════════════════════════
    SELECT available_quantity INTO v_available_qty
    FROM get_products_for_store(
        p_tenant_id, p_customer_id, NULL, NULL, NULL, NULL, NULL,
        'created_at', 'DESC', 1, 0
    )
    WHERE product_id = p_product_id;
    
    IF v_available_qty < p_quantity THEN
        RETURN jsonb_build_object(
            'success', false,
            'error', 'insufficient_stock',
            'message', 'الكمية المتاحة: ' || v_available_qty,
            'available_quantity', v_available_qty
        );
    END IF;
    
    -- ═══════════════════════════════════════════════════════════════
    -- 4. إضافة أو تحديث العنصر
    -- ═══════════════════════════════════════════════════════════════
    INSERT INTO shopping_cart_items (
        cart_id,
        product_id,
        product_variant_id,
        quantity,
        unit_price,
        original_price,
        discount_percent,
        notes
    )
    VALUES (
        v_cart_id,
        p_product_id,
        p_product_variant_id,
        p_quantity,
        v_unit_price,
        v_original_price,
        v_discount_percent,
        p_notes
    )
    ON CONFLICT (cart_id, product_id) 
    DO UPDATE SET
        quantity = shopping_cart_items.quantity + EXCLUDED.quantity,
        updated_at = NOW()
    RETURNING id INTO v_item_id;
    
    -- ═══════════════════════════════════════════════════════════════
    -- 5. تحديث مجاميع السلة
    -- ═══════════════════════════════════════════════════════════════
    PERFORM update_cart_totals(v_cart_id);
    
    -- ═══════════════════════════════════════════════════════════════
    -- 6. إرجاع النتيجة
    -- ═══════════════════════════════════════════════════════════════
    RETURN jsonb_build_object(
        'success', true,
        'cart_id', v_cart_id,
        'item_id', v_item_id,
        'product_name', v_product_name,
        'quantity', p_quantity,
        'unit_price', v_unit_price,
        'message', 'تمت الإضافة للسلة'
    );
    
EXCEPTION
    WHEN OTHERS THEN
        RETURN jsonb_build_object(
            'success', false,
            'error', 'add_failed',
            'message', SQLERRM
        );
END;
$$;


--
-- Name: FUNCTION add_to_cart(p_tenant_id uuid, p_company_id uuid, p_product_id uuid, p_quantity numeric, p_customer_id uuid, p_session_id character varying, p_product_variant_id uuid, p_notes text); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION public.add_to_cart(p_tenant_id uuid, p_company_id uuid, p_product_id uuid, p_quantity numeric, p_customer_id uuid, p_session_id character varying, p_product_variant_id uuid, p_notes text) IS 'إضافة منتج للسلة مع التحقق من التوفر';


--
-- Name: add_user_by_super_admin(character varying, character varying, character varying, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.add_user_by_super_admin(p_user_email character varying, p_user_name character varying, p_role_code character varying, p_tenant_id uuid DEFAULT NULL::uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_user_id UUID;
    v_role_id UUID;
    v_result JSONB;
BEGIN
    -- التحقق من أن المستخدم الحالي Super Admin
    IF NOT is_super_admin(auth.uid()) THEN
        SELECT jsonb_build_object(
            'success', false,
            'error', 'غير مصرح - يجب أن تكون Super Admin'
        ) INTO v_result;
        RETURN v_result;
    END IF;
    
    -- البحث عن المستخدم في Auth
    SELECT id INTO v_user_id
    FROM auth.users
    WHERE email = p_user_email
    LIMIT 1;
    
    IF v_user_id IS NULL THEN
        SELECT jsonb_build_object(
            'success', false,
            'error', 'المستخدم غير موجود في Auth. يرجى إنشاء المستخدم أولاً'
        ) INTO v_result;
        RETURN v_result;
    END IF;
    
    -- الحصول على Role
    SELECT id INTO v_role_id
    FROM roles
    WHERE code = p_role_code
    LIMIT 1;
    
    IF v_role_id IS NULL THEN
        SELECT jsonb_build_object(
            'success', false,
            'error', 'Role غير موجود: ' || p_role_code
        ) INTO v_result;
        RETURN v_result;
    END IF;
    
    -- ربط المستخدم بالـ Role
    INSERT INTO user_roles (user_id, role_id, tenant_id, is_active)
    VALUES (v_user_id, v_role_id, p_tenant_id, true)
    ON CONFLICT (user_id, role_id) 
    DO UPDATE SET is_active = true, tenant_id = p_tenant_id;
    
    -- إرجاع النتيجة
    SELECT jsonb_build_object(
        'success', true,
        'user_id', v_user_id,
        'email', p_user_email,
        'role', p_role_code,
        'message', 'تم إضافة المستخدم بنجاح'
    ) INTO v_result;
    
    RETURN v_result;
END;
$$;


--
-- Name: add_white_label_domain(uuid, character varying, character varying); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.add_white_label_domain(p_agent_id uuid, p_domain character varying, p_domain_type character varying DEFAULT 'subdomain'::character varying) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_agent RECORD;
    v_domain_id UUID;
    v_verification_token VARCHAR(100);
BEGIN
    -- التحقق من الوكيل
    SELECT * INTO v_agent FROM agents WHERE id = p_agent_id AND has_white_label = true AND white_label_status = 'active';
    IF NOT FOUND THEN
        RETURN jsonb_build_object('success', false, 'error', 'الوكيل غير مفعل لـ White Label');
    END IF;
    
    -- التحقق من عدم وجود الدومين
    IF EXISTS (SELECT 1 FROM white_label_domains WHERE domain = p_domain) THEN
        RETURN jsonb_build_object('success', false, 'error', 'الدومين مسجل مسبقاً');
    END IF;
    
    -- توليد token للتحقق
    v_verification_token := 'WL-' || UPPER(SUBSTRING(MD5(RANDOM()::TEXT || NOW()::TEXT), 1, 32));
    
    -- إضافة الدومين
    INSERT INTO white_label_domains (agent_id, domain, domain_type, verification_token, status)
    VALUES (p_agent_id, p_domain, p_domain_type, v_verification_token, 'pending')
    RETURNING id INTO v_domain_id;
    
    RETURN jsonb_build_object(
        'success', true,
        'domain_id', v_domain_id,
        'verification_token', v_verification_token,
        'message', 'تم إضافة الدومين بنجاح - يرجى تكوين DNS'
    );
END;
$$;


--
-- Name: advance_transaction_stage(text, uuid, text, uuid, text, text, text, text, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.advance_transaction_stage(p_type text, p_transaction_id uuid, p_new_stage text, p_user_id uuid, p_user_name text DEFAULT NULL::text, p_notes text DEFAULT NULL::text, p_cancellation_reason text DEFAULT NULL::text, p_ip_address text DEFAULT NULL::text, p_user_agent text DEFAULT NULL::text) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $_$
DECLARE
    v_current_stage TEXT;
    v_company_id UUID;
    v_tenant_id UUID;
    v_generated_no TEXT;
    v_number_field TEXT;
    v_date_field TEXT;
    v_user_field TEXT;
    v_user_name_field TEXT;
    v_at_field TEXT;
    v_sql TEXT;
BEGIN
    -- 1. قفل السجل وقراءة المرحلة الحالية
    IF p_type = 'purchase' THEN
        SELECT stage, company_id, tenant_id
        INTO v_current_stage, v_company_id, v_tenant_id
        FROM purchase_transactions
        WHERE id = p_transaction_id
        FOR UPDATE;
    ELSE
        SELECT stage, company_id, tenant_id
        INTO v_current_stage, v_company_id, v_tenant_id
        FROM sales_transactions
        WHERE id = p_transaction_id
        FOR UPDATE;
    END IF;

    IF v_current_stage IS NULL THEN
        RETURN jsonb_build_object('success', false, 'error', 'المعاملة غير موجودة');
    END IF;

    -- 2. التحقق من صلاحية التحويل
    IF NOT is_valid_stage_transition(p_type, v_current_stage, p_new_stage) THEN
        RETURN jsonb_build_object(
            'success', false,
            'error', format('تحويل غير مسموح: %s → %s', v_current_stage, p_new_stage)
        );
    END IF;

    -- 3. تحديد حقول المستخدم لهذه المرحلة
    v_user_field := CASE p_new_stage
        WHEN 'quotation' THEN 'quoted_by'
        WHEN 'reservation' THEN 'reserved_by'
        WHEN 'order' THEN 'ordered_by'
        WHEN 'approved' THEN 'approved_by'
        WHEN 'receipt' THEN 'received_by'
        WHEN 'delivery' THEN 'delivered_by'
        WHEN 'invoice' THEN 'invoiced_by'
        WHEN 'posted' THEN 'posted_by'
        WHEN 'cancelled' THEN 'cancelled_by'
        ELSE NULL
    END;

    v_user_name_field := CASE WHEN v_user_field IS NOT NULL THEN v_user_field || '_name' ELSE NULL END;

    v_at_field := CASE p_new_stage
        WHEN 'quotation' THEN 'quoted_at'
        WHEN 'reservation' THEN 'reserved_at'
        WHEN 'order' THEN 'ordered_at'
        WHEN 'approved' THEN 'approved_at'
        WHEN 'receipt' THEN 'received_at'
        WHEN 'delivery' THEN 'delivered_at'
        WHEN 'invoice' THEN 'invoiced_at'
        WHEN 'posted' THEN 'posted_at'
        WHEN 'cancelled' THEN 'cancelled_at'
        ELSE NULL
    END;

    -- 4. توليد رقم
    IF p_new_stage IN ('quotation', 'reservation', 'order', 'receipt', 'delivery', 'invoice') THEN
        v_generated_no := generate_stage_number(v_tenant_id, v_company_id, p_type, p_new_stage);
        v_number_field := p_new_stage || '_no';
        v_date_field := p_new_stage || '_date';
    END IF;

    -- 5. تحديث السجل
    IF p_type = 'purchase' THEN
        v_sql := 'UPDATE purchase_transactions SET stage = $1, updated_at = NOW(), updated_by = $2';
    ELSE
        v_sql := 'UPDATE sales_transactions SET stage = $1, updated_at = NOW(), updated_by = $2';
    END IF;

    IF v_number_field IS NOT NULL AND v_generated_no IS NOT NULL THEN
        v_sql := v_sql || format(', %I = %L', v_number_field, v_generated_no);
        v_sql := v_sql || format(', %I = CURRENT_DATE', v_date_field);
    END IF;

    IF v_user_field IS NOT NULL THEN
        v_sql := v_sql || format(', %I = %L', v_user_field, p_user_id);
        IF p_user_name IS NOT NULL AND v_user_name_field IS NOT NULL THEN
            v_sql := v_sql || format(', %I = %L', v_user_name_field, p_user_name);
        END IF;
        IF v_at_field IS NOT NULL THEN
            v_sql := v_sql || format(', %I = NOW()', v_at_field);
        END IF;
    END IF;

    IF p_new_stage = 'posted' THEN
        v_sql := v_sql || ', is_posted = true';
    END IF;

    IF p_new_stage = 'cancelled' AND p_cancellation_reason IS NOT NULL THEN
        v_sql := v_sql || format(', cancellation_reason = %L', p_cancellation_reason);
    END IF;

    IF p_new_stage = 'approved' AND p_notes IS NOT NULL THEN
        v_sql := v_sql || format(', approval_notes = %L', p_notes);
    END IF;

    v_sql := v_sql || ' WHERE id = $3';

    EXECUTE v_sql USING p_new_stage, p_user_id, p_transaction_id;

    -- 6. تسجيل في سجل المراحل
    INSERT INTO transaction_stage_log (
        transaction_type, transaction_id,
        from_stage, to_stage,
        generated_number, notes,
        performed_by, performed_by_name, ip_address, user_agent
    ) VALUES (
        p_type, p_transaction_id,
        v_current_stage, p_new_stage,
        v_generated_no, COALESCE(p_notes, p_cancellation_reason),
        p_user_id, p_user_name, p_ip_address, p_user_agent
    );

    -- 7. النتيجة
    RETURN jsonb_build_object(
        'success', true,
        'from_stage', v_current_stage,
        'to_stage', p_new_stage,
        'generated_number', v_generated_no,
        'performed_by', p_user_id,
        'performed_by_name', p_user_name
    );
END;
$_$;


--
-- Name: allocate_container_costs(uuid, character varying); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.allocate_container_costs(p_container_id uuid, p_allocation_method character varying DEFAULT NULL::character varying) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_container RECORD;
    v_item RECORD;
    v_total_goods_value NUMERIC := 0;
    v_total_expenses NUMERIC := 0;
    v_total_quantity NUMERIC := 0;
    v_allocation_method VARCHAR;
    v_ratio NUMERIC;
    v_allocated_cost NUMERIC;
    v_final_unit_cost NUMERIC;
    v_items_updated INTEGER := 0;
    v_result JSONB;
BEGIN
    -- جلب بيانات الكونتينر
    SELECT c.*, comp.tenant_id 
    INTO v_container
    FROM containers c
    JOIN companies comp ON c.company_id = comp.id
    WHERE c.id = p_container_id;
    
    IF NOT FOUND THEN
        RETURN jsonb_build_object(
            'success', false,
            'error', 'Container not found',
            'error_ar', 'الكونتينر غير موجود'
        );
    END IF;
    
    -- التحقق من أن التكاليف غير مثبتة
    IF v_container.is_cost_finalized = true THEN
        RETURN jsonb_build_object(
            'success', false,
            'error', 'Container costs already finalized',
            'error_ar', 'تكاليف الكونتينر مثبتة بالفعل'
        );
    END IF;
    
    -- تحديد طريقة التوزيع
    v_allocation_method := COALESCE(p_allocation_method, v_container.cost_allocation_method, 'by_value');
    
    -- حساب إجمالي قيمة البضاعة
    SELECT COALESCE(SUM(unit_cost * expected_quantity), 0)
    INTO v_total_goods_value
    FROM container_items
    WHERE container_id = p_container_id;
    
    -- حساب إجمالي المصاريف
    SELECT COALESCE(SUM(COALESCE(actual_amount, expected_amount, amount, 0)), 0)
    INTO v_total_expenses
    FROM container_expenses
    WHERE container_id = p_container_id;
    
    -- حساب إجمالي الكمية (لطريقة by_quantity)
    SELECT COALESCE(SUM(expected_quantity), 0)
    INTO v_total_quantity
    FROM container_items
    WHERE container_id = p_container_id;
    
    -- توزيع المصاريف على البنود
    FOR v_item IN 
        SELECT * FROM container_items WHERE container_id = p_container_id
    LOOP
        -- حساب النسبة حسب طريقة التوزيع
        CASE v_allocation_method
            WHEN 'by_value' THEN
                IF v_total_goods_value > 0 THEN
                    v_ratio := (v_item.unit_cost * v_item.expected_quantity) / v_total_goods_value;
                ELSE
                    v_ratio := 1.0 / NULLIF((SELECT COUNT(*) FROM container_items WHERE container_id = p_container_id), 0);
                END IF;
                
            WHEN 'by_quantity' THEN
                IF v_total_quantity > 0 THEN
                    v_ratio := v_item.expected_quantity / v_total_quantity;
                ELSE
                    v_ratio := 1.0 / NULLIF((SELECT COUNT(*) FROM container_items WHERE container_id = p_container_id), 0);
                END IF;
                
            WHEN 'by_weight' THEN
                -- توزيع حسب الوزن
                SELECT COALESCE(SUM(weight_kg), SUM(expected_quantity)) INTO v_total_quantity
                FROM container_items WHERE container_id = p_container_id;
                
                IF v_total_quantity > 0 THEN
                    v_ratio := COALESCE(v_item.weight_kg, v_item.expected_quantity) / v_total_quantity;
                ELSE
                    v_ratio := 1.0 / NULLIF((SELECT COUNT(*) FROM container_items WHERE container_id = p_container_id), 0);
                END IF;
                
            ELSE -- manual or unknown
                v_ratio := 0; -- keep existing values
        END CASE;
        
        -- حساب التكلفة الموزعة
        v_allocated_cost := v_total_expenses * COALESCE(v_ratio, 0);
        
        -- حساب تكلفة الوحدة النهائية
        IF v_item.expected_quantity > 0 THEN
            v_final_unit_cost := (v_item.unit_cost * v_item.expected_quantity + v_allocated_cost) / v_item.expected_quantity;
        ELSE
            v_final_unit_cost := v_item.unit_cost;
        END IF;
        
        -- تحديث البند
        IF v_allocation_method != 'manual' THEN
            UPDATE container_items
            SET 
                allocated_costs = v_allocated_cost,
                cost_per_unit_allocated = CASE WHEN expected_quantity > 0 THEN v_allocated_cost / expected_quantity ELSE 0 END,
                provisional_unit_cost = v_item.unit_cost,
                final_unit_cost = v_final_unit_cost,
                total_provisional_cost = v_item.unit_cost * expected_quantity,
                total_final_cost = v_final_unit_cost * expected_quantity,
                updated_at = NOW()
            WHERE id = v_item.id;
            
            v_items_updated := v_items_updated + 1;
        END IF;
    END LOOP;
    
    -- تحديث الكونتينر
    UPDATE containers
    SET 
        provisional_goods_cost = v_total_goods_value,
        total_expected_costs = (SELECT COALESCE(SUM(expected_amount), 0) FROM container_expenses WHERE container_id = p_container_id),
        total_actual_costs = v_total_expenses,
        total_landed_cost = v_total_goods_value + v_total_expenses,
        cost_allocation_method = v_allocation_method,
        updated_at = NOW()
    WHERE id = p_container_id;
    
    -- إرجاع النتيجة
    RETURN jsonb_build_object(
        'success', true,
        'container_id', p_container_id,
        'allocation_method', v_allocation_method,
        'total_goods_value', v_total_goods_value,
        'total_expenses', v_total_expenses,
        'total_landed_cost', v_total_goods_value + v_total_expenses,
        'items_updated', v_items_updated
    );
    
EXCEPTION WHEN OTHERS THEN
    RETURN jsonb_build_object(
        'success', false,
        'error', SQLERRM,
        'error_code', SQLSTATE
    );
END;
$$;


--
-- Name: apply_audit_trigger(text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.apply_audit_trigger(p_table_name text) RETURNS void
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_trigger_name TEXT;
BEGIN
    v_trigger_name := 'trg_audit_' || p_table_name;
    
    -- حذف Trigger القديم
    EXECUTE format('DROP TRIGGER IF EXISTS %I ON %I', v_trigger_name, p_table_name);
    
    -- إنشاء Trigger جديد
    EXECUTE format('
        CREATE TRIGGER %I
        AFTER INSERT OR UPDATE OR DELETE ON %I
        FOR EACH ROW
        EXECUTE FUNCTION auto_audit_log()
    ', v_trigger_name, p_table_name);
    
    RAISE NOTICE '✅ تم تطبيق Audit Trigger على %', p_table_name;
EXCEPTION
    WHEN OTHERS THEN
        RAISE NOTICE '⚠️ فشل تطبيق Audit على %: %', p_table_name, SQLERRM;
END;
$$;


--
-- Name: apply_auto_company_trigger(text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.apply_auto_company_trigger(p_table_name text) RETURNS void
    LANGUAGE plpgsql
    AS $$
BEGIN
    EXECUTE format('DROP TRIGGER IF EXISTS trg_auto_company_%I ON public.%I', p_table_name, p_table_name);
    
    EXECUTE format('
        CREATE TRIGGER trg_auto_company_%I
            BEFORE INSERT ON public.%I
            FOR EACH ROW
            EXECUTE FUNCTION public.auto_set_company_id()
    ', p_table_name, p_table_name);
END;
$$;


--
-- Name: apply_auto_tenant_trigger(text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.apply_auto_tenant_trigger(p_table_name text) RETURNS void
    LANGUAGE plpgsql
    AS $$
BEGIN
    -- حذف التريغر القديم إن وجد
    EXECUTE format('DROP TRIGGER IF EXISTS trg_auto_tenant_%I ON public.%I', p_table_name, p_table_name);
    
    -- إنشاء التريغر الجديد
    EXECUTE format('
        CREATE TRIGGER trg_auto_tenant_%I
            BEFORE INSERT ON public.%I
            FOR EACH ROW
            EXECUTE FUNCTION public.auto_set_tenant_id()
    ', p_table_name, p_table_name);
END;
$$;


--
-- Name: apply_brand_isolation_trigger(text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.apply_brand_isolation_trigger(p_table_name text) RETURNS void
    LANGUAGE plpgsql
    AS $$
BEGIN
    EXECUTE format('DROP TRIGGER IF EXISTS trg_brand_isolation_%I ON public.%I', p_table_name, p_table_name);
    
    EXECUTE format('
        CREATE TRIGGER trg_brand_isolation_%I
            BEFORE INSERT OR UPDATE ON public.%I
            FOR EACH ROW
            EXECUTE FUNCTION public.enforce_brand_isolation()
    ', p_table_name, p_table_name);
END;
$$;


--
-- Name: apply_chart_template_to_company(uuid, character varying); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.apply_chart_template_to_company(p_company_id uuid, p_template_code character varying) RETURNS void
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_template RECORD;
    v_tenant_id UUID;
BEGIN
    SELECT tenant_id INTO v_tenant_id FROM companies WHERE id = p_company_id;
    
    SELECT * INTO v_template FROM chart_templates
    WHERE tenant_id = v_tenant_id AND template_code = p_template_code AND is_active = true;

    IF v_template IS NULL THEN
        RAISE EXCEPTION 'القالب % غير موجود أو غير نشط', p_template_code;
    END IF;

    IF EXISTS (SELECT 1 FROM chart_of_accounts WHERE company_id = p_company_id LIMIT 1) THEN
        RAISE EXCEPTION 'الشركة لديها شجرة حسابات مسبقة — لا يمكن تطبيق قالب جديد';
    END IF;

    CASE v_template.chart_type
        WHEN 'simple' THEN
            PERFORM create_simple_chart(p_company_id);
        WHEN 'extended' THEN
            PERFORM create_extended_chart(p_company_id);
        ELSE
            RAISE EXCEPTION 'نوع شجرة غير معروف: %', v_template.chart_type;
    END CASE;

    -- Set defaults
    PERFORM auto_set_default_accounts(p_company_id);

    RAISE NOTICE '✅ تم تطبيق القالب % على الشركة %', p_template_code, p_company_id;
END;
$$;


--
-- Name: apply_coa_template(uuid, character varying); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.apply_coa_template(p_company_id uuid, p_template_code character varying) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_template_id UUID;
    v_tenant_id UUID;
    v_accounts_created INT := 0;
    v_cash_accounts_created INT := 0;
    v_account_map JSONB := '{}'::JSONB;
    v_item RECORD;
    v_new_account_id UUID;
    v_parent_id UUID;
    v_gl_account_id UUID;
    v_account_type_id UUID;
BEGIN
    SELECT id INTO v_template_id FROM coa_templates WHERE code = p_template_code;
    IF v_template_id IS NULL THEN
        RETURN jsonb_build_object('success', false, 'error', 'Template not found');
    END IF;
    
    SELECT tenant_id INTO v_tenant_id FROM companies WHERE id = p_company_id;
    IF v_tenant_id IS NULL THEN
        RETURN jsonb_build_object('success', false, 'error', 'Company not found');
    END IF;
    
    -- إزالة العلاقات وحذف البيانات القديمة
    UPDATE customers SET receivable_account_id = NULL WHERE company_id = p_company_id;
    UPDATE suppliers SET payable_account_id = NULL WHERE company_id = p_company_id;
    UPDATE chart_of_accounts SET parent_id = NULL WHERE company_id = p_company_id;
    DELETE FROM cash_accounts WHERE company_id = p_company_id;
    DELETE FROM chart_of_accounts WHERE company_id = p_company_id;
    
    -- إدراج الحسابات
    FOR v_item IN 
        SELECT * FROM coa_template_items 
        WHERE template_id = v_template_id 
        ORDER BY level, display_order
    LOOP
        v_parent_id := NULL;
        IF v_item.parent_code IS NOT NULL THEN
            v_parent_id := (v_account_map->>v_item.parent_code)::UUID;
        END IF;
        
        SELECT id INTO v_account_type_id FROM account_types WHERE code = v_item.account_type_code;
        
        INSERT INTO chart_of_accounts (
            tenant_id, company_id, account_code, parent_id, account_type_id,
            name_ar, name_en, name_ru, name_uk, name_ro, name_pl, name_tr, name_de, name_it,
            is_group, is_detail, level, is_cash_account, is_bank_account, 
            is_receivable, is_payable, is_active
        ) VALUES (
            v_tenant_id, p_company_id, v_item.account_code, v_parent_id, v_account_type_id,
            v_item.name_ar, v_item.name_en, v_item.name_ru, v_item.name_uk, 
            v_item.name_ro, v_item.name_pl, v_item.name_tr, v_item.name_de, v_item.name_it,
            v_item.is_group, v_item.is_detail, v_item.level,
            v_item.is_cash_account, v_item.is_bank_account, 
            v_item.is_receivable, v_item.is_payable, true
        ) RETURNING id INTO v_new_account_id;
        
        v_account_map := v_account_map || jsonb_build_object(v_item.account_code, v_new_account_id);
        v_accounts_created := v_accounts_created + 1;
    END LOOP;
    
    -- إدراج الحسابات النقدية (بدون is_default)
    FOR v_item IN 
        SELECT * FROM coa_template_cash_accounts WHERE template_id = v_template_id
    LOOP
        v_gl_account_id := (v_account_map->>v_item.account_code)::UUID;
        
        IF v_gl_account_id IS NOT NULL THEN
            INSERT INTO cash_accounts (
                tenant_id, company_id, code, gl_account_id, 
                name_ar, name_en, account_type, currency, bank_name, is_active
            ) VALUES (
                v_tenant_id, p_company_id, v_item.code, v_gl_account_id,
                v_item.name_ar, v_item.name_en, v_item.account_type, 
                COALESCE(v_item.currency, 'UAH'), v_item.bank_name, true
            );
            v_cash_accounts_created := v_cash_accounts_created + 1;
        END IF;
    END LOOP;
    
    -- ربط الحسابات الافتراضية
    UPDATE customers SET receivable_account_id = (v_account_map->>'115')::UUID
    WHERE company_id = p_company_id AND (v_account_map->>'115') IS NOT NULL;
    
    UPDATE suppliers SET payable_account_id = (v_account_map->>'211')::UUID
    WHERE company_id = p_company_id AND (v_account_map->>'211') IS NOT NULL;
    
    UPDATE companies SET coa_template_applied = p_template_code, updated_at = NOW()
    WHERE id = p_company_id;
    
    RETURN jsonb_build_object(
        'success', true,
        'template_code', p_template_code,
        'accounts_created', v_accounts_created,
        'cash_accounts_created', v_cash_accounts_created
    );
    
EXCEPTION WHEN OTHERS THEN
    RETURN jsonb_build_object('success', false, 'error', SQLERRM, 'detail', SQLSTATE);
END;
$$;


--
-- Name: apply_comprehensive_rls(text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.apply_comprehensive_rls(p_table_name text) RETURNS void
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_table_exists BOOLEAN;
    v_tenant_id_exists BOOLEAN;
    v_policy_name TEXT;
BEGIN
    -- التحقق من وجود الجدول
    SELECT EXISTS (
        SELECT 1 FROM information_schema.tables 
        WHERE table_schema = 'public' AND table_name = p_table_name
    ) INTO v_table_exists;
    
    IF NOT v_table_exists THEN
        RAISE NOTICE '⚠️ الجدول % غير موجود - سيتم تخطيه', p_table_name;
        RETURN;
    END IF;
    
    -- التحقق من وجود عمود tenant_id
    SELECT EXISTS (
        SELECT 1 FROM information_schema.columns 
        WHERE table_schema = 'public' 
          AND table_name = p_table_name 
          AND column_name = 'tenant_id'
    ) INTO v_tenant_id_exists;
    
    IF NOT v_tenant_id_exists THEN
        RAISE NOTICE '⚠️ الجدول % لا يحتوي على عمود tenant_id - سيتم تخطيه', p_table_name;
        RETURN;
    END IF;
    
    v_policy_name := p_table_name || '_tenant_isolation';
    
    -- تفعيل RLS
    EXECUTE format('ALTER TABLE %I ENABLE ROW LEVEL SECURITY', p_table_name);
    
    -- حذف جميع Policies القديمة
    EXECUTE format('DROP POLICY IF EXISTS %I ON %I', v_policy_name || '_select', p_table_name);
    EXECUTE format('DROP POLICY IF EXISTS %I ON %I', v_policy_name || '_insert', p_table_name);
    EXECUTE format('DROP POLICY IF EXISTS %I ON %I', v_policy_name || '_update', p_table_name);
    EXECUTE format('DROP POLICY IF EXISTS %I ON %I', v_policy_name || '_delete', p_table_name);
    EXECUTE format('DROP POLICY IF EXISTS %I ON %I', v_policy_name, p_table_name);
    
    -- إنشاء Policies جديدة (مع التحقق من Super Admin مباشرة)
    EXECUTE format('
        CREATE POLICY %I ON %I
        FOR SELECT
        USING (
            tenant_id = get_current_tenant_id() 
            OR COALESCE(
                (auth.jwt() -> ''user_metadata'' ->> ''is_super_admin'')::BOOLEAN,
                (auth.jwt() -> ''app_metadata'' ->> ''is_super_admin'')::BOOLEAN,
                false
            )
        )
    ', v_policy_name || '_select', p_table_name);
    
    EXECUTE format('
        CREATE POLICY %I ON %I
        FOR INSERT
        WITH CHECK (
            tenant_id = get_current_tenant_id() 
            OR COALESCE(
                (auth.jwt() -> ''user_metadata'' ->> ''is_super_admin'')::BOOLEAN,
                (auth.jwt() -> ''app_metadata'' ->> ''is_super_admin'')::BOOLEAN,
                false
            )
        )
    ', v_policy_name || '_insert', p_table_name);
    
    EXECUTE format('
        CREATE POLICY %I ON %I
        FOR UPDATE
        USING (
            tenant_id = get_current_tenant_id() 
            OR COALESCE(
                (auth.jwt() -> ''user_metadata'' ->> ''is_super_admin'')::BOOLEAN,
                (auth.jwt() -> ''app_metadata'' ->> ''is_super_admin'')::BOOLEAN,
                false
            )
        )
        WITH CHECK (
            tenant_id = get_current_tenant_id() 
            OR COALESCE(
                (auth.jwt() -> ''user_metadata'' ->> ''is_super_admin'')::BOOLEAN,
                (auth.jwt() -> ''app_metadata'' ->> ''is_super_admin'')::BOOLEAN,
                false
            )
        )
    ', v_policy_name || '_update', p_table_name);
    
    EXECUTE format('
        CREATE POLICY %I ON %I
        FOR DELETE
        USING (
            tenant_id = get_current_tenant_id() 
            OR COALESCE(
                (auth.jwt() -> ''user_metadata'' ->> ''is_super_admin'')::BOOLEAN,
                (auth.jwt() -> ''app_metadata'' ->> ''is_super_admin'')::BOOLEAN,
                false
            )
        )
    ', v_policy_name || '_delete', p_table_name);
    
    RAISE NOTICE '✅ تم تطبيق RLS على %', p_table_name;
END;
$$;


--
-- Name: apply_rls_to_table(text, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.apply_rls_to_table(p_table_name text, p_policy_name text DEFAULT NULL::text) RETURNS void
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_policy_name TEXT;
    v_table_exists BOOLEAN;
    v_tenant_id_exists BOOLEAN;
BEGIN
    -- التحقق من وجود الجدول
    SELECT EXISTS (
        SELECT 1 FROM information_schema.tables 
        WHERE table_schema = 'public' AND table_name = p_table_name
    ) INTO v_table_exists;
    
    IF NOT v_table_exists THEN
        RAISE NOTICE '⚠️ الجدول % غير موجود - سيتم تخطيه', p_table_name;
        RETURN;
    END IF;
    
    -- التحقق من وجود عمود tenant_id
    SELECT EXISTS (
        SELECT 1 FROM information_schema.columns 
        WHERE table_schema = 'public' 
          AND table_name = p_table_name 
          AND column_name = 'tenant_id'
    ) INTO v_tenant_id_exists;
    
    IF NOT v_tenant_id_exists THEN
        RAISE NOTICE '⚠️ الجدول % لا يحتوي على عمود tenant_id - سيتم تخطيه', p_table_name;
        RETURN;
    END IF;
    
    -- استخدام اسم الـ policy المحدد أو الافتراضي
    v_policy_name := COALESCE(p_policy_name, p_table_name || '_tenant_isolation');
    
    -- تفعيل RLS
    EXECUTE format('ALTER TABLE %I ENABLE ROW LEVEL SECURITY', p_table_name);
    
    -- حذف الـ policy القديم إن وجد
    EXECUTE format('DROP POLICY IF EXISTS %I ON %I', v_policy_name, p_table_name);
    
    -- إنشاء الـ policy الجديد
    EXECUTE format('CREATE POLICY %I ON %I FOR ALL USING (tenant_id = get_current_tenant_id() OR is_super_admin()) WITH CHECK (tenant_id = get_current_tenant_id() OR is_super_admin())', 
        v_policy_name, p_table_name);
    
    RAISE NOTICE '✅ تم تطبيق RLS على %', p_table_name;
END;
$$;


--
-- Name: approve_delivery_note(uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.approve_delivery_note(p_note_id uuid, p_approved_by uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_note RECORD;
BEGIN
    SELECT * INTO v_note FROM delivery_notes WHERE id = p_note_id;
    
    IF NOT FOUND THEN
        RETURN jsonb_build_object('success', false, 'error', 'Delivery note not found');
    END IF;
    
    IF v_note.status != 'pending_approval' THEN
        RETURN jsonb_build_object('success', false, 'error', 'Note is not pending approval');
    END IF;
    
    UPDATE delivery_notes
    SET 
        status = 'approved',
        approved_by = p_approved_by,
        approved_at = NOW()
    WHERE id = p_note_id;
    
    RETURN jsonb_build_object(
        'success', true,
        'note_id', p_note_id,
        'status', 'approved'
    );
END;
$$;


--
-- Name: approve_recurring_entry(uuid, uuid, boolean); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.approve_recurring_entry(p_history_id uuid, p_user_id uuid, p_execute_now boolean DEFAULT true) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_history RECORD;
    v_result JSONB;
BEGIN
    -- جلب السجل
    SELECT * INTO v_history FROM recurring_entry_history WHERE id = p_history_id;
    IF NOT FOUND THEN
        RETURN jsonb_build_object('success', false, 'error', 'Record not found');
    END IF;
    
    -- التحقق من الحالة
    IF v_history.approval_status != 'pending' THEN
        RETURN jsonb_build_object('success', false, 'error', 'Already processed');
    END IF;
    
    -- تحديث الموافقة
    UPDATE recurring_entry_history
    SET 
        approval_status = 'approved',
        approved_by = p_user_id,
        approved_at = NOW()
    WHERE id = p_history_id;
    
    -- تنفيذ القيد إذا طُلب
    IF p_execute_now THEN
        v_result := execute_recurring_entry(p_history_id, p_user_id);
        RETURN v_result;
    END IF;
    
    RETURN jsonb_build_object(
        'success', true,
        'message', 'Approved successfully',
        'executed', false
    );
END;
$$;


--
-- Name: FUNCTION approve_recurring_entry(p_history_id uuid, p_user_id uuid, p_execute_now boolean); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION public.approve_recurring_entry(p_history_id uuid, p_user_id uuid, p_execute_now boolean) IS 'الموافقة على قيد متكرر مع خيار التنفيذ';


--
-- Name: approve_review(uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.approve_review(p_tenant_id uuid, p_review_id uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_product_id UUID;
    v_result JSONB;
BEGIN
    -- تحديث حالة التقييم
    UPDATE product_reviews
    SET status = 'approved',
        approved_at = NOW(),
        updated_at = NOW()
    WHERE id = p_review_id
      AND tenant_id = p_tenant_id
    RETURNING product_id INTO v_product_id;
    
    IF NOT FOUND THEN
        RETURN jsonb_build_object('success', false, 'error', 'التقييم غير موجود');
    END IF;
    
    -- تحديث إحصائيات المنتج
    PERFORM update_product_review_stats(p_tenant_id, v_product_id);
    
    RETURN jsonb_build_object('success', true, 'message', 'تمت الموافقة على التقييم');
END;
$$;


