--
-- Name: assign_available_tenant(character varying, character varying); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.assign_available_tenant(p_user_email character varying, p_user_name character varying) RETURNS uuid
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_tenant_id UUID;
    v_tenant_code VARCHAR(50);
BEGIN
    -- البحث عن tenant متاح
    SELECT id, code INTO v_tenant_id, v_tenant_code
    FROM tenants
    WHERE status = 'available'
    ORDER BY created_at ASC
    LIMIT 1
    FOR UPDATE SKIP LOCKED;  -- تجنب التعارض
    
    IF v_tenant_id IS NULL THEN
        RAISE EXCEPTION 'لا يوجد Tenants متاحة حالياً';
    END IF;
    
    -- تحديث بيانات Tenant
    UPDATE tenants
    SET 
        name = p_user_name,
        owner_email = p_user_email,
        status = 'active',
        updated_at = NOW()
    WHERE id = v_tenant_id;
    
    RAISE NOTICE '✅ تم ربط المشترك بـ Tenant: %', v_tenant_code;
    
    RETURN v_tenant_id;
END;
$$;


--
-- Name: auto_audit_log(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.auto_audit_log() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_action VARCHAR(50);
    v_old_values JSONB;
    v_new_values JSONB;
    v_entity_name VARCHAR(255);
BEGIN
    IF TG_OP = 'INSERT' THEN
        v_action := 'create';
        v_new_values := to_jsonb(NEW);
        v_entity_name := COALESCE(
            (v_new_values->>'name_ar'),
            (v_new_values->>'name_en'),
            (v_new_values->>'name'),
            (v_new_values->>'code'),
            NEW.id::TEXT
        );
    ELSIF TG_OP = 'UPDATE' THEN
        v_action := 'update';
        v_old_values := to_jsonb(OLD);
        v_new_values := to_jsonb(NEW);
        v_entity_name := COALESCE(
            (v_new_values->>'name_ar'),
            (v_new_values->>'name_en'),
            (v_new_values->>'name'),
            (v_new_values->>'code'),
            NEW.id::TEXT
        );
    ELSIF TG_OP = 'DELETE' THEN
        v_action := 'delete';
        v_old_values := to_jsonb(OLD);
        v_entity_name := COALESCE(
            (v_old_values->>'name_ar'),
            (v_old_values->>'name_en'),
            (v_old_values->>'name'),
            (v_old_values->>'code'),
            OLD.id::TEXT
        );
    END IF;
    
    BEGIN
        PERFORM log_audit(v_action, TG_TABLE_NAME, COALESCE(NEW.id, OLD.id), v_entity_name, v_old_values, v_new_values);
    EXCEPTION WHEN OTHERS THEN NULL;
    END;
    
    RETURN COALESCE(NEW, OLD);
END;
$$;


--
-- Name: auto_create_customer_sub_account(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.auto_create_customer_sub_account() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_parent_id UUID;
    v_type_id UUID;
    v_tenant_id UUID;
    v_seq INT;
    v_new_code TEXT;
    v_new_id UUID;
BEGIN
    -- Find the parent account for customers
    -- Extended: 1131 (ذمم الجملة) | Simple: 113 (العملاء)
    SELECT id, account_type_id INTO v_parent_id, v_type_id
    FROM chart_of_accounts
    WHERE company_id = NEW.company_id
      AND account_code IN ('1131', '113', '1130', '1310', '1311')
      AND (is_group = true OR is_detail = false)
    ORDER BY 
        CASE account_code 
            WHEN '1131' THEN 1  -- prefer Extended
            WHEN '113'  THEN 2  -- fallback Simple
            ELSE 3
        END
    LIMIT 1;

    IF v_parent_id IS NULL THEN
        RETURN NEW;  -- No parent found, skip silently
    END IF;

    SELECT tenant_id INTO v_tenant_id
    FROM chart_of_accounts WHERE id = v_parent_id;

    SELECT COUNT(*) + 1 INTO v_seq
    FROM chart_of_accounts
    WHERE parent_id = v_parent_id AND is_party_account = true;

    v_new_code := (SELECT account_code FROM chart_of_accounts WHERE id = v_parent_id)
                  || '-' || LPAD(v_seq::TEXT, 3, '0');

    INSERT INTO chart_of_accounts (
        id, account_code, name_ar, name_en,
        parent_id, company_id, tenant_id, account_type_id,
        is_group, is_detail, is_system, is_party_account,
        party_id, party_type, current_balance
    ) VALUES (
        gen_random_uuid(), v_new_code,
        NEW.name_ar, NEW.name_en,
        v_parent_id, NEW.company_id, v_tenant_id, v_type_id,
        false, true, false, true,
        NEW.id, 'customer', 0
    )
    RETURNING id INTO v_new_id;

    NEW.receivable_account_id := v_new_id;
    RETURN NEW;
END;
$$;


--
-- Name: auto_create_employee_sub_account(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.auto_create_employee_sub_account() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_parent_id UUID;
    v_type_id UUID;
    v_tenant_id UUID;
    v_seq INT;
    v_new_code TEXT;
    v_new_id UUID;
    v_emp_name_ar TEXT;
    v_emp_name_en TEXT;
BEGIN
    -- البحث عن حساب الرواتب المستحقة
    SELECT id, account_type_id INTO v_parent_id, v_type_id
    FROM chart_of_accounts
    WHERE company_id = NEW.company_id
      AND account_code IN ('213', '2120', '2130', '214')
      AND (is_group = true OR is_detail = false)
    ORDER BY CASE account_code WHEN '213' THEN 1 WHEN '2120' THEN 2 WHEN '214' THEN 3 ELSE 4 END
    LIMIT 1;

    IF v_parent_id IS NULL THEN 
        RAISE NOTICE '⚠️ حساب الرواتب (213) غير موجود — تخطي';
        RETURN NEW; 
    END IF;

    SELECT tenant_id INTO v_tenant_id FROM chart_of_accounts WHERE id = v_parent_id;

    -- حساب التسلسل (تجاهل الحساب الملخص)
    SELECT COUNT(*) + 1 INTO v_seq
    FROM chart_of_accounts 
    WHERE parent_id = v_parent_id 
      AND is_party_account = true;

    v_new_code := (SELECT account_code FROM chart_of_accounts WHERE id = v_parent_id)
                  || '-' || LPAD(v_seq::TEXT, 3, '0');

    v_emp_name_ar := TRIM(NEW.first_name_ar || ' ' || COALESCE(NEW.last_name_ar, ''));
    v_emp_name_en := TRIM(COALESCE(NEW.first_name_en, '') || ' ' || COALESCE(NEW.last_name_en, ''));

    INSERT INTO chart_of_accounts (
        id, account_code, name_ar, name_en,
        parent_id, company_id, tenant_id, account_type_id,
        is_group, is_detail, is_system, is_party_account,
        party_id, party_type, current_balance
    ) VALUES (
        gen_random_uuid(), v_new_code, v_emp_name_ar, v_emp_name_en,
        v_parent_id, NEW.company_id, v_tenant_id, v_type_id,
        false, true, false, true, NEW.id, 'employee', 0
    ) RETURNING id INTO v_new_id;

    NEW.payable_account_id := v_new_id;

    RAISE NOTICE '✅ حساب فرعي للموظف: % (كود: %)', v_emp_name_ar, v_new_code;
    RETURN NEW;
END;
$$;


--
-- Name: FUNCTION auto_create_employee_sub_account(); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION public.auto_create_employee_sub_account() IS 'إنشاء حساب فرعي تلقائي للموظف تحت 213 (الرواتب المستحقة)';


--
-- Name: auto_create_supplier_sub_account(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.auto_create_supplier_sub_account() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_parent_id UUID;
    v_type_id UUID;
    v_tenant_id UUID;
    v_seq INT;
    v_new_code TEXT;
    v_new_id UUID;
BEGIN
    -- Find the parent account for suppliers
    -- Extended: 2111 (دين الموردين - رئيسي) | Simple: 211 (الموردون)
    SELECT id, account_type_id INTO v_parent_id, v_type_id
    FROM chart_of_accounts
    WHERE company_id = NEW.company_id
      AND account_code IN ('2111', '211', '2110')
      AND (is_group = true OR is_detail = false)
    ORDER BY 
        CASE account_code 
            WHEN '2111' THEN 1  -- prefer Extended
            WHEN '211'  THEN 2  -- fallback Simple
            ELSE 3
        END
    LIMIT 1;

    IF v_parent_id IS NULL THEN
        RETURN NEW;  -- No parent found, skip silently
    END IF;

    SELECT tenant_id INTO v_tenant_id
    FROM chart_of_accounts WHERE id = v_parent_id;

    SELECT COUNT(*) + 1 INTO v_seq
    FROM chart_of_accounts
    WHERE parent_id = v_parent_id AND is_party_account = true;

    v_new_code := (SELECT account_code FROM chart_of_accounts WHERE id = v_parent_id)
                  || '-' || LPAD(v_seq::TEXT, 3, '0');

    INSERT INTO chart_of_accounts (
        id, account_code, name_ar, name_en,
        parent_id, company_id, tenant_id, account_type_id,
        is_group, is_detail, is_system, is_party_account,
        party_id, party_type, current_balance
    ) VALUES (
        gen_random_uuid(), v_new_code,
        NEW.name_ar, NEW.name_en,
        v_parent_id, NEW.company_id, v_tenant_id, v_type_id,
        false, true, false, true,
        NEW.id, 'supplier', 0
    )
    RETURNING id INTO v_new_id;

    NEW.payable_account_id := v_new_id;
    RETURN NEW;
END;
$$;


