--

CREATE FUNCTION public.calc_transaction_balance() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
    NEW.balance := COALESCE(NEW.total_amount, 0) - COALESCE(NEW.paid_amount, 0);
    NEW.updated_at := NOW();
    RETURN NEW;
END;
$$;


--
-- Name: calculate_next_execution_date(character varying, date, integer, integer, integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.calculate_next_execution_date(p_frequency character varying, p_current_date date, p_day_of_week integer DEFAULT NULL::integer, p_day_of_month integer DEFAULT NULL::integer, p_month_of_year integer DEFAULT NULL::integer) RETURNS date
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_next_date DATE;
    v_temp_date DATE;
BEGIN
    CASE p_frequency
        WHEN 'daily' THEN
            v_next_date := p_current_date + INTERVAL '1 day';
            
        WHEN 'weekly' THEN
            v_next_date := p_current_date + INTERVAL '7 days';
            IF p_day_of_week IS NOT NULL THEN
                v_next_date := p_current_date + ((7 + p_day_of_week - EXTRACT(DOW FROM p_current_date)::INT) % 7 + 7)::INT;
            END IF;
            
        WHEN 'monthly' THEN
            v_temp_date := p_current_date + INTERVAL '1 month';
            IF p_day_of_month IS NOT NULL THEN
                v_next_date := DATE_TRUNC('month', v_temp_date) + (LEAST(p_day_of_month, 
                    EXTRACT(DAY FROM (DATE_TRUNC('month', v_temp_date) + INTERVAL '1 month' - INTERVAL '1 day'))::INT) - 1) * INTERVAL '1 day';
            ELSE
                v_next_date := v_temp_date;
            END IF;
            
        WHEN 'quarterly' THEN
            v_temp_date := p_current_date + INTERVAL '3 months';
            IF p_day_of_month IS NOT NULL THEN
                v_next_date := DATE_TRUNC('month', v_temp_date) + (LEAST(p_day_of_month, 28) - 1) * INTERVAL '1 day';
            ELSE
                v_next_date := v_temp_date;
            END IF;
            
        WHEN 'yearly' THEN
            v_temp_date := p_current_date + INTERVAL '1 year';
            IF p_month_of_year IS NOT NULL AND p_day_of_month IS NOT NULL THEN
                v_next_date := MAKE_DATE(
                    EXTRACT(YEAR FROM v_temp_date)::INT,
                    p_month_of_year,
                    LEAST(p_day_of_month, 28)
                );
            ELSE
                v_next_date := v_temp_date;
            END IF;
            
        ELSE
            v_next_date := p_current_date + INTERVAL '1 month';
    END CASE;
    
    RETURN v_next_date;
END;
$$;


--
-- Name: calculate_next_run_date(date, character varying, integer, integer, integer, integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.calculate_next_run_date(p_current_date date, p_frequency character varying, p_interval_value integer, p_day_of_month integer, p_day_of_week integer, p_month_of_year integer) RETURNS date
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_next_date DATE;
BEGIN
    CASE p_frequency
        WHEN 'daily' THEN
            v_next_date := p_current_date + (p_interval_value * INTERVAL '1 day');
            
        WHEN 'weekly' THEN
            v_next_date := p_current_date + (p_interval_value * INTERVAL '1 week');
            IF p_day_of_week IS NOT NULL THEN
                v_next_date := v_next_date + (p_day_of_week - EXTRACT(DOW FROM v_next_date))::INTEGER;
            END IF;
            
        WHEN 'bi_weekly' THEN
            v_next_date := p_current_date + (p_interval_value * INTERVAL '2 weeks');
            
        WHEN 'monthly' THEN
            v_next_date := p_current_date + (p_interval_value * INTERVAL '1 month');
            IF p_day_of_month IS NOT NULL THEN
                v_next_date := DATE_TRUNC('month', v_next_date) + (LEAST(p_day_of_month, EXTRACT(DAY FROM DATE_TRUNC('month', v_next_date) + INTERVAL '1 month - 1 day')::INTEGER) - 1) * INTERVAL '1 day';
            END IF;
            
        WHEN 'quarterly' THEN
            v_next_date := p_current_date + (p_interval_value * INTERVAL '3 months');
            
        WHEN 'semi_annual' THEN
            v_next_date := p_current_date + (p_interval_value * INTERVAL '6 months');
            
        WHEN 'yearly' THEN
            v_next_date := p_current_date + (p_interval_value * INTERVAL '1 year');
            
        ELSE
            v_next_date := p_current_date + INTERVAL '1 month';
    END CASE;
    
    RETURN v_next_date;
END;
$$;


--
-- Name: calculate_product_price(uuid, uuid, uuid, numeric); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.calculate_product_price(p_tenant_id uuid, p_product_id uuid, p_customer_id uuid DEFAULT NULL::uuid, p_quantity numeric DEFAULT 1) RETURNS jsonb
    LANGUAGE plpgsql STABLE SECURITY DEFINER
    AS $$
DECLARE
    v_base_price DECIMAL;
    v_result JSONB;
BEGIN
    -- الحصول على السعر الأساسي
    SELECT COALESCE(default_price, 0) INTO v_base_price
    FROM products
    WHERE id = p_product_id;
    
    -- إرجاع نتيجة بسيطة
    v_result := jsonb_build_object(
        'base_price', v_base_price,
        'customer_price', v_base_price,
        'discount_percent', 0,
        'discount_amount', 0,
        'total_price', v_base_price * p_quantity,
        'price_source', 'base_price'
    );
    
    RETURN v_result;
END;
$$;


--
-- Name: calculate_sales_commission(uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.calculate_sales_commission(p_invoice_id uuid, p_employee_id uuid DEFAULT NULL::uuid) RETURNS TABLE(employee_id uuid, plan_id uuid, commission_amount numeric, tier_applied integer, base_amount numeric, rate_applied numeric)
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_invoice RECORD;
    v_assignment RECORD;
    v_tier RECORD;
    v_base_amount DECIMAL(15,2);
    v_commission DECIMAL(15,2);
    v_rate DECIMAL(10,4);
    v_tier_num INT;
BEGIN
    SELECT i.*, i.total_amount as invoice_total, i.salesperson_id, i.company_id, i.tenant_id
    INTO v_invoice FROM invoices i WHERE i.id = p_invoice_id;
    
    IF v_invoice IS NULL THEN RETURN; END IF;
    
    IF p_employee_id IS NULL THEN p_employee_id := v_invoice.salesperson_id; END IF;
    IF p_employee_id IS NULL THEN RETURN; END IF;
    
    FOR v_assignment IN 
        SELECT ea.*, ip.*,
               COALESCE(ea.custom_rate, ip.base_rate) as effective_rate,
               COALESCE(ea.custom_cap, ip.max_cap) as effective_cap
        FROM employee_incentive_assignments ea
        JOIN incentive_plans ip ON ip.id = ea.plan_id
        WHERE ea.employee_id = p_employee_id
          AND ea.is_active = true
          AND ea.company_id = v_invoice.company_id
          AND ip.is_active = true
          AND ip.target_type IN ('sales', 'mixed')
          AND v_invoice.invoice_date BETWEEN ea.start_date AND COALESCE(ea.end_date, '9999-12-31')
          AND v_invoice.invoice_date BETWEEN ip.effective_from AND COALESCE(ip.effective_to, '9999-12-31')
    LOOP
        v_base_amount := v_invoice.invoice_total;
        
        IF NOT v_assignment.include_discounts THEN
            v_base_amount := v_base_amount - COALESCE(v_invoice.discount_amount, 0);
        END IF;
        
        IF v_base_amount < v_assignment.min_threshold THEN CONTINUE; END IF;
        
        v_commission := 0;
        v_tier_num := NULL;
        v_rate := v_assignment.effective_rate;
        
        CASE v_assignment.calculation_method
            WHEN 'percentage' THEN
                v_commission := v_base_amount * v_rate / 100;
            WHEN 'fixed_per_unit' THEN
                SELECT COALESCE(SUM(quantity), 0) INTO v_commission FROM invoice_items WHERE invoice_id = p_invoice_id;
                v_commission := v_commission * v_rate;
            WHEN 'tiered', 'slab' THEN
                SELECT * INTO v_tier FROM incentive_plan_tiers
                WHERE plan_id = v_assignment.plan_id
                  AND from_amount <= v_base_amount
                  AND (to_amount IS NULL OR to_amount >= v_base_amount)
                ORDER BY tier_number DESC LIMIT 1;
                
                IF v_tier IS NOT NULL THEN
                    v_tier_num := v_tier.tier_number;
                    IF v_tier.rate_type = 'percentage' THEN
                        v_commission := v_base_amount * v_tier.rate / 100;
                    ELSE
                        v_commission := v_tier.rate;
                    END IF;
                    v_commission := v_commission + v_tier.bonus_amount;
                    v_rate := v_tier.rate;
                END IF;
            ELSE
                v_commission := v_base_amount * v_rate / 100;
        END CASE;
        
        IF v_assignment.effective_cap IS NOT NULL AND v_commission > v_assignment.effective_cap THEN
            v_commission := v_assignment.effective_cap;
        END IF;
        
        employee_id := p_employee_id;
        plan_id := v_assignment.plan_id;
        commission_amount := v_commission;
        tier_applied := v_tier_num;
        base_amount := v_base_amount;
        rate_applied := v_rate;
        
        RETURN NEXT;
    END LOOP;
    
    RETURN;
END;
$$;


--
-- Name: calculate_worked_hours(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.calculate_worked_hours() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
    IF NEW.check_in IS NOT NULL AND NEW.check_out IS NOT NULL THEN
        NEW.worked_hours := ROUND(EXTRACT(EPOCH FROM (NEW.check_out - NEW.check_in)) / 3600.0, 2);
    END IF;
    RETURN NEW;
END;
$$;


--
-- Name: can_access_company(uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.can_access_company(p_company_id uuid, p_user_id uuid DEFAULT auth.uid()) RETURNS boolean
    LANGUAGE plpgsql STABLE SECURITY DEFINER
    AS $$
DECLARE
    v_user_company_id UUID;
    v_user_tenant_id UUID;
    v_company_tenant_id UUID;
    v_company_brand_id UUID;
    v_user_brand_id UUID;
BEGIN
    -- Platform Owner يرى كل شيء (كل البراندات)
    IF is_platform_owner(p_user_id) THEN
        RETURN true;
    END IF;
    
    -- الحصول على بيانات المستخدم
    SELECT company_id, tenant_id 
    INTO v_user_company_id, v_user_tenant_id
    FROM public.user_profiles
    WHERE id = p_user_id;
    
    -- الحصول على بيانات الشركة
    SELECT c.tenant_id, t.product_id INTO v_company_tenant_id, v_company_brand_id
    FROM public.companies c
    LEFT JOIN public.tenants t ON c.tenant_id = t.id
    WHERE c.id = p_company_id;
    
    -- ═══ الخطوة 1: التحقق من البراند ═══
    v_user_brand_id := get_user_brand_id(p_user_id);
    
    -- Partner/Reseller: يتحقق من البراندات المسموح له بها
    IF is_partner_or_reseller(p_user_id) THEN
        IF v_company_brand_id IS NOT NULL 
           AND NOT (v_company_brand_id = ANY(get_partner_allowed_brand_ids(p_user_id))) THEN
            RETURN false;
        END IF;
        -- الوكيل يمكنه الوصول لشركات التينانتات التابعة له
        IF v_company_tenant_id = ANY(get_partner_tenant_ids(p_user_id)) THEN
            RETURN true;
        END IF;
    END IF;
    
    -- المستخدم العادي: يجب أن يكون في نفس البراند
    IF v_user_brand_id IS NOT NULL AND v_company_brand_id IS NOT NULL THEN
        IF v_user_brand_id != v_company_brand_id THEN
            RETURN false;
        END IF;
    END IF;
    
    -- ═══ الخطوة 2: التحقق من التينانت ═══
    IF v_user_tenant_id IS NULL OR v_company_tenant_id IS NULL THEN
        RETURN false;
    END IF;
    
    IF v_user_tenant_id != v_company_tenant_id THEN
        RETURN false;
    END IF;
    
    -- ═══ الخطوة 3: التحقق من الشركة ═══
    -- Tenant Owner يرى كل شركات التينانت
    IF is_tenant_owner(p_user_id) THEN
        RETURN true;
    END IF;
    
    -- التحقق من الشركة المُعينة للمستخدم
    IF v_user_company_id = p_company_id THEN
        RETURN true;
    END IF;
    
    -- التحقق من الصلاحيات المتعددة للشركات عبر user_roles
    RETURN EXISTS (
        SELECT 1 FROM public.user_roles ur
        WHERE ur.user_id = p_user_id
          AND ur.company_id = p_company_id
          AND ur.is_active = true
    );
EXCEPTION WHEN OTHERS THEN
    RETURN false;
END;
$$;


--
-- Name: can_access_fund(uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.can_access_fund(p_fund_account_id uuid, p_user_id uuid DEFAULT auth.uid()) RETURNS boolean
    LANGUAGE plpgsql STABLE SECURITY DEFINER
    AS $$
BEGIN
    -- Platform & Tenant admins see all
    IF is_super_admin(p_user_id) OR is_tenant_admin(p_user_id) THEN
        RETURN true;
    END IF;
    
    -- Company admins see all company funds
    IF is_company_admin(p_user_id) THEN
        RETURN true;
    END IF;
    
    -- Check direct permission
    RETURN EXISTS (
        SELECT 1 FROM user_fund_permissions
        WHERE user_id = p_user_id
          AND fund_account_id = p_fund_account_id
          AND can_view = true
    );
END;
$$;


--
-- Name: can_access_warehouse(uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.can_access_warehouse(p_warehouse_id uuid, p_user_id uuid DEFAULT auth.uid()) RETURNS boolean
    LANGUAGE plpgsql STABLE SECURITY DEFINER
    AS $$
BEGIN
    IF is_super_admin(p_user_id) OR is_tenant_admin(p_user_id) THEN
        RETURN true;
    END IF;
    
    IF is_company_admin(p_user_id) THEN
        RETURN true;
    END IF;
    
    RETURN EXISTS (
        SELECT 1 FROM user_warehouse_permissions
        WHERE user_id = p_user_id
          AND warehouse_id = p_warehouse_id
          AND can_view = true
    );
END;
$$;


