--
-- Name: can_edit_journal_entry(uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.can_edit_journal_entry(p_entry_id uuid, p_user_id uuid DEFAULT auth.uid()) RETURNS jsonb
    LANGUAGE plpgsql STABLE SECURITY DEFINER
    AS $$
DECLARE
    v_entry RECORD;
    v_period RECORD;
    v_fiscal_year RECORD;
    v_settings JSONB;
    v_mode VARCHAR;
BEGIN
    SELECT * INTO v_entry FROM journal_entries WHERE id = p_entry_id;
    IF NOT FOUND THEN
        RETURN jsonb_build_object('can_edit', false, 'reason', 'entry_not_found', 'message', 'القيد غير موجود');
    END IF;
    
    SELECT COALESCE(accounting_settings, '{}'::jsonb) INTO v_settings FROM companies WHERE id = v_entry.company_id;
    v_mode := COALESCE(v_settings->>'fiscal_year_mode', 'independent');
    
    SELECT * INTO v_period FROM accounting_periods WHERE id = v_entry.period_id;
    SELECT * INTO v_fiscal_year FROM fiscal_years WHERE id = v_entry.fiscal_year_id;
    
    IF NOT v_entry.is_posted THEN
        RETURN jsonb_build_object('can_edit', true, 'mode', 'direct', 'message', 'القيد مسودة');
    END IF;
    
    IF (v_fiscal_year IS NULL OR v_fiscal_year.status = 'open') AND 
       (v_period IS NULL OR v_period.status = 'open') THEN
        RETURN jsonb_build_object('can_edit', true, 'mode', 'unpost_edit_repost', 'auto_unpost', true);
    END IF;
    
    IF v_fiscal_year IS NOT NULL AND v_fiscal_year.status = 'closed' AND v_mode = 'independent' THEN
        RETURN jsonb_build_object(
            'can_edit', COALESCE((v_settings->'closed_year_settings'->>'allow_edit_closed_year')::boolean, true),
            'mode', 'independent_closed_year',
            'require_reason', true
        );
    END IF;
    
    IF v_fiscal_year IS NOT NULL AND v_fiscal_year.status = 'closed' AND v_mode = 'linked' THEN
        RETURN jsonb_build_object('can_edit', false, 'mode', 'linked_closed_year');
    END IF;
    
    RETURN jsonb_build_object('can_edit', true, 'mode', 'default');
END;
$$;


--
-- Name: can_enable_mfa(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.can_enable_mfa(p_user_id uuid) RETURNS TABLE(can_enable boolean, reason_ar text, reason_en text, missing_fields text[])
    LANGUAGE plpgsql STABLE SECURITY DEFINER
    AS $$
DECLARE
    v_email TEXT;
    v_phone TEXT;
    v_full_name TEXT;
    v_system_enabled BOOLEAN;
    v_require_profile BOOLEAN;
    v_missing TEXT[] := ARRAY[]::TEXT[];
BEGIN
    -- التحقق من إعدادات النظام
    SELECT is_enabled, require_complete_profile 
    INTO v_system_enabled, v_require_profile
    FROM mfa_system_settings LIMIT 1;
    
    -- إذا الخدمة معطلة على مستوى النظام
    IF NOT COALESCE(v_system_enabled, false) THEN
        RETURN QUERY SELECT 
            false,
            'خدمة التحقق بخطوتين معطلة حالياً'::TEXT,
            'Two-factor authentication is currently disabled'::TEXT,
            ARRAY[]::TEXT[];
        RETURN;
    END IF;
    
    -- الحصول على بيانات المستخدم
    SELECT 
        COALESCE(up.email, au.email),
        up.phone,
        up.full_name
    INTO v_email, v_phone, v_full_name
    FROM user_profiles up
    LEFT JOIN auth.users au ON au.id = up.id
    WHERE up.id = p_user_id;
    
    -- التحقق من اكتمال البيانات إذا مطلوب
    IF v_require_profile THEN
        IF v_email IS NULL OR v_email = '' THEN
            v_missing := array_append(v_missing, 'email');
        END IF;
        
        IF v_full_name IS NULL OR v_full_name = '' THEN
            v_missing := array_append(v_missing, 'full_name');
        END IF;
    END IF;
    
    -- إذا هناك حقول ناقصة
    IF array_length(v_missing, 1) > 0 THEN
        RETURN QUERY SELECT 
            false,
            'يرجى إكمال بياناتك الشخصية أولاً'::TEXT,
            'Please complete your profile first'::TEXT,
            v_missing;
        RETURN;
    END IF;
    
    -- المستخدم مؤهل
    RETURN QUERY SELECT 
        true,
        'يمكنك تفعيل التحقق بخطوتين'::TEXT,
        'You can enable two-factor authentication'::TEXT,
        ARRAY[]::TEXT[];
END;
$$;


--
-- Name: can_user_see_module(uuid, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.can_user_see_module(p_user_id uuid, p_module_code text) RETURNS boolean
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
BEGIN
    RETURN EXISTS (
        SELECT 1
        FROM user_roles ur
        JOIN roles r ON ur.role_id = r.id
        WHERE ur.user_id = p_user_id
          AND ur.is_active = true
          AND p_module_code = ANY(r.visible_modules)
    );
END;
$$;


--
-- Name: change_document_status(uuid, character varying, uuid, uuid, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.change_document_status(p_tenant_id uuid, p_doc_type character varying, p_doc_id uuid, p_new_status_id uuid, p_comment text DEFAULT NULL::text) RETURNS uuid
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_history_id UUID;
  v_old_status_id UUID;
BEGIN
  SELECT to_status_id INTO v_old_status_id
  FROM status_history
  WHERE tenant_id = p_tenant_id AND doc_type = p_doc_type AND doc_id = p_doc_id
  ORDER BY created_at DESC
  LIMIT 1;

  IF v_old_status_id IS NOT NULL THEN
    IF NOT EXISTS (
      SELECT 1 FROM status_transitions
      WHERE (tenant_id = p_tenant_id OR tenant_id IS NULL)
        AND doc_type = p_doc_type
        AND from_status_id = v_old_status_id
        AND to_status_id = p_new_status_id
    ) THEN
      RAISE EXCEPTION 'Transition not allowed from current status';
    END IF;
  END IF;

  INSERT INTO status_history (tenant_id, doc_type, doc_id, from_status_id, to_status_id, changed_by, comment)
  VALUES (p_tenant_id, p_doc_type, p_doc_id, v_old_status_id, p_new_status_id, auth.uid(), p_comment)
  RETURNING id INTO v_history_id;
  
  RETURN v_history_id;
END;
$$;


--
-- Name: change_subscription_plan(uuid, character varying, character varying); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.change_subscription_plan(p_tenant_id uuid, p_new_plan_code character varying, p_billing_cycle character varying DEFAULT 'monthly'::character varying) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_subscription RECORD;
    v_old_plan RECORD;
    v_new_plan RECORD;
    v_new_amount DECIMAL(10,2);
    v_module TEXT;
BEGIN
    -- الحصول على الاشتراك الحالي
    SELECT s.*, p.code as plan_code INTO v_subscription
    FROM subscriptions s
    JOIN subscription_plans p ON s.plan_id = p.id
    WHERE s.tenant_id = p_tenant_id AND s.status IN ('active', 'trial')
    LIMIT 1;
    
    IF NOT FOUND THEN
        RETURN jsonb_build_object('success', false, 'error', 'لا يوجد اشتراك نشط');
    END IF;
    
    -- الحصول على الباقة القديمة
    SELECT * INTO v_old_plan FROM subscription_plans WHERE id = v_subscription.plan_id;
    
    -- الحصول على الباقة الجديدة
    SELECT * INTO v_new_plan FROM subscription_plans 
    WHERE product_id = v_subscription.product_id AND code = p_new_plan_code AND is_active = true;
    
    IF NOT FOUND THEN
        RETURN jsonb_build_object('success', false, 'error', 'الباقة الجديدة غير موجودة');
    END IF;
    
    -- حساب المبلغ الجديد
    v_new_amount := CASE WHEN p_billing_cycle = 'yearly' 
        THEN v_new_plan.price_yearly 
        ELSE v_new_plan.price_monthly 
    END;
    
    -- تحديث الاشتراك
    UPDATE subscriptions
    SET plan_id = v_new_plan.id,
        billing_cycle = p_billing_cycle,
        amount = v_new_amount,
        updated_at = NOW()
    WHERE id = v_subscription.id;
    
    -- إزالة الموديولات القديمة من الباقة
    DELETE FROM tenant_modules
    WHERE tenant_id = p_tenant_id AND source = 'plan';
    
    -- إضافة الموديولات الجديدة
    FOREACH v_module IN ARRAY v_new_plan.included_modules
    LOOP
        INSERT INTO tenant_modules (tenant_id, module_code, source)
        VALUES (p_tenant_id, v_module, 'plan')
        ON CONFLICT (tenant_id, module_code) DO UPDATE SET source = 'plan';
    END LOOP;
    
    -- تسجيل الحدث
    INSERT INTO saas_events (tenant_id, event_type, event_data, actor_type)
    VALUES (p_tenant_id, 'plan_changed', jsonb_build_object(
        'old_plan', v_old_plan.code,
        'new_plan', v_new_plan.code,
        'billing_cycle', p_billing_cycle
    ), 'admin');
    
    RETURN jsonb_build_object(
        'success', true,
        'old_plan', v_old_plan.code,
        'new_plan', v_new_plan.code,
        'new_amount', v_new_amount
    );
END;
$$;


--
-- Name: check_bank_limit(uuid, numeric); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.check_bank_limit(p_account_id uuid, p_amount numeric) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_limit RECORD;
    v_new_total DECIMAL(15, 2);
    v_percentage DECIMAL(5, 2);
    v_status VARCHAR(20);
    v_message TEXT;
BEGIN
    -- Get limit info
    SELECT * INTO v_limit
    FROM bank_account_limits
    WHERE account_id = p_account_id
      AND is_active = true;
    
    -- No limit configured
    IF v_limit IS NULL THEN
        RETURN jsonb_build_object(
            'status', 'ok',
            'has_limit', false,
            'message', 'No limit configured'
        );
    END IF;
    
    -- Calculate new total
    v_new_total := v_limit.current_year_total + p_amount;
    v_percentage := (v_new_total / v_limit.annual_limit) * 100;
    
    -- Determine status
    IF v_percentage >= 100 THEN
        v_status := 'exceeded';
        v_message := 'Annual limit exceeded! ' || v_new_total || '/' || v_limit.annual_limit || ' UAH (' || ROUND(v_percentage, 1) || '%)';
    ELSIF v_percentage >= v_limit.alert_threshold_percent THEN
        v_status := 'alert';
        v_message := 'Alert: Approaching limit! ' || v_new_total || '/' || v_limit.annual_limit || ' UAH (' || ROUND(v_percentage, 1) || '%)';
    ELSIF v_percentage >= v_limit.warning_threshold_percent THEN
        v_status := 'warning';
        v_message := 'Warning: ' || v_new_total || '/' || v_limit.annual_limit || ' UAH (' || ROUND(v_percentage, 1) || '%)';
    ELSE
        v_status := 'ok';
        v_message := 'Within limit: ' || v_new_total || '/' || v_limit.annual_limit || ' UAH (' || ROUND(v_percentage, 1) || '%)';
    END IF;
    
    RETURN jsonb_build_object(
        'status', v_status,
        'has_limit', true,
        'current_total', v_limit.current_year_total,
        'new_total', v_new_total,
        'annual_limit', v_limit.annual_limit,
        'percentage', v_percentage,
        'fop_group', v_limit.fop_group,
        'message', v_message
    );
END;
$$;


--
-- Name: FUNCTION check_bank_limit(p_account_id uuid, p_amount numeric); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION public.check_bank_limit(p_account_id uuid, p_amount numeric) IS 'Check if a transaction would exceed FOP bank limits';


--
-- Name: check_budget_threshold(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.check_budget_threshold() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_percent NUMERIC;
    v_budget RECORD;
    v_alert_type VARCHAR(50);
    v_severity VARCHAR(20);
    v_message_ar TEXT;
    v_message_en TEXT;
BEGIN
    -- حساب النسبة المئوية
    IF NEW.budgeted_amount > 0 THEN
        v_percent := (NEW.actual_amount / NEW.budgeted_amount) * 100;
    ELSE
        v_percent := 0;
    END IF;
    
    -- تحديث نسبة الانحراف
    NEW.variance_percent := v_percent - 100;
    
    -- جلب معلومات الموازنة
    SELECT * INTO v_budget FROM budgets WHERE id = NEW.budget_id;
    
    -- تحديد نوع التنبيه حسب النسبة
    IF v_percent >= 120 THEN
        v_alert_type := 'critical_120';
        v_severity := 'critical';
        v_message_ar := 'تجاوز حرج! النسبة ' || ROUND(v_percent, 1) || '%';
        v_message_en := 'Critical! ' || ROUND(v_percent, 1) || '% of budget used';
    ELSIF v_percent >= 100 THEN
        v_alert_type := 'exceeded';
        v_severity := 'danger';
        v_message_ar := 'تم تجاوز الموازنة! النسبة ' || ROUND(v_percent, 1) || '%';
        v_message_en := 'Budget exceeded! ' || ROUND(v_percent, 1) || '% used';
    ELSIF v_percent >= 90 THEN
        v_alert_type := 'warning_90';
        v_severity := 'warning';
        v_message_ar := 'تحذير: تم استخدام ' || ROUND(v_percent, 1) || '% من الموازنة';
        v_message_en := 'Warning: ' || ROUND(v_percent, 1) || '% of budget used';
    ELSIF v_percent >= 75 THEN
        v_alert_type := 'warning_75';
        v_severity := 'info';
        v_message_ar := 'تنبيه: تم استخدام ' || ROUND(v_percent, 1) || '% من الموازنة';
        v_message_en := 'Notice: ' || ROUND(v_percent, 1) || '% of budget used';
    ELSE
        -- لا حاجة لتنبيه
        RETURN NEW;
    END IF;
    
    -- إلغاء التنبيهات السابقة من نفس النوع
    UPDATE budget_alerts 
    SET is_active = false 
    WHERE budget_line_id = NEW.id 
      AND alert_type = v_alert_type
      AND is_active = true;
    
    -- إدراج تنبيه جديد
    INSERT INTO budget_alerts (
        tenant_id, budget_id, budget_line_id,
        alert_type, severity, threshold_percent, current_percent,
        budgeted_amount, actual_amount,
        message_ar, message_en
    ) VALUES (
        NEW.tenant_id, NEW.budget_id, NEW.id,
        v_alert_type, v_severity, 
        CASE v_alert_type 
            WHEN 'warning_75' THEN 75
            WHEN 'warning_90' THEN 90
            WHEN 'exceeded' THEN 100
            WHEN 'critical_120' THEN 120
        END,
        v_percent,
        NEW.budgeted_amount, NEW.actual_amount,
        v_message_ar, v_message_en
    );
    
    RETURN NEW;
END;
$$;


--
-- Name: FUNCTION check_budget_threshold(); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION public.check_budget_threshold() IS 'فحص تجاوز عتبات الموازنة وإنشاء تنبيهات';


--
-- Name: check_expired_subscriptions(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.check_expired_subscriptions() RETURNS TABLE(tenant_id uuid, tenant_name character varying, subscription_id uuid, end_date date, days_expired integer, action_taken text)
    LANGUAGE plpgsql
    AS $$
BEGIN
    -- 1. تحديث الاشتراكات المنتهية
    UPDATE tenant_subscriptions ts
    SET 
        status = 'expired',
        updated_at = NOW()
    WHERE ts.end_date < CURRENT_DATE
        AND ts.status = 'active';
    
    -- 2. تعليق المستأجرين بعد فترة السماح
    UPDATE tenants t
    SET 
        status = 'suspended',
        updated_at = NOW()
    FROM tenant_subscriptions ts
    WHERE t.id = ts.tenant_id
        AND ts.grace_period_end < CURRENT_DATE
        AND ts.status = 'expired'
        AND t.status IN ('active', 'trial');
    
    -- 3. إرجاع قائمة بالاشتراكات المنتهية/المعلقة
    -- إصلاح: استخدام طرح التواريخ مباشرة
    RETURN QUERY
    SELECT 
        t.id,
        t.name,
        ts.id,
        ts.end_date,
        (CURRENT_DATE - ts.end_date)::INT,  -- إصلاح هنا
        CASE 
            WHEN t.status = 'suspended' THEN 'Tenant Suspended'
            WHEN ts.status = 'expired' THEN 'Subscription Expired'
            ELSE 'Active'
        END
    FROM tenants t
    JOIN tenant_subscriptions ts ON t.id = ts.tenant_id
    WHERE ts.status IN ('expired')
        OR (t.status = 'suspended' AND ts.end_date < CURRENT_DATE)
    ORDER BY ts.end_date;
END;
$$;


--
-- Name: FUNCTION check_expired_subscriptions(); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION public.check_expired_subscriptions() IS 'فحص وتحديث الاشتراكات المنتهية والمعلقة (محدثة)';


--
-- Name: check_feature_access(uuid, character varying, character varying); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.check_feature_access(p_tenant_id uuid, p_module_code character varying, p_feature_code character varying) RETURNS boolean
    LANGUAGE plpgsql STABLE SECURITY DEFINER
    AS $$
DECLARE
    v_plan_id UUID;
    v_has_access BOOLEAN;
    v_module_enabled BOOLEAN;
BEGIN
    -- التحقق من تفعيل الموديول أولاً
    SELECT COALESCE(tm.is_active, sm.is_core) INTO v_module_enabled
    FROM system_modules sm
    LEFT JOIN tenant_modules tm ON tm.module_code = sm.code AND tm.tenant_id = p_tenant_id
    WHERE sm.code = p_module_code;
    
    IF NOT COALESCE(v_module_enabled, false) THEN
        RETURN false;
    END IF;
    
    -- الحصول على plan_id للـ tenant
    SELECT s.plan_id INTO v_plan_id
    FROM subscriptions s
    WHERE s.tenant_id = p_tenant_id
    AND s.status = 'active'
    ORDER BY s.created_at DESC
    LIMIT 1;
    
    IF v_plan_id IS NULL THEN
        RETURN false;
    END IF;
    
    -- التحقق من الميزة في الباقة
    SELECT COALESCE(pmf.is_enabled, false) INTO v_has_access
    FROM plan_module_features pmf
    WHERE pmf.plan_id = v_plan_id
    AND pmf.module_code = p_module_code
    AND pmf.feature_code = p_feature_code;
    
    RETURN COALESCE(v_has_access, false);
END;
$$;


--
-- Name: check_journal_entry_balance(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.check_journal_entry_balance() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
declare
  total_debit decimal;
  total_credit decimal;
begin
  -- Only check if status is changing to POSTED
  if NEW.status = 'POSTED' and (OLD.status IS DISTINCT FROM 'POSTED') then
    
    -- Calculate totals from lines
    select 
      coalesce(sum(debit), 0), 
      coalesce(sum(credit), 0)
    into 
      total_debit, 
      total_credit
    from journal_entry_lines
    where entry_id = NEW.id;

    -- Check if balanced (allow small precision diff if needed, but strict for now)
    if total_debit != total_credit then
      raise exception 'Journal Entry must be balanced to post. Total Debit: %, Total Credit: %', total_debit, total_credit;
    end if;

    -- Also check if there are no lines
    if total_debit = 0 and total_credit = 0 then
       -- Optional: Decide if 0-value postings allowed. Usually no.
       -- Check if lines exist count
       if not exists (select 1 from journal_entry_lines where entry_id = NEW.id) then
          raise exception 'Cannot post Journal Entry with no lines.';
       end if;
    end if;

  end if;

  return NEW;
end;
$$;


--
-- Name: check_language_limit(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.check_language_limit(p_tenant_id uuid DEFAULT NULL::uuid) RETURNS jsonb
    LANGUAGE plpgsql STABLE SECURITY DEFINER
    AS $$
DECLARE
    v_tenant_id UUID;
    v_plan_id UUID;
    v_max_languages INT;
    v_current_languages INT;
    v_remaining INT;
BEGIN
    v_tenant_id := COALESCE(p_tenant_id, get_current_tenant_id());
    
    IF v_tenant_id IS NULL THEN
        RAISE EXCEPTION 'Tenant not found';
    END IF;
    
    -- الحصول على الباقة الحالية
    SELECT s.plan_id INTO v_plan_id
    FROM subscriptions s
    WHERE s.tenant_id = v_tenant_id
    AND s.status = 'active'
    ORDER BY s.created_at DESC
    LIMIT 1;
    
    IF v_plan_id IS NULL THEN
        RETURN jsonb_build_object(
            'max_languages', 0,
            'current_languages', 0,
            'remaining', 0,
            'can_add_more', false,
            'error', 'No active subscription'
        );
    END IF;
    
    -- الحصول على الحد الأقصى
    SELECT sp.max_languages INTO v_max_languages
    FROM subscription_plans sp
    WHERE sp.id = v_plan_id;
    
    -- عد اللغات الحالية
    SELECT COUNT(*) INTO v_current_languages
    FROM tenant_languages
    WHERE tenant_id = v_tenant_id
    AND is_enabled = true;
    
    v_remaining := GREATEST(0, v_max_languages - v_current_languages);
    
    RETURN jsonb_build_object(
        'max_languages', v_max_languages,
        'current_languages', v_current_languages,
        'remaining', v_remaining,
        'can_add_more', v_remaining > 0
    );
END;
$$;


--
-- Name: check_plan_limits(uuid, character varying); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.check_plan_limits(p_tenant_id uuid, p_limit_type character varying) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_subscription_id UUID;
    v_plan_id UUID;
    v_plan RECORD;
    v_current_count INT;
    v_current_size BIGINT;
BEGIN
    -- الحصول على الاشتراك النشط
    SELECT id, plan_id INTO v_subscription_id, v_plan_id
    FROM subscriptions
    WHERE tenant_id = p_tenant_id
      AND status IN ('trial', 'active')
    ORDER BY created_at DESC
    LIMIT 1;
    
    IF v_plan_id IS NULL THEN
        RETURN jsonb_build_object(
            'allowed', false,
            'error', 'no_active_subscription',
            'error_ar', 'لا يوجد اشتراك نشط',
            'error_en', 'No active subscription'
        );
    END IF;
    
    -- الحصول على تفاصيل الباقة
    SELECT * INTO v_plan FROM subscription_plans WHERE id = v_plan_id;
    
    IF NOT FOUND THEN
        RETURN jsonb_build_object(
            'allowed', false,
            'error', 'plan_not_found',
            'error_ar', 'الباقة غير موجودة',
            'error_en', 'Plan not found'
        );
    END IF;
    
    -- ═══════════════════════════════════════════════════════════════
    -- التحقق حسب نوع الحد
    -- ═══════════════════════════════════════════════════════════════
    
    -- 1. التحقق من عدد الشركات
    IF p_limit_type = 'companies' THEN
        SELECT COUNT(*) INTO v_current_count
        FROM companies
        WHERE tenant_id = p_tenant_id;
        
        RETURN jsonb_build_object(
            'allowed', v_current_count < v_plan.max_companies,
            'limit_type', 'companies',
            'current', v_current_count,
            'max', v_plan.max_companies,
            'remaining', GREATEST(v_plan.max_companies - v_current_count, 0),
            'plan_code', v_plan.code,
            'plan_name_ar', v_plan.name_ar,
            'plan_name_en', v_plan.name_en
        );
    END IF;
    
    -- 2. التحقق من عدد المستخدمين
    IF p_limit_type = 'users' THEN
        SELECT COUNT(*) INTO v_current_count
        FROM user_profiles
        WHERE tenant_id = p_tenant_id;
        
        RETURN jsonb_build_object(
            'allowed', v_current_count < v_plan.max_users,
            'limit_type', 'users',
            'current', v_current_count,
            'max', v_plan.max_users,
            'remaining', GREATEST(v_plan.max_users - v_current_count, 0),
            'plan_code', v_plan.code,
            'plan_name_ar', v_plan.name_ar,
            'plan_name_en', v_plan.name_en
        );
    END IF;
    
    -- 3. التحقق من عدد الفروع
    IF p_limit_type = 'branches' THEN
        -- افتراض وجود جدول branches (سيتم إنشاؤه لاحقاً)
        IF EXISTS (SELECT 1 FROM information_schema.tables WHERE table_name = 'branches') THEN
            EXECUTE format('SELECT COUNT(*) FROM branches WHERE tenant_id = %L', p_tenant_id) INTO v_current_count;
        ELSE
            v_current_count := 0;
        END IF;
        
        RETURN jsonb_build_object(
            'allowed', v_current_count < v_plan.max_branches,
            'limit_type', 'branches',
            'current', v_current_count,
            'max', v_plan.max_branches,
            'remaining', GREATEST(v_plan.max_branches - v_current_count, 0),
            'plan_code', v_plan.code
        );
    END IF;
    
    -- 4. التحقق من عدد المخازن
    IF p_limit_type = 'warehouses' THEN
        IF EXISTS (SELECT 1 FROM information_schema.tables WHERE table_name = 'warehouses') THEN
            EXECUTE format('SELECT COUNT(*) FROM warehouses WHERE tenant_id = %L', p_tenant_id) INTO v_current_count;
        ELSE
            v_current_count := 0;
        END IF;
        
        RETURN jsonb_build_object(
            'allowed', v_current_count < v_plan.max_warehouses,
            'limit_type', 'warehouses',
            'current', v_current_count,
            'max', v_plan.max_warehouses,
            'remaining', GREATEST(v_plan.max_warehouses - v_current_count, 0),
            'plan_code', v_plan.code
        );
    END IF;
    
    -- 5. التحقق من عدد المنتجات
    IF p_limit_type = 'products' THEN
        IF EXISTS (SELECT 1 FROM information_schema.tables WHERE table_name = 'products') THEN
            EXECUTE format('SELECT COUNT(*) FROM products WHERE tenant_id = %L', p_tenant_id) INTO v_current_count;
        ELSE
            v_current_count := 0;
        END IF;
        
        -- -1 يعني غير محدود
        IF v_plan.max_products = -1 THEN
            RETURN jsonb_build_object(
                'allowed', true,
                'limit_type', 'products',
                'current', v_current_count,
                'max', -1,
                'unlimited', true,
                'plan_code', v_plan.code
            );
        END IF;
        
        RETURN jsonb_build_object(
            'allowed', v_current_count < v_plan.max_products,
            'limit_type', 'products',
            'current', v_current_count,
            'max', v_plan.max_products,
            'remaining', GREATEST(v_plan.max_products - v_current_count, 0),
            'plan_code', v_plan.code
        );
    END IF;
    
    -- 6. التحقق من المساحة التخزينية (TODO: يحتاج تطبيق لاحقاً)
    IF p_limit_type = 'storage' THEN
        -- حالياً نفترض 0 GB مستخدم
        v_current_size := 0;
        
        RETURN jsonb_build_object(
            'allowed', true,
            'limit_type', 'storage',
            'current_gb', v_current_size,
            'max_gb', v_plan.storage_gb,
            'remaining_gb', v_plan.storage_gb - v_current_size,
            'plan_code', v_plan.code
        );
    END IF;
    
    -- نوع حد غير معروف
    RETURN jsonb_build_object(
        'allowed', false,
        'error', 'unknown_limit_type',
        'limit_type', p_limit_type
    );
    
EXCEPTION
    WHEN OTHERS THEN
        RETURN jsonb_build_object(
            'allowed', false,
            'error', 'exception',
            'error_message', SQLERRM
        );
END;
$$;


