--
-- Name: check_row_access(uuid, uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.check_row_access(p_tenant_id uuid, p_company_id uuid DEFAULT NULL::uuid, p_user_id uuid DEFAULT auth.uid()) RETURNS boolean
    LANGUAGE plpgsql STABLE SECURITY DEFINER
    AS $$
DECLARE
    v_user_tenant_id UUID;
BEGIN
    -- Platform Owner يرى كل شيء
    IF is_platform_owner(p_user_id) THEN
        RETURN true;
    END IF;
    
    -- ═══ الخطوة 1: التحقق من البراند ═══
    -- التحقق من أن التينانت ينتمي لنفس البراند
    IF NOT is_same_brand(p_tenant_id, p_user_id) THEN
        RETURN false;
    END IF;
    
    -- ═══ الخطوة 2: التحقق من التينانت ═══
    -- Partner/Reseller: يرى تينانتاته فقط
    IF is_partner_or_reseller(p_user_id) THEN
        IF p_tenant_id = ANY(get_partner_tenant_ids(p_user_id)) THEN
            -- إذا لم يتم تحديد company_id، التحقق من tenant فقط
            IF p_company_id IS NULL THEN
                RETURN true;
            END IF;
            -- التحقق من صلاحية الوصول للشركة
            RETURN can_access_company(p_company_id, p_user_id);
        END IF;
        RETURN false;
    END IF;
    
    -- الحصول على tenant_id للمستخدم
    v_user_tenant_id := get_user_tenant_id(p_user_id);
    
    -- التحقق من الانتماء لنفس التينانت
    IF v_user_tenant_id IS NULL OR v_user_tenant_id != p_tenant_id THEN
        RETURN false;
    END IF;
    
    -- ═══ الخطوة 3: التحقق من الشركة ═══
    -- إذا لم يتم تحديد company_id، التحقق من tenant فقط
    IF p_company_id IS NULL THEN
        RETURN true;
    END IF;
    
    -- التحقق من صلاحية الوصول للشركة
    RETURN can_access_company(p_company_id, p_user_id);
EXCEPTION WHEN OTHERS THEN
    RETURN false;
END;
$$;


--
-- Name: check_subscription_access(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.check_subscription_access(p_tenant_id uuid DEFAULT NULL::uuid) RETURNS jsonb
    LANGUAGE plpgsql STABLE SECURITY DEFINER
    AS $$
DECLARE
    v_tenant_id UUID;
    v_subscription RECORD;
    v_days_remaining INT;
    v_access_level TEXT;
    v_result JSONB;
BEGIN
    v_tenant_id := COALESCE(p_tenant_id, get_current_tenant_id());
    
    IF v_tenant_id IS NULL THEN
        RETURN jsonb_build_object(
            'access_level', 'denied',
            'reason', 'no_tenant'
        );
    END IF;
    
    -- الحصول على الاشتراك
    SELECT * INTO v_subscription
    FROM subscriptions
    WHERE tenant_id = v_tenant_id
    ORDER BY created_at DESC
    LIMIT 1;
    
    IF NOT FOUND THEN
        RETURN jsonb_build_object(
            'access_level', 'denied',
            'reason', 'no_subscription'
        );
    END IF;
    
    -- التحقق من القفل
    IF v_subscription.locked_at IS NOT NULL THEN
        RETURN jsonb_build_object(
            'access_level', 'locked',
            'reason', v_subscription.lock_reason,
            'locked_at', v_subscription.locked_at
        );
    END IF;
    
    -- حساب الأيام المتبقية
    v_days_remaining := GREATEST(0, 
        (v_subscription.current_period_end::date - CURRENT_DATE)
    );
    
    -- تحديد مستوى الوصول
    IF v_days_remaining <= 0 THEN
        v_access_level := 'expired';
    ELSIF v_days_remaining <= 3 THEN
        v_access_level := 'critical_warning';
    ELSIF v_days_remaining <= 7 THEN
        v_access_level := 'warning';
    ELSE
        v_access_level := 'full';
    END IF;
    
    RETURN jsonb_build_object(
        'access_level', v_access_level,
        'status', v_subscription.status,
        'days_remaining', v_days_remaining,
        'period_end', v_subscription.current_period_end,
        'plan_id', v_subscription.plan_id
    );
END;
$$;


--
-- Name: check_user_module_permission(uuid, character varying, character varying); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.check_user_module_permission(p_user_id uuid, p_module_code character varying, p_permission_type character varying DEFAULT 'view'::character varying) RETURNS boolean
    LANGUAGE plpgsql STABLE SECURITY DEFINER
    AS $$
DECLARE
    v_has_permission BOOLEAN;
    v_tenant_id UUID;
    v_company_id UUID;
    v_is_admin BOOLEAN;
BEGIN
    -- الحصول على معلومات المستخدم
    SELECT tenant_id, company_id, is_admin
    INTO v_tenant_id, v_company_id, v_is_admin
    FROM user_profiles
    WHERE id = p_user_id;
    
    -- إذا كان admin، لديه كل الصلاحيات
    IF v_is_admin THEN
        RETURN true;
    END IF;
    
    -- التحقق من الصلاحية المحددة
    SELECT 
        CASE p_permission_type
            WHEN 'view' THEN can_view
            WHEN 'create' THEN can_create
            WHEN 'edit' THEN can_edit
            WHEN 'delete' THEN can_delete
            WHEN 'export' THEN can_export
            WHEN 'import' THEN can_import
            WHEN 'approve' THEN can_approve
            WHEN 'manage_settings' THEN can_manage_settings
            ELSE false
        END
    INTO v_has_permission
    FROM user_module_permissions
    WHERE user_id = p_user_id
      AND tenant_id = v_tenant_id
      AND company_id = v_company_id
      AND module_code = p_module_code
      AND is_active = true
      AND (expires_at IS NULL OR expires_at > NOW());
    
    RETURN COALESCE(v_has_permission, false);
END;
$$;


--
-- Name: FUNCTION check_user_module_permission(p_user_id uuid, p_module_code character varying, p_permission_type character varying); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION public.check_user_module_permission(p_user_id uuid, p_module_code character varying, p_permission_type character varying) IS 'التحقق من صلاحية معينة للمستخدم على موديول';


--
-- Name: check_white_label_validity(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.check_white_label_validity(p_agent_id uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_agent RECORD;
BEGIN
    SELECT * INTO v_agent FROM agents WHERE id = p_agent_id;
    IF NOT FOUND THEN
        RETURN jsonb_build_object('valid', false, 'reason', 'الوكيل غير موجود');
    END IF;
    
    IF NOT v_agent.has_white_label THEN
        RETURN jsonb_build_object('valid', false, 'reason', 'الوكيل غير مفعل لـ White Label');
    END IF;
    
    IF v_agent.white_label_status != 'active' THEN
        RETURN jsonb_build_object('valid', false, 'reason', 'White Label غير نشط', 'status', v_agent.white_label_status);
    END IF;
    
    IF v_agent.white_label_expires_at IS NOT NULL AND v_agent.white_label_expires_at < NOW() THEN
        -- تحديث الحالة تلقائياً
        UPDATE agents SET white_label_status = 'expired' WHERE id = p_agent_id;
        RETURN jsonb_build_object('valid', false, 'reason', 'White Label منتهي الصلاحية');
    END IF;
    
    RETURN jsonb_build_object(
        'valid', true,
        'expires_at', v_agent.white_label_expires_at,
        'commission_percent', v_agent.white_label_commission_percent
    );
END;
$$;


