-- Name: cleanup_container_transit_account(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.cleanup_container_transit_account() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
BEGIN
    IF OLD.container_account_id IS NOT NULL THEN
        UPDATE chart_of_accounts SET is_active = false
        WHERE id = OLD.container_account_id;
    END IF;
    RETURN OLD;
END;
$$;


--
-- Name: cleanup_expired_guest_checkouts(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.cleanup_expired_guest_checkouts() RETURNS integer
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_deleted_count INT;
BEGIN
    -- حذف guest_checkouts المنتهية والتي لم يتم استخدامها
    DELETE FROM guest_checkouts
    WHERE expires_at < NOW()
      AND status = 'pending'
      AND NOT EXISTS (
          SELECT 1 FROM orders 
          WHERE orders.guest_checkout_id = guest_checkouts.id
      );
    
    GET DIAGNOSTICS v_deleted_count = ROW_COUNT;
    
    RETURN v_deleted_count;
END;
$$;


--
-- Name: FUNCTION cleanup_expired_guest_checkouts(); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION public.cleanup_expired_guest_checkouts() IS 'تنظيف بيانات الزوار المنتهية';


