--
-- Name: clear_cart(uuid, uuid, character varying); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.clear_cart(p_tenant_id uuid, p_customer_id uuid DEFAULT NULL::uuid, p_session_id character varying DEFAULT NULL::character varying) RETURNS boolean
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_cart_id UUID;
BEGIN
    -- الحصول على السلة
    IF p_customer_id IS NOT NULL THEN
        SELECT id INTO v_cart_id
        FROM shopping_carts
        WHERE tenant_id = p_tenant_id
          AND customer_id = p_customer_id
          AND status = 'active'
        LIMIT 1;
    ELSIF p_session_id IS NOT NULL THEN
        SELECT id INTO v_cart_id
        FROM shopping_carts
        WHERE tenant_id = p_tenant_id
          AND session_id = p_session_id
          AND status = 'active'
        LIMIT 1;
    END IF;
    
    IF v_cart_id IS NULL THEN
        RETURN false;
    END IF;
    
    -- حذف جميع العناصر
    DELETE FROM shopping_cart_items WHERE cart_id = v_cart_id;
    
    -- تحديث المجاميع
    PERFORM update_cart_totals(v_cart_id);
    
    RETURN TRUE;
END;
$$;


--
-- Name: FUNCTION clear_cart(p_tenant_id uuid, p_customer_id uuid, p_session_id character varying); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION public.clear_cart(p_tenant_id uuid, p_customer_id uuid, p_session_id character varying) IS 'إفراغ السلة من جميع العناصر';


--
-- Name: confirm_delivery(uuid, character varying, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.confirm_delivery(p_note_id uuid, p_receiver_name character varying DEFAULT NULL::character varying, p_signature text DEFAULT NULL::text) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
BEGIN
    UPDATE delivery_notes
    SET 
        status = 'delivered',
        delivered_at = NOW(),
        receiver_name = COALESCE(p_receiver_name, receiver_name),
        receiver_signature = COALESCE(p_signature, receiver_signature)
    WHERE id = p_note_id;
    
    UPDATE delivery_note_items
    SET quantity_delivered = quantity_to_deliver
    WHERE delivery_note_id = p_note_id;
    
    RETURN jsonb_build_object(
        'success', true,
        'note_id', p_note_id,
        'status', 'delivered'
    );
END;
$$;


--
-- Name: convert_contact_to_customer(uuid, character varying, character varying, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.convert_contact_to_customer(p_contact_id uuid, p_customer_code character varying DEFAULT NULL::character varying, p_customer_type character varying DEFAULT 'individual'::character varying, p_receivable_account_id uuid DEFAULT NULL::uuid) RETURNS json
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_contact RECORD;
    v_customer_id UUID;
    v_user_tenant UUID;
    v_code VARCHAR;
BEGIN
    v_user_tenant := get_user_tenant_id();
    
    IF v_user_tenant IS NULL THEN
        RETURN json_build_object('success', false, 'message', 'User has no tenant');
    END IF;
    
    -- جلب بيانات جهة الاتصال
    SELECT * INTO v_contact FROM contacts
    WHERE id = p_contact_id AND tenant_id = v_user_tenant;
    
    IF v_contact.id IS NULL THEN
        RETURN json_build_object('success', false, 'message', 'Contact not found');
    END IF;
    
    IF v_contact.converted_customer_id IS NOT NULL THEN
        RETURN json_build_object('success', false, 'message', 'Already converted', 
                                 'customer_id', v_contact.converted_customer_id);
    END IF;
    
    -- إنشاء كود تلقائي إن لم يُحدد
    v_code := COALESCE(p_customer_code, 'CUST-' || LPAD(
        (SELECT COALESCE(MAX(CAST(REPLACE(code, 'CUST-', '') AS INT)), 0) + 1 
         FROM customers WHERE tenant_id = v_user_tenant)::TEXT, 5, '0'
    ));
    
    -- إنشاء العميل (نقل الأسماء بنفس النمط)
    INSERT INTO customers (
        tenant_id, company_id, code, customer_type,
        name_ar, name_en, company_name,
        email, phone, mobile, whatsapp,
        country, city, address,
        telegram_username, telegram_chat_id,
        receivable_account_id,
        status, created_by, notes
    ) VALUES (
        v_user_tenant, v_contact.company_id, v_code, p_customer_type,
        COALESCE(v_contact.name_ar, COALESCE(v_contact.first_name, '') || ' ' || COALESCE(v_contact.last_name, '')),
        COALESCE(v_contact.name_en, v_contact.display_name, COALESCE(v_contact.first_name, '') || ' ' || COALESCE(v_contact.last_name, '')),
        v_contact.organization,
        v_contact.email, v_contact.phone, v_contact.mobile, v_contact.whatsapp,
        v_contact.country, v_contact.city, v_contact.address,
        v_contact.telegram_username, v_contact.telegram_chat_id,
        p_receivable_account_id,
        'active', auth.uid(), v_contact.notes
    )
    RETURNING id INTO v_customer_id;
    
    -- تحديث جهة الاتصال
    UPDATE contacts SET
        converted_customer_id = v_customer_id,
        converted_at = NOW(),
        converted_by = auth.uid(),
        lifecycle_stage = 'converted',
        status = 'converted'
    WHERE id = p_contact_id;
    
    -- إضافة تفاعل التحويل
    INSERT INTO contact_interactions (
        tenant_id, contact_id, interaction_type, subject, content, performed_by
    ) VALUES (
        v_user_tenant, p_contact_id, 'status_change', 
        'Converted to Customer',
        'Contact converted to customer with code: ' || v_code,
        auth.uid()
    );
    
    -- ربط المكالمات القديمة بالعميل الجديد
    UPDATE call_logs SET customer_id = v_customer_id
    WHERE contact_id = p_contact_id AND customer_id IS NULL;
    
    RETURN json_build_object(
        'success', true,
        'customer_id', v_customer_id,
        'customer_code', v_code,
        'message', 'Contact converted to customer successfully'
    );
END;
$$;


--
-- Name: convert_currency(numeric, character varying, character varying, uuid, timestamp with time zone); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.convert_currency(p_amount numeric, p_from_currency character varying, p_to_currency character varying, p_company_id uuid, p_date timestamp with time zone DEFAULT now()) RETURNS numeric
    LANGUAGE plpgsql STABLE
    AS $$
DECLARE
    v_rate DECIMAL(18, 8);
    v_result DECIMAL(15, 2);
BEGIN
    -- Same currency
    IF p_from_currency = p_to_currency THEN
        RETURN p_amount;
    END IF;
    
    -- Get exchange rate (use mid_rate)
    SELECT mid_rate INTO v_rate
    FROM exchange_rates
    WHERE company_id = p_company_id
      AND from_currency = p_from_currency
      AND to_currency = p_to_currency
      AND effective_from <= p_date
      AND (effective_to IS NULL OR effective_to >= p_date)
      AND is_active = true
    ORDER BY effective_from DESC
    LIMIT 1;
    
    IF v_rate IS NULL THEN
        RAISE EXCEPTION 'No exchange rate found for % to % on %', 
            p_from_currency, p_to_currency, p_date;
    END IF;
    
    v_result := ROUND(p_amount * v_rate, 2);
    
    RETURN v_result;
END;
$$;


--
-- Name: FUNCTION convert_currency(p_amount numeric, p_from_currency character varying, p_to_currency character varying, p_company_id uuid, p_date timestamp with time zone); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION public.convert_currency(p_amount numeric, p_from_currency character varying, p_to_currency character varying, p_company_id uuid, p_date timestamp with time zone) IS 'Convert amount from one currency to another using company exchange rates';


--
-- Name: convert_guest_order_to_customer(uuid, uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.convert_guest_order_to_customer(p_tenant_id uuid, p_guest_checkout_id uuid, p_customer_id uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_orders_updated INT;
    v_result JSONB;
BEGIN
    -- تحديث الطلبات المرتبطة بالزائر
    UPDATE orders
    SET customer_id = p_customer_id,
        guest_checkout_id = NULL,
        updated_at = NOW()
    WHERE tenant_id = p_tenant_id
      AND guest_checkout_id = p_guest_checkout_id
      AND customer_id IS NULL;
    
    GET DIAGNOSTICS v_orders_updated = ROW_COUNT;
    
    -- تحديث حالة guest_checkout
    UPDATE guest_checkouts
    SET status = 'converted_to_customer',
        converted_to_customer_id = p_customer_id,
        converted_at = NOW()
    WHERE id = p_guest_checkout_id
      AND tenant_id = p_tenant_id;
    
    -- إرجاع النتيجة
    v_result := jsonb_build_object(
        'success', true,
        'orders_converted', v_orders_updated,
        'customer_id', p_customer_id,
        'message', 'تم تحويل الطلبات إلى العميل المسجل'
    );
    
    RETURN v_result;
END;
$$;


--
-- Name: FUNCTION convert_guest_order_to_customer(p_tenant_id uuid, p_guest_checkout_id uuid, p_customer_id uuid); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION public.convert_guest_order_to_customer(p_tenant_id uuid, p_guest_checkout_id uuid, p_customer_id uuid) IS 'تحويل طلبات الزائر إلى عميل مسجل';


--
-- Name: convert_quotation_to_order(uuid, character varying); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.convert_quotation_to_order(p_quotation_id uuid, p_doc_cycle character varying DEFAULT 'purchase'::character varying) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_quote       RECORD;
    v_order_id    UUID;
    v_order_number VARCHAR(50);
    v_items_copied INT := 0;
BEGIN
    IF p_doc_cycle = 'purchase' THEN
        -- ════════════════════════════════════════════════════════
        -- دورة المشتريات: عرض سعر مشتريات → أمر شراء
        -- ════════════════════════════════════════════════════════
        SELECT * INTO v_quote FROM purchase_quotations WHERE id = p_quotation_id;
        
        IF NOT FOUND THEN
            RETURN jsonb_build_object('success', false, 'error', 'عرض السعر غير موجود');
        END IF;
        
        IF v_quote.status = 'converted' THEN
            RETURN jsonb_build_object('success', false, 'error', 'عرض السعر محوّل مسبقاً');
        END IF;
        
        v_order_number := 'PO-' || TO_CHAR(NOW(), 'YYYYMMDD-HH24MISS');
        
        -- إنشاء أمر الشراء (tenant_id + company_id يأتيان من عرض السعر)
        INSERT INTO purchase_orders (
            tenant_id, company_id, branch_id,
            order_number, order_date,
            supplier_id, supplier_name,
            quotation_id,
            status, currency, exchange_rate,
            total_amount, notes,
            created_by
        ) VALUES (
            v_quote.tenant_id, v_quote.company_id, v_quote.branch_id,
            v_order_number, CURRENT_DATE,
            v_quote.supplier_id, v_quote.supplier_name,
            p_quotation_id,
            'draft', COALESCE(v_quote.currency, 'SAR'), COALESCE(v_quote.exchange_rate, 1),
            COALESCE(v_quote.total_amount, 0),
            'تحويل من عرض سعر ' || COALESCE(v_quote.quotation_number, ''),
            auth.uid()
        ) RETURNING id INTO v_order_id;
        
        -- نسخ البنود (بدون company_id لأنها غير موجودة في purchase_order_items)
        INSERT INTO purchase_order_items (
            tenant_id, order_id,
            product_id, material_id, variant_id,
            description, quantity, unit_price, discount_amount,
            tax_rate, tax_amount, subtotal, total
        )
        SELECT 
            tenant_id, v_order_id,
            product_id, material_id, variant_id,
            description, quantity, unit_price, discount_amount,
            tax_rate, tax_amount, subtotal, total
        FROM purchase_quotation_items
        WHERE quotation_id = p_quotation_id;
        
        GET DIAGNOSTICS v_items_copied = ROW_COUNT;
        
        -- تحديث حالة عرض السعر
        UPDATE purchase_quotations SET status = 'converted', updated_at = NOW() WHERE id = p_quotation_id;
        
    ELSIF p_doc_cycle = 'sales' THEN
        -- ════════════════════════════════════════════════════════
        -- دورة المبيعات: عرض سعر مبيعات → أمر بيع
        -- ════════════════════════════════════════════════════════
        SELECT * INTO v_quote FROM quotations WHERE id = p_quotation_id;
        
        IF NOT FOUND THEN
            RETURN jsonb_build_object('success', false, 'error', 'عرض السعر غير موجود');
        END IF;
        
        IF v_quote.status = 'converted' THEN
            RETURN jsonb_build_object('success', false, 'error', 'عرض السعر محوّل مسبقاً');
        END IF;
        
        v_order_number := 'SO-' || TO_CHAR(NOW(), 'YYYYMMDD-HH24MISS');
        
        INSERT INTO sales_orders (
            tenant_id, company_id, branch_id,
            order_number, order_date,
            customer_id, customer_name,
            quotation_id,
            status, currency,
            total_amount, notes,
            created_by
        ) VALUES (
            v_quote.tenant_id, v_quote.company_id, v_quote.branch_id,
            v_order_number, CURRENT_DATE,
            v_quote.customer_id, v_quote.customer_name,
            p_quotation_id,
            'draft', COALESCE(v_quote.currency, 'SAR'),
            COALESCE(v_quote.total_amount, 0),
            'تحويل من عرض سعر ' || COALESCE(v_quote.quotation_number, ''),
            auth.uid()
        ) RETURNING id INTO v_order_id;
        
        -- نسخ البنود (sales_order_items فيها company_id)
        INSERT INTO sales_order_items (
            tenant_id, company_id, order_id,
            product_id, variant_id, material_id,
            description, quantity, unit_price,
            discount_percent, discount_amount,
            tax_percent, tax_amount, subtotal, total
        )
        SELECT 
            tenant_id, company_id, v_order_id,
            product_id, variant_id, material_id,
            description, quantity, unit_price,
            discount_percent, discount_amount,
            tax_percent, tax_amount, subtotal, total
        FROM quotation_items
        WHERE quotation_id = p_quotation_id;
        
        GET DIAGNOSTICS v_items_copied = ROW_COUNT;
        
        UPDATE quotations SET status = 'converted', updated_at = NOW() WHERE id = p_quotation_id;
        
    ELSE
        RETURN jsonb_build_object('success', false, 'error', 'doc_cycle يجب أن يكون purchase أو sales');
    END IF;
    
    RETURN jsonb_build_object(
        'success', true,
        'order_id', v_order_id,
        'order_number', v_order_number,
        'items_copied', v_items_copied,
        'cycle', p_doc_cycle,
        'message', 'تم تحويل عرض السعر إلى أمر بنجاح'
    );

EXCEPTION WHEN OTHERS THEN
    RETURN jsonb_build_object('success', false, 'error', SQLERRM, 'detail', SQLSTATE);
END;
$$;


--
-- Name: FUNCTION convert_quotation_to_order(p_quotation_id uuid, p_doc_cycle character varying); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION public.convert_quotation_to_order(p_quotation_id uuid, p_doc_cycle character varying) IS 'تحويل عرض سعر (مشتريات/مبيعات) إلى أمر مع نسخ البنود';


