--
-- Name: create_accounting_entry_for_payment(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.create_accounting_entry_for_payment(p_payment_id uuid) RETURNS jsonb
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_payment RECORD;
    v_tenant RECORD;
    v_entry_number TEXT;
    v_entry_id UUID;
    v_debit_account_id UUID;
    v_credit_account_id UUID;
    v_default_company_id UUID;
    v_result JSONB;
BEGIN
    -- 1. جلب بيانات الدفعة
    SELECT * INTO v_payment
    FROM saas_payments
    WHERE id = p_payment_id;
    
    IF NOT FOUND THEN
        RETURN jsonb_build_object('success', false, 'error', 'Payment not found');
    END IF;
    
    -- 2. جلب بيانات المستأجر
    SELECT * INTO v_tenant
    FROM tenants
    WHERE id = v_payment.tenant_id;
    
    IF NOT FOUND THEN
        RETURN jsonb_build_object('success', false, 'error', 'Tenant not found');
    END IF;
    
    -- 3. جلب أول شركة للمستأجر (لأن journal_entries يحتاج company_id)
    SELECT id INTO v_default_company_id
    FROM companies
    WHERE tenant_id = v_tenant.id
    ORDER BY created_at
    LIMIT 1;
    
    IF v_default_company_id IS NULL THEN
        -- إنشاء شركة افتراضية للمستأجر إذا لم توجد
        INSERT INTO companies (
            tenant_id,
            code,
            name,
            is_active
        ) VALUES (
            v_tenant.id,
            v_tenant.code || '-DEFAULT',
            v_tenant.name || ' - Default Company',
            true
        )
        RETURNING id INTO v_default_company_id;
        
        RAISE NOTICE '📝 Created default company for tenant: %', v_tenant.name;
    END IF;
    
    -- 4. تحديد الحسابات (المدين والدائن)
    -- البحث عن حساب النقدية/البنك/المحفظة
    CASE v_payment.payment_method
        WHEN 'cash' THEN
            -- البحث عن حساب الصندوق النقدي
            SELECT id INTO v_debit_account_id
            FROM chart_of_accounts
            WHERE tenant_id = v_tenant.id
                AND account_type = 'asset'
                AND (code LIKE '1010%' OR name ILIKE '%cash%' OR name ILIKE '%صندوق%')
            LIMIT 1;
            
        WHEN 'bank_transfer' THEN
            -- البحث عن حساب البنك
            SELECT id INTO v_debit_account_id
            FROM chart_of_accounts
            WHERE tenant_id = v_tenant.id
                AND account_type = 'asset'
                AND (code LIKE '1020%' OR name ILIKE '%bank%' OR name ILIKE '%بنك%')
            LIMIT 1;
            
        WHEN 'digital_wallet' THEN
            -- البحث عن حساب المحفظة
            SELECT id INTO v_debit_account_id
            FROM chart_of_accounts
            WHERE tenant_id = v_tenant.id
                AND account_type = 'asset'
                AND (code LIKE '1030%' OR name ILIKE '%wallet%' OR name ILIKE '%محفظة%')
            LIMIT 1;
            
        ELSE
            -- حساب افتراضي
            SELECT id INTO v_debit_account_id
            FROM chart_of_accounts
            WHERE tenant_id = v_tenant.id
                AND account_type = 'asset'
            LIMIT 1;
    END CASE;
    
    -- البحث عن حساب الإيرادات
    SELECT id INTO v_credit_account_id
    FROM chart_of_accounts
    WHERE tenant_id = v_tenant.id
        AND account_type = 'revenue'
        AND (code LIKE '4%' OR name ILIKE '%revenue%' OR name ILIKE '%إيراد%')
    LIMIT 1;
    
    -- إذا لم توجد الحسابات، إنشاؤها
    IF v_debit_account_id IS NULL THEN
        INSERT INTO chart_of_accounts (
            tenant_id, company_id, code, name, account_type, currency, is_active
        ) VALUES (
            v_tenant.id, v_default_company_id, '1010001', 'Cash Account', 'asset', 'USD', true
        )
        RETURNING id INTO v_debit_account_id;
        RAISE NOTICE '📝 Created default cash account';
    END IF;
    
    IF v_credit_account_id IS NULL THEN
        INSERT INTO chart_of_accounts (
            tenant_id, company_id, code, name, account_type, currency, is_active
        ) VALUES (
            v_tenant.id, v_default_company_id, '4010001', 'Subscription Revenue', 'revenue', 'USD', true
        )
        RETURNING id INTO v_credit_account_id;
        RAISE NOTICE '📝 Created default revenue account';
    END IF;
    
    -- 5. رقم القيد
    v_entry_number := 'JE-' || v_payment.payment_number;
    
    -- 6. التحقق من عدم وجود قيد سابق
    IF EXISTS (
        SELECT 1 FROM journal_entries 
        WHERE reference_id = p_payment_id 
            AND reference_type = 'saas_payment'
    ) THEN
        RETURN jsonb_build_object(
            'success', false, 
            'error', 'Accounting entry already exists for this payment'
        );
    END IF;
    
    -- 7. إنشاء القيد الرئيسي
    INSERT INTO journal_entries (
        tenant_id,
        company_id,
        entry_number,
        entry_date,
        entry_type,
        reference_type,
        reference_id,
        reference_number,
        description,
        currency,
        total_debit,
        total_credit,
        status,
        is_posted
    ) VALUES (
        v_tenant.id,
        v_default_company_id,
        v_entry_number,
        COALESCE(v_payment.collection_date::DATE, CURRENT_DATE),
        'automatic',
        'saas_payment',
        p_payment_id,
        v_payment.payment_number,
        'دفعة اشتراك SaaS من ' || v_tenant.name || ' - ' || v_payment.payment_number,
        v_payment.currency,
        v_payment.amount,
        v_payment.amount,
        'posted',
        true
    )
    RETURNING id INTO v_entry_id;
    
    RAISE NOTICE '✅ Created journal entry: %', v_entry_number;
    
    -- 8. إنشاء سطور القيد
    -- السطر الأول: المدين (الصندوق/البنك)
    INSERT INTO journal_entry_lines (
        tenant_id,
        entry_id,
        line_number,
        account_id,
        debit,
        credit,
        currency,
        description,
        reference_type,
        reference_id
    ) VALUES (
        v_tenant.id,
        v_entry_id,
        1,
        v_debit_account_id,
        v_payment.amount,
        0,
        v_payment.currency,
        'من: دفعة اشتراك - ' || v_tenant.name,
        'saas_payment',
        p_payment_id
    );
    
    -- السطر الثاني: الدائن (الإيرادات)
    INSERT INTO journal_entry_lines (
        tenant_id,
        entry_id,
        line_number,
        account_id,
        debit,
        credit,
        currency,
        description,
        reference_type,
        reference_id
    ) VALUES (
        v_tenant.id,
        v_entry_id,
        2,
        v_credit_account_id,
        0,
        v_payment.amount,
        v_payment.currency,
        'إلى: إيرادات اشتراكات SaaS',
        'saas_payment',
        p_payment_id
    );
    
    RAISE NOTICE '✅ Created journal entry lines (debit & credit)';
    
    -- 9. تحديث أرصدة الحسابات
    UPDATE chart_of_accounts
    SET 
        balance = COALESCE(balance, 0) + v_payment.amount,
        updated_at = NOW()
    WHERE id = v_debit_account_id;
    
    UPDATE chart_of_accounts
    SET 
        balance = COALESCE(balance, 0) + v_payment.amount,
        updated_at = NOW()
    WHERE id = v_credit_account_id;
    
    RAISE NOTICE '✅ Updated account balances';
    
    -- 10. إرجاع النتيجة
    v_result := jsonb_build_object(
        'success', true,
        'entry_id', v_entry_id,
        'entry_number', v_entry_number,
        'debit_account_id', v_debit_account_id,
        'credit_account_id', v_credit_account_id,
        'amount', v_payment.amount,
        'currency', v_payment.currency,
        'description', 'دفعة اشتراك من ' || v_tenant.name
    );
    
    RETURN v_result;
    
EXCEPTION
    WHEN OTHERS THEN
        RAISE NOTICE '❌ Error creating accounting entry: %', SQLERRM;
        RETURN jsonb_build_object(
            'success', false,
            'error', SQLERRM
        );
END;
$$;


--
-- Name: FUNCTION create_accounting_entry_for_payment(p_payment_id uuid); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION public.create_accounting_entry_for_payment(p_payment_id uuid) IS 'إنشاء قيد محاسبي حقيقي في journal_entries (محدث)';


--
-- Name: create_billing_invoice(uuid, date, date); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.create_billing_invoice(p_tenant_id uuid, p_period_start date DEFAULT CURRENT_DATE, p_period_end date DEFAULT NULL::date) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_subscription RECORD;
    v_plan RECORD;
    v_invoice_id UUID;
    v_invoice_number VARCHAR(50);
    v_total DECIMAL(10,2) := 0;
    v_line_items JSONB := '[]';
    v_addon RECORD;
BEGIN
    -- الحصول على الاشتراك
    SELECT s.*, sp.name_ar as plan_name INTO v_subscription
    FROM subscriptions s
    JOIN subscription_plans sp ON s.plan_id = sp.id
    WHERE s.tenant_id = p_tenant_id AND s.status IN ('active', 'trial')
    LIMIT 1;
    
    IF NOT FOUND THEN
        RETURN jsonb_build_object('success', false, 'error', 'لا يوجد اشتراك');
    END IF;
    
    -- الحصول على الباقة
    SELECT * INTO v_plan FROM subscription_plans WHERE id = v_subscription.plan_id;
    
    -- توليد رقم الفاتورة
    v_invoice_number := 'INV-' || TO_CHAR(NOW(), 'YYYYMM') || '-' || LPAD((
        SELECT COUNT(*) + 1 FROM billing_invoices WHERE invoice_number LIKE 'INV-' || TO_CHAR(NOW(), 'YYYYMM') || '%'
    )::TEXT, 4, '0');
    
    -- إضافة بند الباقة
    v_total := v_subscription.amount;
    v_line_items := v_line_items || jsonb_build_object(
        'description', 'اشتراك ' || v_plan.name_ar,
        'quantity', 1,
        'unit_price', v_subscription.amount,
        'total', v_subscription.amount
    );
    
    -- إضافة الموديولات الإضافية
    FOR v_addon IN 
        SELECT tm.module_code, tm.price_monthly, sm.name_ar
        FROM tenant_modules tm
        JOIN system_modules sm ON tm.module_code = sm.code
        WHERE tm.tenant_id = p_tenant_id AND tm.source = 'addon' AND tm.is_active = true
    LOOP
        v_total := v_total + v_addon.price_monthly;
        v_line_items := v_line_items || jsonb_build_object(
            'description', 'موديول ' || v_addon.name_ar,
            'quantity', 1,
            'unit_price', v_addon.price_monthly,
            'total', v_addon.price_monthly
        );
    END LOOP;
    
    -- إنشاء الفاتورة
    INSERT INTO billing_invoices (
        tenant_id, subscription_id, invoice_number, invoice_date,
        period_start, period_end,
        subtotal, total_amount, currency,
        line_items, status, due_date
    ) VALUES (
        p_tenant_id, v_subscription.id, v_invoice_number, CURRENT_DATE,
        p_period_start, COALESCE(p_period_end, p_period_start + INTERVAL '1 month'),
        v_total, v_total, v_subscription.currency,
        v_line_items, 'pending', CURRENT_DATE + INTERVAL '7 days'
    ) RETURNING id INTO v_invoice_id;
    
    RETURN jsonb_build_object(
        'success', true,
        'invoice_id', v_invoice_id,
        'invoice_number', v_invoice_number,
        'total', v_total
    );
END;
$$;


--
-- Name: create_budget_with_lines(uuid, uuid, character varying, character varying, character varying, date, date, uuid[], numeric[], uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.create_budget_with_lines(p_tenant_id uuid, p_company_id uuid, p_name_ar character varying, p_name_en character varying, p_budget_type character varying, p_start_date date, p_end_date date, p_account_ids uuid[], p_amounts numeric[], p_user_id uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_budget_id UUID;
    v_period VARCHAR(10);
    v_current_date DATE;
    v_i INTEGER;
BEGIN
    -- إنشاء الموازنة الرئيسية
    INSERT INTO budgets (
        tenant_id, company_id, name_ar, name_en,
        budget_type, start_date, end_date,
        created_by
    ) VALUES (
        p_tenant_id, p_company_id, p_name_ar, p_name_en,
        p_budget_type, p_start_date, p_end_date,
        p_user_id
    ) RETURNING id INTO v_budget_id;
    
    -- إنشاء بنود لكل شهر وكل حساب
    v_current_date := DATE_TRUNC('month', p_start_date);
    
    WHILE v_current_date <= p_end_date LOOP
        v_period := TO_CHAR(v_current_date, 'YYYY-MM');
        
        FOR v_i IN 1..array_length(p_account_ids, 1) LOOP
            INSERT INTO budget_lines (
                tenant_id, budget_id, account_id,
                period, period_start, period_end,
                budgeted_amount
            ) VALUES (
                p_tenant_id, v_budget_id, p_account_ids[v_i],
                v_period, v_current_date, (v_current_date + INTERVAL '1 month - 1 day')::DATE,
                COALESCE(p_amounts[v_i], 0)
            );
        END LOOP;
        
        v_current_date := v_current_date + INTERVAL '1 month';
    END LOOP;
    
    RETURN jsonb_build_object(
        'success', true,
        'budget_id', v_budget_id,
        'message_ar', 'تم إنشاء الموازنة بنجاح',
        'message_en', 'Budget created successfully'
    );
    
EXCEPTION WHEN OTHERS THEN
    RETURN jsonb_build_object(
        'success', false,
        'error', SQLERRM
    );
END;
$$;


--
-- Name: FUNCTION create_budget_with_lines(p_tenant_id uuid, p_company_id uuid, p_name_ar character varying, p_name_en character varying, p_budget_type character varying, p_start_date date, p_end_date date, p_account_ids uuid[], p_amounts numeric[], p_user_id uuid); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION public.create_budget_with_lines(p_tenant_id uuid, p_company_id uuid, p_name_ar character varying, p_name_en character varying, p_budget_type character varying, p_start_date date, p_end_date date, p_account_ids uuid[], p_amounts numeric[], p_user_id uuid) IS 'إنشاء موازنة كاملة مع بنودها';


--
-- Name: create_company_rls_policies(text, boolean, boolean); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.create_company_rls_policies(p_table_name text, p_has_tenant_id boolean DEFAULT true, p_has_company_id boolean DEFAULT true) RETURNS void
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_policy_exists BOOLEAN;
BEGIN
    -- تفعيل RLS
    EXECUTE format('ALTER TABLE public.%I ENABLE ROW LEVEL SECURITY', p_table_name);
    
    -- حذف السياسات القديمة إن وجدت
    BEGIN
        EXECUTE format('DROP POLICY IF EXISTS %I ON public.%I', p_table_name || '_select_policy', p_table_name);
        EXECUTE format('DROP POLICY IF EXISTS %I ON public.%I', p_table_name || '_insert_policy', p_table_name);
        EXECUTE format('DROP POLICY IF EXISTS %I ON public.%I', p_table_name || '_update_policy', p_table_name);
        EXECUTE format('DROP POLICY IF EXISTS %I ON public.%I', p_table_name || '_delete_policy', p_table_name);
    EXCEPTION WHEN OTHERS THEN NULL;
    END;
    
    -- إنشاء السياسات حسب نوع الجدول
    IF p_has_tenant_id AND p_has_company_id THEN
        -- جدول شركة (tenant_id + company_id)
        EXECUTE format('
            CREATE POLICY %I ON public.%I FOR SELECT TO authenticated
            USING (is_platform_admin() OR check_row_access(tenant_id, company_id))',
            p_table_name || '_select_policy', p_table_name);
            
        EXECUTE format('
            CREATE POLICY %I ON public.%I FOR INSERT TO authenticated
            WITH CHECK (is_platform_admin() OR (tenant_id = get_user_tenant_id() AND can_access_company(company_id)))',
            p_table_name || '_insert_policy', p_table_name);
            
        EXECUTE format('
            CREATE POLICY %I ON public.%I FOR UPDATE TO authenticated
            USING (is_platform_admin() OR (tenant_id = get_user_tenant_id() AND can_access_company(company_id)))',
            p_table_name || '_update_policy', p_table_name);
            
        EXECUTE format('
            CREATE POLICY %I ON public.%I FOR DELETE TO authenticated
            USING (is_platform_admin() OR (tenant_id = get_user_tenant_id() AND can_access_company(company_id)))',
            p_table_name || '_delete_policy', p_table_name);
            
    ELSIF p_has_tenant_id THEN
        -- جدول تينانت (tenant_id فقط)
        EXECUTE format('
            CREATE POLICY %I ON public.%I FOR SELECT TO authenticated
            USING (is_platform_admin() OR tenant_id = get_user_tenant_id())',
            p_table_name || '_select_policy', p_table_name);
            
        EXECUTE format('
            CREATE POLICY %I ON public.%I FOR INSERT TO authenticated
            WITH CHECK (is_platform_admin() OR tenant_id = get_user_tenant_id())',
            p_table_name || '_insert_policy', p_table_name);
            
        EXECUTE format('
            CREATE POLICY %I ON public.%I FOR UPDATE TO authenticated
            USING (is_platform_admin() OR tenant_id = get_user_tenant_id())',
            p_table_name || '_update_policy', p_table_name);
            
        EXECUTE format('
            CREATE POLICY %I ON public.%I FOR DELETE TO authenticated
            USING (is_platform_admin() OR tenant_id = get_user_tenant_id())',
            p_table_name || '_delete_policy', p_table_name);
            
    ELSE
        -- جدول منصة/lookup (للقراءة من الجميع)
        EXECUTE format('
            CREATE POLICY %I ON public.%I FOR SELECT TO authenticated
            USING (true)',
            p_table_name || '_select_policy', p_table_name);
            
        EXECUTE format('
            CREATE POLICY %I ON public.%I FOR INSERT TO authenticated
            WITH CHECK (is_platform_admin())',
            p_table_name || '_insert_policy', p_table_name);
            
        EXECUTE format('
            CREATE POLICY %I ON public.%I FOR UPDATE TO authenticated
            USING (is_platform_admin())',
            p_table_name || '_update_policy', p_table_name);
            
        EXECUTE format('
            CREATE POLICY %I ON public.%I FOR DELETE TO authenticated
            USING (is_platform_admin())',
            p_table_name || '_delete_policy', p_table_name);
    END IF;
    
    RAISE NOTICE 'تم إنشاء سياسات لـ: %', p_table_name;
END;
$$;


--
-- Name: create_container_expense_journal_entry(uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.create_container_expense_journal_entry(p_expense_id uuid, p_user_id uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_expense RECORD;
    v_container RECORD;
    v_journal_entry_id UUID;
    v_expense_account_id UUID;
    v_payable_account_id UUID;
    v_amount NUMERIC;
BEGIN
    -- جلب بيانات المصروف
    SELECT ce.*, c.container_number, c.tenant_id, c.company_id
    INTO v_expense
    FROM container_expenses ce
    JOIN containers c ON ce.container_id = c.id
    WHERE ce.id = p_expense_id;
    
    IF NOT FOUND THEN
        RETURN jsonb_build_object(
            'success', false,
            'error', 'Expense not found',
            'error_ar', 'المصروف غير موجود'
        );
    END IF;
    
    -- التحقق من عدم وجود قيد مسبق
    IF v_expense.journal_entry_id IS NOT NULL THEN
        RETURN jsonb_build_object(
            'success', false,
            'error', 'Journal entry already exists for this expense',
            'error_ar', 'يوجد قيد محاسبي للمصروف بالفعل',
            'existing_journal_entry_id', v_expense.journal_entry_id
        );
    END IF;
    
    -- تحديد المبلغ
    v_amount := COALESCE(v_expense.actual_amount, v_expense.expected_amount, v_expense.amount, 0);
    
    IF v_amount = 0 THEN
        RETURN jsonb_build_object(
            'success', false,
            'error', 'Expense amount is zero',
            'error_ar', 'مبلغ المصروف صفر'
        );
    END IF;
    
    -- البحث عن حساب المصاريف المناسب
    SELECT id INTO v_expense_account_id
    FROM accounts
    WHERE company_id = v_expense.company_id
      AND account_type = 'expense'
      AND (name_ar LIKE '%' || v_expense.expense_type || '%' 
           OR name_en LIKE '%' || v_expense.expense_type || '%'
           OR name_ar LIKE '%استيراد%')
    LIMIT 1;
    
    -- إذا لم يوجد حساب مخصص، استخدم حساب مصاريف عام
    IF v_expense_account_id IS NULL THEN
        SELECT id INTO v_expense_account_id
        FROM accounts
        WHERE company_id = v_expense.company_id
          AND account_type = 'expense'
        LIMIT 1;
    END IF;
    
    -- حساب الدائنين
    SELECT id INTO v_payable_account_id
    FROM accounts
    WHERE company_id = v_expense.company_id
      AND (account_type = 'liability' AND (name_ar LIKE '%دائنين%' OR name_ar LIKE '%موردين%'))
    LIMIT 1;
    
    IF v_payable_account_id IS NULL THEN
        SELECT id INTO v_payable_account_id
        FROM accounts
        WHERE company_id = v_expense.company_id
          AND account_type = 'liability'
        LIMIT 1;
    END IF;
    
    IF v_expense_account_id IS NULL OR v_payable_account_id IS NULL THEN
        RETURN jsonb_build_object(
            'success', false,
            'error', 'Required accounts not found',
            'error_ar', 'الحسابات المطلوبة غير موجودة'
        );
    END IF;
    
    -- إنشاء القيد
    INSERT INTO journal_entries (
        tenant_id,
        company_id,
        entry_date,
        description,
        entry_type,
        source_type,
        source_id,
        total_debit,
        total_credit,
        status,
        created_by
    ) VALUES (
        v_expense.tenant_id,
        v_expense.company_id,
        COALESCE(v_expense.invoice_date::DATE, CURRENT_DATE),
        'مصروف ' || COALESCE(v_expense.expense_type, 'استيراد') || ' - كونتينر ' || v_expense.container_number,
        'posted',
        'container_expense',
        p_expense_id,
        v_amount,
        v_amount,
        'posted',
        p_user_id
    ) RETURNING id INTO v_journal_entry_id;
    
    -- بند المصروف (مدين)
    INSERT INTO journal_entry_lines (
        journal_entry_id,
        account_id,
        debit,
        credit,
        description,
        tenant_id,
        company_id
    ) VALUES (
        v_journal_entry_id,
        v_expense_account_id,
        v_amount,
        0,
        v_expense.expense_type || ' - ' || v_expense.container_number,
        v_expense.tenant_id,
        v_expense.company_id
    );
    
    -- بند الدائنين (دائن)
    INSERT INTO journal_entry_lines (
        journal_entry_id,
        account_id,
        debit,
        credit,
        description,
        tenant_id,
        company_id
    ) VALUES (
        v_journal_entry_id,
        v_payable_account_id,
        0,
        v_amount,
        'مستحق - ' || COALESCE(v_expense.vendor_name, 'مورد'),
        v_expense.tenant_id,
        v_expense.company_id
    );
    
    -- تحديث المصروف بمعرف القيد
    UPDATE container_expenses
    SET journal_entry_id = v_journal_entry_id, updated_at = NOW()
    WHERE id = p_expense_id;
    
    RETURN jsonb_build_object(
        'success', true,
        'journal_entry_id', v_journal_entry_id,
        'expense_type', v_expense.expense_type,
        'amount', v_amount
    );
    
EXCEPTION WHEN OTHERS THEN
    RETURN jsonb_build_object(
        'success', false,
        'error', SQLERRM,
        'error_code', SQLSTATE
    );
END;
$$;


--
-- Name: create_container_journal_entry(uuid, character varying, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.create_container_journal_entry(p_container_id uuid, p_entry_type character varying, p_user_id uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_container RECORD;
    v_journal_entry_id UUID;
    v_inventory_account_id UUID;
    v_supplier_account_id UUID;
    v_total_goods NUMERIC;
    v_total_expenses NUMERIC;
    v_description VARCHAR;
BEGIN
    -- جلب بيانات الكونتينر
    SELECT c.*, comp.tenant_id INTO v_container
    FROM containers c JOIN companies comp ON c.company_id = comp.id
    WHERE c.id = p_container_id;
    
    IF NOT FOUND THEN
        RETURN jsonb_build_object('success', false, 'error', 'Container not found', 'error_ar', 'الكونتينر غير موجود');
    END IF;
    
    -- البحث في chart_of_accounts (استخدام account_code و name_ar)
    -- حساب المخزون
    SELECT id INTO v_inventory_account_id 
    FROM chart_of_accounts
    WHERE company_id = v_container.company_id
      AND is_detail = true
      AND (account_code LIKE '120%' OR account_code LIKE '14%' OR name_ar LIKE '%مخزون%')
    ORDER BY account_code LIMIT 1;
    
    -- حساب الموردين (is_payable = true أو name_ar LIKE '%مورد%')
    SELECT id INTO v_supplier_account_id 
    FROM chart_of_accounts
    WHERE company_id = v_container.company_id
      AND is_detail = true
      AND (is_payable = true OR account_code LIKE '21%' OR name_ar LIKE '%مورد%')
    ORDER BY account_code LIMIT 1;
    
    IF v_inventory_account_id IS NULL OR v_supplier_account_id IS NULL THEN
        RETURN jsonb_build_object(
            'success', false, 
            'error', 'Required accounts not found in chart_of_accounts',
            'error_ar', 'الحسابات المطلوبة غير موجودة في دليل الحسابات',
            'inventory_found', v_inventory_account_id IS NOT NULL,
            'supplier_found', v_supplier_account_id IS NOT NULL
        );
    END IF;
    
    -- حساب الإجماليات
    IF p_entry_type = 'provisional' THEN
        v_total_goods := COALESCE(v_container.provisional_goods_cost, 0);
        v_total_expenses := COALESCE(v_container.total_expected_costs, 0);
        v_description := 'قيد مشتريات تقريبي - كونتينر ' || v_container.container_number;
    ELSE
        v_total_goods := COALESCE(v_container.final_goods_cost, v_container.provisional_goods_cost, 0);
        v_total_expenses := COALESCE(v_container.total_actual_costs, 0);
        v_description := 'قيد مشتريات نهائي - كونتينر ' || v_container.container_number;
    END IF;
    
    IF v_total_goods + v_total_expenses = 0 THEN
        RETURN jsonb_build_object('success', false, 'error', 'Total amount is zero', 'error_ar', 'المبلغ الإجمالي صفر');
    END IF;
    
    -- إنشاء القيد المحاسبي
    INSERT INTO journal_entries (
        tenant_id, company_id, entry_date, description, description_ar, 
        entry_type, reference_type, reference_id, 
        total_debit, total_credit, status, created_by
    ) VALUES (
        v_container.tenant_id, v_container.company_id, CURRENT_DATE, 
        v_description, v_description,
        CASE WHEN p_entry_type = 'provisional' THEN 'provisional' ELSE 'posted' END,
        'container', p_container_id,
        v_total_goods + v_total_expenses, v_total_goods + v_total_expenses,
        CASE WHEN p_entry_type = 'provisional' THEN 'draft' ELSE 'posted' END,
        p_user_id
    ) RETURNING id INTO v_journal_entry_id;
    
    -- بند المخزون (مدين) - entry_id وليس journal_entry_id
    INSERT INTO journal_entry_lines (entry_id, account_id, debit, credit, description, tenant_id)
    VALUES (v_journal_entry_id, v_inventory_account_id, v_total_goods + v_total_expenses, 0,
        'مخزون واردات - كونتينر ' || v_container.container_number, v_container.tenant_id);
    
    -- بند الموردين (دائن)
    INSERT INTO journal_entry_lines (entry_id, account_id, debit, credit, description, tenant_id)
    VALUES (v_journal_entry_id, v_supplier_account_id, 0, v_total_goods + v_total_expenses,
        'ذمم موردين - كونتينر ' || v_container.container_number, v_container.tenant_id);
    
    -- تحديث الكونتينر بمعرف القيد
    IF p_entry_type = 'provisional' THEN
        UPDATE containers SET provisional_journal_entry_id = v_journal_entry_id, updated_at = NOW() WHERE id = p_container_id;
    ELSE
        UPDATE containers SET final_journal_entry_id = v_journal_entry_id, updated_at = NOW() WHERE id = p_container_id;
    END IF;
    
    RETURN jsonb_build_object(
        'success', true, 
        'journal_entry_id', v_journal_entry_id,
        'entry_type', p_entry_type,
        'total_debit', v_total_goods + v_total_expenses,
        'total_credit', v_total_goods + v_total_expenses,
        'container_number', v_container.container_number,
        'accounts_used', jsonb_build_object(
            'inventory', v_inventory_account_id,
            'supplier', v_supplier_account_id
        )
    );
    
EXCEPTION WHEN OTHERS THEN
    RETURN jsonb_build_object('success', false, 'error', SQLERRM, 'error_code', SQLSTATE);
END;
$$;


--
-- Name: create_container_transit_account(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.create_container_transit_account() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    AS $_$
DECLARE
    v_company_id UUID;
    v_tenant_id UUID;
    v_chart_type VARCHAR(30);
    v_git_parent_id UUID;
    v_new_account_id UUID;
    v_next_seq INT;
    v_new_code VARCHAR(20);
    v_container_ref VARCHAR(100);
    v_current_asset_type UUID;
BEGIN
    v_company_id := NEW.company_id;
    SELECT c.tenant_id, c.chart_type INTO v_tenant_id, v_chart_type
    FROM companies c WHERE c.id = v_company_id;

    -- Only for extended charts
    IF v_chart_type != 'extended' THEN
        RETURN NEW;
    END IF;

    -- Find parent account 115 (بضاعة في الطريق) — V5.1: was 1143
    SELECT id INTO v_git_parent_id
    FROM chart_of_accounts
    WHERE company_id = v_company_id
      AND account_code = '115'
      AND is_detail = false AND is_active = true
    LIMIT 1;

    IF v_git_parent_id IS NULL THEN
        RAISE NOTICE '⚠️ حساب 115 (بضاعة بالطريق) غير موجود';
        RETURN NEW;
    END IF;

    -- Get next sequence: 1151, 1152, 1153...
    SELECT COALESCE(MAX(
        CASE WHEN account_code ~ '^115[0-9]+$'
             THEN CAST(SUBSTRING(account_code FROM 4) AS INT) ELSE 0 END
    ), 0) + 1 INTO v_next_seq
    FROM chart_of_accounts WHERE company_id = v_company_id AND parent_id = v_git_parent_id;

    v_new_code := '115' || v_next_seq::TEXT;
    v_container_ref := COALESCE(NEW.container_number, NEW.shipment_number, 'CNT-' || v_next_seq);

    SELECT id INTO v_current_asset_type FROM account_types WHERE code = 'CURRENT_ASSET';

    INSERT INTO chart_of_accounts (
        tenant_id, company_id, account_code, name_ar, name_en,
        account_type_id, parent_id, is_detail, is_active
    ) VALUES (
        v_tenant_id, v_company_id, v_new_code,
        'كونتينر ' || v_container_ref, 'Container ' || v_container_ref,
        v_current_asset_type, v_git_parent_id, true, true
    ) RETURNING id INTO v_new_account_id;

    NEW.container_account_id := v_new_account_id;
    RETURN NEW;
END;
$_$;


--
-- Name: FUNCTION create_container_transit_account(); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION public.create_container_transit_account() IS 'V5.1 — إنشاء حساب GIT (115x) للكونتينرات Extended';


--
-- Name: create_default_company_for_tenant(uuid, character varying, character varying, character varying, character varying, character varying); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.create_default_company_for_tenant(p_tenant_id uuid, p_company_name character varying, p_business_type character varying DEFAULT 'general'::character varying, p_company_type character varying DEFAULT 'production'::character varying, p_currency character varying DEFAULT 'SAR'::character varying, p_country_code character varying DEFAULT 'SA'::character varying) RETURNS uuid
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
    v_company_id UUID;
    v_company_code VARCHAR(50);
    v_count INT;
    v_full_name VARCHAR(255);
BEGIN
    SELECT COUNT(*) INTO v_count FROM companies WHERE tenant_id = p_tenant_id;
    v_company_code := 'COMP-' || LPAD((v_count + 1)::TEXT, 3, '0');
    
    WHILE EXISTS (SELECT 1 FROM companies WHERE code = v_company_code AND tenant_id = p_tenant_id) LOOP
        v_company_code := 'COMP-' || LPAD(FLOOR(RANDOM() * 999999)::TEXT, 6, '0');
    END LOOP;
    
    v_full_name := CASE p_company_type
        WHEN 'training' THEN p_company_name || ' (تدريبية)'
        WHEN 'test' THEN p_company_name || ' (تجريبية)'
        ELSE p_company_name
    END;
    
    INSERT INTO companies (
        tenant_id, code, name, name_en, business_type, company_type,
        default_currency, country_code, fiscal_year_start_month,
        tax_system, vat_rate, inventory_valuation_method
    )
    VALUES (
        p_tenant_id, v_company_code, v_full_name, p_company_name,
        p_business_type, p_company_type, COALESCE(p_currency, 'SAR'), p_country_code, 1,
        CASE WHEN p_country_code IN ('SA', 'AE', 'BH', 'KW', 'OM', 'QA') THEN 'vat_gcc'
             WHEN p_country_code IN ('EG', 'JO', 'LB') THEN 'vat_standard'
             ELSE 'none' END,
        CASE WHEN p_country_code IN ('SA', 'AE', 'BH', 'OM', 'QA') THEN 15.00
             WHEN p_country_code = 'EG' THEN 14.00
             WHEN p_country_code = 'JO' THEN 16.00
             ELSE 0.00 END,
        'weighted_average'
    )
    RETURNING id INTO v_company_id;
    
    RETURN v_company_id;
END;
$$;


