--
-- Name: create_default_user_permissions(uuid, uuid, uuid, character varying); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.create_default_user_permissions(p_user_id uuid, p_tenant_id uuid, p_company_id uuid, p_role_type character varying DEFAULT 'viewer'::character varying) RETURNS void
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_module RECORD;
BEGIN
    DELETE FROM user_module_permissions 
    WHERE user_id = p_user_id 
      AND tenant_id = p_tenant_id 
      AND company_id = p_company_id;
    
    FOR v_module IN 
        SELECT module_code 
        FROM tenant_modules 
        WHERE tenant_id = p_tenant_id AND is_active = true
    LOOP
        INSERT INTO user_module_permissions (
            user_id, tenant_id, company_id, module_code,
            can_view, can_create, can_edit, can_delete, can_export
        ) VALUES (
            p_user_id, p_tenant_id, p_company_id, v_module.module_code,
            true,
            CASE WHEN p_role_type IN ('editor', 'manager') THEN true ELSE false END,
            CASE WHEN p_role_type IN ('editor', 'manager') THEN true ELSE false END,
            CASE WHEN p_role_type = 'manager' THEN true ELSE false END,
            CASE WHEN p_role_type IN ('editor', 'manager') THEN true ELSE false END
        );
    END LOOP;
END;
$$;


