--
-- Name: FUNCTION create_extended_chart(p_company_id uuid); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION public.create_extended_chart(p_company_id uuid) IS 'V5.2 — الشجرة الموسعة (84 حساب): 115=GIT, 212=لوجستيك, 2126=صرافة, 217=أوراق دفع, 58=مشتريات/شحن, 59=متنوعة';


--
-- Name: create_extended_chart_of_accounts(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.create_extended_chart_of_accounts(p_company_id uuid) RETURNS void
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_tenant_id UUID;
    v_base_currency VARCHAR(10);
    v_current_asset_type_id UUID;
    v_current_liability_type_id UUID;
    v_equity_type_id UUID;
    v_revenue_type_id UUID;
    v_expense_type_id UUID;
    v_other_income_type_id UUID;
    v_other_expense_type_id UUID;
    v_cash_parent_id UUID;
    v_bank_parent_id UUID;
    v_receivables_parent_id UUID;
    v_payables_parent_id UUID;
    v_partners_parent_id UUID;
    v_sales_parent_id UUID;
BEGIN
    SELECT tenant_id INTO v_tenant_id FROM companies WHERE id = p_company_id;
    IF v_tenant_id IS NULL THEN RAISE EXCEPTION 'الشركة غير موجودة'; END IF;
    
    -- إنشاء الشجرة البسيطة أولاً إن لم تكن موجودة
    IF NOT EXISTS (SELECT 1 FROM chart_of_accounts WHERE company_id = p_company_id AND account_code = '1000') THEN
        PERFORM create_simple_chart_of_accounts(p_company_id);
    END IF;
    
    -- 🆕 العملة الديناميكية
    SELECT COALESCE(cas.base_currency, 'USD') INTO v_base_currency
    FROM company_accounting_settings cas WHERE cas.company_id = p_company_id;
    IF v_base_currency IS NULL THEN v_base_currency := 'USD'; END IF;
    
    SELECT id INTO v_current_asset_type_id FROM account_types WHERE code = 'CURRENT_ASSET';
    SELECT id INTO v_current_liability_type_id FROM account_types WHERE code = 'CURRENT_LIABILITY';
    SELECT id INTO v_equity_type_id FROM account_types WHERE code = 'EQUITY';
    SELECT id INTO v_revenue_type_id FROM account_types WHERE code = 'REVENUE';
    SELECT id INTO v_expense_type_id FROM account_types WHERE code = 'EXPENSE';
    SELECT id INTO v_other_income_type_id FROM account_types WHERE code = 'OTHER_INCOME';
    SELECT id INTO v_other_expense_type_id FROM account_types WHERE code = 'OTHER_EXPENSE';
    
    SELECT id INTO v_receivables_parent_id FROM chart_of_accounts WHERE company_id = p_company_id AND account_code = '1130';
    SELECT id INTO v_payables_parent_id FROM chart_of_accounts WHERE company_id = p_company_id AND account_code = '2110';
    SELECT id INTO v_partners_parent_id FROM chart_of_accounts WHERE company_id = p_company_id AND account_code = '3500';

    -- ═══ توسيع الصندوق ═══
    UPDATE chart_of_accounts SET is_group = true, is_detail = false WHERE company_id = p_company_id AND account_code = '1110';
    SELECT id INTO v_cash_parent_id FROM chart_of_accounts WHERE company_id = p_company_id AND account_code = '1110';
    
    INSERT INTO chart_of_accounts (tenant_id, company_id, account_code, name_ar, name_en, account_type_id, parent_id, is_group, is_detail, level, currency, is_active, is_cash_account)
    VALUES 
        (v_tenant_id, p_company_id, '1111', 'الصندوق الرئيسي', 'Main Cash', v_current_asset_type_id, v_cash_parent_id, false, true, 4, v_base_currency, true, true),
        (v_tenant_id, p_company_id, '1112', 'صندوق العملات الأجنبية', 'Foreign Currency Cash', v_current_asset_type_id, v_cash_parent_id, false, true, 4, v_base_currency, true, true),
        (v_tenant_id, p_company_id, '1113', 'صندوق المصروفات النثرية', 'Petty Cash', v_current_asset_type_id, v_cash_parent_id, false, true, 4, v_base_currency, true, true)
    ON CONFLICT (tenant_id, company_id, account_code) DO NOTHING;
    
    -- ═══ توسيع البنك ═══
    UPDATE chart_of_accounts SET is_group = true, is_detail = false WHERE company_id = p_company_id AND account_code = '1120';
    SELECT id INTO v_bank_parent_id FROM chart_of_accounts WHERE company_id = p_company_id AND account_code = '1120';
    
    INSERT INTO chart_of_accounts (tenant_id, company_id, account_code, name_ar, name_en, account_type_id, parent_id, is_group, is_detail, level, currency, is_active, is_bank_account)
    VALUES 
        (v_tenant_id, p_company_id, '1121', 'البنك الرئيسي', 'Main Bank', v_current_asset_type_id, v_bank_parent_id, false, true, 4, v_base_currency, true, true),
        (v_tenant_id, p_company_id, '1122', 'البنك - عملات أجنبية', 'Bank - Foreign Currency', v_current_asset_type_id, v_bank_parent_id, false, true, 4, v_base_currency, true, true)
    ON CONFLICT (tenant_id, company_id, account_code) DO NOTHING;
    
    -- شيكات تحت التحصيل
    INSERT INTO chart_of_accounts (tenant_id, company_id, account_code, name_ar, name_en, account_type_id, parent_id, is_group, is_detail, level, currency, is_active)
    SELECT v_tenant_id, p_company_id, '1125', 'شيكات تحت التحصيل', 'Checks Under Collection', v_current_asset_type_id,
        (SELECT id FROM chart_of_accounts WHERE company_id = p_company_id AND account_code = '1100'), false, true, 3, v_base_currency, true
    WHERE NOT EXISTS (SELECT 1 FROM chart_of_accounts WHERE company_id = p_company_id AND account_code = '1125');
    
    -- ═══ توسيع العملاء ═══
    INSERT INTO chart_of_accounts (tenant_id, company_id, account_code, name_ar, name_en, account_type_id, parent_id, is_group, is_detail, level, currency, is_active, is_receivable)
    VALUES 
        (v_tenant_id, p_company_id, '1131', 'عملاء محليين', 'Local Customers', v_current_asset_type_id, v_receivables_parent_id, true, false, 4, v_base_currency, true, true),
        (v_tenant_id, p_company_id, '1132', 'عملاء خارجيين', 'Foreign Customers', v_current_asset_type_id, v_receivables_parent_id, true, false, 4, v_base_currency, true, true),
        (v_tenant_id, p_company_id, '1133', 'عملاء وكلاء', 'Agent Customers', v_current_asset_type_id, v_receivables_parent_id, true, false, 4, v_base_currency, true, true),
        (v_tenant_id, p_company_id, '1134', 'عملاء موزعين', 'Distributor Customers', v_current_asset_type_id, v_receivables_parent_id, true, false, 4, v_base_currency, true, true),
        (v_tenant_id, p_company_id, '1138', 'أوراق قبض', 'Notes Receivable', v_current_asset_type_id, v_receivables_parent_id, false, true, 4, v_base_currency, true, true),
        (v_tenant_id, p_company_id, '1139', 'مخصص الديون المشكوك فيها', 'Allowance for Doubtful Debts', v_current_asset_type_id, v_receivables_parent_id, false, true, 4, v_base_currency, true, true)
    ON CONFLICT (tenant_id, company_id, account_code) DO NOTHING;
    
    -- العهد والسلف
    INSERT INTO chart_of_accounts (tenant_id, company_id, account_code, name_ar, name_en, account_type_id, parent_id, is_group, is_detail, level, currency, is_active)
    SELECT v_tenant_id, p_company_id, '1170', 'العهد والسلف', 'Advances & Custody', v_current_asset_type_id,
        (SELECT id FROM chart_of_accounts WHERE company_id = p_company_id AND account_code = '1100'), true, false, 3, v_base_currency, true
    WHERE NOT EXISTS (SELECT 1 FROM chart_of_accounts WHERE company_id = p_company_id AND account_code = '1170');

    -- ═══ توسيع الموردين ═══
    INSERT INTO chart_of_accounts (tenant_id, company_id, account_code, name_ar, name_en, account_type_id, parent_id, is_group, is_detail, level, currency, is_active, is_payable)
    VALUES 
        (v_tenant_id, p_company_id, '2111', 'موردون محليين', 'Local Suppliers', v_current_liability_type_id, v_payables_parent_id, true, false, 4, v_base_currency, true, true),
        (v_tenant_id, p_company_id, '2112', 'موردون خارجيين', 'Foreign Suppliers', v_current_liability_type_id, v_payables_parent_id, true, false, 4, v_base_currency, true, true),
        (v_tenant_id, p_company_id, '2118', 'أوراق دفع', 'Notes Payable', v_current_liability_type_id, v_payables_parent_id, false, true, 4, v_base_currency, true, true)
    ON CONFLICT (tenant_id, company_id, account_code) DO NOTHING;

    -- ═══ توسيع حقوق الملكية ═══
    INSERT INTO chart_of_accounts (tenant_id, company_id, account_code, name_ar, name_en, account_type_id, parent_id, is_group, is_detail, level, currency, is_active)
    VALUES 
        (v_tenant_id, p_company_id, '3510', 'جاري الشريك 1', 'Partner 1 Current', v_equity_type_id, v_partners_parent_id, false, true, 3, v_base_currency, true),
        (v_tenant_id, p_company_id, '3520', 'جاري الشريك 2', 'Partner 2 Current', v_equity_type_id, v_partners_parent_id, false, true, 3, v_base_currency, true),
        (v_tenant_id, p_company_id, '3530', 'جاري الشريك 3', 'Partner 3 Current', v_equity_type_id, v_partners_parent_id, false, true, 3, v_base_currency, true)
    ON CONFLICT (tenant_id, company_id, account_code) DO NOTHING;
    
    INSERT INTO chart_of_accounts (tenant_id, company_id, account_code, name_ar, name_en, account_type_id, parent_id, is_group, is_detail, level, currency, is_active)
    SELECT v_tenant_id, p_company_id, '3600', 'فروقات صرف العملات', 'Currency Exchange Differences', v_equity_type_id,
        (SELECT id FROM chart_of_accounts WHERE company_id = p_company_id AND account_code = '3000'), true, false, 2, v_base_currency, true
    WHERE NOT EXISTS (SELECT 1 FROM chart_of_accounts WHERE company_id = p_company_id AND account_code = '3600');

    -- ═══ توسيع المبيعات ═══
    UPDATE chart_of_accounts SET is_group = true, is_detail = false WHERE company_id = p_company_id AND account_code = '4100';
    SELECT id INTO v_sales_parent_id FROM chart_of_accounts WHERE company_id = p_company_id AND account_code = '4100';
    
    INSERT INTO chart_of_accounts (tenant_id, company_id, account_code, name_ar, name_en, account_type_id, parent_id, is_group, is_detail, level, currency, is_active)
    VALUES 
        (v_tenant_id, p_company_id, '4110', 'مبيعات بضاعة', 'Product Sales', v_revenue_type_id, v_sales_parent_id, false, true, 3, v_base_currency, true),
        (v_tenant_id, p_company_id, '4120', 'مبيعات خدمات', 'Service Sales', v_revenue_type_id, v_sales_parent_id, false, true, 3, v_base_currency, true),
        (v_tenant_id, p_company_id, '4150', 'خصم مسموح به', 'Sales Discounts', v_revenue_type_id, v_sales_parent_id, false, true, 3, v_base_currency, true)
    ON CONFLICT (tenant_id, company_id, account_code) DO NOTHING;

    UPDATE companies SET chart_type = 'extended' WHERE id = p_company_id;
    RAISE NOTICE '✅ V3 — الشجرة الموسعة بعملة %', v_base_currency;
END;
$$;


