--
-- Name: create_monthly_targets(uuid, integer, integer, boolean); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.create_monthly_targets(p_company_id uuid, p_year integer, p_month integer, p_copy_from_previous boolean DEFAULT true) RETURNS integer
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_assignment RECORD;
    v_prev_target RECORD;
    v_created INT := 0;
    v_tenant_id UUID;
BEGIN
    SELECT tenant_id INTO v_tenant_id FROM companies WHERE id = p_company_id;
    
    FOR v_assignment IN 
        SELECT DISTINCT ea.employee_id, ea.tenant_id, ea.target_amount
        FROM employee_incentive_assignments ea
        WHERE ea.company_id = p_company_id
          AND ea.is_active = true
          AND MAKE_DATE(p_year, p_month, 1) BETWEEN ea.start_date AND COALESCE(ea.end_date, '9999-12-31')
    LOOP
        IF NOT EXISTS (
            SELECT 1 FROM employee_targets
            WHERE employee_id = v_assignment.employee_id
              AND period_year = p_year
              AND period_month = p_month
              AND target_type = 'sales_amount'
        ) THEN
            IF p_copy_from_previous THEN
                SELECT * INTO v_prev_target FROM employee_targets
                WHERE employee_id = v_assignment.employee_id
                  AND target_type = 'sales_amount'
                  AND (
                      (period_year = p_year AND period_month = p_month - 1)
                      OR (p_month = 1 AND period_year = p_year - 1 AND period_month = 12)
                  )
                LIMIT 1;
            END IF;
            
            INSERT INTO employee_targets (
                tenant_id, company_id, employee_id,
                target_type, period_type, period_year, period_month,
                target_amount, bonus_on_achievement, bonus_on_exceed, status
            )
            VALUES (
                v_tenant_id, p_company_id, v_assignment.employee_id,
                'sales_amount', 'monthly', p_year, p_month,
                COALESCE(v_prev_target.target_amount, v_assignment.target_amount, 0),
                COALESCE(v_prev_target.bonus_on_achievement, 0),
                COALESCE(v_prev_target.bonus_on_exceed, 0),
                'active'
            );
            
            v_created := v_created + 1;
        END IF;
    END LOOP;
    
    RETURN v_created;
END;
$$;


--
-- Name: create_new_tenant(character varying, character varying, character varying, character varying, character varying, character varying, character varying); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.create_new_tenant(p_tenant_code character varying, p_tenant_name character varying, p_email character varying, p_phone character varying DEFAULT NULL::character varying, p_country_code character varying DEFAULT 'SA'::character varying, p_default_language character varying DEFAULT 'ar'::character varying, p_business_type character varying DEFAULT 'general'::character varying) RETURNS uuid
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
    v_tenant_id UUID;
BEGIN
    INSERT INTO tenants (
        code, name, email, phone, status, default_language
    )
    VALUES (
        p_tenant_code, p_tenant_name, p_email, p_phone, 'active', p_default_language
    )
    RETURNING id INTO v_tenant_id;
    
    RETURN v_tenant_id;
END;
$$;


--
-- Name: create_order_from_cart(uuid, uuid, uuid, uuid, uuid, character varying, character varying, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.create_order_from_cart(p_tenant_id uuid, p_company_id uuid, p_cart_id uuid, p_customer_id uuid DEFAULT NULL::uuid, p_guest_checkout_id uuid DEFAULT NULL::uuid, p_payment_method character varying DEFAULT 'cash_on_delivery'::character varying, p_shipping_method character varying DEFAULT 'standard'::character varying, p_customer_notes text DEFAULT NULL::text) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_order_id UUID;
    v_order_number VARCHAR;
    v_cart RECORD;
    v_item RECORD;
    v_result JSONB;
BEGIN
    -- التحقق من وجود السلة
    SELECT * INTO v_cart
    FROM shopping_carts
    WHERE id = p_cart_id
      AND tenant_id = p_tenant_id
      AND status = 'active';
    
    IF NOT FOUND THEN
        RETURN jsonb_build_object(
            'success', false,
            'error', 'السلة غير موجودة أو غير نشطة'
        );
    END IF;
    
    -- التحقق من وجود عناصر في السلة
    IF v_cart.items_count = 0 THEN
        RETURN jsonb_build_object(
            'success', false,
            'error', 'السلة فارغة'
        );
    END IF;
    
    -- توليد رقم الطلب
    v_order_number := generate_order_number(p_tenant_id, p_company_id);
    
    -- إنشاء الطلب
    INSERT INTO orders (
        tenant_id, company_id, order_number,
        customer_id, guest_checkout_id, cart_id,
        subtotal, discount_amount, tax_amount, total_amount,
        currency, payment_method, shipping_method, customer_notes,
        status, payment_status
    )
    VALUES (
        p_tenant_id, p_company_id, v_order_number,
        p_customer_id, p_guest_checkout_id, p_cart_id,
        v_cart.subtotal, v_cart.discount_amount, v_cart.tax_amount, v_cart.total_amount,
        v_cart.currency, p_payment_method, p_shipping_method, p_customer_notes,
        'pending', 'pending'
    )
    RETURNING id INTO v_order_id;
    
    -- نسخ عناصر السلة إلى الطلب
    INSERT INTO order_items (
        tenant_id, company_id, order_id, product_id,
        product_name, product_sku, product_image_url,
        quantity, unit_price, discount_amount, tax_amount, total_price
    )
    SELECT
        p_tenant_id, p_company_id, v_order_id, sci.product_id,
        COALESCE(p.name_ar, p.name_en, 'Unknown') as product_name,
        p.sku,
        (p.images->0->>'url')::TEXT as product_image_url,
        sci.quantity,
        sci.unit_price,
        0, -- discount per item
        0, -- tax per item
        sci.total_price
    FROM shopping_cart_items sci
    LEFT JOIN products p ON p.id = sci.product_id
    WHERE sci.cart_id = p_cart_id;
    
    -- تحديث حالة السلة
    UPDATE shopping_carts
    SET status = 'completed',
        updated_at = NOW()
    WHERE id = p_cart_id;
    
    -- إرجاع النتيجة
    v_result := jsonb_build_object(
        'success', true,
        'order_id', v_order_id,
        'order_number', v_order_number,
        'total_amount', v_cart.total_amount,
        'currency', v_cart.currency,
        'message', 'تم إنشاء الطلب بنجاح'
    );
    
    RETURN v_result;
END;
$$;


--
-- Name: FUNCTION create_order_from_cart(p_tenant_id uuid, p_company_id uuid, p_cart_id uuid, p_customer_id uuid, p_guest_checkout_id uuid, p_payment_method character varying, p_shipping_method character varying, p_customer_notes text); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION public.create_order_from_cart(p_tenant_id uuid, p_company_id uuid, p_cart_id uuid, p_customer_id uuid, p_guest_checkout_id uuid, p_payment_method character varying, p_shipping_method character varying, p_customer_notes text) IS 'إنشاء طلب من السلة';


--
-- Name: create_promotional_discount(character varying, character varying, character varying, integer, timestamp with time zone, timestamp with time zone, jsonb, character varying, boolean, integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.create_promotional_discount(p_code character varying, p_name_ar character varying, p_name_en character varying, p_discount_percentage integer, p_valid_from timestamp with time zone, p_valid_to timestamp with time zone, p_applicable_plans jsonb DEFAULT '[]'::jsonb, p_applies_to character varying DEFAULT 'both'::character varying, p_auto_apply boolean DEFAULT true, p_priority integer DEFAULT 0) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_discount_id UUID;
BEGIN
    -- التحقق من الكود
    IF EXISTS (SELECT 1 FROM promotional_discounts WHERE code = p_code) THEN
        RETURN jsonb_build_object(
            'success', false,
            'error', 'code_exists',
            'message', 'كود الخصم موجود مسبقاً'
        );
    END IF;
    
    -- إنشاء الخصم
    INSERT INTO promotional_discounts (
        code, name_ar, name_en,
        discount_percentage,
        valid_from, valid_to,
        applicable_plans, applies_to,
        is_active, auto_apply, priority
    ) VALUES (
        p_code, p_name_ar, p_name_en,
        p_discount_percentage,
        p_valid_from, p_valid_to,
        p_applicable_plans, p_applies_to,
        true, p_auto_apply, p_priority
    )
    RETURNING id INTO v_discount_id;
    
    RETURN jsonb_build_object(
        'success', true,
        'discount_id', v_discount_id,
        'code', p_code,
        'message', 'تم إنشاء الخصم بنجاح'
    );
    
EXCEPTION
    WHEN OTHERS THEN
        RETURN jsonb_build_object(
            'success', false,
            'error', 'exception',
            'message', SQLERRM
        );
END;
$$;


--
-- Name: create_purchase_journal_entry(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.create_purchase_journal_entry() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_entry_id UUID;
    v_entry_number VARCHAR(50);
    v_payable_account_id UUID;
    v_expense_account_id UUID;
    v_item RECORD;
BEGIN
    -- Only process when status changes to 'posted'
    IF NEW.status != 'posted' OR NEW.is_posted != true THEN
        RETURN NEW;
    END IF;

    -- Don't reprocess if already posted
    IF OLD.status = 'posted' AND OLD.is_posted = true THEN
        RETURN NEW;
    END IF;

    -- Get supplier's payable account
    SELECT payable_account_id INTO v_payable_account_id
    FROM suppliers
    WHERE id = NEW.supplier_id;

    -- Get default expense account (you may want to get this from company settings)
    SELECT id INTO v_expense_account_id
    FROM accounts
    WHERE company_id = NEW.company_id
      AND account_type = 'expense'
      AND is_active = true
    LIMIT 1;

    -- Create journal entry
    v_entry_number := 'PI-' || NEW.invoice_number;

    INSERT INTO journal_entries (
        tenant_id, company_id, branch_id,
        entry_number, entry_date,
        description, entry_type, status,
        reference_type, reference_id,
        created_by
    )
    VALUES (
        NEW.tenant_id, NEW.company_id, NEW.branch_id,
        v_entry_number, NEW.invoice_date,
        'قيد فاتورة مشتريات ' || NEW.invoice_number,
        'PURCHASE_INVOICE', 'POSTED',
        'purchase_invoice', NEW.id,
        NEW.created_by
    )
    RETURNING id INTO v_entry_id;

    -- Debit: Expense Account
    INSERT INTO journal_entry_lines (
        tenant_id, entry_id, account_id,
        description, debit, credit
    )
    VALUES (
        NEW.tenant_id, v_entry_id, v_expense_account_id,
        'مشتريات - ' || COALESCE(NEW.supplier_name, ''),
        NEW.total_amount, 0
    );

    -- Credit: Accounts Payable
    INSERT INTO journal_entry_lines (
        tenant_id, entry_id, account_id,
        description, debit, credit
    )
    VALUES (
        NEW.tenant_id, v_entry_id, v_payable_account_id,
        'دائنون - ' || COALESCE(NEW.supplier_name, ''),
        0, NEW.total_amount
    );

    -- Link journal entry to invoice
    UPDATE purchase_invoices
    SET journal_entry_id = v_entry_id
    WHERE id = NEW.id;

    RETURN NEW;
END;
$$;


--
-- Name: FUNCTION create_purchase_journal_entry(); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION public.create_purchase_journal_entry() IS 'Creates accounting journal entry when purchase invoice is posted';


--
-- Name: create_recurring_template(uuid, uuid, character varying, character varying, character varying, date, numeric, uuid, uuid, integer, character varying, text, boolean); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.create_recurring_template(p_tenant_id uuid, p_company_id uuid, p_template_code character varying, p_template_name character varying, p_frequency character varying, p_start_date date, p_total_amount numeric, p_debit_account_id uuid, p_credit_account_id uuid, p_day_of_month integer DEFAULT NULL::integer, p_category character varying DEFAULT 'other'::character varying, p_description text DEFAULT NULL::text, p_auto_post boolean DEFAULT false) RETURNS uuid
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_template_id UUID;
BEGIN
    INSERT INTO recurring_entry_templates (
        tenant_id, company_id, template_code, template_name, description,
        frequency, day_of_month, start_date, next_execution_date,
        total_amount, category, auto_post, is_active
    )
    VALUES (
        p_tenant_id, p_company_id, p_template_code, p_template_name, p_description,
        p_frequency, p_day_of_month, p_start_date, p_start_date,
        p_total_amount, p_category, p_auto_post, true
    )
    RETURNING id INTO v_template_id;
    
    INSERT INTO recurring_entry_lines (tenant_id, template_id, line_number, account_id, debit, credit, description)
    VALUES (p_tenant_id, v_template_id, 1, p_debit_account_id, p_total_amount, 0, p_template_name || ' - مدين');
    
    INSERT INTO recurring_entry_lines (tenant_id, template_id, line_number, account_id, debit, credit, description)
    VALUES (p_tenant_id, v_template_id, 2, p_credit_account_id, 0, p_total_amount, p_template_name || ' - دائن');
    
    RETURN v_template_id;
END;
$$;


--
-- Name: create_shipment_document(uuid, character varying, uuid, character varying, character varying, character varying, character varying, character varying, character varying, text, character varying, character varying, character varying, character varying, character varying, character varying, numeric, integer, numeric, numeric, text, numeric, numeric, numeric, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.create_shipment_document(p_company_id uuid, p_source_table character varying, p_source_id uuid, p_carrier_code character varying, p_recipient_name character varying, p_recipient_phone character varying, p_recipient_city character varying DEFAULT NULL::character varying, p_recipient_city_ref character varying DEFAULT NULL::character varying, p_recipient_address_ref character varying DEFAULT NULL::character varying, p_recipient_address_street text DEFAULT NULL::text, p_recipient_building character varying DEFAULT NULL::character varying, p_recipient_flat character varying DEFAULT NULL::character varying, p_service_type character varying DEFAULT 'WarehouseWarehouse'::character varying, p_cargo_type character varying DEFAULT 'Parcel'::character varying, p_payer_type character varying DEFAULT 'Sender'::character varying, p_payment_method character varying DEFAULT 'NonCash'::character varying, p_weight numeric DEFAULT 1.0, p_seats_amount integer DEFAULT 1, p_declared_value numeric DEFAULT 0, p_cod_amount numeric DEFAULT 0, p_description text DEFAULT NULL::text, p_length numeric DEFAULT NULL::numeric, p_width numeric DEFAULT NULL::numeric, p_height numeric DEFAULT NULL::numeric, p_created_by uuid DEFAULT NULL::uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_tenant_id UUID;
    v_carrier RECORD;
    v_doc_id UUID;
    v_np_request JSONB;
BEGIN
    -- Get tenant_id from company
    SELECT tenant_id INTO v_tenant_id FROM companies WHERE id = p_company_id;
    IF v_tenant_id IS NULL THEN
        RETURN jsonb_build_object('success', false, 'error', 'Company not found');
    END IF;
    
    -- Get carrier config
    SELECT * INTO v_carrier 
    FROM shipping_carriers 
    WHERE company_id = p_company_id 
      AND carrier_code = p_carrier_code 
      AND is_active = true
    LIMIT 1;
    
    IF v_carrier.id IS NULL THEN
        RETURN jsonb_build_object('success', false, 'error', 'Carrier not configured: ' || p_carrier_code);
    END IF;
    
    -- Create shipment document record
    INSERT INTO shipment_documents (
        tenant_id, company_id, carrier_id,
        source_table, source_id, carrier_code,
        status,
        -- Sender (from carrier config)
        sender_ref, sender_city_ref, sender_address_ref,
        sender_contact_ref, sender_phone,
        -- Recipient
        recipient_city_name, recipient_city_ref,
        recipient_address_ref, recipient_address_street,
        recipient_building, recipient_flat,
        recipient_contact_name, recipient_phone,
        -- Details
        service_type, cargo_type, payer_type, payment_method,
        weight, seats_amount,
        length, width, height,
        declared_value, cod_amount,
        description,
        created_by
    ) VALUES (
        v_tenant_id, p_company_id, v_carrier.id,
        p_source_table, p_source_id, p_carrier_code,
        'pending',
        -- Sender
        v_carrier.np_sender_ref, v_carrier.np_sender_city_ref, v_carrier.np_sender_address_ref,
        v_carrier.np_sender_contact_ref, v_carrier.np_sender_phone,
        -- Recipient
        p_recipient_city, p_recipient_city_ref,
        p_recipient_address_ref, p_recipient_address_street,
        p_recipient_building, p_recipient_flat,
        p_recipient_name, p_recipient_phone,
        -- Details
        p_service_type, p_cargo_type, p_payer_type, p_payment_method,
        p_weight, p_seats_amount,
        p_length, p_width, p_height,
        p_declared_value, p_cod_amount,
        p_description,
        p_created_by
    )
    RETURNING id INTO v_doc_id;
    
    -- Build Nova Poshta API request (for n8n to send)
    IF p_carrier_code = 'nova_poshta' THEN
        v_np_request := jsonb_build_object(
            'apiKey', '__API_KEY__',  -- n8n يستبدله بمفتاح API المشفر
            'modelName', 'InternetDocument',
            'calledMethod', 'save',
            'methodProperties', jsonb_build_object(
                'PayerType', p_payer_type,
                'PaymentMethod', p_payment_method,
                'DateTime', to_char(NOW(), 'DD.MM.YYYY'),
                'CargoType', p_cargo_type,
                'Weight', p_weight::text,
                'SeatsAmount', p_seats_amount::text,
                'ServiceType', p_service_type,
                'Description', COALESCE(p_description, 'Shipment from TexaCore'),
                'Cost', p_declared_value::text,
                -- Sender
                'Sender', v_carrier.np_sender_ref,
                'CitySender', v_carrier.np_sender_city_ref,
                'SenderAddress', v_carrier.np_sender_address_ref,
                'ContactSender', v_carrier.np_sender_contact_ref,
                'SendersPhone', v_carrier.np_sender_phone,
                -- Recipient (dynamic)
                'RecipientCityName', COALESCE(p_recipient_city, ''),
                'RecipientAddressName', COALESCE(p_recipient_address_ref, ''),
                'RecipientName', p_recipient_name,
                'RecipientsPhone', p_recipient_phone,
                -- Volume
                'VolumeGeneral', CASE 
                    WHEN p_length IS NOT NULL AND p_width IS NOT NULL AND p_height IS NOT NULL 
                    THEN ((p_length * p_width * p_height) / 1000000)::text
                    ELSE '0.001'
                END
            )
        );
        
        -- Add BackwardDeliveryData if COD
        IF p_cod_amount > 0 THEN
            v_np_request := jsonb_set(
                v_np_request,
                '{methodProperties,BackwardDeliveryData}',
                jsonb_build_array(
                    jsonb_build_object(
                        'PayerType', 'Recipient',
                        'CargoType', 'Money',
                        'RedeliveryString', p_cod_amount::text
                    )
                )
            );
        END IF;
        
        -- Add dimensions if provided
        IF p_length IS NOT NULL THEN
            v_np_request := jsonb_set(
                v_np_request,
                '{methodProperties,OptionsSeat}',
                jsonb_build_array(
                    jsonb_build_object(
                        'volumetricLength', p_length::text,
                        'volumetricWidth', p_width::text,
                        'volumetricHeight', p_height::text,
                        'weight', p_weight::text
                    )
                )
            );
        END IF;
        
        -- Save the request template
        UPDATE shipment_documents SET api_request = v_np_request WHERE id = v_doc_id;
    END IF;
    
    -- Return everything n8n needs
    RETURN jsonb_build_object(
        'success', true,
        'shipment_document_id', v_doc_id,
        'carrier_code', p_carrier_code,
        'carrier_id', v_carrier.id,
        'api_endpoint', COALESCE(v_carrier.api_endpoint, 'https://api.novaposhta.ua/v2.0/json/'),
        'n8n_webhook', v_carrier.n8n_create_shipment_webhook,
        'np_api_request', v_np_request,
        'tracking_url_template', v_carrier.tracking_url_template
    );
END;
$$;


--
-- Name: FUNCTION create_shipment_document(p_company_id uuid, p_source_table character varying, p_source_id uuid, p_carrier_code character varying, p_recipient_name character varying, p_recipient_phone character varying, p_recipient_city character varying, p_recipient_city_ref character varying, p_recipient_address_ref character varying, p_recipient_address_street text, p_recipient_building character varying, p_recipient_flat character varying, p_service_type character varying, p_cargo_type character varying, p_payer_type character varying, p_payment_method character varying, p_weight numeric, p_seats_amount integer, p_declared_value numeric, p_cod_amount numeric, p_description text, p_length numeric, p_width numeric, p_height numeric, p_created_by uuid); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION public.create_shipment_document(p_company_id uuid, p_source_table character varying, p_source_id uuid, p_carrier_code character varying, p_recipient_name character varying, p_recipient_phone character varying, p_recipient_city character varying, p_recipient_city_ref character varying, p_recipient_address_ref character varying, p_recipient_address_street text, p_recipient_building character varying, p_recipient_flat character varying, p_service_type character varying, p_cargo_type character varying, p_payer_type character varying, p_payment_method character varying, p_weight numeric, p_seats_amount integer, p_declared_value numeric, p_cod_amount numeric, p_description text, p_length numeric, p_width numeric, p_height numeric, p_created_by uuid) IS 'إنشاء بوليصة شحن جديدة — تجهز الطلب لإرساله عبر n8n إلى Nova Poshta API';


--
-- Name: create_simple_chart(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.create_simple_chart(p_company_id uuid) RETURNS void
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_tenant_id UUID;
    v_asset_type UUID; v_current_asset_type UUID; v_fixed_asset_type UUID;
    v_liability_type UUID; v_current_liability_type UUID; v_long_liability_type UUID;
    v_equity_type UUID; v_revenue_type UUID; v_expense_type UUID; v_cogs_type UUID;
    -- Parent IDs
    v_assets_id UUID; v_current_assets_id UUID;
    v_cash_grp UUID; v_banks_grp UUID; v_inv_grp UUID;
    v_fixed_assets_id UUID;
    v_liabilities_id UUID; v_current_liab_id UUID; v_long_liab_id UUID;
    v_equity_id UUID;
    v_revenue_id UUID;
    v_expenses_id UUID; v_cogs_grp UUID; v_purchases_grp UUID; v_freight_grp UUID; v_misc_grp UUID;
BEGIN
    SELECT tenant_id INTO v_tenant_id FROM companies WHERE id = p_company_id;
    IF v_tenant_id IS NULL THEN RAISE EXCEPTION 'Company not found: %', p_company_id; END IF;
    IF EXISTS (SELECT 1 FROM chart_of_accounts WHERE company_id = p_company_id LIMIT 1) THEN RETURN; END IF;

    -- Get account types
    SELECT id INTO v_asset_type FROM account_types WHERE code = 'ASSET';
    SELECT id INTO v_current_asset_type FROM account_types WHERE code = 'CURRENT_ASSET';
    SELECT id INTO v_fixed_asset_type FROM account_types WHERE code = 'FIXED_ASSET';
    SELECT id INTO v_liability_type FROM account_types WHERE code = 'LIABILITY';
    SELECT id INTO v_current_liability_type FROM account_types WHERE code = 'CURRENT_LIABILITY';
    SELECT id INTO v_long_liability_type FROM account_types WHERE code IN ('LONG_TERM_LIABILITY','NON_CURRENT_LIABILITY','LIABILITY');
    IF v_long_liability_type IS NULL THEN v_long_liability_type := v_liability_type; END IF;
    SELECT id INTO v_equity_type FROM account_types WHERE code = 'EQUITY';
    SELECT id INTO v_revenue_type FROM account_types WHERE code = 'REVENUE';
    SELECT id INTO v_expense_type FROM account_types WHERE code = 'EXPENSE';
    SELECT id INTO v_cogs_type FROM account_types WHERE code = 'COGS';
    IF v_cogs_type IS NULL THEN v_cogs_type := v_expense_type; END IF;

    -- ═══════════════════════════════════════════════════════
    -- 1️⃣ الأصول (17 حساب)
    -- ═══════════════════════════════════════════════════════
    INSERT INTO chart_of_accounts (tenant_id, company_id, account_code, name_ar, name_en, account_type_id, parent_id, is_detail, is_active)
    VALUES (v_tenant_id, p_company_id, '1', 'الأصول', 'Assets', v_asset_type, NULL, false, true) RETURNING id INTO v_assets_id;

    INSERT INTO chart_of_accounts (tenant_id, company_id, account_code, name_ar, name_en, account_type_id, parent_id, is_detail, is_active)
    VALUES (v_tenant_id, p_company_id, '11', 'الأصول المتداولة', 'Current Assets', v_current_asset_type, v_assets_id, false, true) RETURNING id INTO v_current_assets_id;

    -- الصندوق (111)
    INSERT INTO chart_of_accounts (tenant_id, company_id, account_code, name_ar, name_en, account_type_id, parent_id, is_detail, is_active)
    VALUES (v_tenant_id, p_company_id, '111', 'الصندوق', 'Cash', v_current_asset_type, v_current_assets_id, false, true) RETURNING id INTO v_cash_grp;
    INSERT INTO chart_of_accounts (tenant_id, company_id, account_code, name_ar, name_en, account_type_id, parent_id, is_detail, is_active, is_cash_account)
    VALUES
        (v_tenant_id, p_company_id, '1111', 'صندوق - عملة محلية', 'Cash - Local Currency', v_current_asset_type, v_cash_grp, true, true, true),
        (v_tenant_id, p_company_id, '1112', 'صندوق - عملة أساسية', 'Cash - Base Currency', v_current_asset_type, v_cash_grp, true, true, true);

    -- البنوك (112)
    INSERT INTO chart_of_accounts (tenant_id, company_id, account_code, name_ar, name_en, account_type_id, parent_id, is_detail, is_active)
    VALUES (v_tenant_id, p_company_id, '112', 'البنوك', 'Banks', v_current_asset_type, v_current_assets_id, false, true) RETURNING id INTO v_banks_grp;
    INSERT INTO chart_of_accounts (tenant_id, company_id, account_code, name_ar, name_en, account_type_id, parent_id, is_detail, is_active, is_bank_account)
    VALUES
        (v_tenant_id, p_company_id, '1121', 'بنك - عملة محلية', 'Bank - Local Currency', v_current_asset_type, v_banks_grp, true, true, true),
        (v_tenant_id, p_company_id, '1122', 'بنك - عملة أساسية', 'Bank - Base Currency', v_current_asset_type, v_banks_grp, true, true, true);

    -- العملاء (113)
    INSERT INTO chart_of_accounts (tenant_id, company_id, account_code, name_ar, name_en, account_type_id, parent_id, is_detail, is_active, is_receivable)
    VALUES (v_tenant_id, p_company_id, '113', 'العملاء', 'Accounts Receivable', v_current_asset_type, v_current_assets_id, false, true, true);

    -- المخزون (114)
    INSERT INTO chart_of_accounts (tenant_id, company_id, account_code, name_ar, name_en, account_type_id, parent_id, is_detail, is_active)
    VALUES (v_tenant_id, p_company_id, '114', 'المخزون', 'Inventory', v_current_asset_type, v_current_assets_id, false, true) RETURNING id INTO v_inv_grp;
    INSERT INTO chart_of_accounts (tenant_id, company_id, account_code, name_ar, name_en, account_type_id, parent_id, is_detail, is_active)
    VALUES
        (v_tenant_id, p_company_id, '1141', 'بضاعة جاهزة', 'Finished Goods', v_current_asset_type, v_inv_grp, true, true),
        (v_tenant_id, p_company_id, '1142', 'مواد خام', 'Raw Materials', v_current_asset_type, v_inv_grp, true, true);

    -- باقي الأصول المتداولة
    INSERT INTO chart_of_accounts (tenant_id, company_id, account_code, name_ar, name_en, account_type_id, parent_id, is_detail, is_active)
    VALUES
        (v_tenant_id, p_company_id, '116', 'مصاريف مقدمة', 'Prepaid Expenses', v_current_asset_type, v_current_assets_id, true, true),
        (v_tenant_id, p_company_id, '117', 'ض.ق.م - مدخلات', 'VAT Input', v_current_asset_type, v_current_assets_id, true, true),
        (v_tenant_id, p_company_id, '118', 'دفعات مقدمة للموردين', 'Supplier Deposits', v_current_asset_type, v_current_assets_id, true, true);

    -- الأصول الثابتة (12)
    INSERT INTO chart_of_accounts (tenant_id, company_id, account_code, name_ar, name_en, account_type_id, parent_id, is_detail, is_active)
    VALUES (v_tenant_id, p_company_id, '12', 'الأصول الثابتة', 'Fixed Assets', v_fixed_asset_type, v_assets_id, false, true) RETURNING id INTO v_fixed_assets_id;
    INSERT INTO chart_of_accounts (tenant_id, company_id, account_code, name_ar, name_en, account_type_id, parent_id, is_detail, is_active)
    VALUES
        (v_tenant_id, p_company_id, '121', 'أصول ثابتة', 'Fixed Assets', v_fixed_asset_type, v_fixed_assets_id, true, true),
        (v_tenant_id, p_company_id, '129', 'مجمع الإهلاك', 'Accumulated Depreciation', v_fixed_asset_type, v_fixed_assets_id, true, true);

    -- ═══════════════════════════════════════════════════════
    -- 2️⃣ الخصوم (9 حسابات)
    -- ═══════════════════════════════════════════════════════
    INSERT INTO chart_of_accounts (tenant_id, company_id, account_code, name_ar, name_en, account_type_id, parent_id, is_detail, is_active)
    VALUES (v_tenant_id, p_company_id, '2', 'الخصوم', 'Liabilities', v_liability_type, NULL, false, true) RETURNING id INTO v_liabilities_id;

    INSERT INTO chart_of_accounts (tenant_id, company_id, account_code, name_ar, name_en, account_type_id, parent_id, is_detail, is_active)
    VALUES (v_tenant_id, p_company_id, '21', 'الخصوم المتداولة', 'Current Liabilities', v_current_liability_type, v_liabilities_id, false, true) RETURNING id INTO v_current_liab_id;

    INSERT INTO chart_of_accounts (tenant_id, company_id, account_code, name_ar, name_en, account_type_id, parent_id, is_detail, is_active, is_payable)
    VALUES (v_tenant_id, p_company_id, '211', 'الموردون', 'Accounts Payable', v_current_liability_type, v_current_liab_id, false, true, true);

    INSERT INTO chart_of_accounts (tenant_id, company_id, account_code, name_ar, name_en, account_type_id, parent_id, is_detail, is_active)
    VALUES
        (v_tenant_id, p_company_id, '213', 'مستحقات الموظفين', 'Accrued Salaries', v_current_liability_type, v_current_liab_id, true, true),
        (v_tenant_id, p_company_id, '214', 'ض.ق.م - مخرجات', 'VAT Output', v_current_liability_type, v_current_liab_id, true, true),
        (v_tenant_id, p_company_id, '215', 'سلف العملاء', 'Customer Advances', v_current_liability_type, v_current_liab_id, true, true),
        (v_tenant_id, p_company_id, '216', 'دائنون آخرون', 'Other Payables', v_current_liability_type, v_current_liab_id, true, true),
        (v_tenant_id, p_company_id, '217', 'أوراق الدفع', 'Notes Payable', v_current_liability_type, v_current_liab_id, true, true);

    INSERT INTO chart_of_accounts (tenant_id, company_id, account_code, name_ar, name_en, account_type_id, parent_id, is_detail, is_active)
    VALUES (v_tenant_id, p_company_id, '22', 'الخصوم طويلة الأجل', 'Long-term Liabilities', v_long_liability_type, v_liabilities_id, false, true) RETURNING id INTO v_long_liab_id;
    INSERT INTO chart_of_accounts (tenant_id, company_id, account_code, name_ar, name_en, account_type_id, parent_id, is_detail, is_active)
    VALUES (v_tenant_id, p_company_id, '221', 'قروض طويلة الأجل', 'Long-term Loans', v_long_liability_type, v_long_liab_id, true, true);

    -- ═══════════════════════════════════════════════════════
    -- 3️⃣ حقوق الملكية (6 حسابات)
    -- ═══════════════════════════════════════════════════════
    INSERT INTO chart_of_accounts (tenant_id, company_id, account_code, name_ar, name_en, account_type_id, parent_id, is_detail, is_active)
    VALUES (v_tenant_id, p_company_id, '3', 'حقوق الملكية', 'Equity', v_equity_type, NULL, false, true) RETURNING id INTO v_equity_id;
    INSERT INTO chart_of_accounts (tenant_id, company_id, account_code, name_ar, name_en, account_type_id, parent_id, is_detail, is_active)
    VALUES
        (v_tenant_id, p_company_id, '31', 'رأس المال', 'Capital', v_equity_type, v_equity_id, true, true),
        (v_tenant_id, p_company_id, '32', 'الأرباح المحتجزة', 'Retained Earnings', v_equity_type, v_equity_id, true, true),
        (v_tenant_id, p_company_id, '33', 'أرباح/خسائر العام', 'Current Year P/L', v_equity_type, v_equity_id, true, true),
        (v_tenant_id, p_company_id, '34', 'احتياطيات', 'Reserves', v_equity_type, v_equity_id, true, true),
        (v_tenant_id, p_company_id, '35', 'أرصدة افتتاحية', 'Opening Balance Equity', v_equity_type, v_equity_id, true, true);

    -- ═══════════════════════════════════════════════════════
    -- 4️⃣ الإيرادات (5 حسابات)
    -- ═══════════════════════════════════════════════════════
    INSERT INTO chart_of_accounts (tenant_id, company_id, account_code, name_ar, name_en, account_type_id, parent_id, is_detail, is_active)
    VALUES (v_tenant_id, p_company_id, '4', 'الإيرادات', 'Revenue', v_revenue_type, NULL, false, true) RETURNING id INTO v_revenue_id;
    INSERT INTO chart_of_accounts (tenant_id, company_id, account_code, name_ar, name_en, account_type_id, parent_id, is_detail, is_active)
    VALUES
        (v_tenant_id, p_company_id, '41', 'المبيعات', 'Sales', v_revenue_type, v_revenue_id, true, true),
        (v_tenant_id, p_company_id, '44', 'مردودات المبيعات', 'Sales Returns', v_revenue_type, v_revenue_id, true, true),
        (v_tenant_id, p_company_id, '45', 'إيرادات أخرى', 'Other Income', v_revenue_type, v_revenue_id, true, true),
        (v_tenant_id, p_company_id, '46', 'أرباح فروقات العملة', 'FX Gains', v_revenue_type, v_revenue_id, true, true);

    -- ═══════════════════════════════════════════════════════
    -- 5️⃣ المصروفات (17 حساب)
    -- ═══════════════════════════════════════════════════════
    INSERT INTO chart_of_accounts (tenant_id, company_id, account_code, name_ar, name_en, account_type_id, parent_id, is_detail, is_active)
    VALUES (v_tenant_id, p_company_id, '5', 'المصروفات', 'Expenses', v_expense_type, NULL, false, true) RETURNING id INTO v_expenses_id;

    -- تكلفة المبيعات (51)
    INSERT INTO chart_of_accounts (tenant_id, company_id, account_code, name_ar, name_en, account_type_id, parent_id, is_detail, is_active)
    VALUES (v_tenant_id, p_company_id, '51', 'تكلفة المبيعات', 'Cost of Sales', v_cogs_type, v_expenses_id, false, true) RETURNING id INTO v_cogs_grp;
    INSERT INTO chart_of_accounts (tenant_id, company_id, account_code, name_ar, name_en, account_type_id, parent_id, is_detail, is_active)
    VALUES (v_tenant_id, p_company_id, '511', 'تكلفة المبيعات', 'Cost of Sales', v_cogs_type, v_cogs_grp, true, true);

    -- المشتريات (52)
    INSERT INTO chart_of_accounts (tenant_id, company_id, account_code, name_ar, name_en, account_type_id, parent_id, is_detail, is_active)
    VALUES (v_tenant_id, p_company_id, '52', 'المشتريات', 'Purchases', v_cogs_type, v_expenses_id, false, true) RETURNING id INTO v_purchases_grp;
    INSERT INTO chart_of_accounts (tenant_id, company_id, account_code, name_ar, name_en, account_type_id, parent_id, is_detail, is_active)
    VALUES
        (v_tenant_id, p_company_id, '521', 'مشتريات عامة', 'General Purchases', v_cogs_type, v_purchases_grp, true, true),
        (v_tenant_id, p_company_id, '522', 'مردودات المشتريات', 'Purchase Returns', v_cogs_type, v_purchases_grp, true, true),
        (v_tenant_id, p_company_id, '523', 'خصومات المشتريات', 'Purchase Discounts', v_cogs_type, v_purchases_grp, true, true);

    -- مصروفات تشغيلية
    INSERT INTO chart_of_accounts (tenant_id, company_id, account_code, name_ar, name_en, account_type_id, parent_id, is_detail, is_active)
    VALUES
        (v_tenant_id, p_company_id, '53', 'الرواتب والأجور', 'Salaries & Wages', v_expense_type, v_expenses_id, true, true),
        (v_tenant_id, p_company_id, '54', 'الإيجارات', 'Rent Expense', v_expense_type, v_expenses_id, true, true),
        (v_tenant_id, p_company_id, '55', 'المرافق', 'Utilities', v_expense_type, v_expenses_id, true, true),
        (v_tenant_id, p_company_id, '57', 'مصاريف إدارية', 'Administrative Expenses', v_expense_type, v_expenses_id, true, true);

    -- مصاريف المشتريات والشحن (58) — V5.1: كانت 5800
    INSERT INTO chart_of_accounts (tenant_id, company_id, account_code, name_ar, name_en, account_type_id, parent_id, is_detail, is_active)
    VALUES (v_tenant_id, p_company_id, '58', 'مصاريف المشتريات والشحن', 'Purchase & Shipping Expenses', v_expense_type, v_expenses_id, false, true) RETURNING id INTO v_freight_grp;
    INSERT INTO chart_of_accounts (tenant_id, company_id, account_code, name_ar, name_en, account_type_id, parent_id, is_detail, is_active)
    VALUES (v_tenant_id, p_company_id, '581', 'مصاريف الشحن', 'Shipping Expenses', v_expense_type, v_freight_grp, true, true);

    -- مصروفات متنوعة (59)
    INSERT INTO chart_of_accounts (tenant_id, company_id, account_code, name_ar, name_en, account_type_id, parent_id, is_detail, is_active)
    VALUES (v_tenant_id, p_company_id, '59', 'مصروفات متنوعة', 'Miscellaneous Expenses', v_expense_type, v_expenses_id, false, true) RETURNING id INTO v_misc_grp;
    INSERT INTO chart_of_accounts (tenant_id, company_id, account_code, name_ar, name_en, account_type_id, parent_id, is_detail, is_active)
    VALUES
        (v_tenant_id, p_company_id, '591', 'خسائر فروقات العملة', 'FX Losses', v_expense_type, v_misc_grp, true, true),
        (v_tenant_id, p_company_id, '593', 'مصروفات الصيانة', 'Maintenance Expenses', v_expense_type, v_misc_grp, true, true),
        (v_tenant_id, p_company_id, '596', 'مصروفات أخرى', 'Other Expenses', v_expense_type, v_misc_grp, true, true);

    UPDATE companies SET chart_type = 'simple' WHERE id = p_company_id;
    RAISE NOTICE '✅ تم إنشاء الشجرة القياسية V5.1 للشركة %', p_company_id;
END;
$$;


