    SELECT id INTO v_other_expense_type_id FROM account_types WHERE code = 'OTHER_EXPENSE';

    -- ═══ 1000 الأصول ═══
    INSERT INTO chart_of_accounts (tenant_id, company_id, account_code, name_ar, name_en, account_type_id, parent_id, is_group, is_detail, level, currency, is_active, is_system)
    VALUES (v_tenant_id, p_company_id, '1000', 'الأصول', 'Assets', v_asset_type_id, NULL, true, false, 1, v_base_currency, true, true) RETURNING id INTO v_assets_id;

    INSERT INTO chart_of_accounts (tenant_id, company_id, account_code, name_ar, name_en, account_type_id, parent_id, is_group, is_detail, level, currency, is_active, is_system)
    VALUES (v_tenant_id, p_company_id, '1100', 'الأصول المتداولة', 'Current Assets', v_current_asset_type_id, v_assets_id, true, false, 2, v_base_currency, true, true) RETURNING id INTO v_current_assets_id;

    INSERT INTO chart_of_accounts (tenant_id, company_id, account_code, name_ar, name_en, account_type_id, parent_id, is_group, is_detail, level, currency, is_active, is_cash_account, is_system)
    VALUES (v_tenant_id, p_company_id, '1110', 'الصندوق', 'Cash', v_current_asset_type_id, v_current_assets_id, false, true, 3, v_base_currency, true, true, true);

    INSERT INTO chart_of_accounts (tenant_id, company_id, account_code, name_ar, name_en, account_type_id, parent_id, is_group, is_detail, level, currency, is_active, is_bank_account, is_system)
    VALUES (v_tenant_id, p_company_id, '1120', 'البنك', 'Bank', v_current_asset_type_id, v_current_assets_id, false, true, 3, v_base_currency, true, true, true);

    INSERT INTO chart_of_accounts (tenant_id, company_id, account_code, name_ar, name_en, account_type_id, parent_id, is_group, is_detail, level, currency, is_active, is_receivable, is_system)
    VALUES (v_tenant_id, p_company_id, '1130', 'العملاء', 'Accounts Receivable', v_current_asset_type_id, v_current_assets_id, true, false, 3, v_base_currency, true, true, true);

