--
-- Name: FUNCTION create_simple_chart_of_accounts(p_company_id uuid); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION public.create_simple_chart_of_accounts(p_company_id uuid) IS 'V2: إنشاء شجرة بسيطة مع كل الحسابات المطلوبة (4500 أرباح عملة + 2150 سلف عملاء + 1150 سلف موردين) - متوافقة مع auto_set_default_accounts';


--
-- Name: create_subscription_plan(character varying, character varying, character varying, text, integer, integer, integer, integer, integer, integer, jsonb, jsonb, numeric, numeric, character varying, integer, boolean, integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.create_subscription_plan(p_code character varying, p_name_ar character varying, p_name_en character varying, p_description text, p_max_users integer DEFAULT 5, p_max_companies integer DEFAULT 1, p_max_branches integer DEFAULT 2, p_max_warehouses integer DEFAULT 2, p_max_products integer DEFAULT 1000, p_storage_gb integer DEFAULT 5, p_included_modules jsonb DEFAULT '[]'::jsonb, p_features jsonb DEFAULT '{}'::jsonb, p_price_monthly numeric DEFAULT 0, p_price_yearly numeric DEFAULT 0, p_currency character varying DEFAULT 'SAR'::character varying, p_trial_days integer DEFAULT 14, p_is_popular boolean DEFAULT false, p_display_order integer DEFAULT 999) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_product_id UUID;
    v_plan_id UUID;
BEGIN
    -- الحصول على product_id
    SELECT id INTO v_product_id FROM saas_products WHERE code = 'erp-saas' LIMIT 1;
    
    IF v_product_id IS NULL THEN
        RETURN jsonb_build_object(
            'success', false,
            'error', 'product_not_found',
            'message', 'المنتج الرئيسي غير موجود'
        );
    END IF;
    
    -- التحقق من عدم وجود الكود مسبقاً
    IF EXISTS (SELECT 1 FROM subscription_plans WHERE product_id = v_product_id AND code = p_code) THEN
        RETURN jsonb_build_object(
            'success', false,
            'error', 'code_exists',
            'message', 'كود الباقة موجود مسبقاً'
        );
    END IF;
    
    -- إنشاء الباقة
    INSERT INTO subscription_plans (
        product_id,
        code,
        name_ar,
        name_en,
        description,
        max_users,
        max_companies,
        max_branches,
        max_warehouses,
        max_products,
        storage_gb,
        included_modules,
        features,
        price_monthly,
        price_yearly,
        currency,
        trial_days,
        is_popular,
        display_order,
        is_active
    ) VALUES (
        v_product_id,
        p_code,
        p_name_ar,
        p_name_en,
        p_description,
        p_max_users,
        p_max_companies,
        p_max_branches,
        p_max_warehouses,
        p_max_products,
        p_storage_gb,
        p_included_modules,
        p_features,
        p_price_monthly,
        p_price_yearly,
        p_currency,
        p_trial_days,
        p_is_popular,
        p_display_order,
        true
    )
    RETURNING id INTO v_plan_id;
    
    RETURN jsonb_build_object(
        'success', true,
        'plan_id', v_plan_id,
        'code', p_code,
        'message', 'تم إنشاء الباقة بنجاح'
    );
    
EXCEPTION
    WHEN OTHERS THEN
        RETURN jsonb_build_object(
            'success', false,
            'error', 'exception',
            'message', SQLERRM
        );
END;
$$;


