--
-- Name: create_super_admin_policy(text, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.create_super_admin_policy(p_table_name text, p_policy_name text DEFAULT 'super_admin_access'::text) RETURNS void
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_sql TEXT;
BEGIN
    -- حذف Policy القديم إن وجد
    v_sql := format('DROP POLICY IF EXISTS %I ON %I', p_policy_name, p_table_name);
    EXECUTE v_sql;
    
    -- إنشاء Policy جديد
    v_sql := format('
        CREATE POLICY %I ON %I
        FOR ALL
        USING (
            is_super_admin(auth.uid())
            OR (
                tenant_id = get_user_tenant_id(auth.uid())
                AND company_id = get_user_company_id(auth.uid())
            )
        )
    ', p_policy_name, p_table_name);
    
    EXECUTE v_sql;
END;
$$;


--
-- Name: create_tenant(character varying, character varying, character varying, character varying, character varying, character varying, character varying, character varying); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.create_tenant(p_name character varying, p_owner_email character varying, p_owner_name character varying, p_product_code character varying, p_plan_code character varying, p_country character varying DEFAULT NULL::character varying, p_timezone character varying DEFAULT 'UTC'::character varying, p_language character varying DEFAULT 'ar'::character varying) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_tenant_id UUID;
    v_tenant_code VARCHAR(50);
    v_product RECORD;
    v_plan RECORD;
    v_subscription_id UUID;
    v_trial_ends TIMESTAMPTZ;
    v_module TEXT;
BEGIN
    -- التحقق من المنتج
    SELECT * INTO v_product FROM saas_products WHERE code = p_product_code AND is_active = true;
    IF NOT FOUND THEN
        RETURN jsonb_build_object('success', false, 'error', 'المنتج غير موجود');
    END IF;
    
    -- التحقق من الباقة
    SELECT * INTO v_plan FROM subscription_plans 
    WHERE product_id = v_product.id AND code = p_plan_code AND is_active = true;
    IF NOT FOUND THEN
        RETURN jsonb_build_object('success', false, 'error', 'الباقة غير موجودة');
    END IF;
    
    -- التحقق من عدم تكرار الإيميل
    IF EXISTS (SELECT 1 FROM tenants WHERE owner_email = p_owner_email) THEN
        RETURN jsonb_build_object('success', false, 'error', 'البريد الإلكتروني مسجل مسبقاً');
    END IF;
    
    -- توليد كود فريد
    v_tenant_code := 'T' || EXTRACT(EPOCH FROM NOW())::BIGINT || FLOOR(RANDOM() * 1000)::INT;
    
    -- حساب نهاية الفترة التجريبية
    v_trial_ends := NOW() + (v_plan.trial_days || ' days')::INTERVAL;
    
    -- إنشاء العميل
    INSERT INTO tenants (
        code, name, owner_email, owner_name,
        country, timezone, default_language,
        status
    ) VALUES (
        v_tenant_code, p_name, p_owner_email, p_owner_name,
        p_country, p_timezone, p_language,
        'active'
    ) RETURNING id INTO v_tenant_id;
    
    -- إنشاء الاشتراك
    INSERT INTO subscriptions (
        tenant_id, product_id, plan_id,
        status, trial_started_at, trial_ends_at,
        billing_cycle, amount, currency
    ) VALUES (
        v_tenant_id, v_product.id, v_plan.id,
        'trial', NOW(), v_trial_ends,
        'monthly', v_plan.price_monthly, v_plan.currency
    ) RETURNING id INTO v_subscription_id;
    
    -- تفعيل الموديولات من الباقة
    FOREACH v_module IN ARRAY v_plan.included_modules
    LOOP
        INSERT INTO tenant_modules (tenant_id, module_code, source)
        VALUES (v_tenant_id, v_module, 'plan')
        ON CONFLICT (tenant_id, module_code) DO NOTHING;
    END LOOP;
    
    -- تسجيل الحدث
    INSERT INTO saas_events (tenant_id, event_type, event_data, actor_type)
    VALUES (v_tenant_id, 'tenant_created', jsonb_build_object(
        'name', p_name,
        'product', p_product_code,
        'plan', p_plan_code,
        'trial_ends', v_trial_ends
    ), 'system');
    
    RETURN jsonb_build_object(
        'success', true,
        'tenant_id', v_tenant_id,
        'tenant_code', v_tenant_code,
        'subscription_id', v_subscription_id,
        'trial_ends_at', v_trial_ends
    );
END;
$$;


--
-- Name: create_tenant_isolation_policies(text, boolean); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.create_tenant_isolation_policies(p_table_name text, p_has_tenant_id boolean DEFAULT true) RETURNS void
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_has_tenant_id BOOLEAN;
BEGIN
    -- التحقق الفعلي من وجود عمود tenant_id
    SELECT EXISTS (
        SELECT 1 FROM information_schema.columns
        WHERE table_schema = 'public'
          AND table_name = p_table_name
          AND column_name = 'tenant_id'
    ) INTO v_has_tenant_id;
    
    -- إذا لم يكن لديه tenant_id، تخطي
    IF NOT v_has_tenant_id THEN
        RAISE NOTICE '⚠️ الجدول % لا يحتوي على tenant_id - تم التخطي', p_table_name;
        RETURN;
    END IF;
    -- Policy: SELECT
    EXECUTE format(
        'CREATE POLICY tenant_isolation_select ON %I 
         FOR SELECT USING (
             %s OR is_super_admin()
         )',
        p_table_name,
        CASE WHEN p_has_tenant_id 
             THEN 'tenant_id = get_current_user_tenant_id()' 
             ELSE 'true' 
        END
    );
    
    -- Policy: INSERT
    EXECUTE format(
        'CREATE POLICY tenant_isolation_insert ON %I 
         FOR INSERT WITH CHECK (
             %s OR is_super_admin()
         )',
        p_table_name,
        CASE WHEN p_has_tenant_id 
             THEN 'tenant_id = get_current_user_tenant_id()' 
             ELSE 'true' 
        END
    );
    
    -- Policy: UPDATE
    EXECUTE format(
        'CREATE POLICY tenant_isolation_update ON %I 
         FOR UPDATE USING (
             %s OR is_super_admin()
         ) WITH CHECK (
             %s OR is_super_admin()
         )',
        p_table_name,
        CASE WHEN p_has_tenant_id 
             THEN 'tenant_id = get_current_user_tenant_id()' 
             ELSE 'true' 
        END,
        CASE WHEN p_has_tenant_id 
             THEN 'tenant_id = get_current_user_tenant_id()' 
             ELSE 'true' 
        END
    );
    
    -- Policy: DELETE
    EXECUTE format(
        'CREATE POLICY tenant_isolation_delete ON %I 
         FOR DELETE USING (
             %s OR is_super_admin()
         )',
        p_table_name,
        CASE WHEN p_has_tenant_id 
             THEN 'tenant_id = get_current_user_tenant_id()' 
             ELSE 'true' 
        END
    );
    
    RAISE NOTICE '✅ تم إنشاء Policies لجدول: %', p_table_name;
END;
$$;


--
-- Name: deduct_inventory(uuid, uuid, numeric, text, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.deduct_inventory(p_warehouse_id uuid, p_product_id uuid, p_quantity numeric, p_reference_type text, p_reference_id uuid) RETURNS void
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_tenant_id UUID;
  v_company_id UUID;
  v_user_id UUID;
  v_movement_number VARCHAR(50);
BEGIN
  v_user_id := auth.uid();

  -- user_profiles.id = auth.uid(), tenant_id is in companies table
  SELECT c.tenant_id, up.company_id 
  INTO v_tenant_id, v_company_id
  FROM user_profiles up
  JOIN companies c ON c.id = up.company_id
  WHERE up.id = v_user_id
  LIMIT 1;

  v_movement_number := 'AUTO-' || TO_CHAR(NOW(), 'YYYYMMDD-HH24MISS') || '-' || SUBSTR(gen_random_uuid()::text, 1, 4);

  INSERT INTO inventory_movements (
    tenant_id, company_id, movement_number, movement_date,
    movement_type, product_id,
    from_warehouse_id, quantity,
    reference_type, reference_id,
    notes, created_by
  ) VALUES (
    v_tenant_id, v_company_id, v_movement_number, CURRENT_DATE,
    'out', p_product_id,
    p_warehouse_id, ABS(p_quantity),
    p_reference_type, p_reference_id,
    'Auto deduction: ' || p_reference_type, v_user_id
  );
END;
$$;


--
-- Name: deduct_inventory_on_sale(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.deduct_inventory_on_sale() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_item RECORD;
    v_movement_number VARCHAR(50);
    v_warehouse_id UUID;
    v_default_warehouse_id UUID;
BEGIN
    -- Only process when status changes to 'posted'
    IF NEW.status != 'posted' THEN
        RETURN NEW;
    END IF;

    -- Don't reprocess if already posted
    IF OLD.status = 'posted' THEN
        RETURN NEW;
    END IF;

    -- Get default warehouse from branch if exists
    SELECT default_warehouse_id INTO v_default_warehouse_id
    FROM branches
    WHERE id = NEW.branch_id;

    -- If no branch default, get first active warehouse for company
    IF v_default_warehouse_id IS NULL THEN
        SELECT id INTO v_default_warehouse_id
        FROM warehouses
        WHERE company_id = NEW.company_id
          AND is_active = true
        ORDER BY created_at
        LIMIT 1;
    END IF;

    -- Process each invoice item
    FOR v_item IN
        SELECT * FROM sales_invoice_items
        WHERE invoice_id = NEW.id
          AND product_id IS NOT NULL
    LOOP
        -- Determine warehouse: item warehouse > branch default > company default
        v_warehouse_id := COALESCE(v_item.warehouse_id, v_default_warehouse_id);
        
        -- Skip if no warehouse found
        IF v_warehouse_id IS NULL THEN
            CONTINUE;
        END IF;

        v_movement_number := 'MV-SI-' || NEW.invoice_number || '-' || COALESCE(v_item.line_number, 0);

        -- Create inventory movement
        INSERT INTO inventory_movements (
            tenant_id, company_id,
            movement_number, movement_date,
            movement_type,
            product_id, variant_id,
            from_warehouse_id,
            quantity, unit_id,
            unit_cost, total_cost,
            reference_type, reference_id, reference_number,
            notes,
            created_by
        )
        VALUES (
            NEW.tenant_id, NEW.company_id,
            v_movement_number, NEW.invoice_date,
            'sale',
            v_item.product_id, v_item.variant_id,
            v_warehouse_id,
            v_item.quantity, v_item.unit_id,
            v_item.unit_cost, v_item.total_cost,
            'sales_invoice', NEW.id, NEW.invoice_number,
            'خصم مخزون - فاتورة مبيعات ' || NEW.invoice_number,
            NEW.created_by
        );
    END LOOP;

    RETURN NEW;
END;
$$;


--
-- Name: FUNCTION deduct_inventory_on_sale(); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION public.deduct_inventory_on_sale() IS 'Creates inventory movements when sales invoice is posted. Gets warehouse from: 1) item warehouse_id, 2) branch default, 3) first active warehouse';


--
-- Name: delete_tenant_complete(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.delete_tenant_complete(p_tenant_id uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_tenant_name TEXT;
    v_company_ids UUID[];
    v_user_tenant_id UUID;
BEGIN
    -- 🛡️ التحقق من صلاحية Super Admin
    IF NOT is_super_admin(auth.uid()) THEN
        RETURN jsonb_build_object('success', false, 'error', 'غير مصرح: Super Admin فقط');
    END IF;

    -- 🛡️ منع حذف الـ Tenant الخاص بالمستخدم الحالي
    SELECT tenant_id INTO v_user_tenant_id 
    FROM user_profiles 
    WHERE id = auth.uid();
    
    IF v_user_tenant_id = p_tenant_id THEN
        RETURN jsonb_build_object(
            'success', false, 
            'error', '⛔ لا يمكنك حذف حسابك الخاص! هذا الإجراء ممنوع لحمايتك.',
            'protection', 'self_delete_blocked'
        );
    END IF;

    -- الحصول على اسم الـ Tenant
    SELECT name INTO v_tenant_name FROM tenants WHERE id = p_tenant_id;
    
    IF v_tenant_name IS NULL THEN
        RETURN jsonb_build_object('success', false, 'error', 'الـ Tenant غير موجود');
    END IF;

    -- الحصول على قائمة الشركات التابعة
    SELECT ARRAY_AGG(id) INTO v_company_ids FROM companies WHERE tenant_id = p_tenant_id;

    RAISE NOTICE '🗑️ بدء حذف المشترك: % (ID: %)', v_tenant_name, p_tenant_id;

    -- ═══════════════════════════════════════════════════════════════════════
    -- حذف البيانات من الجداول الموجودة فقط (تجاهل غير الموجودة)
    -- ═══════════════════════════════════════════════════════════════════════
    
    -- القيود المحاسبية
    BEGIN DELETE FROM journal_entry_lines WHERE tenant_id = p_tenant_id; EXCEPTION WHEN undefined_table THEN NULL; END;
    BEGIN DELETE FROM journal_entries WHERE tenant_id = p_tenant_id; EXCEPTION WHEN undefined_table THEN NULL; END;
    BEGIN DELETE FROM recurring_entry_history WHERE tenant_id = p_tenant_id; EXCEPTION WHEN undefined_table THEN NULL; END;
    BEGIN DELETE FROM recurring_entries WHERE tenant_id = p_tenant_id; EXCEPTION WHEN undefined_table THEN NULL; END;
    BEGIN DELETE FROM recurring_entry_templates WHERE tenant_id = p_tenant_id; EXCEPTION WHEN undefined_table THEN NULL; END;
    BEGIN DELETE FROM chart_of_accounts WHERE tenant_id = p_tenant_id; EXCEPTION WHEN undefined_table THEN NULL; END;
    
    -- المخزون والمستودعات
    BEGIN DELETE FROM stock_movements WHERE tenant_id = p_tenant_id; EXCEPTION WHEN undefined_table THEN NULL; END;
    BEGIN DELETE FROM roll_transactions WHERE tenant_id = p_tenant_id; EXCEPTION WHEN undefined_table THEN NULL; END;
    BEGIN DELETE FROM roll_reservations WHERE tenant_id = p_tenant_id; EXCEPTION WHEN undefined_table THEN NULL; END;
    BEGIN DELETE FROM rolls WHERE tenant_id = p_tenant_id; EXCEPTION WHEN undefined_table THEN NULL; END;
    BEGIN DELETE FROM materials WHERE tenant_id = p_tenant_id; EXCEPTION WHEN undefined_table THEN NULL; END;
    BEGIN DELETE FROM material_categories WHERE tenant_id = p_tenant_id; EXCEPTION WHEN undefined_table THEN NULL; END;
    BEGIN DELETE FROM warehouse_locations WHERE tenant_id = p_tenant_id; EXCEPTION WHEN undefined_table THEN NULL; END;
    BEGIN DELETE FROM warehouses WHERE tenant_id = p_tenant_id; EXCEPTION WHEN undefined_table THEN NULL; END;
    
    -- المبيعات والمشتريات
    BEGIN DELETE FROM invoice_items WHERE tenant_id = p_tenant_id; EXCEPTION WHEN undefined_table THEN NULL; END;
    BEGIN DELETE FROM invoices WHERE tenant_id = p_tenant_id; EXCEPTION WHEN undefined_table THEN NULL; END;
    BEGIN DELETE FROM purchase_order_items WHERE tenant_id = p_tenant_id; EXCEPTION WHEN undefined_table THEN NULL; END;
    BEGIN DELETE FROM purchase_orders WHERE tenant_id = p_tenant_id; EXCEPTION WHEN undefined_table THEN NULL; END;
    BEGIN DELETE FROM sale_order_items WHERE tenant_id = p_tenant_id; EXCEPTION WHEN undefined_table THEN NULL; END;
    BEGIN DELETE FROM sale_orders WHERE tenant_id = p_tenant_id; EXCEPTION WHEN undefined_table THEN NULL; END;
    BEGIN DELETE FROM quotation_items WHERE tenant_id = p_tenant_id; EXCEPTION WHEN undefined_table THEN NULL; END;
    BEGIN DELETE FROM quotations WHERE tenant_id = p_tenant_id; EXCEPTION WHEN undefined_table THEN NULL; END;
    BEGIN DELETE FROM customers WHERE tenant_id = p_tenant_id; EXCEPTION WHEN undefined_table THEN NULL; END;
    BEGIN DELETE FROM suppliers WHERE tenant_id = p_tenant_id; EXCEPTION WHEN undefined_table THEN NULL; END;
    
    -- الفروع
    BEGIN DELETE FROM branches WHERE tenant_id = p_tenant_id; EXCEPTION WHEN undefined_table THEN NULL; END;
    
    -- البيانات الإدارية
    BEGIN DELETE FROM in_app_notifications WHERE tenant_id = p_tenant_id; EXCEPTION WHEN undefined_table THEN NULL; END;
    BEGIN DELETE FROM notifications WHERE tenant_id = p_tenant_id; EXCEPTION WHEN undefined_table THEN NULL; END;
    BEGIN DELETE FROM report_shares WHERE tenant_id = p_tenant_id; EXCEPTION WHEN undefined_table THEN NULL; END;
    BEGIN DELETE FROM report_templates WHERE tenant_id = p_tenant_id; EXCEPTION WHEN undefined_table THEN NULL; END;
    BEGIN DELETE FROM saved_reports WHERE tenant_id = p_tenant_id; EXCEPTION WHEN undefined_table THEN NULL; END;
    BEGIN DELETE FROM reviews WHERE tenant_id = p_tenant_id; EXCEPTION WHEN undefined_table THEN NULL; END;
    BEGIN DELETE FROM saas_events WHERE tenant_id = p_tenant_id; EXCEPTION WHEN undefined_table THEN NULL; END;
    BEGIN DELETE FROM support_tickets WHERE tenant_id = p_tenant_id; EXCEPTION WHEN undefined_table THEN NULL; END;
    BEGIN DELETE FROM tenant_referrals WHERE referrer_tenant_id = p_tenant_id; EXCEPTION WHEN undefined_table THEN NULL; END;
    BEGIN DELETE FROM tenant_referrals WHERE referee_tenant_id = p_tenant_id; EXCEPTION WHEN undefined_table THEN NULL; END;
    BEGIN DELETE FROM usage_analytics WHERE tenant_id = p_tenant_id; EXCEPTION WHEN undefined_table THEN NULL; END;
    BEGIN DELETE FROM webhook_endpoints WHERE tenant_id = p_tenant_id; EXCEPTION WHEN undefined_table THEN NULL; END;

    -- المستخدمين
    BEGIN UPDATE user_profiles SET tenant_id = NULL, company_id = NULL WHERE tenant_id = p_tenant_id; EXCEPTION WHEN undefined_table THEN NULL; END;
    
    -- صلاحيات المستخدمين
    IF v_company_ids IS NOT NULL THEN
        BEGIN DELETE FROM user_role_assignments WHERE company_id = ANY(v_company_ids); EXCEPTION WHEN undefined_table THEN NULL; END;
    END IF;

    -- ═══════════════════════════════════════════════════════════════════════
    -- حذف الـ Tenant (باقي الجداول CASCADE تلقائياً)
    -- ═══════════════════════════════════════════════════════════════════════
    DELETE FROM tenants WHERE id = p_tenant_id;

    RAISE NOTICE '✅ تم حذف المشترك: % بنجاح', v_tenant_name;

    RETURN jsonb_build_object(
        'success', true,
        'message', format('تم حذف المشترك "%s" وجميع بياناته بنجاح', v_tenant_name),
        'tenant_id', p_tenant_id
    );

EXCEPTION WHEN OTHERS THEN
    RAISE NOTICE '❌ خطأ في حذف المشترك: % - %', SQLERRM, SQLSTATE;
    RETURN jsonb_build_object(
        'success', false,
        'error', SQLERRM,
        'detail', SQLSTATE
    );
END;
$$;


--
-- Name: disable_addon_module(uuid, character varying); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.disable_addon_module(p_tenant_id uuid, p_module_code character varying) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_module_rec RECORD;
BEGIN
    -- التحقق من الموديول
    SELECT * INTO v_module_rec FROM tenant_modules 
    WHERE tenant_id = p_tenant_id AND module_code = p_module_code;
    
    IF NOT FOUND THEN
        RETURN jsonb_build_object('success', false, 'error', 'الموديول غير مفعل');
    END IF;
    
    -- لا يمكن إلغاء موديولات الباقة
    IF v_module_rec.source = 'plan' THEN
        RETURN jsonb_build_object('success', false, 'error', 'لا يمكن إلغاء موديول من الباقة');
    END IF;
    
    -- التحقق من عدم وجود موديولات تعتمد عليه
    IF EXISTS (
        SELECT 1 FROM tenant_modules tm
        JOIN system_modules sm ON tm.module_code = sm.code
        WHERE tm.tenant_id = p_tenant_id 
          AND tm.is_active = true
          AND p_module_code = ANY(sm.dependencies)
    ) THEN
        RETURN jsonb_build_object('success', false, 'error', 'يوجد موديولات تعتمد على هذا الموديول');
    END IF;
    
    -- إلغاء التفعيل
    UPDATE tenant_modules
    SET is_active = false
    WHERE tenant_id = p_tenant_id AND module_code = p_module_code;
    
    -- تسجيل الحدث
    INSERT INTO saas_events (tenant_id, event_type, event_data, actor_type)
    VALUES (p_tenant_id, 'module_disabled', jsonb_build_object('module', p_module_code), 'admin');
    
    RETURN jsonb_build_object('success', true, 'module', p_module_code);
END;
$$;


--
-- Name: disable_tenant_language(uuid, character varying); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.disable_tenant_language(p_tenant_id uuid, p_language_code character varying) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_current_user_id UUID;
    v_is_primary BOOLEAN;
    v_enabled_count INT;
BEGIN
    v_current_user_id := auth.uid();
    
    -- التحقق من أن اللغة مفعلة
    SELECT is_primary INTO v_is_primary
    FROM tenant_languages
    WHERE tenant_id = p_tenant_id
    AND language_code = p_language_code
    AND is_enabled = true;
    
    IF NOT FOUND THEN
        RETURN jsonb_build_object(
            'success', false,
            'error', 'Language not enabled or not found'
        );
    END IF;
    
    -- التحقق من أنها ليست آخر لغة
    SELECT COUNT(*) INTO v_enabled_count
    FROM tenant_languages
    WHERE tenant_id = p_tenant_id
    AND is_enabled = true;
    
    IF v_enabled_count <= 1 THEN
        RETURN jsonb_build_object(
            'success', false,
            'error', 'Cannot disable last language'
        );
    END IF;
    
    -- تعطيل اللغة
    UPDATE tenant_languages
    SET 
        is_enabled = false,
        disabled_at = NOW(),
        disabled_by = v_current_user_id
    WHERE tenant_id = p_tenant_id
    AND language_code = p_language_code;
    
    -- إذا كانت primary، تعيين لغة أخرى كـ primary
    IF v_is_primary THEN
        UPDATE tenant_languages
        SET is_primary = true
        WHERE id = (
            SELECT id
            FROM tenant_languages
            WHERE tenant_id = p_tenant_id
            AND is_enabled = true
            ORDER BY display_order
            LIMIT 1
        );
    END IF;
    
    -- تسجيل في audit log
    PERFORM log_audit(
        'disable_language',
        'tenant_languages',
        p_tenant_id,
        p_language_code,
        NULL,
        jsonb_build_object('language_code', p_language_code)
    );
    
    RETURN jsonb_build_object(
        'success', true,
        'tenant_id', p_tenant_id,
        'language_code', p_language_code
    );
END;
$$;


--
-- Name: enable_addon_module(uuid, character varying, numeric); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.enable_addon_module(p_tenant_id uuid, p_module_code character varying, p_price_monthly numeric DEFAULT NULL::numeric) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_module RECORD;
    v_dep TEXT;
BEGIN
    -- التحقق من الموديول
    SELECT * INTO v_module FROM system_modules WHERE code = p_module_code AND is_active = true;
    IF NOT FOUND THEN
        RETURN jsonb_build_object('success', false, 'error', 'الموديول غير موجود');
    END IF;
    
    -- التحقق من أنه غير مفعل
    IF EXISTS (SELECT 1 FROM tenant_modules WHERE tenant_id = p_tenant_id AND module_code = p_module_code AND is_active = true) THEN
        RETURN jsonb_build_object('success', false, 'error', 'الموديول مفعل مسبقاً');
    END IF;
    
    -- التحقق من التبعيات
    FOREACH v_dep IN ARRAY v_module.dependencies
    LOOP
        IF NOT EXISTS (SELECT 1 FROM tenant_modules WHERE tenant_id = p_tenant_id AND module_code = v_dep AND is_active = true) THEN
            RETURN jsonb_build_object('success', false, 'error', 'يجب تفعيل موديول ' || v_dep || ' أولاً');
        END IF;
    END LOOP;
    
    -- تفعيل الموديول
    INSERT INTO tenant_modules (tenant_id, module_code, source, price_monthly)
    VALUES (p_tenant_id, p_module_code, 'addon', COALESCE(p_price_monthly, v_module.price_monthly))
    ON CONFLICT (tenant_id, module_code) DO UPDATE SET
        is_active = true,
        enabled_at = NOW(),
        price_monthly = COALESCE(p_price_monthly, v_module.price_monthly);
    
    -- تسجيل الحدث
    INSERT INTO saas_events (tenant_id, event_type, event_data, actor_type)
    VALUES (p_tenant_id, 'module_enabled', jsonb_build_object(
        'module', p_module_code,
        'price', COALESCE(p_price_monthly, v_module.price_monthly)
    ), 'admin');
    
    RETURN jsonb_build_object(
        'success', true,
        'module', p_module_code
    );
END;
$$;


--
-- Name: enable_rls_with_tenant_isolation(text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.enable_rls_with_tenant_isolation(p_table_name text) RETURNS text
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_has_tenant_id BOOLEAN;
    v_policy_exists BOOLEAN;
    v_rls_enabled BOOLEAN;
BEGIN
    -- Check if table exists
    IF NOT EXISTS (
        SELECT 1 FROM information_schema.tables
        WHERE table_schema = 'public' AND table_name = p_table_name
    ) THEN
        RETURN '⚠️  Table ' || p_table_name || ' does not exist - SKIP';
    END IF;
    
    -- Check if table has tenant_id column
    SELECT EXISTS (
        SELECT 1 FROM information_schema.columns
        WHERE table_schema = 'public' 
            AND table_name = p_table_name
            AND column_name = 'tenant_id'
    ) INTO v_has_tenant_id;
    
    IF NOT v_has_tenant_id THEN
        RETURN '⚠️  Table ' || p_table_name || ' does not have tenant_id column - SKIP';
    END IF;
    
    -- Check if RLS already enabled
    SELECT rowsecurity INTO v_rls_enabled
    FROM pg_tables
    WHERE schemaname = 'public' AND tablename = p_table_name;
    
    IF NOT v_rls_enabled THEN
        -- Enable RLS
        EXECUTE format('ALTER TABLE %I ENABLE ROW LEVEL SECURITY', p_table_name);
    END IF;
    
    -- Check if policy already exists
    SELECT EXISTS (
        SELECT 1 FROM pg_policies
        WHERE schemaname = 'public'
            AND tablename = p_table_name
            AND policyname = 'tenant_isolation'
    ) INTO v_policy_exists;
    
    IF NOT v_policy_exists THEN
        -- Create tenant isolation policy
        EXECUTE format('
            CREATE POLICY tenant_isolation ON %I
            FOR ALL 
            USING (tenant_id = current_setting(''app.current_tenant_id'', true)::uuid)
        ', p_table_name);
        RETURN '✅ Enabled RLS + Created policy on: ' || p_table_name;
    ELSE
        IF NOT v_rls_enabled THEN
            RETURN '✅ Enabled RLS on: ' || p_table_name || ' (policy existed)';
        ELSE
            RETURN '⏭️  RLS already enabled on: ' || p_table_name;
        END IF;
    END IF;
    
EXCEPTION WHEN OTHERS THEN
    RETURN '❌ Error on ' || p_table_name || ': ' || SQLERRM;
END;
$$;


--
-- Name: enable_tenant_language(uuid, character varying, boolean); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.enable_tenant_language(p_tenant_id uuid, p_language_code character varying, p_is_primary boolean DEFAULT false) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_limit_check JSONB;
    v_can_add BOOLEAN;
    v_current_user_id UUID;
BEGIN
    v_current_user_id := auth.uid();
    
    -- التحقق من وجود اللغة في النظام
    IF NOT EXISTS (SELECT 1 FROM system_languages WHERE code = p_language_code AND is_active = true) THEN
        RETURN jsonb_build_object(
            'success', false,
            'error', 'Language not available in system'
        );
    END IF;
    
    -- التحقق من أن اللغة غير مفعلة مسبقاً
    IF EXISTS (SELECT 1 FROM tenant_languages WHERE tenant_id = p_tenant_id AND language_code = p_language_code AND is_enabled = true) THEN
        RETURN jsonb_build_object(
            'success', false,
            'error', 'Language already enabled'
        );
    END IF;
    
    -- التحقق من الحد الأقصى
    v_limit_check := check_language_limit(p_tenant_id);
    v_can_add := (v_limit_check->>'can_add_more')::BOOLEAN;
    
    IF NOT v_can_add THEN
        RETURN jsonb_build_object(
            'success', false,
            'error', 'Language limit reached',
            'limit_info', v_limit_check
        );
    END IF;
    
    -- إذا كانت أول لغة، تصبح primary تلقائياً
    IF NOT EXISTS (SELECT 1 FROM tenant_languages WHERE tenant_id = p_tenant_id AND is_enabled = true) THEN
        p_is_primary := true;
    END IF;
    
    -- إذا كانت primary جديدة، إلغاء primary من اللغات الأخرى
    IF p_is_primary THEN
        UPDATE tenant_languages
        SET is_primary = false
        WHERE tenant_id = p_tenant_id;
    END IF;
    
    -- إدراج أو تحديث اللغة
    INSERT INTO tenant_languages (
        tenant_id,
        language_code,
        language_name_ar,
        language_name_en,
        is_primary,
        is_enabled,
        enabled_at,
        enabled_by
    )
    SELECT
        p_tenant_id,
        p_language_code,
        sl.name_ar,
        sl.name_en,
        p_is_primary,
        true,
        NOW(),
        v_current_user_id
    FROM system_languages sl
    WHERE sl.code = p_language_code
    ON CONFLICT (tenant_id, language_code)
    DO UPDATE SET
        is_enabled = true,
        is_primary = p_is_primary,
        enabled_at = NOW(),
        enabled_by = v_current_user_id,
        disabled_at = NULL,
        disabled_by = NULL;
    
    -- تسجيل في audit log
    PERFORM log_audit(
        'enable_language',
        'tenant_languages',
        p_tenant_id,
        p_language_code,
        NULL,
        jsonb_build_object('language_code', p_language_code, 'is_primary', p_is_primary)
    );
    
    RETURN jsonb_build_object(
        'success', true,
        'tenant_id', p_tenant_id,
        'language_code', p_language_code,
        'is_primary', p_is_primary
    );
END;
$$;


--
-- Name: enforce_brand_isolation(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.enforce_brand_isolation() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_current_user_id UUID := auth.uid();
    v_is_platform_admin BOOLEAN;
BEGIN
    IF v_current_user_id IS NULL THEN
        RETURN NEW;
    END IF;

    v_is_platform_admin := is_platform_admin(v_current_user_id);
    
    -- Platform Admin يتخطى التحقق
    IF v_is_platform_admin THEN
        RETURN NEW;
    END IF;

    -- التحقق من أن tenant_id ينتمي لنفس براند المستخدم
    IF NEW.tenant_id IS NOT NULL THEN
        IF NOT is_same_brand(NEW.tenant_id, v_current_user_id) THEN
            RAISE EXCEPTION 'غير مسموح: لا يمكنك إضافة بيانات لتينانت خارج براندك / Not allowed: You cannot add data to a tenant outside your brand';
        END IF;
    END IF;
    
    RETURN NEW;
END;
$$;


--
-- Name: execute_pos_delivery(uuid, uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.execute_pos_delivery(p_invoice_id uuid, p_warehouse_id uuid, p_tenant_id uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  v_delivery_id UUID;
  v_company_id UUID;
  v_user_id UUID;
  v_movement_number VARCHAR(50);
  v_note_number VARCHAR(50);
BEGIN
  v_user_id := auth.uid();
  
  SELECT up.company_id INTO v_company_id
  FROM user_profiles up WHERE up.id = v_user_id LIMIT 1;

  -- Generate delivery note number
  v_note_number := 'POS-DN-' || TO_CHAR(NOW(), 'YYYYMMDD-HH24MISS');

  -- 1. إنشاء إذن تسليم
  INSERT INTO delivery_notes (
    tenant_id, company_id, customer_id, warehouse_id,
    note_number, note_date, status, notes, created_by
  )
  SELECT 
    si.tenant_id, v_company_id, si.customer_id, p_warehouse_id,
    v_note_number, CURRENT_DATE, 'delivered',
    'POS Auto-Delivery for Invoice #' || si.invoice_number,
    v_user_id
  FROM sales_invoices si
  WHERE si.id = p_invoice_id
  RETURNING id INTO v_delivery_id;

  -- 2. نسخ بنود الفاتورة
  INSERT INTO delivery_note_items (
    tenant_id, delivery_note_id, product_id, 
    quantity_ordered, quantity_to_deliver, quantity_delivered
  )
  SELECT 
    p_tenant_id, v_delivery_id, sii.product_id,
    sii.quantity, sii.quantity, sii.quantity
  FROM sales_invoice_items sii
  WHERE sii.invoice_id = p_invoice_id;

  -- 3. تسجيل حركة مخزون (خصم)
  INSERT INTO inventory_movements (
    tenant_id, company_id, movement_number, movement_date,
    movement_type, product_id, from_warehouse_id,
    quantity, reference_type, reference_id,
    notes, created_by
  )
  SELECT 
    p_tenant_id, v_company_id,
    'POS-' || TO_CHAR(NOW(), 'YYYYMMDD-HH24MISS') || '-' || ROW_NUMBER() OVER (),
    CURRENT_DATE,
    'out', sii.product_id, p_warehouse_id,
    sii.quantity, 'pos_sale', p_invoice_id,
    'POS auto-deduction', v_user_id
  FROM sales_invoice_items sii
  WHERE sii.invoice_id = p_invoice_id;

  -- 4. تحديث حالة الفاتورة
  UPDATE sales_invoices SET status = 'posted' WHERE id = p_invoice_id;

  RETURN jsonb_build_object(
    'success', true,
    'invoice_id', p_invoice_id,
    'delivery_id', v_delivery_id,
    'message', 'POS sale completed'
  );
EXCEPTION WHEN OTHERS THEN
  RETURN jsonb_build_object(
    'success', false,
    'error', SQLERRM,
    'invoice_id', p_invoice_id
  );
END;
$$;


--
-- Name: execute_readonly_query(text, uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.execute_readonly_query(query_text text, p_company_id uuid DEFAULT NULL::uuid, p_tenant_id uuid DEFAULT NULL::uuid) RETURNS json
    LANGUAGE plpgsql SECURITY DEFINER
    SET statement_timeout TO '10000'
    AS $$
DECLARE
  result JSON;
  clean_query TEXT;
  has_isolation BOOLEAN := FALSE;
BEGIN
  -- Normalize: remove ALL whitespace from start, lowercase
  clean_query := LOWER(REGEXP_REPLACE(TRIM(BOTH FROM query_text), '^\s+', '', 'g'));
  clean_query := REGEXP_REPLACE(clean_query, '\s+', ' ', 'g');
  
  IF NOT (clean_query LIKE 'select %' OR clean_query LIKE 'with %' OR clean_query = 'select' OR clean_query LIKE 'select*%') THEN
    RAISE EXCEPTION 'Only SELECT queries are allowed. Got: %', LEFT(clean_query, 50);
  END IF;
  
  IF clean_query ~ '\b(insert|update|delete|drop|alter|create|truncate|grant|revoke)\b' THEN
    RAISE EXCEPTION 'Mutation queries are not allowed';
  END IF;
  
  -- SECURITY: Query must contain company_id OR tenant_id
  IF p_company_id IS NOT NULL AND LOWER(query_text) LIKE '%' || p_company_id::text || '%' THEN
    has_isolation := TRUE;
  END IF;
  IF p_tenant_id IS NOT NULL AND LOWER(query_text) LIKE '%' || p_tenant_id::text || '%' THEN
    has_isolation := TRUE;
  END IF;
  IF LOWER(query_text) LIKE '%information_schema%' THEN
    has_isolation := TRUE;
  END IF;
  
  IF NOT has_isolation AND (p_company_id IS NOT NULL OR p_tenant_id IS NOT NULL) THEN
    RAISE EXCEPTION 'Query must filter by company_id or tenant_id';
  END IF;
  
  EXECUTE 'SELECT COALESCE(json_agg(t), ''[]''::json) FROM (' || query_text || ' LIMIT 500) t' INTO result;
  RETURN result;
END;
$$;


--
-- Name: execute_recurring_entry(uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.execute_recurring_entry(p_history_id uuid, p_user_id uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_history RECORD;
    v_recurring RECORD;
    v_journal_entry_id UUID;
    v_line RECORD;
    v_total_debit NUMERIC := 0;
    v_total_credit NUMERIC := 0;
BEGIN
    -- جلب سجل التاريخ
    SELECT * INTO v_history FROM recurring_entry_history WHERE id = p_history_id;
    IF NOT FOUND THEN
        RETURN jsonb_build_object('success', false, 'error', 'History record not found');
    END IF;
    
    -- التحقق من الحالة
    IF v_history.status != 'pending' THEN
        RETURN jsonb_build_object('success', false, 'error', 'Entry already processed');
    END IF;
    
    IF v_history.approval_status NOT IN ('approved', 'auto_approved') THEN
        RETURN jsonb_build_object('success', false, 'error', 'Entry not approved');
    END IF;
    
    -- جلب القيد المتكرر
    SELECT * INTO v_recurring FROM recurring_entries WHERE id = v_history.recurring_entry_id;
    
    -- إنشاء القيد المحاسبي الفعلي
    INSERT INTO journal_entries (
        tenant_id, company_id, branch_id,
        entry_date, description, description_ar,
        entry_type, reference_type, reference_id,
        currency, status, created_by
    ) VALUES (
        v_recurring.tenant_id, v_recurring.company_id, v_recurring.branch_id,
        v_history.scheduled_date, v_recurring.name_en, v_recurring.name_ar,
        'recurring', 'recurring_entry', v_recurring.id,
        v_recurring.currency, 'draft', p_user_id
    ) RETURNING id INTO v_journal_entry_id;
    
    -- إضافة بنود القيد
    FOR v_line IN
        SELECT * FROM recurring_entry_lines WHERE recurring_entry_id = v_recurring.id ORDER BY line_number
    LOOP
        INSERT INTO journal_entry_lines (
            tenant_id, entry_id, line_number, account_id,
            debit, credit, description, cost_center_id
        ) VALUES (
            v_recurring.tenant_id, v_journal_entry_id, v_line.line_number, v_line.account_id,
            v_line.debit, v_line.credit, v_line.description, v_line.cost_center_id
        );
        
        v_total_debit := v_total_debit + v_line.debit;
        v_total_credit := v_total_credit + v_line.credit;
    END LOOP;
    
    -- تحديث إجماليات القيد
    UPDATE journal_entries
    SET total_debit = v_total_debit, total_credit = v_total_credit
    WHERE id = v_journal_entry_id;
    
    -- ترحيل تلقائي إذا مفعّل
    IF v_recurring.auto_post THEN
        UPDATE journal_entries
        SET status = 'posted', is_posted = true, posted_at = NOW(), posted_by = p_user_id
        WHERE id = v_journal_entry_id;
    END IF;
    
    -- تحديث سجل التاريخ
    UPDATE recurring_entry_history
    SET 
        journal_entry_id = v_journal_entry_id,
        executed_at = NOW(),
        executed_by = p_user_id,
        status = 'executed'
    WHERE id = p_history_id;
    
    RETURN jsonb_build_object(
        'success', true,
        'journal_entry_id', v_journal_entry_id,
        'total_debit', v_total_debit,
        'total_credit', v_total_credit,
        'auto_posted', v_recurring.auto_post
    );
    
EXCEPTION WHEN OTHERS THEN
    UPDATE recurring_entry_history
    SET status = 'failed', error_message = SQLERRM
    WHERE id = p_history_id;
    
    RETURN jsonb_build_object('success', false, 'error', SQLERRM);
END;
$$;


--
-- Name: FUNCTION execute_recurring_entry(p_history_id uuid, p_user_id uuid); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION public.execute_recurring_entry(p_history_id uuid, p_user_id uuid) IS 'تنفيذ قيد متكرر وإنشاء قيد محاسبي فعلي';


--
-- Name: execute_report(uuid, jsonb); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.execute_report(p_template_id uuid, p_parameters jsonb DEFAULT '{}'::jsonb) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_template RECORD;
    v_sql TEXT;
    v_result JSONB;
    v_count INTEGER;
BEGIN
    -- جلب القالب
    SELECT * INTO v_template FROM report_templates WHERE id = p_template_id;
    IF NOT FOUND THEN
        RETURN jsonb_build_object('success', false, 'error', 'Template not found');
    END IF;
    
    -- بناء الاستعلام
    v_sql := 'SELECT ';
    
    -- الأعمدة
    SELECT string_agg(
        (col->>'source') || ' AS ' || COALESCE(col->>'alias', 'col_' || ordinality::text),
        ', '
    ) INTO v_sql
    FROM jsonb_array_elements(v_template.columns) WITH ORDINALITY AS col(col, ordinality);
    
    v_sql := 'SELECT ' || v_sql || ' FROM ' || v_template.source_table;
    
    -- إضافة الـ joins
    IF v_template.joins IS NOT NULL AND jsonb_array_length(v_template.joins) > 0 THEN
        SELECT v_sql || ' ' || string_agg(
            COALESCE(j->>'type', 'LEFT') || ' JOIN ' || 
            (j->>'table') || 
            COALESCE(' AS ' || (j->>'alias'), '') || 
            ' ON ' || (j->>'on'),
            ' '
        )
        INTO v_sql
        FROM jsonb_array_elements(v_template.joins) AS j;
    END IF;
    
    -- تحديث عداد الاستخدام
    UPDATE report_templates
    SET use_count = use_count + 1, last_used_at = NOW()
    WHERE id = p_template_id;
    
    -- ملاحظة: التنفيذ الفعلي يحتاج أمان إضافي
    -- هذه نسخة مبسطة للتوضيح
    
    RETURN jsonb_build_object(
        'success', true,
        'template_name', v_template.name_ar,
        'sql_preview', v_sql,
        'message', 'Report execution requires frontend implementation'
    );
    
EXCEPTION WHEN OTHERS THEN
    RETURN jsonb_build_object('success', false, 'error', SQLERRM);
END;
$$;


--
-- Name: FUNCTION execute_report(p_template_id uuid, p_parameters jsonb); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION public.execute_report(p_template_id uuid, p_parameters jsonb) IS 'تنفيذ تقرير من قالب محدد';


--
-- Name: export_tenant_data(uuid, text[]); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.export_tenant_data(p_tenant_id uuid, p_tables text[] DEFAULT NULL::text[]) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $_$
DECLARE
    v_result JSONB := '{}';
    v_table TEXT;
    v_data JSONB;
    v_default_tables TEXT[] := ARRAY[
        'companies', 'branches', 'user_profiles', 'currencies'
    ];
BEGIN
    IF NOT is_super_admin() THEN
        RETURN jsonb_build_object('error', 'Unauthorized');
    END IF;
    
    IF p_tables IS NULL THEN
        p_tables := v_default_tables;
    END IF;
    
    FOREACH v_table IN ARRAY p_tables
    LOOP
        IF EXISTS (
            SELECT 1 FROM information_schema.tables 
            WHERE table_schema = 'public' AND table_name = v_table
        ) AND EXISTS (
            SELECT 1 FROM information_schema.columns 
            WHERE table_schema = 'public' 
              AND table_name = v_table 
              AND column_name = 'tenant_id'
        ) THEN
            EXECUTE format(
                'SELECT COALESCE(jsonb_agg(row_to_json(t)), ''[]''::jsonb) FROM %I t WHERE tenant_id = $1',
                v_table
            ) INTO v_data USING p_tenant_id;
            
            v_result := v_result || jsonb_build_object(v_table, v_data);
        END IF;
    END LOOP;
    
    RETURN v_result || jsonb_build_object(
        '_export_info', jsonb_build_object(
            'tenant_id', p_tenant_id,
            'exported_at', NOW(),
            'tables', p_tables
        )
    );
END;
$_$;


--
-- Name: finalize_container_costs(uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.finalize_container_costs(p_container_id uuid, p_user_id uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_container RECORD;
    v_allocation_result JSONB;
BEGIN
    -- جلب بيانات الكونتينر
    SELECT * INTO v_container
    FROM containers
    WHERE id = p_container_id;
    
    IF NOT FOUND THEN
        RETURN jsonb_build_object(
            'success', false,
            'error', 'Container not found',
            'error_ar', 'الكونتينر غير موجود'
        );
    END IF;
    
    -- التحقق من عدم التثبيت المسبق
    IF v_container.is_cost_finalized = true THEN
        RETURN jsonb_build_object(
            'success', false,
            'error', 'Container costs already finalized',
            'error_ar', 'تكاليف الكونتينر مثبتة بالفعل'
        );
    END IF;
    
    -- توزيع التكاليف أولاً
    v_allocation_result := allocate_container_costs(p_container_id, v_container.cost_allocation_method);
    
    IF NOT (v_allocation_result->>'success')::BOOLEAN THEN
        RETURN v_allocation_result;
    END IF;
    
    -- تثبيت الكونتينر
    UPDATE containers
    SET 
        is_cost_finalized = true,
        finalized_at = NOW(),
        finalized_by = p_user_id,
        final_goods_cost = (v_allocation_result->>'total_goods_value')::NUMERIC,
        updated_at = NOW()
    WHERE id = p_container_id;
    
    -- إرجاع النتيجة
    RETURN jsonb_build_object(
        'success', true,
        'container_id', p_container_id,
        'finalized_at', NOW(),
        'finalized_by', p_user_id,
        'allocation', v_allocation_result
    );
    
EXCEPTION WHEN OTHERS THEN
    RETURN jsonb_build_object(
        'success', false,
        'error', SQLERRM,
        'error_code', SQLSTATE
    );
END;
$$;


--
-- Name: fix_entry_type_from_reference(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.fix_entry_type_from_reference() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
    -- Sales entries
    IF NEW.reference_type IN ('sales_invoice', 'sales_cogs', 'sales_return') AND (NEW.entry_type IS NULL OR NEW.entry_type = 'manual') THEN
        NEW.entry_type := 'sales';
    END IF;
    -- Purchase entries
    IF NEW.reference_type IN ('purchase_invoice', 'purchase_return') AND (NEW.entry_type IS NULL OR NEW.entry_type = 'manual') THEN
        NEW.entry_type := 'purchase_invoice';
    END IF;
    -- Container entries
    IF NEW.reference_type IN ('container', 'container_tax', 'container_close', 'container_expense') AND (NEW.entry_type IS NULL OR NEW.entry_type = 'manual') THEN
        NEW.entry_type := 'purchase_invoice';
    END IF;
    RETURN NEW;
END;
$$;


--
-- Name: fn_container_status_notification(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.fn_container_status_notification() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    rule JSONB;
    rule_user_id UUID;
    rule_trigger TEXT;
    rule_enabled BOOLEAN;
    rule_role TEXT;
    v_container_name TEXT;
    v_container_number TEXT;
    new_status_label_ar TEXT;
    new_status_label_en TEXT;
    notification_title_ar TEXT;
    notification_title_en TEXT;
    notification_body_ar TEXT;
    notification_body_en TEXT;
BEGIN
    -- Only fire if status actually changed
    IF OLD.status IS NOT DISTINCT FROM NEW.status THEN
        RETURN NEW;
    END IF;
    
    -- Skip if no notification_rules
    IF NEW.notification_rules IS NULL OR NEW.notification_rules = '[]'::JSONB OR jsonb_array_length(NEW.notification_rules) = 0 THEN
        RETURN NEW;
    END IF;
    
    -- Get container identifiers
    v_container_number := COALESCE(NEW.container_number, NEW.shipment_number, 'N/A');
    v_container_name := COALESCE(NEW.container_name, v_container_number);
    
    -- Map status key to labels
    new_status_label_ar := CASE NEW.status
        WHEN 'draft'      THEN 'مسودة'
        WHEN 'booked'     THEN 'تم الحجز'
        WHEN 'loading'    THEN 'جاري التحميل'
        WHEN 'in_transit' THEN 'بالبحر'
        WHEN 'at_port'    THEN 'وصل الميناء'
        WHEN 'customs'    THEN 'بالجمركة'
        WHEN 'cleared'    THEN 'تم التخليص'
        WHEN 'delivered'  THEN 'تم التسليم'
        WHEN 'received'   THEN 'تم الاستلام'
        ELSE NEW.status
    END;
    
    new_status_label_en := CASE NEW.status
        WHEN 'draft'      THEN 'Draft'
        WHEN 'booked'     THEN 'Booked'
        WHEN 'loading'    THEN 'Loading'
        WHEN 'in_transit' THEN 'In Transit'
        WHEN 'at_port'    THEN 'At Port'
        WHEN 'customs'    THEN 'At Customs'
        WHEN 'cleared'    THEN 'Cleared'
        WHEN 'delivered'  THEN 'Delivered'
        WHEN 'received'   THEN 'Received'
        ELSE NEW.status
    END;
    
    -- Loop through notification rules
    FOR rule IN SELECT jsonb_array_elements(NEW.notification_rules)
    LOOP
        rule_enabled := COALESCE((rule ->> 'enabled')::BOOLEAN, false);
        rule_trigger := rule ->> 'trigger_status';
        rule_user_id := (rule ->> 'user_id')::UUID;
        rule_role := COALESCE(rule ->> 'role', 'unknown');
        
        -- Skip disabled rules or rules that don't match
        IF NOT rule_enabled THEN CONTINUE; END IF;
        IF rule_trigger IS NULL OR rule_trigger != NEW.status THEN CONTINUE; END IF;
        IF rule_user_id IS NULL THEN CONTINUE; END IF;
        
        -- Build notification content
        notification_title_ar := 'كونتينر ' || v_container_number || ' — ' || new_status_label_ar;
        notification_title_en := 'Container ' || v_container_number || ' — ' || new_status_label_en;
        
        IF rule_role = 'warehouse' THEN
            notification_body_ar := 'الكونتينر "' || v_container_name || '" أصبح جاهزاً للاستلام في المستودع';
            notification_body_en := 'Container "' || v_container_name || '" is ready for warehouse receiving';
        ELSIF rule_role = 'sales' THEN
            notification_body_ar := 'الكونتينر "' || v_container_name || '" وصل للحالة: ' || new_status_label_ar;
            notification_body_en := 'Container "' || v_container_name || '" reached status: ' || new_status_label_en;
        ELSE
            notification_body_ar := 'حالة الكونتينر تغيرت إلى: ' || new_status_label_ar;
            notification_body_en := 'Container status changed to: ' || new_status_label_en;
        END IF;
        
        -- Insert notification
        INSERT INTO notifications (
            tenant_id, user_id, title, body, type,
            source_type, source_id, metadata
        ) VALUES (
            NEW.company_id,
            rule_user_id,
            notification_title_ar || ' | ' || notification_title_en,
            notification_body_ar || ' | ' || notification_body_en,
            CASE 
                WHEN NEW.status IN ('cleared', 'received', 'delivered') THEN 'success'
                WHEN NEW.status = 'customs' THEN 'warning'
                ELSE 'info'
            END,
            'container',
            NEW.id,
            jsonb_build_object(
                'container_number', v_container_number,
                'container_name', v_container_name,
                'old_status', OLD.status,
                'new_status', NEW.status,
                'role', rule_role,
                'status_label_ar', new_status_label_ar,
                'status_label_en', new_status_label_en
            )
        );
    END LOOP;
    
    RETURN NEW;
END;
$$;


--
-- Name: fn_mark_all_notifications_read(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.fn_mark_all_notifications_read() RETURNS integer
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    affected INTEGER;
BEGIN
    UPDATE notifications
    SET is_read = true, read_at = now(), updated_at = now()
    WHERE user_id = auth.uid()
      AND is_read = false;
    GET DIAGNOSTICS affected = ROW_COUNT;
    RETURN affected;
END;
$$;


--
-- Name: fn_mark_notifications_read(uuid[]); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.fn_mark_notifications_read(notification_ids uuid[]) RETURNS integer
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    affected INTEGER;
BEGIN
    UPDATE notifications
    SET is_read = true, read_at = now(), updated_at = now()
    WHERE id = ANY(notification_ids)
      AND user_id = auth.uid()
      AND is_read = false;
    GET DIAGNOSTICS affected = ROW_COUNT;
    RETURN affected;
END;
$$;


--
-- Name: fn_purchase_invoice_notification(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.fn_purchase_invoice_notification() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    status_ar TEXT;
    status_en TEXT;
    notif_type TEXT;
    v_invoice_num TEXT;
BEGIN
    IF OLD.status IS NOT DISTINCT FROM NEW.status THEN RETURN NEW; END IF;
    IF NEW.created_by IS NULL THEN RETURN NEW; END IF;
    
    v_invoice_num := COALESCE(NEW.invoice_number, 'N/A');
    
    status_ar := CASE NEW.status
        WHEN 'draft' THEN 'مسودة' WHEN 'pending' THEN 'بانتظار الموافقة'
        WHEN 'approved' THEN 'تمت الموافقة' WHEN 'confirmed' THEN 'مؤكدة'
        WHEN 'posted' THEN 'مرحّلة' WHEN 'paid' THEN 'مدفوعة'
        WHEN 'partial_paid' THEN 'مدفوعة جزئياً' WHEN 'cancelled' THEN 'ملغاة'
        WHEN 'rejected' THEN 'مرفوضة'
        ELSE NEW.status END;
    
    status_en := CASE NEW.status
        WHEN 'draft' THEN 'Draft' WHEN 'pending' THEN 'Pending Approval'
        WHEN 'approved' THEN 'Approved' WHEN 'confirmed' THEN 'Confirmed'
        WHEN 'posted' THEN 'Posted' WHEN 'paid' THEN 'Paid'
        WHEN 'partial_paid' THEN 'Partially Paid' WHEN 'cancelled' THEN 'Cancelled'
        WHEN 'rejected' THEN 'Rejected'
        ELSE NEW.status END;
    
    notif_type := CASE 
        WHEN NEW.status IN ('approved', 'posted', 'paid') THEN 'success'
        WHEN NEW.status IN ('cancelled', 'rejected') THEN 'error'
        WHEN NEW.status = 'pending' THEN 'warning'
        ELSE 'info' END;
    
    INSERT INTO notifications (tenant_id, user_id, title, body, type, source_type, source_id, metadata)
    VALUES (
        NEW.company_id,
        NEW.created_by,
        'فاتورة مشتريات ' || v_invoice_num || ' — ' || status_ar || ' | Purchase Invoice ' || v_invoice_num || ' — ' || status_en,
        'حالة فاتورة المشتريات تغيرت إلى: ' || status_ar || ' | Purchase invoice status changed to: ' || status_en,
        notif_type,
        'purchase_invoice',
        NEW.id,
        jsonb_build_object(
            'invoice_number', v_invoice_num,
            'old_status', OLD.status,
            'new_status', NEW.status,
            'status_label_ar', status_ar,
            'status_label_en', status_en
        )
    );
    
    RETURN NEW;
END;
$$;


