--
-- Name: fn_transfer_status_notification(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.fn_transfer_status_notification() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_transfer_number TEXT;
    v_from_wh_name TEXT;
    v_to_wh_name TEXT;
    v_creator UUID;
    v_title TEXT;
    v_body TEXT;
    v_driver_info TEXT;
    v_tracking TEXT;
    v_keeper RECORD;
BEGIN
    IF OLD.status IS NOT DISTINCT FROM NEW.status THEN RETURN NEW; END IF;

    v_transfer_number := COALESCE(NEW.transfer_number, NEW.id::TEXT);
    v_creator := NEW.created_by;

    SELECT COALESCE(name_ar, name_en, 'مستودع') INTO v_from_wh_name
    FROM warehouses WHERE id = NEW.from_warehouse_id;

    SELECT COALESCE(name_ar, name_en, 'مستودع') INTO v_to_wh_name
    FROM warehouses WHERE id = NEW.to_warehouse_id;

    -- Build shipping info
    v_driver_info := '';
    v_tracking := '';
    IF NEW.status = 'shipped' THEN
        IF NEW.shipping_method = 'company_driver' AND NEW.driver_name IS NOT NULL THEN
            v_driver_info := ' | السائق: ' || NEW.driver_name;
            IF NEW.vehicle_number IS NOT NULL THEN
                v_driver_info := v_driver_info || ' (' || NEW.vehicle_number || ')';
            END IF;
        ELSIF NEW.shipping_method = 'external_truck' AND NEW.driver_name IS NOT NULL THEN
            v_driver_info := ' | سائق خارجي: ' || NEW.driver_name;
        ELSIF NEW.shipping_method = 'shipping_company' AND NEW.shipping_carrier IS NOT NULL THEN
            v_driver_info := ' | شركة شحن: ' || NEW.shipping_carrier;
        END IF;
        IF NEW.tracking_number IS NOT NULL THEN
            v_tracking := ' | رقم التتبع: ' || NEW.tracking_number;
        END IF;
    END IF;

    -- ══════════════════════════════════════════════════
    -- 1. confirmed → إشعار لكل أمناء المستودع المصدر
    -- ══════════════════════════════════════════════════
    IF NEW.status = 'confirmed' THEN
        FOR v_keeper IN
            SELECT user_id FROM warehouse_keepers 
            WHERE warehouse_id = NEW.from_warehouse_id
        LOOP
            INSERT INTO notifications (tenant_id, user_id, title, body, type, source_type, source_id, metadata)
            VALUES (
                NEW.tenant_id, v_keeper.user_id,
                '📋 مناقلة جديدة — ' || v_transfer_number,
                'طلب مناقلة من ' || v_from_wh_name || ' إلى ' || v_to_wh_name || ' — الرجاء تجهيز البضاعة وبدء التحميل',
                'info', 'stock_transfer', NEW.id,
                jsonb_build_object(
                    'transfer_number', v_transfer_number,
                    'from_warehouse', v_from_wh_name,
                    'to_warehouse', v_to_wh_name,
                    'status', 'confirmed',
                    'action', 'prepare_and_load'
                )
            );
        END LOOP;
    END IF;

    -- ══════════════════════════════════════════════════
    -- 2. shipped → إشعار لكل أمناء المستودع الوجهة
    -- ══════════════════════════════════════════════════
    IF NEW.status = 'shipped' THEN
        FOR v_keeper IN
            SELECT user_id FROM warehouse_keepers 
            WHERE warehouse_id = NEW.to_warehouse_id
        LOOP
            INSERT INTO notifications (tenant_id, user_id, title, body, type, source_type, source_id, metadata)
            VALUES (
                NEW.tenant_id, v_keeper.user_id,
                '🚚 شحنة في الطريق — ' || v_transfer_number,
                'تم شحن بضاعة من ' || v_from_wh_name || ' إلى ' || v_to_wh_name 
                    || ' — الرجاء الاستعداد للاستلام' || v_driver_info || v_tracking,
                'warning', 'stock_transfer', NEW.id,
                jsonb_build_object(
                    'transfer_number', v_transfer_number,
                    'from_warehouse', v_from_wh_name,
                    'to_warehouse', v_to_wh_name,
                    'status', 'shipped',
                    'action', 'receive_goods',
                    'shipping_method', NEW.shipping_method,
                    'driver_name', NEW.driver_name,
                    'vehicle_number', NEW.vehicle_number,
                    'tracking_number', NEW.tracking_number,
                    'shipping_carrier', NEW.shipping_carrier
                )
            );
        END LOOP;
    END IF;

    -- ══════════════════════════════════════════════════
    -- 3. received/completed → إشعار لمُنشئ المناقلة
    -- ══════════════════════════════════════════════════
    IF NEW.status IN ('received', 'completed') AND v_creator IS NOT NULL THEN
        INSERT INTO notifications (tenant_id, user_id, title, body, type, source_type, source_id, metadata)
        VALUES (
            NEW.tenant_id, v_creator,
            '✅ مناقلة مكتملة — ' || v_transfer_number,
            'تم استلام المناقلة من ' || v_from_wh_name || ' في ' || v_to_wh_name || ' — المناقلة مكتملة بنجاح',
            'success', 'stock_transfer', NEW.id,
            jsonb_build_object(
                'transfer_number', v_transfer_number,
                'from_warehouse', v_from_wh_name,
                'to_warehouse', v_to_wh_name,
                'status', NEW.status,
                'action', 'completed'
            )
        );
    END IF;

    -- ══════════════════════════════════════════════════
    -- 4. cancelled → إشعار لمُنشئ المناقلة
    -- ══════════════════════════════════════════════════
    IF NEW.status = 'cancelled' AND v_creator IS NOT NULL THEN
        INSERT INTO notifications (tenant_id, user_id, title, body, type, source_type, source_id, metadata)
        VALUES (
            NEW.tenant_id, v_creator,
            '❌ مناقلة ملغاة — ' || v_transfer_number,
            'تم إلغاء المناقلة من ' || v_from_wh_name || ' إلى ' || v_to_wh_name,
            'error', 'stock_transfer', NEW.id,
            jsonb_build_object(
                'transfer_number', v_transfer_number,
                'from_warehouse', v_from_wh_name,
                'to_warehouse', v_to_wh_name,
                'status', 'cancelled',
                'action', 'cancelled'
            )
        );
    END IF;

    RETURN NEW;
END;
$$;


--
-- Name: generate_customer_code(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.generate_customer_code(p_tenant_id uuid) RETURNS character varying
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_count INT;
    v_code VARCHAR;
BEGIN
    -- عد العملاء الموجودين
    SELECT COUNT(*) INTO v_count 
    FROM customers 
    WHERE tenant_id = p_tenant_id;
    
    -- توليد الكود
    v_code := 'CUST-' || LPAD((v_count + 1)::TEXT, 5, '0');
    
    -- التأكد من عدم التكرار
    WHILE EXISTS (SELECT 1 FROM customers WHERE code = v_code AND tenant_id = p_tenant_id) LOOP
        v_code := 'CUST-' || LPAD(FLOOR(RANDOM() * 99999)::TEXT, 5, '0');
    END LOOP;
    
    RETURN v_code;
END;
$$;


--
-- Name: FUNCTION generate_customer_code(p_tenant_id uuid); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION public.generate_customer_code(p_tenant_id uuid) IS 'توليد كود عميل فريد (CUST-XXXXX)';


--
-- Name: generate_delivery_note_number(uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.generate_delivery_note_number(p_tenant_id uuid, p_company_id uuid) RETURNS character varying
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_prefix VARCHAR(10) := 'DN';
    v_year VARCHAR(4) := TO_CHAR(CURRENT_DATE, 'YYYY');
    v_sequence INT;
    v_number VARCHAR(50);
BEGIN
    SELECT COALESCE(MAX(
        CAST(NULLIF(REGEXP_REPLACE(note_number, '[^0-9]', '', 'g'), '') AS INT)
    ), 0) + 1 INTO v_sequence
    FROM delivery_notes
    WHERE tenant_id = p_tenant_id
    AND EXTRACT(YEAR FROM note_date) = EXTRACT(YEAR FROM CURRENT_DATE);
    
    v_number := v_prefix || '-' || v_year || '-' || LPAD(v_sequence::TEXT, 6, '0');
    
    RETURN v_number;
END;
$$;


--
-- Name: generate_employee_number(uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.generate_employee_number(p_tenant_id uuid, p_company_id uuid DEFAULT NULL::uuid) RETURNS text
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_prefix TEXT;
    v_counter INTEGER;
    v_number TEXT;
BEGIN
    SELECT employee_number_prefix, employee_number_counter
    INTO v_prefix, v_counter
    FROM hr_settings
    WHERE tenant_id = p_tenant_id 
    AND (company_id = p_company_id OR (company_id IS NULL AND p_company_id IS NULL))
    LIMIT 1;
    
    v_prefix := COALESCE(v_prefix, 'EMP');
    v_counter := COALESCE(v_counter, 1);
    
    v_number := v_prefix || '-' || LPAD(v_counter::TEXT, 4, '0');
    
    -- تحديث العداد
    UPDATE hr_settings SET employee_number_counter = v_counter + 1
    WHERE tenant_id = p_tenant_id 
    AND (company_id = p_company_id OR (company_id IS NULL AND p_company_id IS NULL));
    
    -- إذا لم يوجد سجل إعدادات، أنشئه
    IF NOT FOUND THEN
        INSERT INTO hr_settings (tenant_id, company_id, employee_number_counter)
        VALUES (p_tenant_id, p_company_id, 2);
    END IF;
    
    RETURN v_number;
END;
$$;


--
-- Name: generate_entry_number(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.generate_entry_number() RETURNS trigger
    LANGUAGE plpgsql
    AS $_$
DECLARE
    v_max_number INTEGER;
    v_year INTEGER;
    v_prefix VARCHAR(10);
BEGIN
    -- Skip if entry_number already provided
    IF NEW.entry_number IS NOT NULL THEN
        RETURN NEW;
    END IF;
    
    -- Get year from entry_date
    v_year := EXTRACT(YEAR FROM NEW.entry_date);
    
    -- Get max entry number for this company and year
    SELECT COALESCE(
        MAX(
            CASE 
                WHEN entry_number ~ '^\d+/\d{4}$' 
                THEN SPLIT_PART(entry_number, '/', 1)::INTEGER
                ELSE 0
            END
        ), 
        0
    ) INTO v_max_number
    FROM journal_entries
    WHERE company_id = NEW.company_id
      AND EXTRACT(YEAR FROM entry_date) = v_year;
    
    -- Generate new entry number
    NEW.entry_number := (v_max_number + 1)::TEXT || '/' || v_year::TEXT;
    
    RETURN NEW;
END;
$_$;


--
-- Name: FUNCTION generate_entry_number(); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION public.generate_entry_number() IS 'Auto-generates entry_number in format: number/year (e.g., 1/2026, 2/2026)';


--
-- Name: generate_order_number(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.generate_order_number() RETURNS text
    LANGUAGE plpgsql
    AS $$
DECLARE
  new_num TEXT;
  seq_val INT;
BEGIN
  SELECT COALESCE(MAX(
    CAST(NULLIF(regexp_replace(order_number, '[^0-9]', '', 'g'), '') AS INT)
  ), 10000) + 1
  INTO seq_val
  FROM ecommerce_orders;
  new_num := 'TXO-' || seq_val;
  RETURN new_num;
END;
$$;


--
-- Name: generate_order_number(uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.generate_order_number(p_tenant_id uuid, p_company_id uuid DEFAULT NULL::uuid) RETURNS character varying
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_count INT;
    v_order_number VARCHAR;
    v_date_part VARCHAR;
BEGIN
    -- تنسيق التاريخ: YYYYMMDD
    v_date_part := TO_CHAR(NOW(), 'YYYYMMDD');
    
    -- عدد الطلبات اليوم
    SELECT COUNT(*) INTO v_count
    FROM orders
    WHERE tenant_id = p_tenant_id
      AND (p_company_id IS NULL OR company_id = p_company_id)
      AND DATE(created_at) = CURRENT_DATE;
    
    -- رقم الطلب: ORD-YYYYMMDD-XXXX
    v_order_number := 'ORD-' || v_date_part || '-' || LPAD((v_count + 1)::TEXT, 4, '0');
    
    RETURN v_order_number;
END;
$$;


--
-- Name: FUNCTION generate_order_number(p_tenant_id uuid, p_company_id uuid); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION public.generate_order_number(p_tenant_id uuid, p_company_id uuid) IS 'توليد رقم طلب فريد';


--
-- Name: generate_payment_number(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.generate_payment_number() RETURNS character varying
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_number VARCHAR;
    v_year VARCHAR;
    v_month VARCHAR;
BEGIN
    v_year := TO_CHAR(NOW(), 'YY');
    v_month := TO_CHAR(NOW(), 'MM');
    v_number := 'PAY-' || v_year || v_month || '-' || LPAD(nextval('saas_payment_number_seq')::TEXT, 5, '0');
    RETURN v_number;
END;
$$;


--
-- Name: generate_recurring_entries(uuid, date, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.generate_recurring_entries(p_company_id uuid DEFAULT NULL::uuid, p_as_of_date date DEFAULT CURRENT_DATE, p_user_id uuid DEFAULT NULL::uuid) RETURNS integer
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_template RECORD;
    v_line RECORD;
    v_entry_id UUID;
    v_entry_number VARCHAR(50);
    v_entries_created INT := 0;
    v_fiscal_year_id UUID;
    v_line_number INT;
BEGIN
    FOR v_template IN 
        SELECT * FROM recurring_entry_templates
        WHERE is_active = true
          AND (p_company_id IS NULL OR company_id = p_company_id)
          AND next_execution_date <= p_as_of_date
          AND (end_date IS NULL OR next_execution_date <= end_date)
          AND (max_executions IS NULL OR execution_count < max_executions)
        ORDER BY next_execution_date
    LOOP
        BEGIN
            SELECT id INTO v_fiscal_year_id
            FROM fiscal_years
            WHERE company_id = v_template.company_id
              AND is_current = true
            LIMIT 1;
            
            v_entry_number := 'JE-RC-' || v_template.template_code || '-' || TO_CHAR(v_template.next_execution_date, 'YYYYMMDD');
            
            INSERT INTO journal_entries (
                tenant_id, company_id, entry_number, entry_date,
                fiscal_year_id, entry_type,
                reference_type, reference_id, reference_number,
                description, currency,
                total_debit, total_credit,
                status, is_posted, posted_at,
                created_by, created_at
            )
            VALUES (
                v_template.tenant_id, v_template.company_id,
                v_entry_number, v_template.next_execution_date,
                v_fiscal_year_id, 'recurring',
                'recurring_template', v_template.id, v_template.template_code,
                v_template.template_name || ' - ' || TO_CHAR(v_template.next_execution_date, 'YYYY-MM-DD'),
                v_template.currency,
                v_template.total_amount, v_template.total_amount,
                CASE WHEN v_template.auto_post THEN 'posted' ELSE 'draft' END,
                v_template.auto_post,
                CASE WHEN v_template.auto_post THEN NOW() ELSE NULL END,
                p_user_id, NOW()
            )
            RETURNING id INTO v_entry_id;
            
            v_line_number := 1;
            FOR v_line IN 
                SELECT * FROM recurring_entry_lines
                WHERE template_id = v_template.id
                ORDER BY line_number
            LOOP
                INSERT INTO journal_entry_lines (
                    tenant_id, entry_id, line_number, account_id,
                    debit, credit, description, cost_center_id
                )
                VALUES (
                    v_template.tenant_id, v_entry_id, v_line_number,
                    v_line.account_id,
                    CASE WHEN v_line.is_percentage THEN v_template.total_amount * v_line.percentage / 100 ELSE v_line.debit END,
                    CASE WHEN v_line.is_percentage THEN v_template.total_amount * v_line.percentage / 100 ELSE v_line.credit END,
                    COALESCE(v_line.description, v_template.template_name),
                    v_line.cost_center_id
                );
                v_line_number := v_line_number + 1;
            END LOOP;
            
            INSERT INTO recurring_entry_executions (
                tenant_id, template_id, journal_entry_id,
                execution_date, scheduled_date, status,
                executed_by, executed_at
            )
            VALUES (
                v_template.tenant_id, v_template.id, v_entry_id,
                p_as_of_date, v_template.next_execution_date, 'success',
                p_user_id, NOW()
            );
            
            UPDATE recurring_entry_templates
            SET last_execution_date = next_execution_date,
                next_execution_date = calculate_next_execution_date(
                    frequency, next_execution_date, day_of_week, day_of_month, month_of_year
                ),
                execution_count = execution_count + 1,
                updated_at = NOW()
            WHERE id = v_template.id;
            
            v_entries_created := v_entries_created + 1;
            
        EXCEPTION WHEN OTHERS THEN
            INSERT INTO recurring_entry_executions (
                tenant_id, template_id, execution_date, scheduled_date,
                status, error_message, executed_at
            )
            VALUES (
                v_template.tenant_id, v_template.id,
                p_as_of_date, v_template.next_execution_date,
                'failed', SQLERRM, NOW()
            );
        END;
    END LOOP;
    
    RETURN v_entries_created;
END;
$$;


--
-- Name: generate_sequence_number(uuid, uuid, character varying); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.generate_sequence_number(p_tenant_id uuid, p_company_id uuid, p_sequence_type character varying) RETURNS text
    LANGUAGE plpgsql
    AS $_$
DECLARE
    v_prefix TEXT;
    v_next_number INT;
    v_formatted_number TEXT;
    v_year TEXT;
    v_month TEXT;
BEGIN
    -- Get current year and month
    v_year := TO_CHAR(CURRENT_DATE, 'YYYY');
    v_month := TO_CHAR(CURRENT_DATE, 'MM');
    
    -- Set prefix based on sequence type
    CASE p_sequence_type
        WHEN 'journal_entry' THEN v_prefix := 'JE';
        WHEN 'receipt' THEN v_prefix := 'RC';
        WHEN 'payment' THEN v_prefix := 'PY';
        WHEN 'cash_journal' THEN v_prefix := 'CJ';
        ELSE v_prefix := 'DOC';
    END CASE;
    
    -- Get next number for this company and type
    SELECT COALESCE(MAX(
        CAST(
            SUBSTRING(entry_number FROM '[0-9]+$') AS INT
        )
    ), 0) + 1
    INTO v_next_number
    FROM journal_entries
    WHERE tenant_id = p_tenant_id
        AND company_id = p_company_id
        AND entry_number LIKE v_prefix || '-' || v_year || '%';
    
    -- Format: JE-2026-00001
    v_formatted_number := v_prefix || '-' || v_year || '-' || LPAD(v_next_number::TEXT, 5, '0');
    
    RETURN v_formatted_number;
END;
$_$;


--
-- Name: generate_stage_number(uuid, uuid, text, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.generate_stage_number(p_tenant_id uuid, p_company_id uuid, p_doc_type text, p_stage text) RETURNS text
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_prefix TEXT;
    v_year INTEGER := EXTRACT(YEAR FROM CURRENT_DATE);
    v_next INTEGER;
BEGIN
    v_prefix := CASE
        WHEN p_doc_type = 'purchase' AND p_stage = 'quotation' THEN 'PQ'
        WHEN p_doc_type = 'purchase' AND p_stage = 'order' THEN 'PO'
        WHEN p_doc_type = 'purchase' AND p_stage = 'receipt' THEN 'PR'
        WHEN p_doc_type = 'purchase' AND p_stage = 'invoice' THEN 'PI'
        WHEN p_doc_type = 'sale' AND p_stage = 'quotation' THEN 'SQ'
        WHEN p_doc_type = 'sale' AND p_stage = 'reservation' THEN 'SR'
        WHEN p_doc_type = 'sale' AND p_stage = 'order' THEN 'SO'
        WHEN p_doc_type = 'sale' AND p_stage = 'delivery' THEN 'SD'
        WHEN p_doc_type = 'sale' AND p_stage = 'invoice' THEN 'SI'
        ELSE 'DOC'
    END;

    INSERT INTO document_sequences (tenant_id, company_id, doc_type, stage, year, prefix, next_number)
    VALUES (p_tenant_id, p_company_id, p_doc_type, p_stage, v_year, v_prefix, 1)
    ON CONFLICT (tenant_id, company_id, doc_type, stage, year) DO NOTHING;

    UPDATE document_sequences
    SET next_number = next_number + 1, updated_at = NOW()
    WHERE tenant_id = p_tenant_id
      AND company_id = p_company_id
      AND doc_type = p_doc_type
      AND stage = p_stage
      AND year = v_year
    RETURNING prefix, next_number - 1 INTO v_prefix, v_next;

    RETURN v_prefix || '-' || v_year || '-' || LPAD(v_next::TEXT, 4, '0');
END;
$$;


--
-- Name: get_account_balance(uuid, date); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_account_balance(p_account_id uuid, p_as_of_date date DEFAULT CURRENT_DATE) RETURNS numeric
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_balance DECIMAL(15, 2);
BEGIN
    SELECT COALESCE(SUM(jel.debit - jel.credit), 0) INTO v_balance
    FROM journal_entry_lines jel
    INNER JOIN journal_entries je ON jel.journal_entry_id = je.id
    WHERE jel.account_id = p_account_id
      AND je.entry_date <= p_as_of_date;
    
    RETURN v_balance;
END;
$$;


