-- Name: FUNCTION get_account_balance(p_account_id uuid, p_as_of_date date); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION public.get_account_balance(p_account_id uuid, p_as_of_date date) IS 'Get account balance as of a specific date';


