-- Name: get_admin_statistics(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_admin_statistics() RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_stats JSONB;
BEGIN
    SELECT jsonb_build_object(
        'total_tenants', (SELECT COUNT(*) FROM tenants),
        'active_tenants', (SELECT COUNT(*) FROM tenants WHERE status = 'active'),
        'total_companies', (SELECT COUNT(*) FROM companies),
        'total_users', (SELECT COUNT(*) FROM user_profiles)
    ) INTO v_stats;
    
    RETURN v_stats;
END;
$$;


--
-- Name: get_allowed_tabs(uuid, character varying); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_allowed_tabs(p_tenant_id uuid, p_section_code character varying) RETURNS jsonb
    LANGUAGE plpgsql STABLE SECURITY DEFINER
    AS $$
DECLARE
    v_plan_id UUID;
    v_plan_code VARCHAR(50);
    v_tabs JSONB;
BEGIN
    -- الحصول على plan_id و plan_code
    SELECT s.plan_id, sp.code INTO v_plan_id, v_plan_code
    FROM subscriptions s
    JOIN subscription_plans sp ON sp.id = s.plan_id
    WHERE s.tenant_id = p_tenant_id
    AND s.status = 'active'
    ORDER BY s.created_at DESC
    LIMIT 1;
    
    -- إرجاع التبويبات المتاحة
    SELECT jsonb_agg(
        jsonb_build_object(
            'code', tab_code,
            'name_ar', tab_name_ar,
            'name_en', tab_name_en,
            'icon', icon,
            'order', display_order,
            'is_core', is_core
        )
        ORDER BY display_order
    ) INTO v_tabs
    FROM ui_tabs
    WHERE section_code = p_section_code
    AND is_active = true
    AND (
        -- التبويبات الأساسية
        is_core = true
        OR
        -- التبويبات بدون شروط
        (required_feature_code IS NULL AND min_plan_level IS NULL)
        OR
        -- التبويبات بشرط الباقة فقط
        (
            required_feature_code IS NULL 
            AND min_plan_level IS NOT NULL
            AND CASE v_plan_code
                WHEN 'starter' THEN min_plan_level = 'starter'
                WHEN 'professional' THEN min_plan_level IN ('starter', 'professional')
                WHEN 'enterprise' THEN true
                ELSE false
            END
        )
        OR
        -- التبويبات بشرط الميزة
        (
            required_feature_code IS NOT NULL
            AND EXISTS (
                SELECT 1 FROM plan_module_features pmf
                WHERE pmf.plan_id = v_plan_id
                AND pmf.feature_code = required_feature_code
                AND pmf.is_enabled = true
            )
        )
    );
    
    RETURN COALESCE(v_tabs, '[]'::jsonb);
END;
$$;


--
-- Name: get_available_categories_for_customer(uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_available_categories_for_customer(p_tenant_id uuid, p_customer_id uuid DEFAULT NULL::uuid) RETURNS TABLE(id uuid, code character varying, name_ar character varying, name_en character varying, description text, image_url text, slug character varying, parent_id uuid, display_order integer, products_count bigint)
    LANGUAGE plpgsql STABLE SECURITY DEFINER
    AS $$
BEGIN
    -- نسخة بسيطة - ترجع جميع الفئات (استعلام ديناميكي آمن)
    RETURN QUERY
    SELECT 
        pc.id,
        COALESCE(pc.code, '') as code,
        COALESCE(pc.name_en, '') as name_ar,
        COALESCE(pc.name_en, '') as name_en,
        ''::TEXT as description,
        NULL::TEXT as image_url,
        NULL::VARCHAR as slug,
        pc.parent_id,
        0 as display_order,
        0::BIGINT as products_count
    FROM product_categories pc
    ORDER BY pc.name_en;
END;
$$;


--
-- Name: get_available_mfa_methods(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_available_mfa_methods() RETURNS TABLE(method character varying, is_available boolean)
    LANGUAGE plpgsql STABLE SECURITY DEFINER
    AS $$
DECLARE
    v_totp BOOLEAN;
    v_email BOOLEAN;
    v_sms BOOLEAN;
BEGIN
    SELECT allow_totp, allow_email_otp, allow_sms_otp 
    INTO v_totp, v_email, v_sms
    FROM mfa_system_settings LIMIT 1;
    
    method := 'totp'; is_available := COALESCE(v_totp, true); RETURN NEXT;
    method := 'email'; is_available := COALESCE(v_email, true); RETURN NEXT;
    method := 'sms'; is_available := COALESCE(v_sms, false); RETURN NEXT;
END;
$$;


--
-- Name: get_available_reports(character varying); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_available_reports(p_category character varying DEFAULT NULL::character varying) RETURNS TABLE(id uuid, code character varying, name_ar character varying, name_en character varying, category character varying, description text, is_system boolean, use_count integer, last_used_at timestamp with time zone)
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
BEGIN
    RETURN QUERY
    SELECT 
        rt.id, rt.code, rt.name_ar, rt.name_en,
        rt.category, rt.description, rt.is_system,
        rt.use_count, rt.last_used_at
    FROM report_templates rt
    WHERE rt.is_active = true
      AND (p_category IS NULL OR rt.category = p_category)
    ORDER BY rt.is_system DESC, rt.use_count DESC, rt.name_ar;
END;
$$;


