-- Name: FUNCTION get_available_reports(p_category character varying); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION public.get_available_reports(p_category character varying) IS 'الحصول على قائمة التقارير المتاحة';


