-- Name: get_brand_tenant_ids(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_brand_tenant_ids(p_product_id uuid) RETURNS uuid[]
    LANGUAGE plpgsql STABLE SECURITY DEFINER
    AS $$
DECLARE
    v_tenant_ids UUID[];
BEGIN
    SELECT ARRAY_AGG(id)
    INTO v_tenant_ids
    FROM public.tenants
    WHERE product_id = p_product_id
      AND status = 'active';
    
    RETURN COALESCE(v_tenant_ids, ARRAY[]::UUID[]);
EXCEPTION WHEN OTHERS THEN
    RETURN ARRAY[]::UUID[];
END;
$$;


--
-- Name: get_budget_vs_actual_report(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_budget_vs_actual_report(p_budget_id uuid) RETURNS TABLE(account_code character varying, account_name character varying, period character varying, budgeted numeric, actual numeric, variance numeric, variance_percent numeric, status character varying)
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
BEGIN
    RETURN QUERY
    SELECT 
        coa.account_code,
        coa.name_ar as account_name,
        bl.period,
        bl.budgeted_amount as budgeted,
        bl.actual_amount as actual,
        bl.variance,
        bl.variance_percent,
        CASE 
            WHEN bl.actual_amount >= bl.budgeted_amount * 1.2 THEN 'critical'
            WHEN bl.actual_amount >= bl.budgeted_amount THEN 'exceeded'
            WHEN bl.actual_amount >= bl.budgeted_amount * 0.9 THEN 'warning'
            ELSE 'ok'
        END as status
    FROM budget_lines bl
    JOIN chart_of_accounts coa ON bl.account_id = coa.id
    WHERE bl.budget_id = p_budget_id
    ORDER BY coa.account_code, bl.period;
END;
$$;


--
-- Name: FUNCTION get_budget_vs_actual_report(p_budget_id uuid); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION public.get_budget_vs_actual_report(p_budget_id uuid) IS 'تقرير مقارنة الموازنة بالفعلي';


--
-- Name: get_cart(uuid, uuid, character varying); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_cart(p_tenant_id uuid, p_customer_id uuid DEFAULT NULL::uuid, p_session_id character varying DEFAULT NULL::character varying) RETURNS TABLE(cart_id uuid, item_id uuid, product_id uuid, product_code character varying, product_name_ar character varying, product_name_en character varying, product_image text, variant_id uuid, quantity numeric, unit_price numeric, original_price numeric, discount_percent numeric, subtotal numeric, notes text, available_quantity numeric, in_stock boolean, price_changed boolean)
    LANGUAGE plpgsql STABLE SECURITY DEFINER
    AS $$
DECLARE
    v_cart_id UUID;
BEGIN
    -- الحصول على السلة
    IF p_customer_id IS NOT NULL THEN
        SELECT id INTO v_cart_id
        FROM shopping_carts
        WHERE tenant_id = p_tenant_id
          AND customer_id = p_customer_id
          AND status = 'active'
        LIMIT 1;
    ELSIF p_session_id IS NOT NULL THEN
        SELECT id INTO v_cart_id
        FROM shopping_carts
        WHERE tenant_id = p_tenant_id
          AND session_id = p_session_id
          AND status = 'active'
        LIMIT 1;
    END IF;
    
    IF v_cart_id IS NULL THEN
        RETURN;
    END IF;
    
    -- إرجاع العناصر
    RETURN QUERY
    SELECT 
        sci.cart_id,
        sci.id,
        sci.product_id,
        p.sku,
        p.name_ar,
        p.name_en,
        get_product_primary_image(p.id),
        sci.product_variant_id,
        sci.quantity,
        sci.unit_price,
        sci.original_price,
        sci.discount_percent,
        sci.subtotal,
        sci.notes,
        COALESCE(
            (SELECT SUM(quantity_on_hand) 
             FROM inventory_stock 
             WHERE product_id = p.id),
            0
        ) as available_quantity,
        CASE 
            WHEN COALESCE(
                (SELECT SUM(quantity_on_hand) 
                 FROM inventory_stock 
                 WHERE product_id = p.id),
                0
            ) >= sci.quantity THEN true
            ELSE false
        END as in_stock,
        sci.price_changed
    FROM shopping_cart_items sci
    JOIN products p ON p.id = sci.product_id
    WHERE sci.cart_id = v_cart_id
    ORDER BY sci.created_at;
END;
$$;


--
-- Name: FUNCTION get_cart(p_tenant_id uuid, p_customer_id uuid, p_session_id character varying); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION public.get_cart(p_tenant_id uuid, p_customer_id uuid, p_session_id character varying) IS 'جلب محتويات السلة الكاملة';


--
-- Name: get_cart_summary(uuid, uuid, character varying); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_cart_summary(p_tenant_id uuid, p_customer_id uuid DEFAULT NULL::uuid, p_session_id character varying DEFAULT NULL::character varying) RETURNS jsonb
    LANGUAGE plpgsql STABLE SECURITY DEFINER
    AS $$
DECLARE
    v_cart_id UUID;
    v_summary JSONB;
BEGIN
    -- الحصول على السلة
    IF p_customer_id IS NOT NULL THEN
        SELECT id INTO v_cart_id
        FROM shopping_carts
        WHERE tenant_id = p_tenant_id
          AND customer_id = p_customer_id
          AND status = 'active'
        LIMIT 1;
    ELSIF p_session_id IS NOT NULL THEN
        SELECT id INTO v_cart_id
        FROM shopping_carts
        WHERE tenant_id = p_tenant_id
          AND session_id = p_session_id
          AND status = 'active'
        LIMIT 1;
    END IF;
    
    IF v_cart_id IS NULL THEN
        RETURN jsonb_build_object(
            'cart_exists', false,
            'items_count', 0,
            'subtotal', 0,
            'total', 0
        );
    END IF;
    
    -- بناء الملخص
    SELECT jsonb_build_object(
        'cart_exists', true,
        'cart_id', sc.id,
        'items_count', (SELECT COUNT(*) FROM shopping_cart_items WHERE cart_id = sc.id),
        'total_quantity', (SELECT SUM(quantity) FROM shopping_cart_items WHERE cart_id = sc.id),
        'subtotal', sc.subtotal,
        'discount', sc.promo_discount,
        'total', sc.total_amount,
        'currency', sc.currency,
        'promo_code', sc.promo_code,
        'updated_at', sc.updated_at
    )
    INTO v_summary
    FROM shopping_carts sc
    WHERE sc.id = v_cart_id;
    
    RETURN v_summary;
END;
$$;


--
-- Name: FUNCTION get_cart_summary(p_tenant_id uuid, p_customer_id uuid, p_session_id character varying); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION public.get_cart_summary(p_tenant_id uuid, p_customer_id uuid, p_session_id character varying) IS 'ملخص السلة (عدد العناصر والمجاميع)';


