--
-- Name: get_company_rounding_settings(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_company_rounding_settings(p_company_id uuid) RETURNS TABLE(rounding_method character varying, tax_rounding integer, amount_rounding integer, unit_price_rounding integer, total_rounding integer)
    LANGUAGE plpgsql STABLE
    AS $$
BEGIN
    RETURN QUERY
    SELECT
        COALESCE(
            CASE WHEN c.inherit_country_rounding THEN co.rounding_method ELSE c.rounding_method END,
            'half_up'
        )::VARCHAR(10),
        COALESCE(
            CASE WHEN c.inherit_country_rounding THEN co.tax_rounding ELSE c.tax_rounding END,
            2
        )::INT,
        COALESCE(
            CASE WHEN c.inherit_country_rounding THEN co.amount_rounding ELSE c.amount_rounding END,
            2
        )::INT,
        COALESCE(
            CASE WHEN c.inherit_country_rounding THEN co.unit_price_rounding ELSE c.unit_price_rounding END,
            2
        )::INT,
        COALESCE(
            CASE WHEN c.inherit_country_rounding THEN co.total_rounding ELSE c.total_rounding END,
            2
        )::INT
    FROM companies c
    LEFT JOIN company_countries cc ON cc.company_id = c.id AND cc.is_primary = true
    LEFT JOIN countries co ON co.code = cc.country_code
    WHERE c.id = p_company_id;
END;
$$;


--
-- Name: get_cost_center_expenses(uuid, date, date); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_cost_center_expenses(p_cost_center_id uuid, p_start_date date DEFAULT NULL::date, p_end_date date DEFAULT NULL::date) RETURNS TABLE(entry_date date, entry_number character varying, account_name character varying, description text, debit numeric, credit numeric, running_total numeric)
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
BEGIN
    RETURN QUERY
    SELECT 
        je.entry_date,
        je.entry_number,
        coa.name_ar as account_name,
        jel.description,
        jel.debit,
        jel.credit,
        SUM(jel.debit - jel.credit) OVER (ORDER BY je.entry_date, je.entry_number) as running_total
    FROM journal_entry_lines jel
    JOIN journal_entries je ON jel.entry_id = je.id
    JOIN chart_of_accounts coa ON jel.account_id = coa.id
    WHERE jel.cost_center_id = p_cost_center_id
      AND je.is_posted = true
      AND (p_start_date IS NULL OR je.entry_date >= p_start_date)
      AND (p_end_date IS NULL OR je.entry_date <= p_end_date)
    ORDER BY je.entry_date, je.entry_number, jel.line_number;
END;
$$;


--
-- Name: FUNCTION get_cost_center_expenses(p_cost_center_id uuid, p_start_date date, p_end_date date); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION public.get_cost_center_expenses(p_cost_center_id uuid, p_start_date date, p_end_date date) IS 'تفاصيل مصاريف مركز تكلفة محدد';


--
-- Name: get_cost_centers_comparison(uuid, character varying); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_cost_centers_comparison(p_company_id uuid, p_period character varying DEFAULT 'current_year'::character varying) RETURNS TABLE(cost_center_id uuid, code character varying, name character varying, parent_name character varying, total_expenses numeric, budget_limit numeric, variance numeric, utilization_percent numeric)
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_start_date DATE;
    v_end_date DATE;
BEGIN
    -- تحديد الفترة
    CASE p_period
        WHEN 'current_month' THEN
            v_start_date := DATE_TRUNC('month', CURRENT_DATE);
            v_end_date := (DATE_TRUNC('month', CURRENT_DATE) + INTERVAL '1 month - 1 day')::DATE;
        WHEN 'current_quarter' THEN
            v_start_date := DATE_TRUNC('quarter', CURRENT_DATE);
            v_end_date := (DATE_TRUNC('quarter', CURRENT_DATE) + INTERVAL '3 months - 1 day')::DATE;
        ELSE -- current_year
            v_start_date := DATE_TRUNC('year', CURRENT_DATE);
            v_end_date := (DATE_TRUNC('year', CURRENT_DATE) + INTERVAL '1 year - 1 day')::DATE;
    END CASE;
    
    RETURN QUERY
    SELECT 
        cc.id as cost_center_id,
        cc.code,
        cc.name_ar as name,
        p.name_ar as parent_name,
        COALESCE(SUM(jel.debit), 0) as total_expenses,
        cc.budget_limit,
        cc.budget_limit - COALESCE(SUM(jel.debit), 0) as variance,
        CASE 
            WHEN cc.budget_limit > 0 THEN 
                ROUND((COALESCE(SUM(jel.debit), 0) / cc.budget_limit) * 100, 2)
            ELSE 0
        END as utilization_percent
    FROM cost_centers cc
    LEFT JOIN cost_centers p ON cc.parent_id = p.id
    LEFT JOIN journal_entry_lines jel ON jel.cost_center_id = cc.id
    LEFT JOIN journal_entries je ON jel.entry_id = je.id 
        AND je.is_posted = true
        AND je.entry_date BETWEEN v_start_date AND v_end_date
    WHERE cc.company_id = p_company_id
      AND cc.is_active = true
      AND cc.is_group = false
    GROUP BY cc.id, cc.code, cc.name_ar, p.name_ar, cc.budget_limit
    ORDER BY total_expenses DESC;
END;
$$;


--
-- Name: FUNCTION get_cost_centers_comparison(p_company_id uuid, p_period character varying); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION public.get_cost_centers_comparison(p_company_id uuid, p_period character varying) IS 'مقارنة مراكز التكلفة مع الموازنة';


