--
-- Name: get_current_tenant(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_current_tenant() RETURNS jsonb
    LANGUAGE plpgsql STABLE SECURITY DEFINER
    AS $$
DECLARE
    v_tenant_id UUID;
    v_result JSONB;
BEGIN
    v_tenant_id := get_current_tenant_id();
    
    IF v_tenant_id IS NULL THEN
        RETURN NULL;
    END IF;
    
    SELECT jsonb_build_object(
        'id', t.id,
        'code', t.code,
        'name', t.name,
        'status', t.status,
        'default_language', t.default_language,
        'settings', t.settings
    ) INTO v_result
    FROM tenants t
    WHERE t.id = v_tenant_id;
    
    RETURN v_result;
END;
$$;


