-- Name: get_current_user_product_code(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_current_user_product_code() RETURNS character varying
    LANGUAGE plpgsql STABLE SECURITY DEFINER
    AS $$
DECLARE
    v_code VARCHAR;
BEGIN
    SELECT sp.code INTO v_code
    FROM user_profiles up
    JOIN tenants t ON up.tenant_id = t.id
    JOIN saas_products sp ON t.product_id = sp.id
    WHERE up.id = auth.uid();
    
    RETURN v_code;
END;
$$;


