    AS $$
DECLARE
    v_product_id UUID;
BEGIN
    SELECT t.product_id INTO v_product_id
    FROM user_profiles up
    JOIN tenants t ON up.tenant_id = t.id
    WHERE up.id = auth.uid();
    
    RETURN v_product_id;
END;
$$;


--
-- Name: get_current_user_tenant_id(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_current_user_tenant_id() RETURNS uuid
    LANGUAGE plpgsql STABLE SECURITY DEFINER
    AS $$
DECLARE
    v_tenant_id UUID;
BEGIN
    -- البحث عن tenant_id من user_profiles
    SELECT tenant_id INTO v_tenant_id
    FROM user_profiles
    WHERE id = auth.uid()
    LIMIT 1;
    
    -- إذا لم يوجد، تحقق من user_metadata
    IF v_tenant_id IS NULL THEN
        SELECT (raw_user_meta_data->>'tenant_id')::UUID INTO v_tenant_id
        FROM auth.users
        WHERE id = auth.uid();
    END IF;
    
    RETURN v_tenant_id;
END;
$$;


