--
-- Name: get_daily_stats(uuid, date); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_daily_stats(p_tenant_id uuid DEFAULT NULL::uuid, target_date date DEFAULT CURRENT_DATE) RETURNS json
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  result json;
  v_tenant_id UUID;
BEGIN
  -- Resolve tenant_id: parameter > official helper > NULL
  v_tenant_id := COALESCE(p_tenant_id, get_user_tenant_id());

  SELECT json_build_object(
    'total_entries', COUNT(*),
    'posted_entries', COUNT(CASE WHEN status = 'posted' THEN 1 END),
    'draft_entries', COUNT(CASE WHEN status = 'draft' THEN 1 END),
    'total_debit', COALESCE(SUM(total_debit), 0),
    'total_credit', COALESCE(SUM(total_credit), 0),
    'journal_count', COUNT(CASE WHEN entry_type = 'journal' THEN 1 END),
    'receipt_count', COUNT(CASE WHEN entry_type = 'receipt' THEN 1 END),
    'payment_count', COUNT(CASE WHEN entry_type = 'payment' THEN 1 END),
    'cash_count', COUNT(CASE WHEN entry_type = 'cash' THEN 1 END),
    'total_receipts', COALESCE(SUM(CASE WHEN entry_type = 'receipt' THEN total_credit END), 0),
    'total_payments', COALESCE(SUM(CASE WHEN entry_type = 'payment' THEN total_debit END), 0),
    'report_date', target_date,
    'tenant_id', v_tenant_id
  ) INTO result
  FROM journal_entries
  WHERE entry_date = target_date
    AND deleted_at IS NULL
    AND (v_tenant_id IS NULL OR tenant_id = v_tenant_id);
  
  RETURN result;
END;
$$;


--
-- Name: get_ecommerce_products(uuid, text, text, boolean, integer, integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_ecommerce_products(p_store_id uuid DEFAULT NULL::uuid, p_category_slug text DEFAULT NULL::text, p_search text DEFAULT NULL::text, p_featured_only boolean DEFAULT false, p_limit integer DEFAULT 20, p_offset integer DEFAULT 0) RETURNS SETOF json
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
BEGIN
  RETURN QUERY
  SELECT row_to_json(t) FROM (
    SELECT ep.id, ep.material_id, ep.marketing_title, ep.marketing_description,
      ep.short_description, ep.gallery_images, ep.seo_slug, ep.tags,
      ep.is_featured, ep.is_new, ep.is_bestseller, ep.is_on_sale,
      ep.sale_price, ep.sale_unit, ep.min_order_quantity,
      ep.view_count, ep.order_count, ep.published_at,
      fm.code AS material_code, fm.name_ar AS material_name_ar, fm.name_en AS material_name_en,
      fm.selling_price,
      COALESCE(ep.sale_price, fm.selling_price) AS effective_price,
      COALESCE(fm.currency, 'USD') AS currency,
      ARRAY(SELECT ec.slug FROM ecommerce_product_categories epc
        JOIN ecommerce_categories ec ON ec.id = epc.category_id
        WHERE epc.product_id = ep.id) AS category_slugs
    FROM ecommerce_products ep
    JOIN fabric_materials fm ON fm.id = ep.material_id
    WHERE ep.is_published = true
      AND (p_store_id IS NULL OR ep.store_id = p_store_id)
      AND (p_featured_only = false OR ep.is_featured = true)
      AND (p_category_slug IS NULL OR EXISTS(
        SELECT 1 FROM ecommerce_product_categories epc2
        JOIN ecommerce_categories ec2 ON ec2.id = epc2.category_id
        WHERE epc2.product_id = ep.id AND ec2.slug = p_category_slug))
      AND (p_search IS NULL OR fm.name_ar ILIKE '%' || p_search || '%'
        OR fm.name_en ILIKE '%' || p_search || '%'
        OR ep.seo_slug ILIKE '%' || p_search || '%')
    ORDER BY ep.is_featured DESC, ep.display_order, ep.created_at DESC
    LIMIT p_limit OFFSET p_offset
  ) t;
END; $$;


--
-- Name: get_employee_commission_report(uuid, date, date, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_employee_commission_report(p_company_id uuid, p_from_date date, p_to_date date, p_employee_id uuid DEFAULT NULL::uuid) RETURNS TABLE(employee_id uuid, employee_name character varying, total_sales numeric, total_commission numeric, total_bonus numeric, net_commission numeric, invoice_count integer, avg_commission_rate numeric, status_summary jsonb)
    LANGUAGE plpgsql
    AS $$
BEGIN
    RETURN QUERY
    SELECT 
        ec.employee_id,
        'موظف'::VARCHAR as employee_name,
        COALESCE(SUM(ec.base_amount), 0)::DECIMAL(15,2),
        COALESCE(SUM(ec.commission_amount), 0)::DECIMAL(15,2),
        COALESCE(SUM(ec.bonus_amount), 0)::DECIMAL(15,2),
        COALESCE(SUM(ec.net_amount), 0)::DECIMAL(15,2),
        COUNT(DISTINCT ec.source_id)::INT,
        CASE WHEN SUM(ec.base_amount) > 0 
            THEN (SUM(ec.commission_amount) / SUM(ec.base_amount) * 100)::DECIMAL(10,4)
            ELSE 0 END,
        jsonb_build_object(
            'calculated', COUNT(*) FILTER (WHERE ec.status = 'calculated'),
            'approved', COUNT(*) FILTER (WHERE ec.status = 'approved'),
            'paid', COUNT(*) FILTER (WHERE ec.status = 'paid'),
            'cancelled', COUNT(*) FILTER (WHERE ec.status = 'cancelled')
        )
    FROM employee_commissions ec
    WHERE ec.company_id = p_company_id
      AND ec.period_start >= p_from_date
      AND ec.period_end <= p_to_date
      AND (p_employee_id IS NULL OR ec.employee_id = p_employee_id)
    GROUP BY ec.employee_id
    ORDER BY COALESCE(SUM(ec.net_amount), 0) DESC;
END;
$$;


