CREATE FUNCTION public.get_guest_orders(p_tenant_id uuid, p_email character varying, p_session_id character varying DEFAULT NULL::character varying) RETURNS TABLE(order_id uuid, order_number character varying, total_amount numeric, currency character varying, status character varying, payment_status character varying, created_at timestamp with time zone)
    LANGUAGE plpgsql STABLE SECURITY DEFINER
    AS $$
BEGIN
