    SELECT
        o.id as order_id,
        o.order_number,
        o.total_amount,
        o.currency,
        o.status,
        o.payment_status,
        o.created_at
    FROM orders o
    INNER JOIN guest_checkouts gc ON gc.id = o.guest_checkout_id
    WHERE o.tenant_id = p_tenant_id
      AND gc.email = p_email
      AND (p_session_id IS NULL OR gc.session_id = p_session_id)
    ORDER BY o.created_at DESC;
