--
-- Name: get_material_inventory_stats_batch(uuid[]); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_material_inventory_stats_batch(material_ids uuid[]) RETURNS TABLE(material_id uuid, rolls_count bigint, rolls_total_length numeric, reserved_length numeric, available_length numeric)
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
BEGIN
    RETURN QUERY
    SELECT
        fr.material_id,
        COUNT(fr.id)::BIGINT as rolls_count,
        COALESCE(SUM(fr.current_length), 0)::DECIMAL(15,3) as rolls_total_length,
        COALESCE(SUM(fr.reserved_length), 0)::DECIMAL(15,3) as reserved_length,
        COALESCE(SUM(fr.available_length), 0)::DECIMAL(15,3) as available_length
    FROM
        fabric_rolls fr
    WHERE
        fr.material_id = ANY(material_ids)
        AND fr.status IN ('available', 'reserved', 'partial')
        AND fr.current_length > 0
    GROUP BY
        fr.material_id;
END;
$$;


--
-- Name: get_mfa_status(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_mfa_status(p_user_id uuid DEFAULT auth.uid()) RETURNS TABLE(service_enabled boolean, is_required boolean, user_enabled boolean, can_enable boolean, preferred_method text)
    LANGUAGE plpgsql STABLE SECURITY DEFINER
    AS $$
BEGIN
    RETURN QUERY
    SELECT 
        COALESCE(ss.is_enabled, false),
        is_mfa_required(p_user_id),
        COALESCE(us.is_enabled, false),
        COALESCE(ss.is_enabled, false),
        COALESCE(us.preferred_method, 'totp')::TEXT
    FROM mfa_system_settings ss
    LEFT JOIN mfa_user_settings us ON us.user_id = p_user_id
    LIMIT 1;
EXCEPTION
    WHEN OTHERS THEN
        -- Return default values if error
        RETURN QUERY SELECT false, false, false, false, 'totp'::TEXT;
END;
$$;


--
-- Name: get_modules_by_product(character varying); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_modules_by_product(p_product_code character varying) RETURNS TABLE(code character varying, name_en character varying, name_ar character varying, category character varying, price_monthly numeric, is_core boolean)
    LANGUAGE plpgsql
    AS $$
BEGIN
    RETURN QUERY
    SELECT 
        sm.code,
        sm.name_en,
        sm.name_ar,
        sm.category,
        sm.price_monthly,
        sm.is_core
    FROM system_modules sm
    WHERE sm.is_active = true
    AND (
        '*' = ANY(sm.available_in_products)
        OR p_product_code = ANY(sm.available_in_products)
    )
    ORDER BY sm.display_order;
END;
$$;


--
-- Name: get_monthly_expenses(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_monthly_expenses(p_tenant_id uuid DEFAULT NULL::uuid) RETURNS json
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  result json;
  v_tenant_id UUID;
BEGIN
  v_tenant_id := COALESCE(p_tenant_id, get_user_tenant_id());

  SELECT json_build_object(
    'count', COUNT(*),
    'total', COALESCE(SUM(total_debit), 0)
  ) INTO result
  FROM journal_entries
  WHERE entry_type = 'payment'
    AND entry_date >= date_trunc('month', CURRENT_DATE)
    AND deleted_at IS NULL 
    AND status = 'posted'
    AND (v_tenant_id IS NULL OR tenant_id = v_tenant_id);
  
  RETURN result;
END;
$$;


--
-- Name: get_monthly_revenue(integer, character varying); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_monthly_revenue(p_months integer DEFAULT 12, p_currency character varying DEFAULT 'USD'::character varying) RETURNS TABLE(month character varying, revenue numeric, payment_count integer)
    LANGUAGE plpgsql
    AS $$
BEGIN
    RETURN QUERY
    SELECT 
        TO_CHAR(collection_date, 'YYYY-MM') as month,
        SUM(amount) as revenue,
        COUNT(*)::INT as payment_count
    FROM saas_payments
    WHERE status = 'completed'
    AND currency = p_currency
    AND collection_date >= NOW() - (p_months || ' months')::INTERVAL
    GROUP BY TO_CHAR(collection_date, 'YYYY-MM')
    ORDER BY month;
END;
$$;


--
-- Name: get_monthly_sales(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_monthly_sales(p_tenant_id uuid DEFAULT NULL::uuid) RETURNS json
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  result json;
  v_tenant_id UUID;
BEGIN
  v_tenant_id := COALESCE(p_tenant_id, get_user_tenant_id());

  SELECT json_build_object(
    'count', COUNT(*),
    'total', COALESCE(SUM(total_credit), 0)
  ) INTO result
  FROM journal_entries
  WHERE entry_type = 'receipt'
    AND entry_date >= date_trunc('month', CURRENT_DATE)
    AND deleted_at IS NULL 
    AND status = 'posted'
    AND (v_tenant_id IS NULL OR tenant_id = v_tenant_id);
  
  RETURN result;
END;
$$;


--
-- Name: get_monthly_summary(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_monthly_summary(p_tenant_id uuid DEFAULT NULL::uuid) RETURNS json
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  result json;
  v_tenant_id UUID;
BEGIN
  v_tenant_id := COALESCE(p_tenant_id, get_user_tenant_id());

  SELECT json_build_object(
    'total_entries', COUNT(*),
    'posted', COUNT(CASE WHEN status = 'posted' THEN 1 END),
    'draft', COUNT(CASE WHEN status = 'draft' THEN 1 END),
    'total_debit', COALESCE(SUM(total_debit), 0),
    'total_credit', COALESCE(SUM(total_credit), 0),
    'month_start', date_trunc('month', CURRENT_DATE)::date,
    'tenant_id', v_tenant_id
  ) INTO result
  FROM journal_entries
  WHERE entry_date >= date_trunc('month', CURRENT_DATE)
    AND deleted_at IS NULL
    AND (v_tenant_id IS NULL OR tenant_id = v_tenant_id);
  
  RETURN result;
END;
$$;


--
-- Name: get_or_create_cart(uuid, uuid, uuid, character varying); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_or_create_cart(p_tenant_id uuid, p_company_id uuid, p_customer_id uuid DEFAULT NULL::uuid, p_session_id character varying DEFAULT NULL::character varying) RETURNS uuid
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_cart_id UUID;
BEGIN
    -- البحث عن سلة نشطة موجودة
    IF p_customer_id IS NOT NULL THEN
        SELECT id INTO v_cart_id
        FROM shopping_carts
        WHERE tenant_id = p_tenant_id
          AND customer_id = p_customer_id
          AND status = 'active'
        LIMIT 1;
    ELSIF p_session_id IS NOT NULL THEN
        SELECT id INTO v_cart_id
        FROM shopping_carts
        WHERE tenant_id = p_tenant_id
          AND session_id = p_session_id
          AND status = 'active'
        LIMIT 1;
    END IF;
    
    -- إنشاء سلة جديدة إذا لم توجد
    IF v_cart_id IS NULL THEN
        INSERT INTO shopping_carts (
            tenant_id,
            company_id,
            customer_id,
            session_id,
            status,
            expires_at
        )
        VALUES (
            p_tenant_id,
            p_company_id,
            p_customer_id,
            p_session_id,
            'active',
            NOW() + INTERVAL '30 days'
        )
        RETURNING id INTO v_cart_id;
    END IF;
    
    RETURN v_cart_id;
END;
$$;


--
-- Name: FUNCTION get_or_create_cart(p_tenant_id uuid, p_company_id uuid, p_customer_id uuid, p_session_id character varying); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION public.get_or_create_cart(p_tenant_id uuid, p_company_id uuid, p_customer_id uuid, p_session_id character varying) IS 'الحصول على سلة نشطة أو إنشاء جديدة';


--
-- Name: get_order_details(uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_order_details(p_tenant_id uuid, p_order_id uuid) RETURNS jsonb
    LANGUAGE plpgsql STABLE SECURITY DEFINER
    AS $$
DECLARE
    v_order RECORD;
    v_items JSONB;
    v_customer JSONB;
    v_guest JSONB;
    v_result JSONB;
BEGIN
    -- الحصول على الطلب
    SELECT * INTO v_order
    FROM orders
    WHERE id = p_order_id
      AND tenant_id = p_tenant_id;
    
    IF NOT FOUND THEN
        RETURN jsonb_build_object('success', false, 'error', 'الطلب غير موجود');
    END IF;
    
    -- الحصول على عناصر الطلب
    SELECT jsonb_agg(
        jsonb_build_object(
            'product_id', oi.product_id,
            'product_name', oi.product_name,
            'product_sku', oi.product_sku,
            'product_image_url', oi.product_image_url,
            'quantity', oi.quantity,
            'unit_price', oi.unit_price,
            'total_price', oi.total_price
        )
    ) INTO v_items
    FROM order_items oi
    WHERE oi.order_id = p_order_id;
    
    -- الحصول على معلومات العميل أو الزائر
    IF v_order.customer_id IS NOT NULL THEN
        SELECT jsonb_build_object(
            'type', 'customer',
            'id', c.id,
            'code', c.code,
            'full_name', c.full_name,
            'email', c.email,
            'phone', c.phone
        ) INTO v_customer
        FROM customers c
        WHERE c.id = v_order.customer_id;
    ELSIF v_order.guest_checkout_id IS NOT NULL THEN
        SELECT jsonb_build_object(
            'type', 'guest',
            'email', gc.email,
            'full_name', gc.full_name,
            'phone', gc.phone,
            'shipping_address', gc.shipping_address,
            'billing_address', gc.billing_address
        ) INTO v_guest
        FROM guest_checkouts gc
        WHERE gc.id = v_order.guest_checkout_id;
    END IF;
    
    -- بناء النتيجة
    v_result := jsonb_build_object(
        'success', true,
        'order', jsonb_build_object(
            'id', v_order.id,
            'order_number', v_order.order_number,
            'subtotal', v_order.subtotal,
            'discount_amount', v_order.discount_amount,
            'tax_amount', v_order.tax_amount,
            'shipping_amount', v_order.shipping_amount,
            'total_amount', v_order.total_amount,
            'currency', v_order.currency,
            'status', v_order.status,
            'payment_status', v_order.payment_status,
            'payment_method', v_order.payment_method,
            'shipping_method', v_order.shipping_method,
            'tracking_number', v_order.tracking_number,
            'customer_notes', v_order.customer_notes,
            'created_at', v_order.created_at,
            'items', COALESCE(v_items, '[]'::jsonb),
            'customer', COALESCE(v_customer, v_guest, '{}'::jsonb)
        )
    );
    
    RETURN v_result;
END;
$$;


--
-- Name: FUNCTION get_order_details(p_tenant_id uuid, p_order_id uuid); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION public.get_order_details(p_tenant_id uuid, p_order_id uuid) IS 'الحصول على تفاصيل الطلب الكاملة';


--
-- Name: get_partner_allowed_brand_ids(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_partner_allowed_brand_ids(p_user_id uuid DEFAULT auth.uid()) RETURNS uuid[]
    LANGUAGE plpgsql STABLE SECURITY DEFINER
    AS $$
DECLARE
    v_partner_id UUID;
    v_brand_ids UUID[];
BEGIN
    -- Platform Owner يرى كل البراندات
    IF is_platform_owner(p_user_id) THEN
        SELECT ARRAY_AGG(id)
        INTO v_brand_ids
        FROM public.saas_products
        WHERE is_active = true;
        RETURN COALESCE(v_brand_ids, ARRAY[]::UUID[]);
    END IF;
    
    -- الحصول على partner_id
    SELECT p.id INTO v_partner_id
    FROM public.partners p
    JOIN public.user_profiles up ON up.email = p.email
    WHERE up.id = p_user_id
      AND p.is_active = true;
    
    IF v_partner_id IS NULL THEN
        -- ليس وكيلاً، إرجاع البراند الخاص به فقط
        RETURN ARRAY[get_user_brand_id(p_user_id)]::UUID[];
    END IF;
    
    -- الحصول على البراندات المسموح للوكيل بيعها
    SELECT ARRAY_AGG(pap.product_id)
    INTO v_brand_ids
    FROM public.partner_allowed_products pap
    WHERE pap.partner_id = v_partner_id
      AND pap.can_sell = true;
    
    -- إذا لم يكن هناك تحديد (backwards compatibility)، إرجاع كل البراندات
    IF v_brand_ids IS NULL OR array_length(v_brand_ids, 1) IS NULL THEN
        SELECT ARRAY_AGG(id)
        INTO v_brand_ids
        FROM public.saas_products
        WHERE is_active = true;
    END IF;
    
    RETURN COALESCE(v_brand_ids, ARRAY[]::UUID[]);
EXCEPTION WHEN OTHERS THEN
    RETURN ARRAY[]::UUID[];
END;
$$;


--
-- Name: get_partner_tenant_ids(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_partner_tenant_ids(p_user_id uuid DEFAULT auth.uid()) RETURNS uuid[]
    LANGUAGE plpgsql STABLE SECURITY DEFINER
    AS $$
DECLARE
    v_partner_id UUID;
    v_allowed_brands UUID[];
    v_tenant_ids UUID[];
BEGIN
    -- الحصول على partner_id
    SELECT p.id INTO v_partner_id
    FROM public.partners p
    JOIN public.user_profiles up ON up.email = p.email
    WHERE up.id = p_user_id
      AND p.is_active = true;
    
    IF v_partner_id IS NULL THEN
        RETURN ARRAY[]::UUID[];
    END IF;
    
    -- الحصول على البراندات المسموح للوكيل بيعها
    v_allowed_brands := get_partner_allowed_brand_ids(p_user_id);
    
    -- الحصول على جميع التينانتات التي أنشأها الوكيل ضمن البراندات المسموح بها
    SELECT ARRAY_AGG(t.id)
    INTO v_tenant_ids
    FROM public.tenants t
    WHERE t.partner_id = v_partner_id
      AND t.status = 'active'
      AND (t.product_id = ANY(v_allowed_brands) OR t.product_id IS NULL);
    
    RETURN COALESCE(v_tenant_ids, ARRAY[]::UUID[]);
EXCEPTION WHEN OTHERS THEN
    RETURN ARRAY[]::UUID[];
END;
$$;


--
-- Name: get_party_balance(character varying, uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_party_balance(p_party_type character varying, p_party_id uuid, p_company_id uuid DEFAULT NULL::uuid) RETURNS jsonb
    LANGUAGE plpgsql STABLE SECURITY DEFINER
    AS $$
DECLARE
    v_total_debit  NUMERIC(15,4) := 0;
    v_total_credit NUMERIC(15,4) := 0;
    v_balance      NUMERIC(15,4);
BEGIN
    SELECT 
        COALESCE(SUM(jel.debit), 0),
        COALESCE(SUM(jel.credit), 0)
    INTO v_total_debit, v_total_credit
    FROM journal_entry_lines jel
    JOIN journal_entries je ON je.id = jel.entry_id
    WHERE jel.party_type = p_party_type
      AND jel.party_id = p_party_id
      AND je.is_posted = true
      AND (p_company_id IS NULL OR je.company_id = p_company_id);
    
    v_balance := v_total_debit - v_total_credit;
    
    RETURN jsonb_build_object(
        'party_type', p_party_type,
        'party_id', p_party_id,
        'total_debit', v_total_debit,
        'total_credit', v_total_credit,
        'balance', v_balance,
        'balance_label', CASE 
            WHEN p_party_type = 'supplier' THEN 
                CASE WHEN v_balance < 0 THEN 'مستحق للمورد' ELSE 'رصيد لصالحنا' END
            ELSE
                CASE WHEN v_balance > 0 THEN 'مستحق لنا' ELSE 'رصيد لصالح العميل' END
        END
    );
END;
$$;


--
-- Name: FUNCTION get_party_balance(p_party_type character varying, p_party_id uuid, p_company_id uuid); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION public.get_party_balance(p_party_type character varying, p_party_id uuid, p_company_id uuid) IS 'حساب رصيد مورد أو عميل من القيود المحاسبية المرحّلة';


--
-- Name: get_party_balances_bulk(uuid, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_party_balances_bulk(p_company_id uuid, p_party_type text) RETURNS TABLE(party_id uuid, total_debit numeric, total_credit numeric, balance numeric, transaction_count bigint, last_transaction_date date)
    LANGUAGE plpgsql STABLE
    AS $$
BEGIN
    RETURN QUERY
    SELECT 
        jel.party_id,
        COALESCE(SUM(jel.debit), 0) as total_debit,
        COALESCE(SUM(jel.credit), 0) as total_credit,
        CASE 
            WHEN p_party_type = 'supplier' THEN COALESCE(SUM(jel.credit), 0) - COALESCE(SUM(jel.debit), 0)
            ELSE COALESCE(SUM(jel.debit), 0) - COALESCE(SUM(jel.credit), 0)
        END as balance,
        COUNT(*)::BIGINT as transaction_count,
        MAX(je.entry_date) as last_transaction_date
    FROM journal_entry_lines jel
    JOIN journal_entries je ON je.id = jel.entry_id
    WHERE je.company_id = p_company_id
      AND je.status = 'posted'
      AND je.is_posted = true
      AND jel.party_type = p_party_type
      AND jel.party_id IS NOT NULL
    GROUP BY jel.party_id;
END;
$$;


--
-- Name: get_pending_recurring_entries(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_pending_recurring_entries(p_company_id uuid DEFAULT NULL::uuid) RETURNS TABLE(history_id uuid, recurring_entry_id uuid, entry_name character varying, scheduled_date date, amount numeric, approval_status character varying, days_pending integer, created_at timestamp with time zone)
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
BEGIN
    RETURN QUERY
    SELECT 
        reh.id as history_id,
        reh.recurring_entry_id,
        re.name_ar as entry_name,
        reh.scheduled_date,
        reh.amount,
        reh.approval_status,
        (CURRENT_DATE - reh.scheduled_date)::INTEGER as days_pending,
        reh.created_at
    FROM recurring_entry_history reh
    JOIN recurring_entries re ON reh.recurring_entry_id = re.id
    WHERE reh.approval_status = 'pending'
      AND reh.status = 'pending'
      AND (p_company_id IS NULL OR re.company_id = p_company_id)
    ORDER BY reh.scheduled_date ASC;
END;
$$;


--
-- Name: get_plan_modules(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_plan_modules(p_plan_id uuid) RETURNS TABLE(module_id uuid, module_code character varying, module_name_en character varying, module_name_ar character varying, module_icon character varying, is_enabled boolean, is_core boolean, is_active boolean)
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
BEGIN
    RETURN QUERY
    SELECT 
        pm.module_id,
        sm.code,
        sm.name_en,
        sm.name_ar,
        sm.icon,
        pm.is_enabled,
        pm.is_core,
        sm.is_active
    FROM plan_modules pm
    JOIN system_modules sm ON pm.module_id = sm.id
    WHERE pm.plan_id = p_plan_id
    ORDER BY pm.display_order, sm.display_order;
END;
$$;


--
-- Name: FUNCTION get_plan_modules(p_plan_id uuid); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION public.get_plan_modules(p_plan_id uuid) IS 'الحصول على موديولات باقة معينة مع تفاصيلها';


--
-- Name: get_plan_pricing(character varying, character varying, integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_plan_pricing(p_plan_code character varying, p_billing_cycle character varying DEFAULT 'monthly'::character varying, p_free_months integer DEFAULT 2) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_plan RECORD;
    v_discount RECORD;
    v_original_price DECIMAL(10,2);
    v_monthly_after_promo DECIMAL(10,2);
    v_final_price DECIMAL(10,2);
    v_yearly_months_paid INT;
    v_promo_discount INT := 0;
BEGIN
    -- 1. الحصول على الباقة
    SELECT * INTO v_plan
    FROM subscription_plans
    WHERE code = p_plan_code AND is_active = true;
    
    IF NOT FOUND THEN
        RETURN jsonb_build_object(
            'success', false,
            'error', 'plan_not_found',
            'message', 'الباقة غير موجودة'
        );
    END IF;
    
    -- 2. الحصول على الخصم الموسمي النشط
    SELECT * INTO v_discount
    FROM promotional_discounts
    WHERE is_active = true
      AND auto_apply = true
      AND NOW() BETWEEN valid_from AND valid_to
      AND (
          applies_to = 'both'
          OR applies_to = p_billing_cycle
      )
      AND (
          applicable_plans = '[]'::jsonb
          OR applicable_plans @> to_jsonb(ARRAY[p_plan_code])
      )
    ORDER BY priority DESC, discount_percentage DESC
    LIMIT 1;
    
    -- 3. حساب السعر حسب نوع الاشتراك
    IF p_billing_cycle = 'monthly' THEN
        -- ═══ شهري ═══
        v_original_price := v_plan.price_monthly;
        
        -- تطبيق الخصم الموسمي
        IF v_discount IS NOT NULL THEN
            v_promo_discount := v_discount.discount_percentage;
            v_monthly_after_promo := v_original_price * (1 - v_promo_discount::DECIMAL / 100);
        ELSE
            v_monthly_after_promo := v_original_price;
        END IF;
        
        v_final_price := v_monthly_after_promo;
        
    ELSE
        -- ═══ سنوي ═══
        v_original_price := v_plan.price_yearly; -- شهري × 12
        
        -- تطبيق الخصم الموسمي على الشهري أولاً
        IF v_discount IS NOT NULL THEN
            v_promo_discount := v_discount.discount_percentage;
            v_monthly_after_promo := v_plan.price_monthly * (1 - v_promo_discount::DECIMAL / 100);
        ELSE
            v_monthly_after_promo := v_plan.price_monthly;
        END IF;
        
        -- حساب السنوي مع بونص الأشهر المجانية
        -- مثال: 12 شهر - 2 شهر مجاني = 10 أشهر مدفوعة
        v_yearly_months_paid := 12 - p_free_months;
        v_final_price := v_monthly_after_promo * v_yearly_months_paid;
    END IF;
    
    -- 4. إرجاع النتيجة
    RETURN jsonb_build_object(
        'success', true,
        'plan_code', v_plan.code,
        'plan_name_ar', v_plan.name_ar,
        'plan_name_en', v_plan.name_en,
        'billing_cycle', p_billing_cycle,
        'currency', v_plan.currency,
        
        -- الأسعار
        'original_price', v_original_price,
        'monthly_after_promo', v_monthly_after_promo,
        'final_price', ROUND(v_final_price, 2),
        
        -- التفاصيل
        'promo_discount', v_promo_discount,
        'promo_name_ar', COALESCE(v_discount.name_ar, NULL),
        'promo_name_en', COALESCE(v_discount.name_en, NULL),
        'free_months', CASE WHEN p_billing_cycle = 'yearly' THEN p_free_months ELSE 0 END,
        'months_paid', CASE WHEN p_billing_cycle = 'yearly' THEN v_yearly_months_paid ELSE 1 END,
        
        -- التوفير
        'total_savings', ROUND(v_original_price - v_final_price, 2),
        'savings_percentage', ROUND((v_original_price - v_final_price) / v_original_price * 100, 2)
    );
    
EXCEPTION
    WHEN OTHERS THEN
        RETURN jsonb_build_object(
            'success', false,
            'error', 'exception',
            'message', SQLERRM
        );
END;
$$;


--
-- Name: FUNCTION get_plan_pricing(p_plan_code character varying, p_billing_cycle character varying, p_free_months integer); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION public.get_plan_pricing(p_plan_code character varying, p_billing_cycle character varying, p_free_months integer) IS 'حساب السعر النهائي مع الخصومات والبونص السنوي';


--
-- Name: get_plans_by_product(character varying); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_plans_by_product(p_product_code character varying) RETURNS TABLE(id uuid, code character varying, name_en character varying, name_ar character varying, price_monthly numeric, price_yearly numeric, currency character varying, max_users integer, max_companies integer, is_popular boolean, is_active boolean)
    LANGUAGE plpgsql
    AS $$
BEGIN
    RETURN QUERY
    SELECT 
        sp.id,
        sp.code,
        sp.name_en,
        sp.name_ar,
        sp.price_monthly,
        sp.price_yearly,
        sp.currency,
        sp.max_users,
        sp.max_companies,
        sp.is_popular,
        sp.is_active
    FROM subscription_plans sp
    JOIN saas_products prod ON sp.product_id = prod.id
    WHERE prod.code = p_product_code
    AND sp.is_active = true
    ORDER BY sp.display_order;
END;
$$;


--
-- Name: get_product_name(uuid, character varying); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_product_name(p_product_id uuid, p_language character varying DEFAULT 'en'::character varying) RETURNS character varying
    LANGUAGE plpgsql STABLE
    AS $_$
DECLARE
    v_name VARCHAR;
BEGIN
    EXECUTE format(
        'SELECT COALESCE(name_%s, name_en, name_ar) FROM products WHERE id = $1',
        p_language
    ) INTO v_name USING p_product_id;
    
    RETURN v_name;
EXCEPTION
    WHEN OTHERS THEN
        -- إذا فشل، نرجع name_en أو name_ar
        SELECT COALESCE(name_en, name_ar) INTO v_name FROM products WHERE id = p_product_id;
        RETURN v_name;
END;
$_$;


--
-- Name: FUNCTION get_product_name(p_product_id uuid, p_language character varying); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION public.get_product_name(p_product_id uuid, p_language character varying) IS 'الحصول على اسم المنتج بلغة محددة';


--
-- Name: get_product_primary_image(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_product_primary_image(p_product_id uuid) RETURNS text
    LANGUAGE plpgsql STABLE
    AS $$
DECLARE
    v_primary_image TEXT;
BEGIN
    SELECT img->>'url'
    INTO v_primary_image
    FROM products p,
         jsonb_array_elements(p.images) AS img
    WHERE p.id = p_product_id
      AND (img->>'is_primary')::boolean = true
    LIMIT 1;
    
    -- إذا لم توجد صورة primary، أرجع أول صورة
    IF v_primary_image IS NULL THEN
        SELECT img->>'url'
        INTO v_primary_image
        FROM products p,
             jsonb_array_elements(p.images) AS img
        WHERE p.id = p_product_id
        ORDER BY (img->>'display_order')::int
        LIMIT 1;
    END IF;
    
    RETURN v_primary_image;
END;
$$;


--
-- Name: FUNCTION get_product_primary_image(p_product_id uuid); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION public.get_product_primary_image(p_product_id uuid) IS 'الحصول على الصورة الرئيسية للمنتج';


--
-- Name: get_product_review_statistics(uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_product_review_statistics(p_tenant_id uuid, p_product_id uuid) RETURNS jsonb
    LANGUAGE plpgsql STABLE SECURITY DEFINER
    AS $$
DECLARE
    v_stats RECORD;
    v_result JSONB;
BEGIN
    SELECT * INTO v_stats
    FROM product_review_stats
    WHERE tenant_id = p_tenant_id
      AND product_id = p_product_id;
    
    IF NOT FOUND THEN
        -- إذا لم توجد إحصائيات، حسابها الآن
        PERFORM update_product_review_stats(p_tenant_id, p_product_id);
        
        SELECT * INTO v_stats
        FROM product_review_stats
        WHERE tenant_id = p_tenant_id AND product_id = p_product_id;
    END IF;
    
    v_result := jsonb_build_object(
        'total_reviews', COALESCE(v_stats.total_reviews, 0),
        'average_rating', COALESCE(v_stats.average_rating, 0),
        'rating_distribution', jsonb_build_object(
            '5', COALESCE(v_stats.rating_5_count, 0),
            '4', COALESCE(v_stats.rating_4_count, 0),
            '3', COALESCE(v_stats.rating_3_count, 0),
            '2', COALESCE(v_stats.rating_2_count, 0),
            '1', COALESCE(v_stats.rating_1_count, 0)
        ),
        'verified_reviews', jsonb_build_object(
            'count', COALESCE(v_stats.verified_reviews_count, 0),
            'average_rating', COALESCE(v_stats.verified_average_rating, 0)
        )
    );
    
    RETURN v_result;
END;
$$;


--
-- Name: FUNCTION get_product_review_statistics(p_tenant_id uuid, p_product_id uuid); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION public.get_product_review_statistics(p_tenant_id uuid, p_product_id uuid) IS 'الحصول على إحصائيات تقييمات المنتج';


--
-- Name: get_product_reviews(uuid, uuid, integer, integer, integer, boolean, character varying); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_product_reviews(p_tenant_id uuid, p_product_id uuid, p_limit integer DEFAULT 10, p_offset integer DEFAULT 0, p_rating_filter integer DEFAULT NULL::integer, p_verified_only boolean DEFAULT false, p_sort_by character varying DEFAULT 'recent'::character varying) RETURNS TABLE(review_id uuid, customer_name character varying, rating integer, title character varying, review_text text, images jsonb, is_verified_purchase boolean, helpful_count integer, not_helpful_count integer, seller_response text, seller_response_at timestamp with time zone, created_at timestamp with time zone)
    LANGUAGE plpgsql STABLE SECURITY DEFINER
    AS $$
BEGIN
    RETURN QUERY
    SELECT
        pr.id as review_id,
        COALESCE(c.full_name, 'عميل') as customer_name,
        pr.rating,
        pr.title,
        pr.review_text,
        pr.images,
        pr.is_verified_purchase,
        pr.helpful_count,
        pr.not_helpful_count,
        pr.seller_response,
        pr.seller_response_at,
        pr.created_at
    FROM product_reviews pr
    LEFT JOIN customers c ON c.id = pr.customer_id
    WHERE pr.tenant_id = p_tenant_id
      AND pr.product_id = p_product_id
      AND pr.status = 'approved'
      AND (p_rating_filter IS NULL OR pr.rating = p_rating_filter)
      AND (p_verified_only = false OR pr.is_verified_purchase = true)
    ORDER BY
        CASE WHEN p_sort_by = 'recent' THEN pr.created_at END DESC,
        CASE WHEN p_sort_by = 'helpful' THEN pr.helpful_count END DESC,
        CASE WHEN p_sort_by = 'rating_high' THEN pr.rating END DESC,
        CASE WHEN p_sort_by = 'rating_low' THEN pr.rating END ASC
    LIMIT p_limit
    OFFSET p_offset;
END;
$$;


--
-- Name: FUNCTION get_product_reviews(p_tenant_id uuid, p_product_id uuid, p_limit integer, p_offset integer, p_rating_filter integer, p_verified_only boolean, p_sort_by character varying); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION public.get_product_reviews(p_tenant_id uuid, p_product_id uuid, p_limit integer, p_offset integer, p_rating_filter integer, p_verified_only boolean, p_sort_by character varying) IS 'الحصول على تقييمات المنتج مع الفلاتر';


--
-- Name: get_product_stats(character varying); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_product_stats(p_product_code character varying) RETURNS TABLE(product_name character varying, total_plans integer, active_plans integer, total_tenants bigint, active_tenants bigint, available_modules bigint)
    LANGUAGE plpgsql
    AS $$
BEGIN
    RETURN QUERY
    SELECT 
        prod.name,
        COUNT(DISTINCT sp.id)::INT as total_plans,
        COUNT(DISTINCT CASE WHEN sp.is_active THEN sp.id END)::INT as active_plans,
        COUNT(DISTINCT t.id) as total_tenants,
        COUNT(DISTINCT CASE WHEN t.status = 'active' THEN t.id END) as active_tenants,
        COUNT(DISTINCT sm.code) as available_modules
    FROM saas_products prod
    LEFT JOIN subscription_plans sp ON prod.id = sp.product_id
    LEFT JOIN tenants t ON prod.id = t.product_id
    LEFT JOIN system_modules sm ON (
        '*' = ANY(sm.available_in_products)
        OR prod.code = ANY(sm.available_in_products)
    ) AND sm.is_active = true
    WHERE prod.code = p_product_code
    GROUP BY prod.name;
END;
$$;


--
-- Name: get_products_for_store(uuid, uuid, uuid, uuid, numeric, numeric, boolean, character varying, character varying, character varying, integer, integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_products_for_store(p_tenant_id uuid, p_company_id uuid DEFAULT NULL::uuid, p_customer_id uuid DEFAULT NULL::uuid, p_category_id uuid DEFAULT NULL::uuid, p_min_price numeric DEFAULT NULL::numeric, p_max_price numeric DEFAULT NULL::numeric, p_is_featured boolean DEFAULT NULL::boolean, p_search_term character varying DEFAULT NULL::character varying, p_sort_by character varying DEFAULT 'created_at'::character varying, p_sort_order character varying DEFAULT 'DESC'::character varying, p_limit integer DEFAULT 20, p_offset integer DEFAULT 0) RETURNS TABLE(id uuid, sku character varying, barcode character varying, name_ar character varying, name_en character varying, description text, category_id uuid, category_name_ar character varying, brand_id uuid, brand_name character varying, images jsonb, slug character varying, base_price numeric, customer_price numeric, discount_percent numeric, discount_amount numeric, price_source character varying, is_on_sale boolean, stock_status character varying, available_quantity numeric, is_featured boolean, rating numeric, reviews_count integer, created_at timestamp with time zone)
    LANGUAGE plpgsql STABLE SECURITY DEFINER
    AS $$
BEGIN
    -- نسخة بسيطة جداً - ترجع كل المنتجات بدون فلاتر
    RETURN QUERY
    SELECT 
        p.id,
        COALESCE(p.sku, '') as sku,
        COALESCE(p.barcode, '') as barcode,
        COALESCE(p.name_ar, '') as name_ar,
        COALESCE(p.name_en, '') as name_en,
        COALESCE(p.description, '') as description,
        p.category_id,
        NULL::VARCHAR as category_name_ar,
        NULL::UUID as brand_id,
        NULL::VARCHAR as brand_name,
        COALESCE(p.images, '[]'::jsonb) as images,
        COALESCE(p.slug, '') as slug,
        COALESCE(p.default_price, 0) as base_price,
        COALESCE(p.default_price, 0) as customer_price,
        0::DECIMAL as discount_percent,
        0::DECIMAL as discount_amount,
        'base_price'::VARCHAR as price_source,
        false as is_on_sale,
        'in_stock'::VARCHAR as stock_status,
        999999::DECIMAL as available_quantity,
        COALESCE(p.is_featured, false) as is_featured,
        0.0 as rating,
        0 as reviews_count,
        COALESCE(p.created_at, NOW()) as created_at
    FROM products p
    ORDER BY p.created_at DESC
    LIMIT p_limit
    OFFSET p_offset;
END;
$$;


--
-- Name: FUNCTION get_products_for_store(p_tenant_id uuid, p_company_id uuid, p_customer_id uuid, p_category_id uuid, p_min_price numeric, p_max_price numeric, p_is_featured boolean, p_search_term character varying, p_sort_by character varying, p_sort_order character varying, p_limit integer, p_offset integer); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION public.get_products_for_store(p_tenant_id uuid, p_company_id uuid, p_customer_id uuid, p_category_id uuid, p_min_price numeric, p_max_price numeric, p_is_featured boolean, p_search_term character varying, p_sort_by character varying, p_sort_order character varying, p_limit integer, p_offset integer) IS 'عرض المنتجات للمتجر الإلكتروني (نسخة الاختبار - بدون فلاتر)';


--
-- Name: get_promotional_discounts(boolean); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_promotional_discounts(p_active_only boolean DEFAULT false) RETURNS TABLE(id uuid, code character varying, name_ar character varying, name_en character varying, discount_percentage integer, valid_from timestamp with time zone, valid_to timestamp with time zone, applicable_plans jsonb, applies_to character varying, is_active boolean, auto_apply boolean, priority integer, is_current boolean)
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
BEGIN
    RETURN QUERY
    SELECT 
        pd.id,
        pd.code,
        pd.name_ar,
        pd.name_en,
        pd.discount_percentage,
        pd.valid_from,
        pd.valid_to,
        pd.applicable_plans,
        pd.applies_to,
        pd.is_active,
        pd.auto_apply,
        pd.priority,
        (NOW() BETWEEN pd.valid_from AND pd.valid_to)::BOOLEAN as is_current
    FROM promotional_discounts pd
    WHERE (NOT p_active_only OR pd.is_active = true)
    ORDER BY pd.priority DESC, pd.created_at DESC;
END;
$$;


--
-- Name: get_remaining_days(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_remaining_days(p_tenant_id uuid) RETURNS integer
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_end_date DATE;
    v_days_remaining INT;
BEGIN
    SELECT end_date INTO v_end_date
    FROM tenant_subscriptions
    WHERE tenant_id = p_tenant_id
        AND status = 'active'
    ORDER BY end_date DESC
    LIMIT 1;
    
    IF v_end_date IS NULL THEN
        RETURN 0;
    END IF;
    
    v_days_remaining := v_end_date - CURRENT_DATE;
    RETURN GREATEST(v_days_remaining, 0);
END;
$$;


--
-- Name: FUNCTION get_remaining_days(p_tenant_id uuid); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION public.get_remaining_days(p_tenant_id uuid) IS 'حساب الأيام المتبقية في اشتراك المستأجر';


--
-- Name: get_schema_info(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_schema_info() RETURNS json
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  result JSON;
BEGIN
  SELECT json_agg(json_build_object(
    'table', t.table_name,
    'columns', (
      SELECT json_agg(json_build_object(
        'name', c.column_name,
        'type', c.data_type
      ) ORDER BY c.ordinal_position)
      FROM information_schema.columns c
      WHERE c.table_schema = 'public' AND c.table_name = t.table_name
    )
  ) ORDER BY t.table_name)
  INTO result
  FROM information_schema.tables t
  WHERE t.table_schema = 'public' 
    AND t.table_type = 'BASE TABLE'
    AND t.table_name NOT LIKE 'pg_%';
  RETURN result;
END;
$$;


--
-- Name: get_shipment_items_summary(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_shipment_items_summary(p_shipment_id uuid) RETURNS TABLE(total_items bigint, total_expected_quantity numeric, total_received_quantity numeric, total_reserved_quantity numeric, total_available_quantity numeric, total_goods_value numeric, total_provisional_cost numeric, total_final_cost numeric, unique_suppliers bigint, unique_invoices bigint, unique_materials bigint)
    LANGUAGE plpgsql
    AS $$
BEGIN
    RETURN QUERY
    SELECT
        COUNT(*)::BIGINT AS total_items,
        COALESCE(SUM(si.expected_quantity), 0)::DECIMAL(15,3) AS total_expected_quantity,
        COALESCE(SUM(si.received_quantity), 0)::DECIMAL(15,3) AS total_received_quantity,
        COALESCE(SUM(si.reserved_quantity), 0)::DECIMAL(15,3) AS total_reserved_quantity,
        COALESCE(SUM(
            COALESCE(si.expected_quantity, 0) - COALESCE(si.reserved_quantity, 0) - COALESCE(si.sold_quantity, 0)
        ), 0)::DECIMAL(15,3) AS total_available_quantity,
        COALESCE(SUM(si.total_price), 0)::DECIMAL(15,2) AS total_goods_value,
        COALESCE(SUM(si.total_provisional_cost), 0)::DECIMAL(15,2) AS total_provisional_cost,
        COALESCE(SUM(si.total_final_cost), 0)::DECIMAL(15,2) AS total_final_cost,
        COUNT(DISTINCT si.supplier_id)::BIGINT AS unique_suppliers,
        COUNT(DISTINCT si.purchase_invoice_id)::BIGINT AS unique_invoices,
        COUNT(DISTINCT si.material_id)::BIGINT AS unique_materials
    FROM shipment_items si
    WHERE si.shipment_id = p_shipment_id;
END;
$$;


--
-- Name: FUNCTION get_shipment_items_summary(p_shipment_id uuid); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION public.get_shipment_items_summary(p_shipment_id uuid) IS 'إحصائيات بنود كونتينر: عدد المواد، الكميات، القيم، عدد الموردين والفواتير';


--
-- Name: get_status_color_class(character varying); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_status_color_class(color character varying) RETURNS character varying
    LANGUAGE plpgsql IMMUTABLE
    AS $$
BEGIN
  RETURN CASE color
    WHEN 'gray' THEN 'bg-gray-100 text-gray-700'
    WHEN 'blue' THEN 'bg-blue-100 text-blue-700'
    WHEN 'green' THEN 'bg-green-100 text-green-700'
    WHEN 'red' THEN 'bg-red-100 text-red-700'
    WHEN 'yellow' THEN 'bg-yellow-100 text-yellow-700'
    WHEN 'orange' THEN 'bg-orange-100 text-orange-700'
    WHEN 'purple' THEN 'bg-purple-100 text-purple-700'
    WHEN 'indigo' THEN 'bg-indigo-100 text-indigo-700'
    WHEN 'cyan' THEN 'bg-cyan-100 text-cyan-700'
    WHEN 'teal' THEN 'bg-teal-100 text-teal-700'
    WHEN 'pink' THEN 'bg-pink-100 text-pink-700'
    ELSE 'bg-gray-100 text-gray-700'
  END;
END;
$$;


--
-- Name: get_subscription_plans(boolean); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_subscription_plans(p_active_only boolean DEFAULT true) RETURNS TABLE(id uuid, product_id uuid, code character varying, name_ar character varying, name_en character varying, description text, max_users integer, max_companies integer, max_branches integer, max_warehouses integer, max_products integer, storage_gb integer, included_modules jsonb, features jsonb, price_monthly numeric, price_yearly numeric, currency character varying, trial_days integer, is_popular boolean, display_order integer, is_active boolean, created_at timestamp with time zone)
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
BEGIN
    RETURN QUERY
    SELECT 
        sp.id,
        sp.product_id,
        sp.code,
        sp.name_ar,
        sp.name_en,
        sp.description,
        sp.max_users,
        sp.max_companies,
        sp.max_branches,
        sp.max_warehouses,
        sp.max_products,
        sp.storage_gb,
        sp.included_modules,
        sp.features,
        sp.price_monthly,
        sp.price_yearly,
        sp.currency,
        sp.trial_days,
        sp.is_popular,
        sp.display_order,
        sp.is_active,
        sp.created_at
    FROM subscription_plans sp
    WHERE (NOT p_active_only OR sp.is_active = true)
    ORDER BY sp.display_order ASC, sp.created_at ASC;
END;
$$;


