--
-- Name: get_subscription_stats(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_subscription_stats(p_tenant_id uuid) RETURNS jsonb
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_subscription RECORD;
    v_stats JSONB;
BEGIN
    SELECT 
        ts.id,
        ts.status,
        ts.start_date,
        ts.end_date,
        ts.total_days_purchased,
        ts.remaining_balance,
        sp.name_en,
        sp.name_ar,
        sp.price_monthly,
        sp.price_daily,
        sp.currency,
        -- إصلاح: استخدام طرح التواريخ مباشرة بدلاً من EXTRACT
        (ts.end_date - CURRENT_DATE) as days_remaining,
        (CURRENT_DATE - ts.start_date) as days_used,
        CASE 
            WHEN ts.end_date < CURRENT_DATE THEN 'expired'
            WHEN (ts.end_date - CURRENT_DATE) <= 7 THEN 'expiring_soon'
            ELSE 'active'
        END as health_status
    INTO v_subscription
    FROM tenant_subscriptions ts
    JOIN subscription_plans sp ON ts.plan_id = sp.id
    WHERE ts.tenant_id = p_tenant_id
        AND ts.status IN ('active', 'trial', 'expired')
    ORDER BY ts.end_date DESC
    LIMIT 1;
    
    IF NOT FOUND THEN
        RETURN jsonb_build_object('found', false);
    END IF;
    
    v_stats := jsonb_build_object(
        'found', true,
        'subscription_id', v_subscription.id,
        'status', v_subscription.status,
        'health_status', v_subscription.health_status,
        'start_date', v_subscription.start_date,
        'end_date', v_subscription.end_date,
        'days_remaining', GREATEST(v_subscription.days_remaining, 0),
        'days_used', v_subscription.days_used,
        'total_days_purchased', v_subscription.total_days_purchased,
        'remaining_balance', v_subscription.remaining_balance,
        'plan', jsonb_build_object(
            'name_en', v_subscription.name_en,
            'name_ar', v_subscription.name_ar,
            'price_monthly', v_subscription.price_monthly,
            'price_daily', v_subscription.price_daily,
            'currency', v_subscription.currency
        )
    );
    
    RETURN v_stats;
END;
$$;


--
-- Name: FUNCTION get_subscription_stats(p_tenant_id uuid); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION public.get_subscription_stats(p_tenant_id uuid) IS 'الحصول على إحصائيات كاملة لاشتراك المستأجر';


--
-- Name: get_target_achievement_report(uuid, integer, integer, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_target_achievement_report(p_company_id uuid, p_period_year integer, p_period_month integer DEFAULT NULL::integer, p_employee_id uuid DEFAULT NULL::uuid) RETURNS TABLE(employee_id uuid, target_type character varying, target_amount numeric, achieved_amount numeric, achievement_percentage numeric, remaining_amount numeric, bonus_earned numeric, status character varying)
    LANGUAGE plpgsql
    AS $$
BEGIN
    RETURN QUERY
    SELECT 
        et.employee_id,
        et.target_type,
        et.target_amount,
        et.achieved_amount,
        et.achievement_percentage,
        GREATEST(et.target_amount - et.achieved_amount, 0)::DECIMAL(15,2),
        CASE WHEN et.achievement_percentage >= 100 THEN et.bonus_on_achievement ELSE 0 END + 
        CASE WHEN et.achievement_percentage > 100 
            THEN (et.achieved_amount - et.target_amount) * et.bonus_on_exceed / 100 ELSE 0 END,
        et.status
    FROM employee_targets et
    WHERE et.company_id = p_company_id
      AND et.period_year = p_period_year
      AND (p_period_month IS NULL OR et.period_month = p_period_month)
      AND (p_employee_id IS NULL OR et.employee_id = p_employee_id)
    ORDER BY et.employee_id, et.target_type;
END;
$$;


--
-- Name: get_tenant_active_languages(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_tenant_active_languages(p_tenant_id uuid DEFAULT NULL::uuid) RETURNS TABLE(language_code character varying, language_name_ar character varying, language_name_en character varying, is_primary boolean, display_order integer, direction character varying, flag_emoji character varying)
    LANGUAGE plpgsql STABLE SECURITY DEFINER
    AS $$
DECLARE
    v_tenant_id UUID;
BEGIN
    v_tenant_id := COALESCE(p_tenant_id, get_current_tenant_id());
    
    IF v_tenant_id IS NULL THEN
        RAISE EXCEPTION 'Tenant not found';
    END IF;
    
    RETURN QUERY
    SELECT 
        tl.language_code,
        sl.name_ar,
        sl.name_en,
        tl.is_primary,
        tl.display_order,
        sl.direction,
        sl.flag_emoji
    FROM tenant_languages tl
    JOIN system_languages sl ON sl.code = tl.language_code
    WHERE tl.tenant_id = v_tenant_id
    AND tl.is_enabled = true
    ORDER BY tl.is_primary DESC, tl.display_order, sl.name_en;
END;
$$;


--
-- Name: get_tenant_available_modules(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_tenant_available_modules(p_tenant_id uuid) RETURNS TABLE(module_code character varying, name_ar character varying, name_en character varying, icon character varying, display_order integer, is_enabled boolean, requires_upgrade boolean)
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
BEGIN
    RETURN QUERY
    SELECT 
        m.code AS module_code,
        m.name_ar,
        m.name_en,
        m.icon,
        m.display_order,
        COALESCE(tm.is_enabled, FALSE) AS is_enabled,
        (
            (tm.is_enabled IS NULL OR tm.is_enabled = FALSE) 
            AND 
            (m.code = ANY(sp.included_modules))
        ) AS requires_upgrade
    FROM system_modules m
    LEFT JOIN tenant_modules tm 
        ON tm.module_code = m.code 
        AND tm.tenant_id = p_tenant_id
    LEFT JOIN tenants t 
        ON t.id = p_tenant_id
    LEFT JOIN subscriptions sub 
        ON sub.tenant_id = t.id 
        AND sub.status = 'active'
    LEFT JOIN subscription_plans sp 
        ON sp.id = sub.plan_id
    WHERE m.is_active = true
    ORDER BY m.display_order;
END;
$$;


--
-- Name: get_tenant_company_ids(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_tenant_company_ids(p_tenant_id uuid DEFAULT NULL::uuid) RETURNS uuid[]
    LANGUAGE plpgsql STABLE SECURITY DEFINER
    AS $$
DECLARE
    v_tenant_id UUID;
    v_company_ids UUID[];
BEGIN
    -- إذا لم يتم تحديد tenant_id، استخدم tenant_id للمستخدم الحالي
    v_tenant_id := COALESCE(p_tenant_id, get_user_tenant_id());
    
    IF v_tenant_id IS NULL THEN
        RETURN ARRAY[]::UUID[];
    END IF;
    
    SELECT ARRAY_AGG(id)
    INTO v_company_ids
    FROM public.companies
    WHERE tenant_id = v_tenant_id
      AND is_active = true;
    
    RETURN COALESCE(v_company_ids, ARRAY[]::UUID[]);
EXCEPTION WHEN OTHERS THEN
    RETURN ARRAY[]::UUID[];
END;
$$;


--
-- Name: get_tenant_limits(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_tenant_limits(p_tenant_id uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_plan RECORD;
BEGIN
    SELECT sp.* INTO v_plan
    FROM subscriptions s
    JOIN subscription_plans sp ON s.plan_id = sp.id
    WHERE s.tenant_id = p_tenant_id AND s.status IN ('active', 'trial')
    LIMIT 1;
    
    IF NOT FOUND THEN
        RETURN jsonb_build_object('error', 'لا يوجد اشتراك');
    END IF;
    
    RETURN jsonb_build_object(
        'max_users', v_plan.max_users,
        'max_companies', v_plan.max_companies,
        'max_branches', v_plan.max_branches,
        'max_warehouses', v_plan.max_warehouses,
        'max_products', v_plan.max_products,
        'max_invoices_monthly', v_plan.max_invoices_monthly,
        'storage_gb', v_plan.storage_gb,
        'features', v_plan.features
    );
END;
$$;


--
-- Name: get_tenant_sidebar_structure(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_tenant_sidebar_structure(p_tenant_id uuid DEFAULT NULL::uuid) RETURNS jsonb
    LANGUAGE plpgsql STABLE SECURITY DEFINER
    AS $$
DECLARE
    v_tenant_id UUID;
    v_result JSONB;
BEGIN
    v_tenant_id := COALESCE(p_tenant_id, get_current_tenant_id());
    
    SELECT jsonb_build_object(
        'categories', jsonb_agg(
            jsonb_build_object(
                'category', category,
                'modules', modules
            )
        )
    ) INTO v_result
    FROM (
        SELECT 
            COALESCE(sm.category, 'basic') as category,
            jsonb_agg(
                jsonb_build_object(
                    'code', sm.code,
                    'name_ar', sm.name_ar,
                    'name_en', sm.name_en,
                    'icon', sm.icon,
                    'path', '/' || sm.code,
                    'is_enabled', COALESCE(tm.is_active, sm.is_core),
                    'is_core', sm.is_core,
                    'badge', CASE 
                        WHEN NOT COALESCE(tm.is_active, sm.is_core) THEN 'locked'
                        ELSE NULL
                    END
                )
                ORDER BY sm.display_order
            ) as modules
        FROM system_modules sm
        LEFT JOIN tenant_modules tm ON tm.module_code = sm.code 
            AND tm.tenant_id = v_tenant_id
        WHERE sm.is_active = true
        GROUP BY sm.category
    ) categories;
    
    RETURN v_result;
END;
$$;


--
-- Name: get_tenant_statistics(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_tenant_statistics(p_tenant_id uuid DEFAULT NULL::uuid) RETURNS jsonb
    LANGUAGE plpgsql STABLE SECURITY DEFINER
    AS $$
DECLARE
    v_tenant_id UUID;
    v_result JSONB;
BEGIN
    v_tenant_id := COALESCE(p_tenant_id, get_current_tenant_id());
    
    SELECT jsonb_build_object(
        'companies', (SELECT COUNT(*) FROM companies WHERE tenant_id = v_tenant_id),
        'users', (SELECT COUNT(*) FROM user_profiles WHERE tenant_id = v_tenant_id),
        'customers', (SELECT COUNT(*) FROM customers WHERE tenant_id = v_tenant_id),
        'suppliers', (SELECT COUNT(*) FROM suppliers WHERE tenant_id = v_tenant_id),
        'products', (SELECT COUNT(*) FROM products WHERE tenant_id = v_tenant_id),
        'journal_entries', (SELECT COUNT(*) FROM journal_entries WHERE tenant_id = v_tenant_id),
        'sales_invoices', (SELECT COUNT(*) FROM sales_invoices WHERE tenant_id = v_tenant_id),
        'documents', (SELECT COUNT(*) FROM documents WHERE tenant_id = v_tenant_id),
        'storage_used', (
            SELECT COALESCE(SUM(file_size), 0)
            FROM documents
            WHERE tenant_id = v_tenant_id
        )
    ) INTO v_result;
    
    RETURN v_result;
END;
$$;


--
-- Name: get_tenants_by_product(character varying); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_tenants_by_product(p_product_code character varying) RETURNS TABLE(id uuid, code character varying, name character varying, email character varying, status character varying, created_at timestamp with time zone)
    LANGUAGE plpgsql
    AS $$
BEGIN
    RETURN QUERY
    SELECT 
        t.id,
        t.code,
        t.name,
        t.email,
        t.status,
        t.created_at
    FROM tenants t
    JOIN saas_products prod ON t.product_id = prod.id
    WHERE prod.code = p_product_code
    ORDER BY t.created_at DESC;
END;
$$;


--
-- Name: get_total_revenue(character varying, date, date); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_total_revenue(p_currency character varying DEFAULT 'USD'::character varying, p_start_date date DEFAULT NULL::date, p_end_date date DEFAULT NULL::date) RETURNS numeric
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_total DECIMAL(12,2);
BEGIN
    SELECT COALESCE(SUM(amount), 0)
    INTO v_total
    FROM saas_payments
    WHERE status = 'completed'
    AND currency = p_currency
    AND (p_start_date IS NULL OR collection_date >= p_start_date)
    AND (p_end_date IS NULL OR collection_date <= p_end_date);
    
    RETURN v_total;
END;
$$;


--
-- Name: get_transfer_history(uuid, integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_transfer_history(p_account_id uuid, p_limit integer DEFAULT 50) RETURNS TABLE(transfer_id uuid, transfer_date timestamp with time zone, transfer_type character varying, source_account_code character varying, source_account_name character varying, target_account_code character varying, target_account_name character varying, amount numeric, notes text)
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
BEGIN
    RETURN QUERY
    SELECT 
        t.id,
        t.created_at,
        t.transfer_type,
        sa.account_code,
        sa.name_ar,
        ta.account_code,
        ta.name_ar,
        t.amount,
        t.notes
    FROM account_transfers t
    INNER JOIN chart_of_accounts sa ON t.source_account_id = sa.id
    INNER JOIN chart_of_accounts ta ON t.target_account_id = ta.id
    WHERE t.source_account_id = p_account_id 
       OR t.target_account_id = p_account_id
    ORDER BY t.created_at DESC
    LIMIT p_limit;
END;
$$;


--
-- Name: FUNCTION get_transfer_history(p_account_id uuid, p_limit integer); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION public.get_transfer_history(p_account_id uuid, p_limit integer) IS 'Get transfer history for an account';


