--
-- Name: get_user_accessible_company_ids(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_user_accessible_company_ids(p_user_id uuid DEFAULT auth.uid()) RETURNS uuid[]
    LANGUAGE plpgsql STABLE SECURITY DEFINER
    AS $$
DECLARE
    v_user_tenant_id UUID;
    v_user_company_id UUID;
    v_company_ids UUID[];
BEGIN
    -- Platform Owner يرى كل الشركات في كل البراندات
    IF is_platform_owner(p_user_id) THEN
        SELECT ARRAY_AGG(id)
        INTO v_company_ids
        FROM public.companies
        WHERE is_active = true;
        RETURN COALESCE(v_company_ids, ARRAY[]::UUID[]);
    END IF;
    
    -- Partner/Reseller: شركات التينانتات التابعة له ضمن البراندات المسموح بها
    IF is_partner_or_reseller(p_user_id) THEN
        SELECT ARRAY_AGG(c.id)
        INTO v_company_ids
        FROM public.companies c
        WHERE c.tenant_id = ANY(get_partner_tenant_ids(p_user_id))
          AND c.is_active = true;
        RETURN COALESCE(v_company_ids, ARRAY[]::UUID[]);
    END IF;
    
    -- الحصول على بيانات المستخدم
    SELECT tenant_id, company_id 
    INTO v_user_tenant_id, v_user_company_id
    FROM public.user_profiles
    WHERE id = p_user_id;
    
    IF v_user_tenant_id IS NULL THEN
        RETURN ARRAY[]::UUID[];
    END IF;
    
    -- Tenant Owner يرى كل شركات التينانت
    IF is_tenant_owner(p_user_id) THEN
        RETURN get_tenant_company_ids(v_user_tenant_id);
    END IF;
    
    -- المستخدم العادي: الشركة الافتراضية + الشركات المُعينة عبر user_roles
    SELECT ARRAY_AGG(DISTINCT company_id)
    INTO v_company_ids
    FROM (
        -- الشركة الافتراضية
        SELECT v_user_company_id AS company_id
        WHERE v_user_company_id IS NOT NULL
        UNION
        -- الشركات من user_roles
        SELECT ur.company_id
        FROM public.user_roles ur
        WHERE ur.user_id = p_user_id
          AND ur.is_active = true
          AND ur.company_id IS NOT NULL
    ) AS accessible;
    
    RETURN COALESCE(v_company_ids, ARRAY[]::UUID[]);
EXCEPTION WHEN OTHERS THEN
    RETURN ARRAY[]::UUID[];
END;
$$;


--
-- Name: get_user_accessible_funds(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_user_accessible_funds(p_user_id uuid DEFAULT auth.uid()) RETURNS TABLE(fund_account_id uuid, can_deposit boolean, can_withdraw boolean, can_transfer boolean, is_primary boolean)
    LANGUAGE plpgsql STABLE SECURITY DEFINER
    AS $$
BEGIN
    -- Platform/Tenant/Company admins see all
    IF is_super_admin(p_user_id) OR is_tenant_admin(p_user_id) OR is_company_admin(p_user_id) THEN
        RETURN QUERY
        SELECT coa.id, true, true, true, false
        FROM chart_of_accounts coa
        WHERE coa.account_type IN ('cash', 'bank')
          AND coa.is_active = true
          AND coa.tenant_id = get_current_tenant_id();
        RETURN;
    END IF;
    
    -- Regular users - assigned funds only
    RETURN QUERY
    SELECT 
        ufp.fund_account_id,
        ufp.can_deposit,
        ufp.can_withdraw,
        ufp.can_transfer,
        ufp.is_primary
    FROM user_fund_permissions ufp
    WHERE ufp.user_id = p_user_id
      AND ufp.can_view = true;
END;
$$;


--
-- Name: get_user_accessible_warehouses(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_user_accessible_warehouses(p_user_id uuid DEFAULT auth.uid()) RETURNS TABLE(warehouse_id uuid, can_receive boolean, can_issue boolean, can_transfer boolean, can_count boolean, is_keeper boolean)
    LANGUAGE plpgsql STABLE SECURITY DEFINER
    AS $$
BEGIN
    IF is_super_admin(p_user_id) OR is_tenant_admin(p_user_id) OR is_company_admin(p_user_id) THEN
        RETURN QUERY
        SELECT w.id, true, true, true, true, false
        FROM warehouses w
        WHERE w.is_active = true
          AND w.tenant_id = get_current_tenant_id();
        RETURN;
    END IF;
    
    RETURN QUERY
    SELECT 
        uwp.warehouse_id,
        uwp.can_receive,
        uwp.can_issue,
        uwp.can_transfer,
        uwp.can_count,
        uwp.is_keeper
    FROM user_warehouse_permissions uwp
    WHERE uwp.user_id = p_user_id
      AND uwp.can_view = true;
END;
$$;


--
-- Name: get_user_allowed_modules(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_user_allowed_modules(p_user_id uuid) RETURNS TABLE(module_code character varying, name_ar character varying, name_en character varying, name_de character varying, name_tr character varying, name_ru character varying, name_uk character varying, name_it character varying, name_pl character varying, name_ro character varying, description_ar text, description_en text, icon character varying, color character varying, category character varying, display_order integer, is_core boolean, is_beta boolean, requires_setup boolean, is_enabled boolean, requires_upgrade boolean, can_view boolean, can_create boolean, can_edit boolean, can_delete boolean, can_export boolean, can_import boolean, can_approve boolean, can_manage_settings boolean)
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_tenant_id UUID;
    v_company_id UUID;
BEGIN
    -- الحصول على tenant_id و company_id للمستخدم
    SELECT up.tenant_id, up.company_id
    INTO v_tenant_id, v_company_id
    FROM user_profiles up
    WHERE up.id = p_user_id;
    
    -- إذا لم يوجد user_profile، إرجاع فارغ
    IF v_tenant_id IS NULL THEN
        RETURN;
    END IF;
    
    -- إرجاع الموديولات مع الصلاحيات
    RETURN QUERY
    SELECT 
        m.module_code,
        m.name_ar,
        m.name_en,
        m.name_de,
        m.name_tr,
        m.name_ru,
        m.name_uk,
        m.name_it,
        m.name_pl,
        m.name_ro,
        m.description_ar,
        m.description_en,
        m.icon,
        m.color,
        m.category,
        m.display_order,
        m.is_core,
        m.is_beta,
        m.requires_setup,
        
        -- التحقق من تفعيل الموديول للـ tenant
        COALESCE(tm.is_active, false) as is_enabled,
        
        -- التحقق من الحاجة للترقية
        CASE 
            WHEN tm.is_active = false THEN true
            ELSE false
        END as requires_upgrade,
        
        -- الصلاحيات من user_module_permissions (أو افتراضي true إذا لم توجد)
        COALESCE(ump.can_view, true) as can_view,
        COALESCE(ump.can_create, false) as can_create,
        COALESCE(ump.can_edit, false) as can_edit,
        COALESCE(ump.can_delete, false) as can_delete,
        COALESCE(ump.can_export, false) as can_export,
        COALESCE(ump.can_import, false) as can_import,
        COALESCE(ump.can_approve, false) as can_approve,
        COALESCE(ump.can_manage_settings, false) as can_manage_settings
        
    FROM modules m
    LEFT JOIN tenant_modules tm 
        ON m.module_code = tm.module_code 
        AND tm.tenant_id = v_tenant_id
    LEFT JOIN user_module_permissions ump
        ON m.module_code = ump.module_code
        AND ump.user_id = p_user_id
        AND ump.tenant_id = v_tenant_id
        AND ump.company_id = v_company_id
    WHERE m.is_active = true
    ORDER BY m.display_order;
    
END;
$$;


--
-- Name: get_user_brand_id(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_user_brand_id(p_user_id uuid DEFAULT auth.uid()) RETURNS uuid
    LANGUAGE plpgsql STABLE SECURITY DEFINER
    AS $$
DECLARE
    v_product_id UUID;
    v_tenant_id UUID;
BEGIN
    -- الحصول على tenant_id للمستخدم
    SELECT tenant_id INTO v_tenant_id
    FROM public.user_profiles
    WHERE id = p_user_id;
    
    IF v_tenant_id IS NULL THEN
        RETURN NULL;
    END IF;
    
    -- الحصول على product_id من tenant
    SELECT product_id INTO v_product_id
    FROM public.tenants
    WHERE id = v_tenant_id;
    
    RETURN v_product_id;
EXCEPTION WHEN OTHERS THEN
    RETURN NULL;
END;
$$;


--
-- Name: get_user_companies(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_user_companies(p_user_id uuid DEFAULT NULL::uuid) RETURNS TABLE(id uuid, code character varying, name character varying, name_ar character varying, name_en character varying, business_type character varying, company_type character varying, is_active boolean, is_current boolean)
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
    v_user_id UUID;
    v_tenant_id UUID;
    v_current_company_id UUID;
BEGIN
    -- تحديد المستخدم
    v_user_id := COALESCE(p_user_id, auth.uid());
    
    IF v_user_id IS NULL THEN
        RAISE EXCEPTION 'User ID is required';
    END IF;
    
    -- الحصول على tenant_id و company_id الحالي
    SELECT up.tenant_id, up.company_id
    INTO v_tenant_id, v_current_company_id
    FROM user_profiles up
    WHERE up.id = v_user_id;
    
    IF v_tenant_id IS NULL THEN
        RAISE EXCEPTION 'User not found or not assigned to a tenant';
    END IF;
    
    -- إرجاع جميع الشركات التابعة لنفس الـ tenant
    RETURN QUERY
    SELECT 
        c.id,
        c.code,
        c.name,
        c.name_ar,
        c.name_en,
        c.business_type,
        c.company_type,
        c.is_active,
        (c.id = v_current_company_id) AS is_current
    FROM companies c
    WHERE c.tenant_id = v_tenant_id
    ORDER BY 
        c.company_type DESC,  -- production أولاً
        c.created_at ASC;
END;
$$;


--
-- Name: get_user_company_id(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_user_company_id(p_user_id uuid DEFAULT auth.uid()) RETURNS uuid
    LANGUAGE plpgsql STABLE SECURITY DEFINER
    AS $$
DECLARE
    v_company_id UUID;
BEGIN
    SELECT company_id INTO v_company_id
    FROM public.user_profiles
    WHERE id = p_user_id;
    
    RETURN v_company_id;
EXCEPTION WHEN OTHERS THEN
    RETURN NULL;
END;
$$;


--
-- Name: get_user_full_permissions(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_user_full_permissions(p_user_id uuid DEFAULT auth.uid()) RETURNS jsonb
    LANGUAGE plpgsql STABLE SECURITY DEFINER
    AS $$
DECLARE
    v_result JSONB;
    v_roles JSONB;
    v_funds JSONB;
    v_warehouses JSONB;
    v_branches JSONB;
    v_level TEXT;
BEGIN
    -- Get role level
    v_level := get_user_role_level(p_user_id);
    
    -- Get roles
    SELECT jsonb_agg(jsonb_build_object(
        'role_code', r.code,
        'role_name', r.name_ar,
        'level', COALESCE(r.permissions->>'level', 'operations'),
        'permissions', r.permissions
    ))
    INTO v_roles
    FROM user_roles ur
    JOIN roles r ON ur.role_id = r.id
    WHERE ur.user_id = p_user_id
      AND ur.is_active = true;
    
    -- Get funds (only for non-admins)
    IF v_level NOT IN ('platform', 'tenant', 'company') THEN
        SELECT jsonb_agg(jsonb_build_object(
            'fund_id', ufp.fund_account_id,
            'can_deposit', ufp.can_deposit,
            'can_withdraw', ufp.can_withdraw,
            'is_primary', ufp.is_primary
        ))
        INTO v_funds
        FROM user_fund_permissions ufp
        WHERE ufp.user_id = p_user_id AND ufp.can_view = true;
    ELSE
        v_funds := '"all"'::jsonb;
    END IF;
    
    -- Get warehouses
    IF v_level NOT IN ('platform', 'tenant', 'company') THEN
        SELECT jsonb_agg(jsonb_build_object(
            'warehouse_id', uwp.warehouse_id,
            'is_keeper', uwp.is_keeper,
            'can_receive', uwp.can_receive,
            'can_issue', uwp.can_issue
        ))
        INTO v_warehouses
        FROM user_warehouse_permissions uwp
        WHERE uwp.user_id = p_user_id AND uwp.can_view = true;
    ELSE
        v_warehouses := '"all"'::jsonb;
    END IF;
    
    -- Get branches
    IF v_level NOT IN ('platform', 'tenant', 'company') THEN
        SELECT jsonb_agg(jsonb_build_object(
            'branch_id', ubp.branch_id,
            'is_primary', ubp.is_primary,
            'can_manage', ubp.can_manage
        ))
        INTO v_branches
        FROM user_branch_permissions ubp
        WHERE ubp.user_id = p_user_id AND ubp.can_access = true;
    ELSE
        v_branches := '"all"'::jsonb;
    END IF;
    
    -- Build result
    v_result := jsonb_build_object(
        'user_id', p_user_id,
        'is_super_admin', is_super_admin(p_user_id),
        'is_tenant_admin', is_tenant_admin(p_user_id),
        'is_company_admin', is_company_admin(p_user_id),
        'level', v_level,
        'roles', COALESCE(v_roles, '[]'::jsonb),
        'funds', COALESCE(v_funds, '[]'::jsonb),
        'warehouses', COALESCE(v_warehouses, '[]'::jsonb),
        'branches', COALESCE(v_branches, '[]'::jsonb)
    );
    
    RETURN v_result;
END;
$$;


--
-- Name: get_user_module_permissions(uuid, character varying); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_user_module_permissions(p_user_id uuid, p_module_code character varying) RETURNS TABLE(can_view boolean, can_create boolean, can_edit boolean, can_delete boolean, can_export boolean, can_import boolean, can_approve boolean, can_manage_settings boolean)
    LANGUAGE plpgsql STABLE SECURITY DEFINER
    AS $$
DECLARE
    v_tenant_id UUID;
    v_company_id UUID;
    v_is_admin BOOLEAN;
BEGIN
    SELECT up.tenant_id, up.company_id, up.is_admin
    INTO v_tenant_id, v_company_id, v_is_admin
    FROM user_profiles up
    WHERE up.id = p_user_id;
    
    IF v_is_admin THEN
        RETURN QUERY SELECT true, true, true, true, true, true, true, true;
        RETURN;
    END IF;
    
    RETURN QUERY
    SELECT 
        ump.can_view,
        ump.can_create,
        ump.can_edit,
        ump.can_delete,
        ump.can_export,
        ump.can_import,
        ump.can_approve,
        ump.can_manage_settings
    FROM user_module_permissions ump
    WHERE ump.user_id = p_user_id
      AND ump.tenant_id = v_tenant_id
      AND ump.company_id = v_company_id
      AND ump.module_code = p_module_code
      AND ump.is_active = true
      AND (ump.expires_at IS NULL OR ump.expires_at > NOW());
    
    IF NOT FOUND THEN
        RETURN QUERY SELECT false, false, false, false, false, false, false, false;
    END IF;
END;
$$;


--
-- Name: FUNCTION get_user_module_permissions(p_user_id uuid, p_module_code character varying); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION public.get_user_module_permissions(p_user_id uuid, p_module_code character varying) IS 'الحصول على كل صلاحيات المستخدم على موديول';


--
-- Name: get_user_permissions(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_user_permissions(p_user_id uuid DEFAULT auth.uid()) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_permissions JSONB;
    v_roles JSONB;
BEGIN
    -- الحصول على Roles والصلاحيات
    SELECT jsonb_agg(
        jsonb_build_object(
            'role_code', r.code,
            'role_name', r.name_ar,
            'is_super_admin', r.is_super_admin,
            'permissions', r.permissions
        )
    ) INTO v_roles
    FROM user_roles ur
    JOIN roles r ON ur.role_id = r.id
    WHERE ur.user_id = p_user_id
      AND ur.is_active = true;
    
    SELECT jsonb_build_object(
        'user_id', p_user_id,
        'is_super_admin', is_super_admin(p_user_id),
        'roles', COALESCE(v_roles, '[]'::jsonb)
    ) INTO v_permissions;
    
    RETURN v_permissions;
END;
$$;


--
-- Name: get_user_product_id(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_user_product_id(p_user_id uuid DEFAULT auth.uid()) RETURNS uuid
    LANGUAGE plpgsql STABLE SECURITY DEFINER
    AS $$
BEGIN
    RETURN get_user_brand_id(p_user_id);
END;
$$;


--
-- Name: get_user_role_level(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_user_role_level(p_user_id uuid DEFAULT auth.uid()) RETURNS text
    LANGUAGE plpgsql STABLE SECURITY DEFINER
    AS $$
DECLARE
    v_level TEXT;
BEGIN
    -- التحقق من super_admin أولاً
    IF is_super_admin(p_user_id) THEN
        RETURN 'platform';
    END IF;
    
    -- الحصول على أعلى مستوى
    SELECT COALESCE(
        (r.permissions->>'level')::TEXT,
        'operations'
    ) INTO v_level
    FROM user_roles ur
    JOIN roles r ON ur.role_id = r.id
    WHERE ur.user_id = p_user_id
      AND ur.is_active = true
    ORDER BY 
        CASE (r.permissions->>'level')::TEXT
            WHEN 'tenant' THEN 1
            WHEN 'company' THEN 2
            WHEN 'branch' THEN 3
            WHEN 'operations' THEN 4
            ELSE 5
        END
    LIMIT 1;
    
    RETURN COALESCE(v_level, 'none');
END;
$$;


--
-- Name: get_user_roles(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.get_user_roles(p_user_id uuid) RETURNS TABLE(role_id uuid, role_code text, role_name_ar text, role_name_en text, role_level text, is_active boolean)
    LANGUAGE plpgsql STABLE SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
BEGIN
    RETURN QUERY
    SELECT 
        r.id AS role_id,
        r.code AS role_code,
        r.name_ar AS role_name_ar,
        r.name_en AS role_name_en,
        r.level AS role_level,
        ur.is_active
    FROM user_roles ur
    JOIN roles r ON ur.role_id = r.id
    WHERE ur.user_id = p_user_id
      AND ur.is_active = true;
EXCEPTION
    WHEN OTHERS THEN
        -- Return empty on error
        RETURN;
END;
$$;


