-- Name: FUNCTION is_super_admin(); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION public.is_super_admin() IS 'التحقق من أن المستخدم الحالي هو Super Admin';


--
-- Name: is_super_admin(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.is_super_admin(p_user_id uuid DEFAULT auth.uid()) RETURNS boolean
    LANGUAGE plpgsql STABLE SECURITY DEFINER
    AS $$
BEGIN
    RETURN is_platform_owner(p_user_id);
END;
$$;


--
-- Name: is_tenant_admin(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.is_tenant_admin(p_user_id uuid DEFAULT auth.uid()) RETURNS boolean
    LANGUAGE plpgsql STABLE SECURITY DEFINER
    AS $$
BEGIN
    -- Platform Owner أعلى من Tenant Admin
    IF is_platform_owner(p_user_id) THEN
        RETURN true;
    END IF;
    
    -- Tenant Owner هو tenant_admin بالضرورة
    IF is_tenant_owner(p_user_id) THEN
        RETURN true;
    END IF;
    
    -- التحقق من دور tenant_admin
    RETURN EXISTS (
        SELECT 1 FROM public.user_roles ur
        JOIN public.roles r ON ur.role_id = r.id
        WHERE ur.user_id = p_user_id
          AND r.code = 'tenant_admin'
          AND ur.is_active = true
    );
EXCEPTION WHEN OTHERS THEN
    RETURN false;
END;
$$;


--
-- Name: is_tenant_owner(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.is_tenant_owner(p_user_id uuid DEFAULT auth.uid()) RETURNS boolean
    LANGUAGE plpgsql STABLE SECURITY DEFINER
    AS $$
DECLARE
    v_user_email TEXT;
    v_tenant_id UUID;
    v_owner_email TEXT;
BEGIN
    -- Platform Admin يعتبر أعلى من Tenant Owner
    IF is_platform_owner(p_user_id) THEN
        RETURN true;
    END IF;
    
    -- الحصول على بريد المستخدم و tenant_id
    SELECT email, tenant_id INTO v_user_email, v_tenant_id
    FROM public.user_profiles
    WHERE id = p_user_id;
    
    IF v_tenant_id IS NULL THEN
        RETURN false;
    END IF;
    
    -- التحقق من أن المستخدم هو صاحب التينانت
    SELECT owner_email INTO v_owner_email
    FROM public.tenants
    WHERE id = v_tenant_id;
    
    RETURN LOWER(v_user_email) = LOWER(v_owner_email);
EXCEPTION WHEN OTHERS THEN
    RETURN false;
END;
$$;


--
-- Name: is_valid_stage_transition(text, text, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.is_valid_stage_transition(p_type text, p_from text, p_to text) RETURNS boolean
    LANGUAGE plpgsql IMMUTABLE
    AS $$
BEGIN
    IF p_type = 'purchase' THEN
        RETURN (p_from, p_to) IN (
            ('draft', 'confirmed'),
            ('draft', 'quotation'),
            ('draft', 'order'),
            ('draft', 'invoice'),
            ('draft', 'cancelled'),
            ('confirmed', 'partially_received'),
            ('confirmed', 'received'),
            ('confirmed', 'posted'),
            ('confirmed', 'draft'),
            ('confirmed', 'invoice'),
            ('confirmed', 'receipt'),
            ('confirmed', 'cancelled'),
            ('quotation', 'order'),
            ('quotation', 'invoice'),
            ('quotation', 'cancelled'),
            ('order', 'approved'),
            ('order', 'cancelled'),
            ('approved', 'receipt'),
            ('approved', 'invoice'),
            ('approved', 'cancelled'),
            ('receipt', 'invoice'),
            ('receipt', 'cancelled'),
            ('partially_received', 'received'),
            ('partially_received', 'posted'),
            ('partially_received', 'cancelled'),
            ('received', 'posted'),
            ('received', 'cancelled'),
            ('invoice', 'posted'),
            ('invoice', 'cancelled'),
            ('posted', 'partial_paid'),
            ('posted', 'paid'),
            ('partial_paid', 'paid'),
            ('cancelled', 'draft')
        );
    END IF;

    IF p_type = 'sale' THEN
        RETURN (p_from, p_to) IN (
            ('draft', 'confirmed'),
            ('draft', 'quotation'),
            ('draft', 'order'),
            ('draft', 'invoice'),
            ('draft', 'cancelled'),
            -- المسار العادي
            ('confirmed', 'in_delivery'),
            ('confirmed', 'delivery'),
            ('confirmed', 'invoice'),
            ('confirmed', 'cancelled'),
            -- مسار التحميل
            ('in_delivery', 'delivered'),
            ('in_delivery', 'confirmed'),
            ('in_delivery', 'cancelled'),
            -- مسار بعد التسليم
            ('delivered', 'invoice'),
            ('delivered', 'posted'),
            ('delivered', 'cancelled'),
            -- باقي المسار
            ('quotation', 'reservation'),
            ('quotation', 'order'),
            ('quotation', 'cancelled'),
            ('reservation', 'order'),
            ('reservation', 'cancelled'),
            ('order', 'delivery'),
            ('order', 'in_delivery'),
            ('order', 'invoice'),
            ('order', 'cancelled'),
            ('delivery', 'invoice'),
            ('delivery', 'cancelled'),
            ('invoice', 'posted'),
            ('invoice', 'cancelled'),
            ('posted', 'partial_paid'),
            ('posted', 'paid'),
            ('partial_paid', 'paid'),
            ('cancelled', 'draft')
        );
    END IF;

    RETURN false;
END;
$$;


--
-- Name: is_whitelabel_partner(uuid); Type: FUNCTION; Schema: public; Owner: -
