$$;


--
-- Name: link_existing_customer_to_auth(uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.link_existing_customer_to_auth(p_customer_id uuid, p_auth_user_id uuid) RETURNS boolean
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_customer_email VARCHAR;
    v_tenant_id UUID;
    v_company_id UUID;
BEGIN
    -- الحصول على بيانات العميل
    SELECT email, tenant_id, company_id
    INTO v_customer_email, v_tenant_id, v_company_id
    FROM customers
    WHERE id = p_customer_id;
    
    IF NOT FOUND THEN
        RAISE EXCEPTION 'Customer not found';
    END IF;
    
    -- تحديث customers
    UPDATE customers
    SET auth_user_id = p_auth_user_id
    WHERE id = p_customer_id;
    
    -- إنشاء أو تحديث user_profiles
    INSERT INTO user_profiles (
        id,
        email,
        role,
        tenant_id,
        company_id,
        customer_id
    )
    VALUES (
        p_auth_user_id,
        v_customer_email,
        'customer',
        v_tenant_id,
        v_company_id,
        p_customer_id
    )
    ON CONFLICT (id) DO UPDATE SET
        customer_id = EXCLUDED.customer_id,
        role = 'customer';
    
    RETURN TRUE;
END;
$$;


--
-- Name: FUNCTION link_existing_customer_to_auth(p_customer_id uuid, p_auth_user_id uuid); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION public.link_existing_customer_to_auth(p_customer_id uuid, p_auth_user_id uuid) IS 'ربط عميل موجود بحساب auth.users';


--
-- Name: link_user_to_tenant(uuid, uuid, character varying); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.link_user_to_tenant(p_tenant_id uuid, p_user_id uuid, p_role character varying DEFAULT 'member'::character varying) RETURNS uuid
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_link_id UUID;
BEGIN
    INSERT INTO tenant_users (tenant_id, user_id, role)
    VALUES (p_tenant_id, p_user_id, p_role)
    ON CONFLICT (tenant_id, user_id) 
    DO UPDATE SET 
        role = EXCLUDED.role,
        is_active = true,
        updated_at = NOW()
    RETURNING id INTO v_link_id;
    
    RETURN v_link_id;
END;
$$;


--
-- Name: log_audit(character varying, character varying, uuid, character varying, jsonb, jsonb, jsonb, character varying); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.log_audit(p_action character varying, p_entity_type character varying, p_entity_id uuid DEFAULT NULL::uuid, p_entity_name character varying DEFAULT NULL::character varying, p_old_values jsonb DEFAULT NULL::jsonb, p_new_values jsonb DEFAULT NULL::jsonb, p_metadata jsonb DEFAULT '{}'::jsonb, p_severity character varying DEFAULT 'info'::character varying) RETURNS uuid
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_audit_id UUID;
    v_changes JSONB;
BEGIN
    -- حساب التغييرات
    IF p_old_values IS NOT NULL AND p_new_values IS NOT NULL THEN
        SELECT jsonb_object_agg(key, value)
        INTO v_changes
        FROM jsonb_each(p_new_values)
        WHERE p_old_values -> key IS DISTINCT FROM value;
    END IF;
    
    INSERT INTO audit_logs (
        tenant_id,
        user_id,
        action,
        entity_type,
        entity_id,
        entity_name,
        old_values,
        new_values,
        changes,
        metadata,
        severity
    ) VALUES (
        get_current_tenant_id(),
        auth.uid(),
        p_action,
        p_entity_type,
        p_entity_id,
        p_entity_name,
        p_old_values,
        p_new_values,
        v_changes,
        p_metadata,
        p_severity
    )
    RETURNING id INTO v_audit_id;
    
    RETURN v_audit_id;
END;
$$;


--
-- Name: log_sensitive_changes(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.log_sensitive_changes() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_user_id UUID := auth.uid();
    v_changes JSONB;
BEGIN
    -- تسجيل التغييرات في الجداول الحساسة
    IF TG_OP = 'UPDATE' THEN
        v_changes := jsonb_build_object(
            'old', to_jsonb(OLD),
            'new', to_jsonb(NEW)
        );
    ELSIF TG_OP = 'DELETE' THEN
        v_changes := to_jsonb(OLD);
    ELSIF TG_OP = 'INSERT' THEN
        v_changes := to_jsonb(NEW);
    END IF;

    -- إدراج في جدول التدقيق إذا كان موجوداً
    IF EXISTS (SELECT 1 FROM information_schema.tables WHERE table_schema = 'public' AND table_name = 'audit_logs') THEN
        INSERT INTO public.audit_logs (
            user_id,
            action,
            table_name,
            record_id,
            changes,
            created_at
        ) VALUES (
            v_user_id,
            TG_OP,
            TG_TABLE_NAME,
            COALESCE(NEW.id, OLD.id),
            v_changes,
            NOW()
        );
    END IF;

    RETURN COALESCE(NEW, OLD);
END;
$$;


--
-- Name: merge_carts(uuid, uuid, character varying); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.merge_carts(p_tenant_id uuid, p_customer_id uuid, p_session_id character varying) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_guest_cart_id UUID;
    v_customer_cart_id UUID;
    v_merged_count INT := 0;
BEGIN
    -- الحصول على سلة الزائر
    SELECT id INTO v_guest_cart_id
    FROM shopping_carts
    WHERE tenant_id = p_tenant_id
      AND session_id = p_session_id
      AND status = 'active'
    LIMIT 1;
    
    IF v_guest_cart_id IS NULL THEN
        RETURN jsonb_build_object(
            'success', false,
            'message', 'سلة الزائر غير موجودة'
        );
    END IF;
    
    -- الحصول على أو إنشاء سلة العميل
    v_customer_cart_id := get_or_create_cart(
        p_tenant_id,
        (SELECT company_id FROM shopping_carts WHERE id = v_guest_cart_id),
        p_customer_id,
        NULL
    );
    
    -- دمج العناصر
    WITH moved_items AS (
        INSERT INTO shopping_cart_items (
            cart_id,
            product_id,
            product_variant_id,
            quantity,
            unit_price,
            original_price,
            discount_percent,
            notes
        )
        SELECT 
            v_customer_cart_id,
            product_id,
            product_variant_id,
            quantity,
            unit_price,
            original_price,
            discount_percent,
            notes
        FROM shopping_cart_items
        WHERE cart_id = v_guest_cart_id
        ON CONFLICT (cart_id, product_id) 
        DO UPDATE SET
            quantity = shopping_cart_items.quantity + EXCLUDED.quantity
        RETURNING id
    )
    SELECT COUNT(*) INTO v_merged_count FROM moved_items;
    
    -- حذف سلة الزائر
    DELETE FROM shopping_carts WHERE id = v_guest_cart_id;
    
    -- تحديث المجاميع
    PERFORM update_cart_totals(v_customer_cart_id);
    
    RETURN jsonb_build_object(
        'success', true,
        'customer_cart_id', v_customer_cart_id,
        'merged_items', v_merged_count,
        'message', 'تم دمج السلة بنجاح'
    );
END;
$$;


--
-- Name: FUNCTION merge_carts(p_tenant_id uuid, p_customer_id uuid, p_session_id character varying); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION public.merge_carts(p_tenant_id uuid, p_customer_id uuid, p_session_id character varying) IS 'دمج سلة الزائر مع سلة العميل عند تسجيل الدخول';


--
-- Name: move_account_to_parent(uuid, uuid, text, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.move_account_to_parent(p_account_id uuid, p_new_parent_id uuid, p_notes text DEFAULT NULL::text, p_user_id uuid DEFAULT NULL::uuid) RETURNS boolean
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_account RECORD;
    v_new_parent RECORD;
    v_old_parent_id UUID;
    v_tenant_id UUID;
    v_company_id UUID;
BEGIN
    -- Get account details
    SELECT * INTO v_account
    FROM chart_of_accounts
    WHERE id = p_account_id;
    
    IF v_account IS NULL THEN
        RAISE EXCEPTION 'Account not found';
    END IF;
    
    -- Get new parent details
    SELECT * INTO v_new_parent
    FROM chart_of_accounts
    WHERE id = p_new_parent_id;
    
    IF v_new_parent IS NULL THEN
        RAISE EXCEPTION 'New parent account not found';
    END IF;
    
    -- Validate same company
    IF v_account.company_id != v_new_parent.company_id THEN
        RAISE EXCEPTION 'Account and new parent must belong to the same company';
    END IF;
    
    -- Validate new parent is a group
    IF NOT v_new_parent.is_group THEN
        RAISE EXCEPTION 'New parent must be a group account';
    END IF;
    
    -- Prevent moving to self or descendant
    IF p_account_id = p_new_parent_id THEN
        RAISE EXCEPTION 'Cannot move account to itself';
    END IF;
    
    -- Check if new parent is a descendant of the account
    IF EXISTS (
        WITH RECURSIVE descendants AS (
            SELECT id, parent_id
            FROM chart_of_accounts
            WHERE parent_id = p_account_id
            
            UNION ALL
            
            SELECT c.id, c.parent_id
            FROM chart_of_accounts c
            INNER JOIN descendants d ON c.parent_id = d.id
        )
        SELECT 1 FROM descendants WHERE id = p_new_parent_id
    ) THEN
        RAISE EXCEPTION 'Cannot move account to its own descendant';
    END IF;
    
    v_tenant_id := v_account.tenant_id;
    v_company_id := v_account.company_id;
    v_old_parent_id := v_account.parent_id;
    
    -- Update account parent
    UPDATE chart_of_accounts
    SET parent_id = p_new_parent_id,
        updated_at = NOW()
    WHERE id = p_account_id;
    
    -- Record the move
    INSERT INTO account_transfers (
        tenant_id,
        company_id,
        source_account_id,
        target_account_id,
        transfer_type,
        notes,
        created_by
    ) VALUES (
        v_tenant_id,
        v_company_id,
        v_old_parent_id,
        p_new_parent_id,
        'move_account',
        COALESCE(p_notes, format('Moved account %s from parent %s to %s',
            v_account.account_code,
            (SELECT account_code FROM chart_of_accounts WHERE id = v_old_parent_id),
            v_new_parent.account_code
        )),
        p_user_id
    );
    
    RAISE NOTICE 'Account % moved from parent % to %', 
        v_account.account_code,
        (SELECT account_code FROM chart_of_accounts WHERE id = v_old_parent_id),
        v_new_parent.account_code;
    
    RETURN TRUE;
END;
$$;


--
-- Name: FUNCTION move_account_to_parent(p_account_id uuid, p_new_parent_id uuid, p_notes text, p_user_id uuid); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION public.move_account_to_parent(p_account_id uuid, p_new_parent_id uuid, p_notes text, p_user_id uuid) IS 'Move an account to a different parent group';


--
-- Name: notify_n8n_webhook(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.notify_n8n_webhook() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
  payload jsonb;
  webhook_url text;
BEGIN
  -- ⚠️ IMPORTANT: Replace with your actual n8n webhook URL
  -- When running locally: http://localhost:5678/webhook/texacore-erp-events
  -- When on server: https://your-n8n-domain.com/webhook/texacore-erp-events
  webhook_url := 'http://localhost:5678/webhook/texacore-erp-events';
  
  -- Build the payload with tenant isolation data
  payload := jsonb_build_object(
    'type', TG_OP,
    'table', TG_TABLE_NAME,
    'schema', TG_TABLE_SCHEMA,
    'timestamp', now()::text,
    'tenant_id', CASE 
      WHEN TG_OP = 'DELETE' THEN OLD.tenant_id::text
      ELSE NEW.tenant_id::text
    END,
    'record', CASE 
      WHEN TG_OP = 'DELETE' THEN row_to_json(OLD)::jsonb
      ELSE row_to_json(NEW)::jsonb
    END,
    'old_record', CASE 
      WHEN TG_OP = 'UPDATE' THEN row_to_json(OLD)::jsonb
      ELSE NULL
    END
  );

  -- Send HTTP request to n8n (using pg_net extension)
  -- Note: pg_net must be enabled in Supabase Dashboard → Database → Extensions
  BEGIN
    PERFORM net.http_post(
      url := webhook_url,
      headers := jsonb_build_object(
        'Content-Type', 'application/json',
        'X-Webhook-Secret', 'texacore-n8n-secret-2026'
      ),
      body := payload
    );
  EXCEPTION WHEN OTHERS THEN
    -- Don't fail the transaction if webhook fails
    RAISE WARNING 'n8n webhook failed: %', SQLERRM;
  END;

  RETURN COALESCE(NEW, OLD);
END;
$$;


--
-- Name: on_company_created(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.on_company_created() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
