--
-- Name: post_journal_entry(uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.post_journal_entry(p_entry_id uuid, p_user_id uuid) RETURNS boolean
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
    v_entry RECORD;
    v_line RECORD;
BEGIN
    -- Input Validation
    IF p_entry_id IS NULL THEN
        RAISE EXCEPTION 'رقم القيد مطلوب';
    END IF;

    -- Fetch Entry
    SELECT * INTO v_entry
    FROM journal_entries
    WHERE id = p_entry_id;
    
    IF NOT FOUND THEN
        RAISE EXCEPTION 'القيد غير موجود: %', p_entry_id;
    END IF;
    
    IF v_entry.is_posted THEN
        RAISE EXCEPTION 'القيد مرحّل مسبقاً: %', v_entry.entry_number;
    END IF;
    
    -- Strict Balance Check
    IF ABS(v_entry.total_debit - v_entry.total_credit) > 0.01 THEN
        RAISE EXCEPTION 'القيد غير متوازن! الفرق: % (مدين: %, دائن: %)', 
            ABS(v_entry.total_debit - v_entry.total_credit), v_entry.total_debit, v_entry.total_credit;
    END IF;

    -- Ensure lines exist
    IF NOT EXISTS (SELECT 1 FROM journal_entry_lines WHERE entry_id = p_entry_id) THEN
        RAISE EXCEPTION 'القيد لا يحتوي على أسطر';
    END IF;
    
    -- Process Lines: ALWAYS use Net (Dr-Cr)
    -- Assets/Expenses → positive when debited
    -- Liabilities/Revenue → negative when credited
    FOR v_line IN 
        SELECT * FROM journal_entry_lines WHERE entry_id = p_entry_id
    LOOP
        UPDATE chart_of_accounts
        SET current_balance = COALESCE(current_balance, 0) + (v_line.debit - v_line.credit),
            updated_at = NOW()
        WHERE id = v_line.account_id;
    END LOOP;
    
    -- Mark as Posted
    UPDATE journal_entries
    SET is_posted = true,
        posted_at = NOW(),
        posted_by = p_user_id,
        status = 'posted'
    WHERE id = p_entry_id;
    
    RETURN true;
END;
$$;


--
-- Name: post_purchase_invoice(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.post_purchase_invoice(p_invoice_id uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_invoice    purchase_invoices%ROWTYPE;
    v_je_id      UUID;
    v_user_id    UUID;
    v_account_purchases UUID;
    v_account_ap        UUID;
    v_account_tax       UUID;
    v_net_amount NUMERIC(15,4);
    v_tax_amount NUMERIC(15,4);
    v_total      NUMERIC(15,4);
    v_line_num   INT := 0;
BEGIN
    v_user_id := auth.uid();
    
    -- جلب الفاتورة
    SELECT * INTO v_invoice FROM purchase_invoices WHERE id = p_invoice_id;
    
    IF NOT FOUND THEN
        RETURN jsonb_build_object('success', false, 'error', 'الفاتورة غير موجودة');
    END IF;
    
    IF v_invoice.is_posted = true THEN
        RETURN jsonb_build_object('success', false, 'error', 'الفاتورة مُرحَّلة مسبقاً');
    END IF;
    
    v_total := COALESCE(v_invoice.total_amount, 0);
    v_tax_amount := COALESCE(v_invoice.tax_amount, 0);
    v_net_amount := v_total - v_tax_amount;
    
    IF v_total <= 0 THEN
        RETURN jsonb_build_object('success', false, 'error', 'مبلغ الفاتورة صفر');
    END IF;
    
    -- ════════════════════════════════════════════════════════
    -- البحث عن الحسابات
    -- ════════════════════════════════════════════════════════
    SELECT id INTO v_account_purchases FROM chart_of_accounts
    WHERE tenant_id = v_invoice.tenant_id
      AND (company_id = v_invoice.company_id OR company_id IS NULL)
      AND account_code IN ('5100', '5000', '1400')
    ORDER BY CASE WHEN account_code = '5100' THEN 0 WHEN account_code = '5000' THEN 1 ELSE 2 END,
             CASE WHEN company_id = v_invoice.company_id THEN 0 ELSE 1 END
    LIMIT 1;
    
    -- ⚡ Fallback: إذا لم يجد الحسابات بالـ tenant_id, ابحث بالـ company_id فقط
    IF v_account_purchases IS NULL THEN
        SELECT id INTO v_account_purchases FROM chart_of_accounts
        WHERE company_id = v_invoice.company_id
          AND account_code IN ('5100', '5000', '1400')
        ORDER BY CASE WHEN account_code = '5100' THEN 0 WHEN account_code = '5000' THEN 1 ELSE 2 END
        LIMIT 1;
    END IF;
    
    -- ⚡ Fallback 2: ابحث بأي tenant/company متاح
    IF v_account_purchases IS NULL THEN
        SELECT id INTO v_account_purchases FROM chart_of_accounts
        WHERE account_code IN ('5100', '5000', '1400')
        ORDER BY CASE WHEN account_code = '5100' THEN 0 WHEN account_code = '5000' THEN 1 ELSE 2 END
        LIMIT 1;
    END IF;
    
    SELECT id INTO v_account_ap FROM chart_of_accounts
    WHERE tenant_id = v_invoice.tenant_id
      AND (company_id = v_invoice.company_id OR company_id IS NULL)
      AND account_code IN ('2100', '2000')
    ORDER BY CASE WHEN account_code = '2100' THEN 0 ELSE 1 END,
             CASE WHEN company_id = v_invoice.company_id THEN 0 ELSE 1 END
    LIMIT 1;
    
    -- ⚡ Fallback for AP
    IF v_account_ap IS NULL THEN
        SELECT id INTO v_account_ap FROM chart_of_accounts
        WHERE company_id = v_invoice.company_id
          AND account_code IN ('2100', '2000')
        ORDER BY CASE WHEN account_code = '2100' THEN 0 ELSE 1 END
        LIMIT 1;
    END IF;
    
    IF v_account_ap IS NULL THEN
        SELECT id INTO v_account_ap FROM chart_of_accounts
        WHERE account_code IN ('2100', '2000')
        ORDER BY CASE WHEN account_code = '2100' THEN 0 ELSE 1 END
        LIMIT 1;
    END IF;
    
    -- حساب الضريبة (اختياري)
    IF v_tax_amount > 0 THEN
        SELECT id INTO v_account_tax FROM chart_of_accounts
        WHERE tenant_id = v_invoice.tenant_id
          AND (company_id = v_invoice.company_id OR company_id IS NULL)
          AND account_code IN ('1510', '1500')
        ORDER BY CASE WHEN account_code = '1510' THEN 0 ELSE 1 END,
                 CASE WHEN company_id = v_invoice.company_id THEN 0 ELSE 1 END
        LIMIT 1;
    END IF;
    
    -- ════════════════════════════════════════════════════════
    -- التحقق من وجود الحسابات
    -- ════════════════════════════════════════════════════════
    IF v_account_purchases IS NULL THEN
        RETURN jsonb_build_object(
            'success', false, 
            'error', 'لم يتم العثور على حساب المشتريات (5100/5000/1400). يرجى إضافته في دليل الحسابات.',
            'invoice_id', p_invoice_id,
            'debug_tenant_id', v_invoice.tenant_id,
            'debug_company_id', v_invoice.company_id
        );
    END IF;
    
    IF v_account_ap IS NULL THEN
        RETURN jsonb_build_object(
            'success', false, 
            'error', 'لم يتم العثور على حساب الذمم الدائنة (2100/2000). يرجى إضافته في دليل الحسابات.',
            'invoice_id', p_invoice_id
        );
    END IF;
    
    -- ════════════════════════════════════════════════════════
    -- تحديث حالة الفاتورة أولاً
    -- ════════════════════════════════════════════════════════
    UPDATE purchase_invoices
    SET status = 'posted',
        is_posted = true,
        posted_at = NOW(),
        updated_at = NOW()
    WHERE id = p_invoice_id;
    
    -- ════════════════════════════════════════════════════════
    -- إنشاء القيد المحاسبي
    -- ════════════════════════════════════════════════════════
    INSERT INTO journal_entries (
        tenant_id, company_id, branch_id,
        entry_date, entry_type,
        description,
        reference_type, reference_id, reference_number,
        currency, exchange_rate,
        status, is_posted, posted_at, posted_by,
        created_by
    ) VALUES (
        v_invoice.tenant_id, v_invoice.company_id, v_invoice.branch_id,
        COALESCE(v_invoice.invoice_date, CURRENT_DATE), 'auto',
        'فاتورة مشتريات — ' || COALESCE(v_invoice.invoice_number, ''),
        'purchase_invoice', p_invoice_id, v_invoice.invoice_number,
        COALESCE(v_invoice.currency, 'SAR'), COALESCE(v_invoice.exchange_rate, 1),
        'posted', true, NOW(), v_user_id,
        v_user_id
    ) RETURNING id INTO v_je_id;
    
    -- مدين: المشتريات
    v_line_num := v_line_num + 1;
    INSERT INTO journal_entry_lines (
        tenant_id, entry_id, line_number,
        account_id, description,
        debit, credit,
        party_type, party_id
    ) VALUES (
        v_invoice.tenant_id, v_je_id, v_line_num,
        v_account_purchases,
        'مشتريات — ' || COALESCE(v_invoice.invoice_number, ''),
        CASE WHEN v_tax_amount > 0 AND v_account_tax IS NOT NULL 
             THEN v_net_amount ELSE v_total END,
        0,
        NULL, NULL
    );
    
    -- مدين: ضريبة المدخلات (إن وجدت)
    IF v_tax_amount > 0 AND v_account_tax IS NOT NULL THEN
        v_line_num := v_line_num + 1;
        INSERT INTO journal_entry_lines (
            tenant_id, entry_id, line_number,
            account_id, description,
            debit, credit
        ) VALUES (
            v_invoice.tenant_id, v_je_id, v_line_num,
            v_account_tax,
            'ضريبة مدخلات — ' || COALESCE(v_invoice.invoice_number, ''),
            v_tax_amount, 0
        );
    END IF;
    
    -- دائن: الذمم الدائنة
    v_line_num := v_line_num + 1;
    INSERT INTO journal_entry_lines (
        tenant_id, entry_id, line_number,
        account_id, description,
        debit, credit,
        party_type, party_id
    ) VALUES (
        v_invoice.tenant_id, v_je_id, v_line_num,
        v_account_ap,
        'ذمم دائنة — ' || COALESCE(v_invoice.supplier_name, '') || ' — ' || COALESCE(v_invoice.invoice_number, ''),
        0, v_total,
        'supplier', v_invoice.supplier_id
    );
    
    -- ربط القيد بالفاتورة
    UPDATE purchase_invoices SET journal_entry_id = v_je_id WHERE id = p_invoice_id;
    
    RETURN jsonb_build_object(
        'success', true,
        'invoice_id', p_invoice_id,
        'invoice_number', v_invoice.invoice_number,
        'journal_entry_id', v_je_id,
        'total_amount', v_total,
        'tax_amount', v_tax_amount,
        'message', 'تم ترحيل فاتورة المشتريات بنجاح'
    );

EXCEPTION WHEN OTHERS THEN
    -- إعادة حالة الفاتورة عند الخطأ
    UPDATE purchase_invoices SET status = 'draft', is_posted = false, posted_at = NULL WHERE id = p_invoice_id;
    RETURN jsonb_build_object('success', false, 'error', SQLERRM, 'detail', SQLSTATE, 'invoice_id', p_invoice_id);
END;
$$;


--
-- Name: FUNCTION post_purchase_invoice(p_invoice_id uuid); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION public.post_purchase_invoice(p_invoice_id uuid) IS 'ترحيل فاتورة مشتريات — قيد محاسبي مع دعم الضريبة';


--
-- Name: post_purchase_receipt(uuid, uuid, jsonb); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.post_purchase_receipt(p_receipt_id uuid, p_warehouse_id uuid, p_items jsonb) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_receipt      RECORD;
    v_item         JSONB;
    v_movement_count INT := 0;
    v_total_amount NUMERIC(15,4) := 0;
    v_je_id        UUID;
    v_movement_number VARCHAR(50);
    v_user_id      UUID;
    v_account_inventory UUID;
    v_account_ap   UUID;
    v_item_qty     NUMERIC(15,3);
    v_item_price   NUMERIC(15,4);
    v_item_total   NUMERIC(15,4);
BEGIN
    v_user_id := auth.uid();
    
    -- ════════════════════════════════════════════════════════
    -- الخطوة ٠: التحقق من سند الاستلام
    -- ════════════════════════════════════════════════════════
    SELECT * INTO v_receipt
    FROM purchase_receipts
    WHERE id = p_receipt_id;
    
    IF NOT FOUND THEN
        RETURN jsonb_build_object('success', false, 'error', 'سند الاستلام غير موجود');
    END IF;
    
    IF v_receipt.status = 'completed' THEN
        RETURN jsonb_build_object('success', false, 'error', 'سند الاستلام مُرحَّل مسبقاً');
    END IF;
    
    -- ════════════════════════════════════════════════════════
    -- الخطوة ١: تحديث حالة سند الاستلام
    -- ════════════════════════════════════════════════════════
    UPDATE purchase_receipts
    SET status = 'completed',
        warehouse_id = COALESCE(p_warehouse_id, warehouse_id),
        updated_at = NOW()
    WHERE id = p_receipt_id;
    
    -- ════════════════════════════════════════════════════════
    -- الخطوة ٢: إنشاء حركات المخزون (واحدة لكل صنف)
    -- trigger: update_inventory_stock يحدّث inventory_stock تلقائياً
    -- ════════════════════════════════════════════════════════
    FOR v_item IN SELECT * FROM jsonb_array_elements(p_items)
    LOOP
        v_item_qty   := COALESCE((v_item->>'quantity')::NUMERIC, 0);
        v_item_price := COALESCE((v_item->>'unit_price')::NUMERIC, 0);
        v_item_total := v_item_qty * v_item_price;
        v_total_amount := v_total_amount + v_item_total;
        v_movement_count := v_movement_count + 1;
        
        v_movement_number := 'GRN-' || COALESCE(v_receipt.receipt_number, '') || '-' || v_movement_count;
        
        INSERT INTO inventory_movements (
            tenant_id, company_id,
            movement_number, movement_date,
            movement_type,
            product_id, material_id, variant_id,
            to_warehouse_id,
            quantity, unit_cost, total_cost,
            reference_type, reference_id, reference_number,
            notes, created_by
        ) VALUES (
            v_receipt.tenant_id, v_receipt.company_id,
            v_movement_number, CURRENT_DATE,
            'receipt',
            (v_item->>'product_id')::UUID,
            (v_item->>'material_id')::UUID,
            (v_item->>'variant_id')::UUID,
            COALESCE(p_warehouse_id, v_receipt.warehouse_id),
            v_item_qty, v_item_price, v_item_total,
            'purchase_receipt', p_receipt_id, v_receipt.receipt_number,
            COALESCE(v_item->>'description', 'استلام مشتريات'),
            v_user_id
        );
    END LOOP;
    
    -- ════════════════════════════════════════════════════════
    -- الخطوة ٣: إنشاء قيد محاسبي
    -- مدين: المخزون (1400)  /  دائن: الموردون (2100)
    -- 
    -- ملاحظة: entry_number يتولّد تلقائياً بواسطة generate_entry_number trigger
    -- ملاحظة: total_debit/total_credit تتحسب بواسطة update_journal_entry_totals trigger
    -- ════════════════════════════════════════════════════════
    
    -- البحث عن حساب المخزون (خاص بالشركة أولاً، ثم عام)
    SELECT id INTO v_account_inventory
    FROM chart_of_accounts
    WHERE tenant_id = v_receipt.tenant_id
      AND (company_id = v_receipt.company_id OR company_id IS NULL)
      AND account_code = '1400'
    ORDER BY CASE WHEN company_id = v_receipt.company_id THEN 0 ELSE 1 END
    LIMIT 1;
    
    -- البحث عن حساب الموردين / الذمم الدائنة
    SELECT id INTO v_account_ap
    FROM chart_of_accounts
    WHERE tenant_id = v_receipt.tenant_id
      AND (company_id = v_receipt.company_id OR company_id IS NULL)
      AND account_code IN ('2100', '2108')
    ORDER BY CASE WHEN account_code = '2100' THEN 0 ELSE 1 END,
             CASE WHEN company_id = v_receipt.company_id THEN 0 ELSE 1 END
    LIMIT 1;
    
    IF v_account_inventory IS NOT NULL AND v_account_ap IS NOT NULL AND v_total_amount > 0 THEN
        -- إنشاء رأس القيد (entry_number يتولّد تلقائياً)
        INSERT INTO journal_entries (
            tenant_id, company_id, branch_id,
            entry_date, entry_type,
            description,
            reference_type, reference_id, reference_number,
            status, is_posted, posted_at, posted_by,
            created_by
        ) VALUES (
            v_receipt.tenant_id, v_receipt.company_id, v_receipt.branch_id,
            CURRENT_DATE, 'auto',
            'قيد استلام مشتريات — ' || COALESCE(v_receipt.receipt_number, ''),
            'purchase_receipt', p_receipt_id, v_receipt.receipt_number,
            'posted', true, NOW(), v_user_id,
            v_user_id
        ) RETURNING id INTO v_je_id;
        
        -- سطر مدين: المخزون
        INSERT INTO journal_entry_lines (
            tenant_id, entry_id, line_number,
            account_id, description,
            debit, credit,
            party_type, party_id
        ) VALUES (
            v_receipt.tenant_id, v_je_id, 1,
            v_account_inventory,
            'استلام مخزني — ' || COALESCE(v_receipt.receipt_number, ''),
            v_total_amount, 0,
            NULL, NULL
        );
        
        -- سطر دائن: الموردون
        INSERT INTO journal_entry_lines (
            tenant_id, entry_id, line_number,
            account_id, description,
            debit, credit,
            party_type, party_id
        ) VALUES (
            v_receipt.tenant_id, v_je_id, 2,
            v_account_ap,
            'تسوية استلام — ' || COALESCE(v_receipt.receipt_number, ''),
            0, v_total_amount,
            'supplier', v_receipt.supplier_id
        );
        
        -- ربط القيد بسند الاستلام
        UPDATE purchase_receipts
        SET journal_entry_id = v_je_id
        WHERE id = p_receipt_id;
    END IF;
    
    -- ════════════════════════════════════════════════════════
    -- الخطوة ٤: تحديث حالة المستند المصدر
    -- ════════════════════════════════════════════════════════
    IF v_receipt.invoice_id IS NOT NULL THEN
        UPDATE purchase_invoices
        SET receiving_status = 'received', updated_at = NOW()
        WHERE id = v_receipt.invoice_id;
    END IF;
    
    IF v_receipt.order_id IS NOT NULL THEN
        UPDATE purchase_orders
        SET updated_at = NOW()
        WHERE id = v_receipt.order_id;
    END IF;
    
    RETURN jsonb_build_object(
        'success', true,
        'receipt_id', p_receipt_id,
        'receipt_number', v_receipt.receipt_number,
        'movements_created', v_movement_count,
        'total_amount', v_total_amount,
        'journal_entry_id', v_je_id,
        'message', 'تم ترحيل سند الاستلام بنجاح'
    );

EXCEPTION WHEN OTHERS THEN
    RETURN jsonb_build_object(
        'success', false,
        'error', SQLERRM,
        'detail', SQLSTATE,
        'receipt_id', p_receipt_id
    );
END;
$$;


--
-- Name: FUNCTION post_purchase_receipt(p_receipt_id uuid, p_warehouse_id uuid, p_items jsonb); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION public.post_purchase_receipt(p_receipt_id uuid, p_warehouse_id uuid, p_items jsonb) IS 'ترحيل سند استلام — حركات مخزون + قيد محاسبي + تحديث المصدر';


--
-- Name: post_purchase_return(uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.post_purchase_return(p_return_id uuid, p_warehouse_id uuid DEFAULT NULL::uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_return       RECORD;
    v_item         RECORD;
    v_je_id        UUID;
    v_user_id      UUID;
    v_total        NUMERIC(15,4) := 0;
    v_movement_count INT := 0;
    v_account_inventory UUID;
    v_account_ap   UUID;
    v_movement_number VARCHAR(50);
    v_wh_id        UUID;
BEGIN
    v_user_id := auth.uid();
    
    SELECT * INTO v_return FROM purchase_returns WHERE id = p_return_id;
    
    IF NOT FOUND THEN
        RETURN jsonb_build_object('success', false, 'error', 'مرتجع المشتريات غير موجود');
    END IF;
    
    IF v_return.status = 'posted' THEN
        RETURN jsonb_build_object('success', false, 'error', 'المرتجع مُرحَّل مسبقاً');
    END IF;
    
    v_wh_id := COALESCE(p_warehouse_id, v_return.warehouse_id);
    
    -- تحديث الحالة
    UPDATE purchase_returns SET status = 'posted', updated_at = NOW() WHERE id = p_return_id;
    
    -- معالجة البنود → حركات مخزون (خروج)
    FOR v_item IN SELECT * FROM purchase_return_items WHERE return_id = p_return_id
    LOOP
        v_movement_count := v_movement_count + 1;
        v_total := v_total + COALESCE(v_item.total, v_item.quantity_returned * COALESCE(v_item.unit_price, 0));
        
        v_movement_number := 'PR-' || COALESCE(v_return.return_number, '') || '-' || v_movement_count;
        
        INSERT INTO inventory_movements (
            tenant_id, company_id,
            movement_number, movement_date,
            movement_type,
            product_id, material_id, variant_id,
            from_warehouse_id,
            quantity, unit_cost, total_cost,
            reference_type, reference_id, reference_number,
            notes, created_by
        ) VALUES (
            v_return.tenant_id, v_return.company_id,
            v_movement_number, CURRENT_DATE,
            'return_out',
            v_item.product_id, v_item.material_id, v_item.variant_id,
            v_wh_id,
            v_item.quantity_returned, COALESCE(v_item.unit_price, 0),
            COALESCE(v_item.total, v_item.quantity_returned * COALESCE(v_item.unit_price, 0)),
            'purchase_return', p_return_id, v_return.return_number,
            'مرتجع مشتريات', v_user_id
        );
    END LOOP;
    
    -- القيد: مدين ذمم دائنة / دائن مخزون
    SELECT id INTO v_account_inventory FROM chart_of_accounts
    WHERE tenant_id = v_return.tenant_id
      AND (company_id = v_return.company_id OR company_id IS NULL)
      AND account_code = '1400'
    ORDER BY CASE WHEN company_id = v_return.company_id THEN 0 ELSE 1 END LIMIT 1;
    
    SELECT id INTO v_account_ap FROM chart_of_accounts
    WHERE tenant_id = v_return.tenant_id
      AND (company_id = v_return.company_id OR company_id IS NULL)
      AND account_code = '2100'
    ORDER BY CASE WHEN company_id = v_return.company_id THEN 0 ELSE 1 END LIMIT 1;
    
    IF v_account_inventory IS NOT NULL AND v_account_ap IS NOT NULL AND v_total > 0 THEN
        INSERT INTO journal_entries (
            tenant_id, company_id, branch_id,
            entry_date, entry_type,
            description,
            reference_type, reference_id, reference_number,
            status, is_posted, posted_at, posted_by,
            created_by
        ) VALUES (
            v_return.tenant_id, v_return.company_id, v_return.branch_id,
            CURRENT_DATE, 'auto',
            'مرتجع مشتريات — ' || COALESCE(v_return.return_number, ''),
            'purchase_return', p_return_id, v_return.return_number,
            'posted', true, NOW(), v_user_id,
            v_user_id
        ) RETURNING id INTO v_je_id;
        
        -- مدين: تخفيض ذمم دائنة
        INSERT INTO journal_entry_lines (tenant_id, entry_id, line_number, account_id, description, debit, credit, party_type, party_id)
        VALUES (v_return.tenant_id, v_je_id, 1, v_account_ap, 'تخفيض ذمم دائنة — مرتجع', v_total, 0, 'supplier', v_return.supplier_id);
        
        -- دائن: إرجاع مخزون
        INSERT INTO journal_entry_lines (tenant_id, entry_id, line_number, account_id, description, debit, credit)
        VALUES (v_return.tenant_id, v_je_id, 2, v_account_inventory, 'إرجاع مخزون — مرتجع مشتريات', 0, v_total);
    END IF;
    
    RETURN jsonb_build_object(
        'success', true,
        'return_id', p_return_id,
        'movements_created', v_movement_count,
        'total_amount', v_total,
        'journal_entry_id', v_je_id,
        'message', 'تم ترحيل مرتجع المشتريات بنجاح'
    );

EXCEPTION WHEN OTHERS THEN
    RETURN jsonb_build_object('success', false, 'error', SQLERRM, 'detail', SQLSTATE);
END;
$$;


--
-- Name: FUNCTION post_purchase_return(p_return_id uuid, p_warehouse_id uuid); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION public.post_purchase_return(p_return_id uuid, p_warehouse_id uuid) IS 'ترحيل مرتجع مشتريات — إخراج مخزون + قيد عكسي';


--
-- Name: post_sales_invoice(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.post_sales_invoice(p_invoice_id uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_trx        RECORD;
    v_je_id      UUID;      -- قيد الفاتورة (المبيعات + ضريبة)
    v_je_cogs_id UUID;      -- قيد COGS (منفصل)
    v_user_id    UUID;
    v_account_ar  UUID;
    v_account_rev UUID;
    v_account_tax UUID;
    v_account_cogs UUID;
    v_account_inv  UUID;
    v_delivered_subtotal NUMERIC(15,4) := 0;
    v_delivered_discount NUMERIC(15,4) := 0;
    v_net_amount  NUMERIC(15,4) := 0;
    v_tax_amount  NUMERIC(15,4) := 0;
    v_total       NUMERIC(15,4) := 0;
    v_cost_amount NUMERIC(15,4) := 0;
    v_line_num    INT := 0;
    v_entry_no    TEXT;
    v_entry_no_cogs TEXT;
    v_inv_label   TEXT;
    v_item_count  INT := 0;
    v_has_delivered BOOLEAN := false;
BEGIN
    v_user_id := auth.uid();
    
    -- ════════════════════════════════════════════════════════
    -- 1. جلب بيانات الفاتورة
    -- ════════════════════════════════════════════════════════
    SELECT * INTO v_trx FROM sales_transactions WHERE id = p_invoice_id;
    
    IF NOT FOUND THEN
        RETURN jsonb_build_object('success', false, 'error', 'الفاتورة غير موجودة');
    END IF;
    
    IF v_trx.is_posted = true THEN
        RETURN jsonb_build_object('success', false, 'error', 'الفاتورة مُرحَّلة مسبقاً');
    END IF;
    
    v_inv_label := COALESCE(v_trx.invoice_no, v_trx.draft_no, LEFT(p_invoice_id::text, 8));
    
    -- ════════════════════════════════════════════════════════
    -- 2. حساب المبالغ من البنود المسلّمة فعلياً
    -- ════════════════════════════════════════════════════════
    SELECT COUNT(*) INTO v_item_count
    FROM sales_transaction_items sti
    WHERE sti.transaction_id = p_invoice_id
      AND COALESCE(sti.delivered_qty, 0) > 0;
    
    v_has_delivered := v_item_count > 0;
    
    SELECT
        COALESCE(SUM(COALESCE(sti.delivered_qty, 0) * COALESCE(sti.unit_price, 0)), 0),
        COALESCE(SUM(COALESCE(sti.delivered_qty, 0) * COALESCE(sti.unit_price, 0) * COALESCE(sti.discount_percent, 0) / 100), 0),
        COALESCE(SUM(
            (COALESCE(sti.delivered_qty, 0) * COALESCE(sti.unit_price, 0)
             - COALESCE(sti.delivered_qty, 0) * COALESCE(sti.unit_price, 0) * COALESCE(sti.discount_percent, 0) / 100
            ) * COALESCE(sti.tax_rate, 0) / 100
        ), 0),
        COALESCE(SUM(COALESCE(sti.cost_price, 0) * COALESCE(sti.delivered_qty, 0)), 0)
    INTO v_delivered_subtotal, v_delivered_discount, v_tax_amount, v_cost_amount
    FROM sales_transaction_items sti
    WHERE sti.transaction_id = p_invoice_id;
    
    v_net_amount := v_delivered_subtotal - v_delivered_discount;
    v_total := v_net_amount + v_tax_amount;
    
    IF NOT v_has_delivered THEN
        v_total := COALESCE(v_trx.total_amount, 0);
        v_tax_amount := COALESCE(v_trx.tax_amount, 0);
        v_net_amount := v_total - v_tax_amount;
        
        SELECT COALESCE(SUM(COALESCE(sti.cost_price, 0) * COALESCE(sti.quantity, 0)), 0)
        INTO v_cost_amount
        FROM sales_transaction_items sti
        WHERE sti.transaction_id = p_invoice_id;
    END IF;
    
    IF v_total <= 0 THEN
        RETURN jsonb_build_object('success', false, 'error', 
            'مبلغ الفاتورة صفر أو سالب — تحقق من الكميات المسلّمة');
    END IF;
    
    -- ════════════════════════════════════════════════════════
    -- 3. البحث عن الحسابات
    -- ════════════════════════════════════════════════════════
    IF v_trx.customer_id IS NOT NULL THEN
        SELECT c.receivable_account_id INTO v_account_ar
        FROM customers c WHERE c.id = v_trx.customer_id AND c.receivable_account_id IS NOT NULL;
        
        IF v_account_ar IS NULL THEN
            SELECT id INTO v_account_ar FROM chart_of_accounts
            WHERE is_party_account = true AND party_type = 'customer' AND party_id = v_trx.customer_id LIMIT 1;
        END IF;
    END IF;
    
    IF v_account_ar IS NULL THEN
        SELECT id INTO v_account_ar FROM chart_of_accounts
        WHERE tenant_id = v_trx.tenant_id AND (company_id = v_trx.company_id OR company_id IS NULL)
          AND account_code IN ('1131', '1130')
        ORDER BY CASE WHEN account_code = '1131' THEN 0 ELSE 1 END,
                 CASE WHEN company_id = v_trx.company_id THEN 0 ELSE 1 END LIMIT 1;
    END IF;
    
    SELECT id INTO v_account_rev FROM chart_of_accounts
    WHERE tenant_id = v_trx.tenant_id AND (company_id = v_trx.company_id OR company_id IS NULL)
      AND account_code IN ('41', '411', '4110', '4100')
    ORDER BY CASE WHEN account_code = '41' THEN 0 WHEN account_code = '4110' THEN 1 WHEN account_code = '4100' THEN 2 ELSE 3 END,
             CASE WHEN company_id = v_trx.company_id THEN 0 ELSE 1 END LIMIT 1;
    
    IF v_tax_amount > 0 THEN
        SELECT id INTO v_account_tax FROM chart_of_accounts
        WHERE tenant_id = v_trx.tenant_id AND (company_id = v_trx.company_id OR company_id IS NULL)
          AND account_code IN ('214', '2130', '2141', '2150')
        ORDER BY CASE WHEN account_code = '214' THEN 0 WHEN account_code = '2130' THEN 1 WHEN account_code = '2141' THEN 2 ELSE 3 END,
                 CASE WHEN company_id = v_trx.company_id THEN 0 ELSE 1 END LIMIT 1;
    END IF;
    
    SELECT id INTO v_account_cogs FROM chart_of_accounts
    WHERE tenant_id = v_trx.tenant_id AND (company_id = v_trx.company_id OR company_id IS NULL)
      AND account_code IN ('511', '5100', '5110')
    ORDER BY CASE WHEN account_code = '511' THEN 0 WHEN account_code = '5100' THEN 1 ELSE 2 END,
             CASE WHEN company_id = v_trx.company_id THEN 0 ELSE 1 END LIMIT 1;
    
    SELECT id INTO v_account_inv FROM chart_of_accounts
    WHERE tenant_id = v_trx.tenant_id AND (company_id = v_trx.company_id OR company_id IS NULL)
      AND account_code IN ('1140', '1141')
    ORDER BY CASE WHEN account_code = '1140' THEN 0 ELSE 1 END,
             CASE WHEN company_id = v_trx.company_id THEN 0 ELSE 1 END LIMIT 1;
    
    IF v_account_ar IS NULL OR v_account_rev IS NULL THEN
        RETURN jsonb_build_object('success', false, 'error',
            'حسابات المبيعات غير مكتملة — تحقق من الذمم المدينة (1130) وحساب الإيرادات (4100)');
    END IF;
    
    -- ════════════════════════════════════════════════════════
    -- 4. تحديث الفاتورة
    -- ════════════════════════════════════════════════════════
    UPDATE sales_transactions
    SET stage = 'posted', is_posted = true, posted_at = NOW(), posted_by = v_user_id,
        subtotal = v_delivered_subtotal, discount_amount = v_delivered_discount,
        tax_amount = v_tax_amount, total_amount = v_total, updated_at = NOW()
    WHERE id = p_invoice_id;
    
    -- ════════════════════════════════════════════════════════
    -- 5. قيد ① — فاتورة المبيعات (Dr عميل / Cr مبيعات + ضريبة)
    --    المبلغ = قيمة الفاتورة ← لا يُربك المستخدم
    -- ════════════════════════════════════════════════════════
    v_entry_no := 'JE-S-' || to_char(NOW(), 'YYMMDD') || '-' ||
                  LPAD(nextval('journal_entry_number_seq')::text, 4, '0');
    
    INSERT INTO journal_entries (
        tenant_id, company_id, entry_number, entry_date,
        description, reference_type, reference_id, reference_number,
        currency, exchange_rate, status, is_posted, created_by,
        total_debit, total_credit
    ) VALUES (
        v_trx.tenant_id, v_trx.company_id, v_entry_no, CURRENT_DATE,
        'فاتورة مبيعات — ' || v_inv_label || CASE WHEN v_has_delivered THEN ' (بناءً على المسلّم فعلياً)' ELSE '' END,
        'sales_invoice', p_invoice_id, v_inv_label,
        COALESCE(v_trx.currency, 'SAR'), COALESCE(v_trx.exchange_rate, 1),
        'draft', false, v_user_id,
        v_total, v_total
    ) RETURNING id INTO v_je_id;
    
    -- ① مدين: العميل
    v_line_num := 1;
    INSERT INTO journal_entry_lines (tenant_id, entry_id, line_number, account_id, description, debit, credit, party_type, party_id)
    VALUES (v_trx.tenant_id, v_je_id, v_line_num, v_account_ar, 'ذمم مدينة — ' || COALESCE(v_trx.customer_name, ''), v_total, 0, 'customer', v_trx.customer_id);
    
    -- ② دائن: مبيعات
    v_line_num := 2;
    INSERT INTO journal_entry_lines (tenant_id, entry_id, line_number, account_id, description, debit, credit)
    VALUES (v_trx.tenant_id, v_je_id, v_line_num, v_account_rev, 'إيرادات مبيعات — ' || v_inv_label, 0,
            CASE WHEN v_tax_amount > 0 AND v_account_tax IS NOT NULL THEN v_net_amount ELSE v_total END);
    
    -- ③ دائن: ضريبة مخرجات
    IF v_tax_amount > 0 AND v_account_tax IS NOT NULL THEN
        v_line_num := 3;
        INSERT INTO journal_entry_lines (tenant_id, entry_id, line_number, account_id, description, debit, credit)
        VALUES (v_trx.tenant_id, v_je_id, v_line_num, v_account_tax, 'ضريبة مخرجات — ' || v_inv_label, 0, v_tax_amount);
    END IF;
    
    -- تفعيل القيد
    UPDATE journal_entries SET status = 'posted', is_posted = true, posted_at = NOW(), posted_by = v_user_id WHERE id = v_je_id;
    
    -- ════════════════════════════════════════════════════════
    -- 6. قيد ② — تكلفة البضاعة المباعة (COGS) — منفصل ومخفي
    --    reference_type = 'sales_cogs' ← يُخفيه النظام
    -- ════════════════════════════════════════════════════════
    IF v_cost_amount > 0 AND v_account_cogs IS NOT NULL AND v_account_inv IS NOT NULL THEN
        v_entry_no_cogs := 'JE-COGS-' || to_char(NOW(), 'YYMMDD') || '-' ||
                           LPAD(nextval('journal_entry_number_seq')::text, 4, '0');
        
        INSERT INTO journal_entries (
            tenant_id, company_id, entry_number, entry_date,
            description, reference_type, reference_id, reference_number,
            currency, exchange_rate, status, is_posted, created_by,
            total_debit, total_credit
        ) VALUES (
            v_trx.tenant_id, v_trx.company_id, v_entry_no_cogs, CURRENT_DATE,
            'تكلفة بضاعة مباعة — ' || v_inv_label,
            'sales_cogs', p_invoice_id, v_inv_label,
            COALESCE(v_trx.currency, 'SAR'), COALESCE(v_trx.exchange_rate, 1),
            'draft', false, v_user_id,
            v_cost_amount, v_cost_amount
        ) RETURNING id INTO v_je_cogs_id;
        
        -- Dr COGS
        INSERT INTO journal_entry_lines (tenant_id, entry_id, line_number, account_id, description, debit, credit)
        VALUES (v_trx.tenant_id, v_je_cogs_id, 1, v_account_cogs, 'تكلفة مبيعات — ' || v_inv_label, v_cost_amount, 0);
        
        -- Cr Inventory
        INSERT INTO journal_entry_lines (tenant_id, entry_id, line_number, account_id, description, debit, credit)
        VALUES (v_trx.tenant_id, v_je_cogs_id, 2, v_account_inv, 'إخراج مخزون — ' || v_inv_label, 0, v_cost_amount);
        
        -- تفعيل
        UPDATE journal_entries SET status = 'posted', is_posted = true, posted_at = NOW(), posted_by = v_user_id WHERE id = v_je_cogs_id;
    END IF;
    
    -- ════════════════════════════════════════════════════════
    -- 7. ربط القيود بالفاتورة
    -- ════════════════════════════════════════════════════════
    UPDATE sales_transactions
    SET journal_entry_id = v_je_id,
        cogs_journal_entry_id = v_je_cogs_id
    WHERE id = p_invoice_id;
    
    RETURN jsonb_build_object(
        'success', true,
        'invoice_id', p_invoice_id,
        'invoice_number', v_inv_label,
        'journal_entry_id', v_je_id,
        'cogs_journal_entry_id', v_je_cogs_id,
        'customer_account_id', v_account_ar,
        'based_on_delivered', v_has_delivered,
        'delivered_subtotal', v_delivered_subtotal,
        'delivered_discount', v_delivered_discount,
        'net_amount', v_net_amount,
        'tax_amount', v_tax_amount,
        'total_amount', v_total,
        'cost_amount', v_cost_amount,
        'cogs_recorded', v_cost_amount > 0 AND v_account_cogs IS NOT NULL,
        'gross_profit', v_net_amount - v_cost_amount,
        'message', CASE 
            WHEN v_has_delivered THEN 'تم ترحيل فاتورة المبيعات بنجاح — بناءً على الكميات المسلّمة فعلياً'
            ELSE 'تم ترحيل فاتورة المبيعات بنجاح — بناءً على الفاتورة الأصلية (لا توجد كميات مسلّمة)'
        END
    );

EXCEPTION WHEN OTHERS THEN
    UPDATE sales_transactions 
    SET stage = 'delivered', is_posted = false, posted_at = NULL, posted_by = NULL
    WHERE id = p_invoice_id AND is_posted = true;
    
    RETURN jsonb_build_object('success', false, 'error', SQLERRM, 'detail', SQLSTATE);
END;
$$;


--
-- Name: FUNCTION post_sales_invoice(p_invoice_id uuid); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION public.post_sales_invoice(p_invoice_id uuid) IS 'ترحيل فاتورة مبيعات — V2: قيد محاسبي بناءً على الكميات المسلّمة فعلياً + COGS + حساب عميل فرعي';


--
-- Name: post_sales_return(uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.post_sales_return(p_return_id uuid, p_warehouse_id uuid DEFAULT NULL::uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_return       RECORD;
    v_item         RECORD;
    v_je_id        UUID;
    v_user_id      UUID;
    v_total        NUMERIC(15,4) := 0;
    v_movement_count INT := 0;
    v_account_ar   UUID;
    v_account_rev  UUID;
    v_movement_number VARCHAR(50);
    v_wh_id        UUID;
BEGIN
    v_user_id := auth.uid();
    
    SELECT * INTO v_return FROM sales_returns WHERE id = p_return_id;
    
    IF NOT FOUND THEN
        RETURN jsonb_build_object('success', false, 'error', 'مرتجع المبيعات غير موجود');
    END IF;
    
    IF v_return.status = 'posted' THEN
        RETURN jsonb_build_object('success', false, 'error', 'المرتجع مُرحَّل مسبقاً');
    END IF;
    
    v_wh_id := COALESCE(p_warehouse_id, v_return.warehouse_id);
    
    UPDATE sales_returns SET status = 'posted', updated_at = NOW() WHERE id = p_return_id;
    
    -- معالجة البنود → حركات مخزون (دخول)
    FOR v_item IN SELECT * FROM sales_return_items WHERE return_id = p_return_id
    LOOP
        v_movement_count := v_movement_count + 1;
        v_total := v_total + COALESCE(v_item.total, v_item.quantity_returned * COALESCE(v_item.unit_price, 0));
        
        v_movement_number := 'SR-' || COALESCE(v_return.return_number, '') || '-' || v_movement_count;
        
        INSERT INTO inventory_movements (
            tenant_id, company_id,
            movement_number, movement_date,
            movement_type,
            product_id, material_id, variant_id,
            to_warehouse_id,
            quantity, unit_cost, total_cost,
            reference_type, reference_id, reference_number,
            notes, created_by
        ) VALUES (
            v_return.tenant_id, v_return.company_id,
            v_movement_number, CURRENT_DATE,
            'return_in',
            v_item.product_id, v_item.material_id, v_item.variant_id,
            v_wh_id,
            v_item.quantity_returned, COALESCE(v_item.unit_price, 0),
            COALESCE(v_item.total, v_item.quantity_returned * COALESCE(v_item.unit_price, 0)),
            'sales_return', p_return_id, v_return.return_number,
            'مرتجع مبيعات', v_user_id
        );
    END LOOP;
    
    -- القيد: مدين إيرادات / دائن ذمم مدينة
    SELECT id INTO v_account_ar FROM chart_of_accounts
    WHERE tenant_id = v_return.tenant_id
      AND (company_id = v_return.company_id OR company_id IS NULL)
      AND account_code IN ('1200', '1210')
    ORDER BY CASE WHEN company_id = v_return.company_id THEN 0 ELSE 1 END LIMIT 1;
    
    SELECT id INTO v_account_rev FROM chart_of_accounts
    WHERE tenant_id = v_return.tenant_id
      AND (company_id = v_return.company_id OR company_id IS NULL)
      AND account_code IN ('4100', '4000')
    ORDER BY CASE WHEN company_id = v_return.company_id THEN 0 ELSE 1 END LIMIT 1;
    
    IF v_account_ar IS NOT NULL AND v_account_rev IS NOT NULL AND v_total > 0 THEN
        INSERT INTO journal_entries (
            tenant_id, company_id, branch_id,
            entry_date, entry_type,
            description,
            reference_type, reference_id, reference_number,
            status, is_posted, posted_at, posted_by,
            created_by
        ) VALUES (
            v_return.tenant_id, v_return.company_id, v_return.branch_id,
            CURRENT_DATE, 'auto',
            'مرتجع مبيعات — ' || COALESCE(v_return.return_number, ''),
            'sales_return', p_return_id, v_return.return_number,
            'posted', true, NOW(), v_user_id,
            v_user_id
        ) RETURNING id INTO v_je_id;
        
        INSERT INTO journal_entry_lines (tenant_id, entry_id, line_number, account_id, description, debit, credit)
        VALUES (v_return.tenant_id, v_je_id, 1, v_account_rev, 'تخفيض إيرادات — مرتجع', v_total, 0);
        
        INSERT INTO journal_entry_lines (tenant_id, entry_id, line_number, account_id, description, debit, credit, party_type, party_id)
        VALUES (v_return.tenant_id, v_je_id, 2, v_account_ar, 'تخفيض ذمم مدينة — مرتجع', 0, v_total, 'customer', v_return.customer_id);
    END IF;
    
    RETURN jsonb_build_object(
        'success', true,
        'return_id', p_return_id,
        'movements_created', v_movement_count,
        'total_amount', v_total,
        'journal_entry_id', v_je_id,
        'message', 'تم ترحيل مرتجع المبيعات بنجاح'
    );

EXCEPTION WHEN OTHERS THEN
    RETURN jsonb_build_object('success', false, 'error', SQLERRM, 'detail', SQLSTATE);
END;
$$;


--
-- Name: FUNCTION post_sales_return(p_return_id uuid, p_warehouse_id uuid); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION public.post_sales_return(p_return_id uuid, p_warehouse_id uuid) IS 'ترحيل مرتجع مبيعات — إدخال مخزون + قيد عكسي';


--
-- Name: prevent_base_currency_change(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.prevent_base_currency_change() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
DECLARE
    has_entries BOOLEAN;
BEGIN
    -- فقط عند تغيير العملة الأساسية
    IF OLD.default_currency IS DISTINCT FROM NEW.default_currency THEN
        -- هل يوجد قيود محاسبية لهذه الشركة؟
        SELECT EXISTS (
            SELECT 1 FROM journal_entries 
            WHERE company_id = NEW.id
            LIMIT 1
        ) INTO has_entries;
        
        IF has_entries THEN
            RAISE EXCEPTION 'Cannot change base currency after journal entries exist. Current: %, Attempted: %',
                OLD.default_currency, NEW.default_currency;
        END IF;
    END IF;
    
    RETURN NEW;
END;
$$;


--
-- Name: prevent_delete_if_referenced(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.prevent_delete_if_referenced() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
BEGIN
    -- هذه الدالة ستُستخدم للجداول التي لا يجب حذف سجلاتها
    -- إذا كانت مرتبطة بسجلات أخرى
    RAISE EXCEPTION 'غير مسموح: لا يمكن حذف هذا السجل لارتباطه ببيانات أخرى / Not allowed: Cannot delete this record as it is referenced by other data';
END;
$$;


--
-- Name: prevent_removing_used_currency(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.prevent_removing_used_currency() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_removed_currency TEXT;
    has_entries BOOLEAN;
BEGIN
    IF OLD.supported_currencies IS NOT DISTINCT FROM NEW.supported_currencies THEN
        RETURN NEW;
    END IF;

    FOREACH v_removed_currency IN ARRAY COALESCE(OLD.supported_currencies, ARRAY[]::TEXT[])
    LOOP
        IF NOT (v_removed_currency = ANY(COALESCE(NEW.supported_currencies, ARRAY[]::TEXT[]))) THEN
            SELECT EXISTS (
                SELECT 1 FROM journal_entries
                WHERE company_id = NEW.company_id AND currency = v_removed_currency
                LIMIT 1
            ) INTO has_entries;

            IF has_entries THEN
                RAISE EXCEPTION '❌ لا يمكن حذف العملة % — يوجد قيود محاسبية بها', v_removed_currency;
            END IF;
        END IF;
    END LOOP;

    RETURN NEW;
END;
$$;


--
-- Name: prevent_settings_base_currency_change(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.prevent_settings_base_currency_change() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
DECLARE
    has_entries BOOLEAN;
BEGIN
    IF OLD.base_currency IS DISTINCT FROM NEW.base_currency THEN
        SELECT EXISTS (
            SELECT 1 FROM journal_entries 
            WHERE company_id = NEW.company_id
            LIMIT 1
        ) INTO has_entries;
        
        IF has_entries THEN
            RAISE EXCEPTION 'Cannot change base currency in accounting settings after journal entries exist. Current: %, Attempted: %',
                OLD.base_currency, NEW.base_currency;
        END IF;
    END IF;
    
    RETURN NEW;
END;
$$;


--
-- Name: process_due_recurring_entries(date); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.process_due_recurring_entries(p_as_of_date date DEFAULT CURRENT_DATE) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_entry RECORD;
    v_history_id UUID;
    v_processed_count INTEGER := 0;
    v_results JSONB := '[]'::JSONB;
BEGIN
    -- البحث عن القيود المستحقة
    FOR v_entry IN
        SELECT *
        FROM recurring_entries
        WHERE is_active = true
          AND status = 'active'
          AND next_run_date <= p_as_of_date
          AND (end_date IS NULL OR end_date >= p_as_of_date)
          AND (max_executions IS NULL OR times_executed < max_executions)
    LOOP
        -- إنشاء سجل في التاريخ
        INSERT INTO recurring_entry_history (
            tenant_id, recurring_entry_id, scheduled_date, amount,
            approval_status, status
        ) VALUES (
            v_entry.tenant_id, v_entry.id, v_entry.next_run_date, v_entry.amount,
            CASE WHEN v_entry.requires_approval THEN 'pending' ELSE 'auto_approved' END,
            CASE WHEN v_entry.requires_approval THEN 'pending' ELSE 'pending' END
        ) RETURNING id INTO v_history_id;
        
        -- تحديث تاريخ التنفيذ التالي
        UPDATE recurring_entries
        SET 
            next_run_date = calculate_next_run_date(
                next_run_date, frequency, interval_value,
                day_of_month, day_of_week, month_of_year
            ),
            last_run_date = p_as_of_date,
            times_executed = times_executed + 1,
            updated_at = NOW()
        WHERE id = v_entry.id;
        
        -- إذا لا يحتاج موافقة، نفذ مباشرة
        IF NOT v_entry.requires_approval THEN
            PERFORM execute_recurring_entry(v_history_id, NULL);
        END IF;
        
        v_processed_count := v_processed_count + 1;
        v_results := v_results || jsonb_build_object(
            'entry_id', v_entry.id,
            'name', v_entry.name_ar,
            'history_id', v_history_id,
            'requires_approval', v_entry.requires_approval
        );
    END LOOP;
    
    RETURN jsonb_build_object(
        'success', true,
        'processed_count', v_processed_count,
        'entries', v_results
    );
END;
$$;


--
-- Name: FUNCTION process_due_recurring_entries(p_as_of_date date); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION public.process_due_recurring_entries(p_as_of_date date) IS 'فحص وإنشاء سجلات للقيود المستحقة';


--
-- Name: process_shipment_api_response(uuid, character varying, character varying, date, numeric, text, jsonb, boolean, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.process_shipment_api_response(p_shipment_doc_id uuid, p_tracking_number character varying, p_carrier_ref character varying, p_estimated_delivery date DEFAULT NULL::date, p_shipping_cost numeric DEFAULT NULL::numeric, p_label_url text DEFAULT NULL::text, p_api_response jsonb DEFAULT NULL::jsonb, p_success boolean DEFAULT true, p_error_message text DEFAULT NULL::text) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_doc RECORD;
BEGIN
    IF NOT p_success THEN
        UPDATE shipment_documents
        SET status = 'failed',
            status_description = p_error_message,
            api_response = p_api_response,
            updated_at = NOW()
        WHERE id = p_shipment_doc_id;
        
        RETURN jsonb_build_object('success', false, 'error', p_error_message);
    END IF;
    
    -- Update shipment document with API response
    UPDATE shipment_documents
    SET tracking_number = p_tracking_number,
        carrier_ref = p_carrier_ref,
        status = 'created',
        status_description = 'البوليصة تم إنشاؤها بنجاح',
        estimated_delivery_date = p_estimated_delivery,
        shipping_cost = COALESCE(p_shipping_cost, shipping_cost),
        label_url = p_label_url,
        barcode = p_tracking_number,
        api_response = p_api_response,
        status_history = status_history || jsonb_build_array(
            jsonb_build_object(
                'status', 'created',
                'date', to_char(NOW(), 'YYYY-MM-DD HH24:MI:SS'),
                'description', 'البوليصة تم إنشاؤها — TTN: ' || p_tracking_number
            )
        ),
        updated_at = NOW()
    WHERE id = p_shipment_doc_id
    RETURNING * INTO v_doc;
    
    -- Update the source trade document with tracking number
    IF v_doc.source_table = 'sales_orders' THEN
        UPDATE sales_orders 
        SET tracking_number = p_tracking_number,
            shipping_cost = COALESCE(p_shipping_cost, shipping_cost)
        WHERE id = v_doc.source_id;
    ELSIF v_doc.source_table = 'sales_deliveries' THEN
        UPDATE sales_deliveries
        SET tracking_number = p_tracking_number,
            shipping_cost = COALESCE(p_shipping_cost, shipping_cost)
        WHERE id = v_doc.source_id;
    ELSIF v_doc.source_table = 'transit_reservations' THEN
        UPDATE transit_reservations
        SET tracking_number = p_tracking_number,
            shipping_cost = COALESCE(p_shipping_cost, shipping_cost)
        WHERE id = v_doc.source_id;
    ELSIF v_doc.source_table = 'quotations' THEN
        UPDATE quotations
        SET tracking_number = p_tracking_number,
            shipping_cost = COALESCE(p_shipping_cost, shipping_cost)
        WHERE id = v_doc.source_id;
    ELSIF v_doc.source_table = 'sales_invoices' THEN
        UPDATE sales_invoices
        SET tracking_number = p_tracking_number,
            shipping_cost = COALESCE(p_shipping_cost, shipping_cost)
        WHERE id = v_doc.source_id;
    END IF;
    
    RETURN jsonb_build_object(
        'success', true,
        'tracking_number', p_tracking_number,
        'carrier_ref', p_carrier_ref,
        'shipment_document_id', p_shipment_doc_id,
        'label_url', p_label_url
    );
END;
$$;


--
-- Name: FUNCTION process_shipment_api_response(p_shipment_doc_id uuid, p_tracking_number character varying, p_carrier_ref character varying, p_estimated_delivery date, p_shipping_cost numeric, p_label_url text, p_api_response jsonb, p_success boolean, p_error_message text); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION public.process_shipment_api_response(p_shipment_doc_id uuid, p_tracking_number character varying, p_carrier_ref character varying, p_estimated_delivery date, p_shipping_cost numeric, p_label_url text, p_api_response jsonb, p_success boolean, p_error_message text) IS 'معالجة رد API شركة الشحن — يُستدعى من n8n بعد تلقي رقم البوليصة (TTN)';


--
-- Name: propagate_templates_to_all_tenants(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.propagate_templates_to_all_tenants() RETURNS TABLE(tenant_id uuid, tenant_name character varying, templates_created integer)
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    rec RECORD;
    v_count INT;
BEGIN
    -- إعداد القوالب لكل تينانت موجود
    FOR rec IN SELECT id, name FROM tenants LOOP
        BEGIN
            PERFORM setup_chart_templates_for_tenant(rec.id);
            SELECT COUNT(*) INTO v_count FROM chart_templates WHERE tenant_id = rec.id;
            
            tenant_id := rec.id;
            tenant_name := rec.name;
            templates_created := v_count;
            RETURN NEXT;
        EXCEPTION WHEN OTHERS THEN
            RAISE NOTICE '⚠️ خطأ في إعداد القوالب للتينانت %: %', rec.id, SQLERRM;
            tenant_id := rec.id;
            tenant_name := rec.name;
            templates_created := 0;
            RETURN NEXT;
        END;
    END LOOP;
END;
$$;


--
-- Name: FUNCTION propagate_templates_to_all_tenants(); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION public.propagate_templates_to_all_tenants() IS 'تعميم القوالب الأربعة على جميع التينانتات الموجودة';


--
-- Name: protect_companies(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.protect_companies() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_current_user_id UUID := auth.uid();
    v_is_platform_admin BOOLEAN;
BEGIN
    IF v_current_user_id IS NULL THEN
        RETURN NEW;
    END IF;

    v_is_platform_admin := is_platform_admin(v_current_user_id);

    -- ════════ حماية tenant_id ════════
    IF OLD.tenant_id IS DISTINCT FROM NEW.tenant_id THEN
        IF NOT v_is_platform_admin THEN
            RAISE EXCEPTION 'غير مسموح: لا يمكن نقل شركة من تينانت لآخر إلا من مدير المنصة / Not allowed: Only platform admin can move company between tenants';
        END IF;
    END IF;

    RETURN NEW;
END;
$$;


--
-- Name: protect_company_fields(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.protect_company_fields() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
BEGIN
    -- منع تغيير tenant_id
    IF TG_OP = 'UPDATE' THEN
        IF OLD.tenant_id IS DISTINCT FROM NEW.tenant_id THEN
            -- فقط Super Admin
            IF NOT COALESCE(
                (SELECT is_super_admin FROM user_profiles WHERE id = auth.uid()), 
                false
            ) THEN
                RAISE EXCEPTION 'غير مسموح بنقل الشركة لمستأجر آخر';
            END IF;
        END IF;
    END IF;
    
    RETURN NEW;
END;
$$;


--
-- Name: protect_partners(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.protect_partners() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_current_user_id UUID := auth.uid();
    v_is_platform_admin BOOLEAN;
    v_current_user_email TEXT;
BEGIN
    IF v_current_user_id IS NULL THEN
        RETURN NEW;
    END IF;

    v_is_platform_admin := is_platform_admin(v_current_user_id);
    
    -- Platform Admin يمكنه كل شيء
    IF v_is_platform_admin THEN
        RETURN NEW;
    END IF;

    -- الحصول على بريد المستخدم الحالي
    SELECT email INTO v_current_user_email FROM public.user_profiles WHERE id = v_current_user_id;

    -- عند الإضافة: فقط Platform Admin
    IF TG_OP = 'INSERT' THEN
        RAISE EXCEPTION 'غير مسموح: فقط مدير المنصة يمكنه إنشاء وكلاء / Not allowed: Only platform admin can create partners';
    END IF;

    -- عند التعديل: الوكيل يعدّل بياناته الشخصية فقط
    IF TG_OP = 'UPDATE' THEN
        -- التحقق من أن المستخدم هو الوكيل نفسه
        IF LOWER(OLD.email) != LOWER(v_current_user_email) THEN
            RAISE EXCEPTION 'غير مسموح: لا يمكنك تعديل بيانات وكيل آخر / Not allowed: You cannot modify another partner''s data';
        END IF;
        
        -- الحقول المسموح للوكيل بتعديلها
        -- الحقول غير المسموحة: email, partner_type, commission_rate, is_active
        IF OLD.email IS DISTINCT FROM NEW.email THEN
            RAISE EXCEPTION 'غير مسموح: لا يمكنك تغيير البريد الإلكتروني / Not allowed: You cannot change email';
        END IF;
        IF OLD.partner_type IS DISTINCT FROM NEW.partner_type THEN
            RAISE EXCEPTION 'غير مسموح: لا يمكنك تغيير نوع الوكالة / Not allowed: You cannot change partner type';
        END IF;
        IF OLD.commission_rate IS DISTINCT FROM NEW.commission_rate THEN
            RAISE EXCEPTION 'غير مسموح: لا يمكنك تغيير نسبة العمولة / Not allowed: You cannot change commission rate';
        END IF;
        IF OLD.is_active IS DISTINCT FROM NEW.is_active THEN
            RAISE EXCEPTION 'غير مسموح: لا يمكنك تغيير حالة التفعيل / Not allowed: You cannot change activation status';
        END IF;
    END IF;

    RETURN NEW;
END;
$$;


--
-- Name: protect_role_assignments(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.protect_role_assignments() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_is_super_admin BOOLEAN := false;
    v_is_tenant_admin BOOLEAN := false;
    v_current_user_id UUID;
BEGIN
    -- الحصول على المستخدم الحالي
    v_current_user_id := auth.uid();
    
    -- ═══════════════════════════════════════════════════════════
    -- السماح إذا كنا في SECURITY DEFINER context
    -- أو إذا لم يكن هناك مستخدم نشط (admin operations)
    -- ═══════════════════════════════════════════════════════════
    IF v_current_user_id IS NULL THEN
        RETURN COALESCE(NEW, OLD);
    END IF;
    
    -- التحقق إذا المستخدم موجود في user_profiles
    SELECT 
        COALESCE(is_super_admin, false),
        COALESCE(is_tenant_admin, false)
    INTO v_is_super_admin, v_is_tenant_admin
    FROM user_profiles 
    WHERE id = v_current_user_id;
    
    -- ═══════════════════════════════════════════════════════════
    -- إذا لم يوجد سجل في user_profiles = مستخدم جديد = السماح
    -- (هذا يحدث أثناء عملية register_new_subscriber)
    -- ═══════════════════════════════════════════════════════════
    IF NOT FOUND THEN
        RETURN COALESCE(NEW, OLD);
    END IF;
    
    -- ═══════════════════════════════════════════════════════════
    -- السماح للمستخدم بإنشاء role assignment لنفسه للمرة الأولى
    -- (عند التسجيل الجديد، لا يوجد له أي أدوار بعد)
    -- ═══════════════════════════════════════════════════════════
    IF TG_OP = 'INSERT' AND NEW.user_id = v_current_user_id THEN
        -- هل لديه أي دور حالي؟
        IF NOT EXISTS (
            SELECT 1 FROM user_role_assignments 
            WHERE user_id = v_current_user_id
        ) THEN
            -- لا يوجد له دور = تسجيل جديد = السماح
            RETURN NEW;
        END IF;
    END IF;
    
    -- فقط Super Admin أو Tenant Admin يمكنهم تعديل الأدوار
    IF NOT (v_is_super_admin OR v_is_tenant_admin) THEN
        RAISE EXCEPTION 'غير مسموح بتعديل صلاحيات المستخدمين';
    END IF;
    
    -- منع المستخدم من تعديل صلاحياته الخاصة (إلا Super Admin)
    IF TG_OP = 'UPDATE' AND NEW.user_id = v_current_user_id AND NOT v_is_super_admin THEN
        RAISE EXCEPTION 'لا يمكنك تعديل صلاحياتك الخاصة';
    END IF;
    
    RETURN COALESCE(NEW, OLD);
END;
$$;


--
-- Name: protect_sensitive_user_fields(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.protect_sensitive_user_fields() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
BEGIN
    -- السماح لـ Super Admin فقط بتغيير هذه الحقول
    IF NOT COALESCE(
        (SELECT is_super_admin FROM user_profiles WHERE id = auth.uid()), 
        false
    ) THEN
        -- منع تغيير is_super_admin
        IF OLD.is_super_admin IS DISTINCT FROM NEW.is_super_admin THEN
            RAISE EXCEPTION 'غير مسموح بتغيير حقل is_super_admin';
        END IF;
        
        -- منع تغيير tenant_id
        IF OLD.tenant_id IS DISTINCT FROM NEW.tenant_id THEN
            RAISE EXCEPTION 'غير مسموح بتغيير حقل tenant_id';
        END IF;
        
        -- منع تغيير brand_id
        IF OLD.brand_id IS DISTINCT FROM NEW.brand_id THEN
            RAISE EXCEPTION 'غير مسموح بتغيير حقل brand_id';
        END IF;
        
        -- منع تغيير company_id
        IF OLD.company_id IS DISTINCT FROM NEW.company_id THEN
            RAISE EXCEPTION 'غير مسموح بتغيير حقل company_id';
        END IF;
    END IF;
    
    RETURN NEW;
END;
$$;


--
-- Name: protect_super_admins(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.protect_super_admins() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_current_user_id UUID := auth.uid();
    v_is_platform_owner BOOLEAN;
    v_super_admin_count INT;
BEGIN
    IF v_current_user_id IS NULL THEN
        -- السماح للعمليات النظامية بدون مستخدم (مثل الـ migrations)
        RETURN COALESCE(NEW, OLD);
    END IF;

    v_is_platform_owner := is_platform_owner(v_current_user_id);
    
    -- فقط Platform Owner يمكنه تعديل جدول super_admins
    IF NOT v_is_platform_owner THEN
        RAISE EXCEPTION 'غير مسموح: فقط مالك المنصة يمكنه إدارة مديري المنصة / Not allowed: Only platform owner can manage super admins';
    END IF;

    -- عند الحذف: منع حذف آخر Platform Owner
    IF TG_OP = 'DELETE' THEN
        SELECT COUNT(*) INTO v_super_admin_count
        FROM public.super_admins
        WHERE is_active = true;
        
        IF v_super_admin_count <= 1 THEN
            RAISE EXCEPTION 'غير مسموح: لا يمكن حذف آخر مالك للمنصة / Not allowed: Cannot delete the last platform owner';
        END IF;
        
        RETURN OLD;
    END IF;

    -- عند إلغاء التفعيل: منع إلغاء تفعيل آخر Platform Owner
    IF TG_OP = 'UPDATE' AND OLD.is_active = true AND NEW.is_active = false THEN
        SELECT COUNT(*) INTO v_super_admin_count
        FROM public.super_admins
        WHERE is_active = true AND id != OLD.id;
        
        IF v_super_admin_count < 1 THEN
            RAISE EXCEPTION 'غير مسموح: لا يمكن إلغاء تفعيل آخر مالك للمنصة / Not allowed: Cannot deactivate the last platform owner';
        END IF;
    END IF;

    RETURN NEW;
END;
$$;


--
-- Name: protect_tenant_fields(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.protect_tenant_fields() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
BEGIN
    -- فقط Super Admin يمكنه تعديل الـ tenants
    IF NOT COALESCE(
        (SELECT is_super_admin FROM user_profiles WHERE id = auth.uid()), 
        false
    ) THEN
        -- منع تغيير brand_id
        IF TG_OP = 'UPDATE' AND OLD.brand_id IS DISTINCT FROM NEW.brand_id THEN
            RAISE EXCEPTION 'غير مسموح بتغيير العلامة التجارية للمستأجر';
        END IF;
    END IF;
    
    RETURN NEW;
END;
$$;


--
-- Name: protect_tenants(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.protect_tenants() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_current_user_id UUID := auth.uid();
    v_is_platform_owner BOOLEAN;
    v_is_platform_admin BOOLEAN;
    v_user_email TEXT;
BEGIN
    IF v_current_user_id IS NULL THEN
        RETURN NEW;
    END IF;

    v_is_platform_owner := is_platform_owner(v_current_user_id);
    v_is_platform_admin := is_platform_admin(v_current_user_id);
    
    -- الحصول على بريد المستخدم الحالي
    SELECT email INTO v_user_email FROM public.user_profiles WHERE id = v_current_user_id;

    -- ════════ حماية product_id (البراند) ════════
    IF OLD.product_id IS DISTINCT FROM NEW.product_id THEN
        IF NOT v_is_platform_owner THEN
            RAISE EXCEPTION 'غير مسموح: لا يمكن تغيير البراند إلا من مالك المنصة / Not allowed: Only platform owner can change brand (product_id)';
        END IF;
    END IF;

    -- ════════ حماية owner_email ════════
    IF OLD.owner_email IS DISTINCT FROM NEW.owner_email THEN
        IF NOT (v_is_platform_admin OR LOWER(OLD.owner_email) = LOWER(v_user_email)) THEN
            RAISE EXCEPTION 'غير مسموح: فقط مدير المنصة أو صاحب الاشتراك يمكنه تغيير owner_email / Not allowed: Only platform admin or current owner can change owner_email';
        END IF;
    END IF;

    -- ════════ حماية partner_id ════════
    IF OLD.partner_id IS DISTINCT FROM NEW.partner_id THEN
        IF NOT v_is_platform_admin THEN
            RAISE EXCEPTION 'غير مسموح: فقط مدير المنصة يمكنه تغيير partner_id / Not allowed: Only platform admin can change partner_id';
        END IF;
    END IF;

    RETURN NEW;
END;
$$;


--
-- Name: protect_user_profile_fields(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.protect_user_profile_fields() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
BEGIN
    -- فقط Super Admin يمكنه تغيير هذه الحقول
    IF NOT is_super_admin(auth.uid()) THEN
        -- منع تغيير role
        IF OLD.role IS DISTINCT FROM NEW.role THEN
            RAISE EXCEPTION 'Cannot change role field';
        END IF;
        
        -- منع تغيير tenant_id
        IF OLD.tenant_id IS DISTINCT FROM NEW.tenant_id THEN
            RAISE EXCEPTION 'Cannot change tenant_id field';
        END IF;
        
        -- منع تغيير company_id
        IF OLD.company_id IS DISTINCT FROM NEW.company_id THEN
            RAISE EXCEPTION 'Cannot change company_id field';
        END IF;
    END IF;
    
    RETURN NEW;
END;
$$;


--
-- Name: protect_user_profiles(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.protect_user_profiles() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_current_user_id UUID := auth.uid();
    v_is_platform_owner BOOLEAN;
    v_is_platform_admin BOOLEAN;
    v_is_tenant_owner BOOLEAN;
BEGIN
    -- تخطي للعمليات النظامية (بدون مستخدم)
    IF v_current_user_id IS NULL THEN
        RETURN NEW;
    END IF;

    -- الحصول على صلاحيات المستخدم الحالي
    v_is_platform_owner := is_platform_owner(v_current_user_id);
    v_is_platform_admin := is_platform_admin(v_current_user_id);
    v_is_tenant_owner := is_tenant_owner(v_current_user_id);

    -- ════════ حماية is_super_admin ════════
    IF OLD.is_super_admin IS DISTINCT FROM NEW.is_super_admin THEN
        IF NOT v_is_platform_owner THEN
            RAISE EXCEPTION 'غير مسموح: فقط مالك المنصة يمكنه تغيير is_super_admin / Not allowed: Only platform owner can change is_super_admin';
        END IF;
    END IF;

    -- ════════ حماية is_platform_admin ════════
    IF OLD.is_platform_admin IS DISTINCT FROM NEW.is_platform_admin THEN
        IF NOT v_is_platform_owner THEN
            RAISE EXCEPTION 'غير مسموح: فقط مالك المنصة يمكنه تغيير is_platform_admin / Not allowed: Only platform owner can change is_platform_admin';
        END IF;
    END IF;

    -- ════════ حماية tenant_id ════════
    IF OLD.tenant_id IS DISTINCT FROM NEW.tenant_id THEN
        IF NOT v_is_platform_admin THEN
            RAISE EXCEPTION 'غير مسموح: فقط مدير المنصة يمكنه تغيير tenant_id / Not allowed: Only platform admin can change tenant_id';
        END IF;
    END IF;

    -- ════════ حماية company_id ════════
    IF OLD.company_id IS DISTINCT FROM NEW.company_id THEN
        IF NOT (v_is_platform_admin OR v_is_tenant_owner) THEN
            RAISE EXCEPTION 'غير مسموح: فقط مدير المنصة أو صاحب الاشتراك يمكنه تغيير company_id / Not allowed: Only platform admin or tenant owner can change company_id';
        END IF;
    END IF;

    -- ════════ المستخدم العادي: تحقق من الحقول المسموحة فقط ════════
    IF NOT (v_is_platform_admin OR v_is_tenant_owner) THEN
        -- المستخدم يعدّل بياناته فقط
        IF OLD.id = v_current_user_id THEN
            -- الحقول المسموح تعديلها: full_name, display_name, phone, avatar_url, settings, preferred_language
            IF OLD.email IS DISTINCT FROM NEW.email THEN
                RAISE EXCEPTION 'غير مسموح: لا يمكنك تغيير البريد الإلكتروني / Not allowed: You cannot change email';
            END IF;
            IF OLD.role IS DISTINCT FROM NEW.role THEN
                RAISE EXCEPTION 'غير مسموح: لا يمكنك تغيير دورك / Not allowed: You cannot change your role';
            END IF;
        ELSE
            -- محاولة تعديل بيانات مستخدم آخر
            RAISE EXCEPTION 'غير مسموح: لا يمكنك تعديل بيانات مستخدم آخر / Not allowed: You cannot modify another user''s data';
        END IF;
    END IF;

    RETURN NEW;
END;
$$;


--
-- Name: protect_user_roles(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.protect_user_roles() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_current_user_id UUID := auth.uid();
    v_is_platform_admin BOOLEAN;
    v_is_tenant_owner BOOLEAN;
    v_is_company_admin BOOLEAN;
    v_target_user_tenant_id UUID;
    v_target_user_company_id UUID;
    v_current_user_tenant_id UUID;
    v_target_role_level INT;
    v_current_user_max_role_level INT;
BEGIN
    IF v_current_user_id IS NULL THEN
        RETURN NEW;
    END IF;

    v_is_platform_admin := is_platform_admin(v_current_user_id);
    v_is_tenant_owner := is_tenant_owner(v_current_user_id);
    v_current_user_tenant_id := get_user_tenant_id(v_current_user_id);

    -- Platform Admin يمكنه كل شيء
    IF v_is_platform_admin THEN
        RETURN NEW;
    END IF;

    -- ════════ منع تعديل صلاحيات النفس ════════
    IF NEW.user_id = v_current_user_id THEN
        RAISE EXCEPTION 'غير مسموح: لا يمكنك تغيير صلاحياتك بنفسك / Not allowed: You cannot modify your own permissions';
    END IF;

    -- الحصول على بيانات المستخدم المستهدف
    SELECT tenant_id, company_id INTO v_target_user_tenant_id, v_target_user_company_id
    FROM public.user_profiles
    WHERE id = NEW.user_id;

    -- ════════ Tenant Owner: يمكنه تعديل صلاحيات مستخدمي تينانته ════════
    IF v_is_tenant_owner THEN
        IF v_target_user_tenant_id != v_current_user_tenant_id THEN
            RAISE EXCEPTION 'غير مسموح: لا يمكنك تعديل صلاحيات مستخدم خارج تينانتك / Not allowed: You cannot modify permissions of users outside your tenant';
        END IF;
        RETURN NEW;
    END IF;

    -- ════════ Company Admin: يمكنه تعديل صلاحيات مستخدمي شركته فقط ════════
    v_is_company_admin := is_company_admin(v_current_user_id, v_target_user_company_id);
    
    IF v_is_company_admin THEN
        -- التحقق من أن المستخدم المستهدف في نفس الشركة
        IF NOT can_access_company(v_target_user_company_id, v_current_user_id) THEN
            RAISE EXCEPTION 'غير مسموح: لا يمكنك تعديل صلاحيات مستخدم خارج شركتك / Not allowed: You cannot modify permissions of users outside your company';
        END IF;
        
        -- التحقق من عدم منح صلاحيات أعلى من صلاحيات المانح
        -- الحصول على مستوى الدور المستهدف
        SELECT COALESCE(r.level, 100) INTO v_target_role_level
        FROM public.roles r
        WHERE r.id = NEW.role_id;
        
        -- الحصول على أعلى مستوى دور للمستخدم الحالي
        SELECT COALESCE(MIN(r.level), 100) INTO v_current_user_max_role_level
        FROM public.user_roles ur
        JOIN public.roles r ON ur.role_id = r.id
        WHERE ur.user_id = v_current_user_id
          AND ur.is_active = true;
        
        IF v_target_role_level < v_current_user_max_role_level THEN
            RAISE EXCEPTION 'غير مسموح: لا يمكنك منح صلاحيات أعلى من صلاحياتك / Not allowed: You cannot grant permissions higher than your own';
        END IF;
        
        RETURN NEW;
    END IF;

    -- المستخدم العادي لا يمكنه تعديل الصلاحيات
    RAISE EXCEPTION 'غير مسموح: ليس لديك صلاحية تعديل أدوار المستخدمين / Not allowed: You do not have permission to modify user roles';
END;
$$;


--
-- Name: record_payment(uuid, uuid, numeric, character varying, character varying, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.record_payment(p_tenant_id uuid, p_invoice_id uuid, p_amount numeric, p_payment_method character varying, p_transaction_id character varying DEFAULT NULL::character varying, p_notes text DEFAULT NULL::text) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_invoice RECORD;
    v_payment_id UUID;
    v_subscription RECORD;
BEGIN
    -- الحصول على الفاتورة
    SELECT * INTO v_invoice FROM billing_invoices 
    WHERE id = p_invoice_id AND tenant_id = p_tenant_id;
    
    IF NOT FOUND THEN
        RETURN jsonb_build_object('success', false, 'error', 'الفاتورة غير موجودة');
    END IF;
    
    -- تسجيل الدفعة
    INSERT INTO billing_payments (
        tenant_id, invoice_id, amount, currency,
        payment_method, transaction_id, notes, status
    ) VALUES (
        p_tenant_id, p_invoice_id, p_amount, v_invoice.currency,
        p_payment_method, p_transaction_id, p_notes, 'completed'
    ) RETURNING id INTO v_payment_id;
    
    -- تحديث الفاتورة
    UPDATE billing_invoices
    SET status = CASE WHEN p_amount >= total_amount THEN 'paid' ELSE 'partial' END,
        paid_at = NOW(),
        paid_amount = COALESCE(paid_amount, 0) + p_amount
    WHERE id = p_invoice_id;
    
    -- تفعيل الاشتراك إذا كان في الانتظار
    UPDATE subscriptions
    SET status = 'active',
        current_period_start = NOW(),
        current_period_end = NOW() + CASE WHEN billing_cycle = 'yearly' THEN INTERVAL '1 year' ELSE INTERVAL '1 month' END
    WHERE tenant_id = p_tenant_id AND status IN ('trial', 'past_due')
    RETURNING * INTO v_subscription;
    
    -- تسجيل الحدث
    INSERT INTO saas_events (tenant_id, event_type, event_data, actor_type)
    VALUES (p_tenant_id, 'payment_received', jsonb_build_object(
        'invoice_id', p_invoice_id,
        'amount', p_amount,
        'method', p_payment_method
    ), 'admin');
    
    RETURN jsonb_build_object(
        'success', true,
        'payment_id', v_payment_id,
        'subscription_status', v_subscription.status
    );
END;
$$;


