--
-- Name: register_customer(character varying, character varying, character varying, character varying, uuid, uuid, character varying, character varying, character varying); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.register_customer(p_email character varying, p_password character varying, p_full_name character varying, p_phone character varying, p_tenant_id uuid, p_company_id uuid, p_customer_group_code character varying DEFAULT 'RETAIL'::character varying, p_country character varying DEFAULT NULL::character varying, p_city character varying DEFAULT NULL::character varying) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_auth_user_id UUID;
    v_customer_id UUID;
    v_customer_code VARCHAR;
    v_customer_group_id UUID;
    v_name_parts TEXT[];
    v_first_name VARCHAR;
    v_last_name VARCHAR;
BEGIN
    -- ═══════════════════════════════════════════════════════════════
    -- 1. التحقق من عدم وجود Email مسبقاً
    -- ═══════════════════════════════════════════════════════════════
    
    IF EXISTS (SELECT 1 FROM customers WHERE email = p_email AND tenant_id = p_tenant_id) THEN
        RETURN jsonb_build_object(
            'success', false,
            'error', 'email_exists',
            'message', 'البريد الإلكتروني مسجل مسبقاً'
        );
    END IF;
    
    -- ═══════════════════════════════════════════════════════════════
    -- 2. إنشاء المستخدم في Supabase Auth
    -- ═══════════════════════════════════════════════════════════════
    
    -- ملاحظة: هذا يحتاج تنفيذ من خلال Supabase Auth API
    -- في الـ Frontend أو عبر Edge Function
    -- هنا نفترض أن auth_user_id سيُمرر من الخارج
    
    -- للاختبار فقط، يمكن استخدام gen_random_uuid()
    -- في الواقع، يجب استخدام Supabase Auth signup
    v_auth_user_id := gen_random_uuid();
    
    RAISE NOTICE 'ℹ️ تم توليد auth_user_id: %', v_auth_user_id;
    RAISE NOTICE 'ℹ️ في Production، استخدم Supabase Auth API لإنشاء المستخدم';
    
    -- ═══════════════════════════════════════════════════════════════
    -- 3. توليد customer_code
    -- ═══════════════════════════════════════════════════════════════
    
    v_customer_code := generate_customer_code(p_tenant_id);
    
    -- ═══════════════════════════════════════════════════════════════
    -- 4. الحصول على customer_group_id
    -- ═══════════════════════════════════════════════════════════════
    
    SELECT id INTO v_customer_group_id
    FROM customer_groups
    WHERE code = p_customer_group_code 
      AND tenant_id = p_tenant_id
    LIMIT 1;
    
    -- إذا لم توجد المجموعة، استخدم RETAIL الافتراضية
    IF v_customer_group_id IS NULL THEN
        SELECT id INTO v_customer_group_id
        FROM customer_groups
        WHERE code = 'RETAIL' 
          AND tenant_id = p_tenant_id
        LIMIT 1;
    END IF;
    
    -- ═══════════════════════════════════════════════════════════════
    -- 5. فصل الاسم الأول والأخير
    -- ═══════════════════════════════════════════════════════════════
    
    v_name_parts := string_to_array(p_full_name, ' ');
    v_first_name := v_name_parts[1];
    
    IF array_length(v_name_parts, 1) > 1 THEN
        v_last_name := array_to_string(v_name_parts[2:], ' ');
    ELSE
        v_last_name := '';
    END IF;
    
    -- ═══════════════════════════════════════════════════════════════
    -- 6. إنشاء customers record
    -- ═══════════════════════════════════════════════════════════════
    
    INSERT INTO customers (
        tenant_id,
        company_id,
        code,
        customer_type,
        name_ar,
        name_en,
        first_name,
        last_name,
        email,
        phone,
        mobile,
        country,
        city,
        group_id,
        auth_user_id,
        status,
        created_at
    )
    VALUES (
        p_tenant_id,
        p_company_id,
        v_customer_code,
        'individual',
        p_full_name,
        p_full_name,
        v_first_name,
        v_last_name,
        p_email,
        p_phone,
        p_phone,
        p_country,
        p_city,
        v_customer_group_id,
        v_auth_user_id,
        'active',
        NOW()
    )
    RETURNING id INTO v_customer_id;
    
    RAISE NOTICE '✅ تم إنشاء customer: % (%)', v_customer_code, v_customer_id;
    
    -- ═══════════════════════════════════════════════════════════════
    -- 7. إنشاء user_profiles record
    -- ═══════════════════════════════════════════════════════════════
    
    INSERT INTO user_profiles (
        id,
        email,
        full_name,
        role,
        tenant_id,
        company_id,
        customer_id,
        phone,
        created_at
    )
    VALUES (
        v_auth_user_id,
        p_email,
        p_full_name,
        'customer',
        p_tenant_id,
        p_company_id,
        v_customer_id,
        p_phone,
        NOW()
    )
    ON CONFLICT (id) DO UPDATE SET
        email = EXCLUDED.email,
        full_name = EXCLUDED.full_name,
        role = EXCLUDED.role,
        tenant_id = EXCLUDED.tenant_id,
        company_id = EXCLUDED.company_id,
        customer_id = EXCLUDED.customer_id,
        phone = EXCLUDED.phone;
    
    RAISE NOTICE '✅ تم إنشاء user_profile: role=customer';
    
    -- ═══════════════════════════════════════════════════════════════
    -- 8. إرجاع النتيجة
    -- ═══════════════════════════════════════════════════════════════
    
    RETURN jsonb_build_object(
        'success', true,
        'customer_id', v_customer_id,
        'customer_code', v_customer_code,
        'auth_user_id', v_auth_user_id,
        'message', 'تم التسجيل بنجاح'
    );
    
EXCEPTION
    WHEN OTHERS THEN
        RAISE NOTICE '❌ خطأ في register_customer: %', SQLERRM;
        RETURN jsonb_build_object(
            'success', false,
            'error', 'registration_failed',
            'message', SQLERRM
        );
END;
$$;


