--
-- Name: register_new_subscriber(uuid, character varying, character varying, character varying, character varying, character varying, character varying, character varying, character varying, character varying, character varying); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.register_new_subscriber(p_user_id uuid, p_user_email character varying, p_user_name character varying, p_company_name character varying DEFAULT NULL::character varying, p_phone character varying DEFAULT NULL::character varying, p_business_type character varying DEFAULT 'general'::character varying, p_currency character varying DEFAULT 'USD'::character varying, p_country_code character varying DEFAULT 'SA'::character varying, p_plan_code character varying DEFAULT 'starter'::character varying, p_chart_template character varying DEFAULT 'fabric_extended'::character varying, p_local_currency character varying DEFAULT NULL::character varying) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_tenant_code VARCHAR(50);
    v_tenant_id UUID;
    v_company_id UUID;
    v_plan_id UUID;
    v_subscription_id UUID;
    v_trial_days INT := 30; -- افتراضي 30 يوم
    v_included_modules text[];
    v_result JSONB;
    v_currencies TEXT[];
    v_tenant_owner_role_id UUID;
BEGIN
    -- إنشاء رمز فريد للـ Tenant
    v_tenant_code := 'T-' || UPPER(SUBSTRING(MD5(RANDOM()::TEXT || NOW()::TEXT), 1, 10));
    
    -- تحضير قائمة العملات
    v_currencies := ARRAY[p_currency];
    IF p_local_currency IS NOT NULL AND p_local_currency != p_currency THEN
        v_currencies := array_append(v_currencies, p_local_currency);
    END IF;
    
    -- الحصول على الباقة
    SELECT id, COALESCE(trial_days, 30), included_modules 
    INTO v_plan_id, v_trial_days, v_included_modules
    FROM subscription_plans
    WHERE code = p_plan_code AND is_active = true
    LIMIT 1;
    
    -- إذا لم توجد الباقة المطلوبة، استخدم starter
    IF v_plan_id IS NULL THEN
        SELECT id, COALESCE(trial_days, 30), included_modules 
        INTO v_plan_id, v_trial_days, v_included_modules
        FROM subscription_plans
        WHERE code = 'starter' AND is_active = true
        LIMIT 1;
    END IF;
    
    IF v_plan_id IS NULL THEN
        RAISE EXCEPTION 'لا توجد باقات نشطة';
    END IF;
    
    -- 🔐 الحصول على role_id لـ tenant_owner
    SELECT id INTO v_tenant_owner_role_id
    FROM roles WHERE code = 'tenant_owner'
    LIMIT 1;
    
    IF v_tenant_owner_role_id IS NULL THEN
        RAISE EXCEPTION 'لم يتم العثور على دور tenant_owner';
    END IF;
    
    -- إنشاء Tenant
    v_tenant_id := create_new_tenant(
        v_tenant_code,
        COALESCE(p_company_name, p_user_name),
        p_user_email,
        p_phone,
        p_country_code,
        'ar',
        p_business_type
    );
    
    IF v_tenant_id IS NULL THEN
        RAISE EXCEPTION 'فشل إنشاء Tenant';
    END IF;
    
    -- إنشاء Subscription
    INSERT INTO subscriptions (
        tenant_id, product_id, plan_id, status,
        trial_ends_at, current_period_start, current_period_end
    )
    SELECT
        v_tenant_id, sp.product_id, v_plan_id, 'trial',
        NOW() + (v_trial_days || ' days')::INTERVAL, NOW(),
        NOW() + (v_trial_days || ' days')::INTERVAL
    FROM subscription_plans sp
    WHERE sp.id = v_plan_id
    RETURNING id INTO v_subscription_id;
    
    -- إنشاء الشركة الافتراضية
    v_company_id := create_default_company_for_tenant(
        v_tenant_id,
        COALESCE(p_company_name, p_user_name),
        p_business_type,
        'production',
        p_currency,
        p_country_code
    );
    
    IF v_company_id IS NULL THEN
        RAISE EXCEPTION 'فشل إنشاء الشركة';
    END IF;
    
    -- إنشاء company_accounting_settings
    INSERT INTO company_accounting_settings (
        company_id, base_currency, supported_currencies,
        fiscal_year_start_month, fiscal_year_end_month, enable_vat, decimal_places
    )
    VALUES (v_company_id, p_currency, v_currencies, 1, 12, true, 2)
    ON CONFLICT (company_id) DO UPDATE SET
        base_currency = EXCLUDED.base_currency,
        supported_currencies = EXCLUDED.supported_currencies,
        updated_at = NOW();
    
    -- إضافة بيانات المستخدم في user_profiles
    INSERT INTO user_profiles (id, email, full_name, tenant_id, company_id, role)
    VALUES (p_user_id, p_user_email, p_user_name, v_tenant_id, v_company_id, 'tenant_owner')
    ON CONFLICT (id) DO UPDATE SET
        email = EXCLUDED.email,
        full_name = EXCLUDED.full_name,
        tenant_id = EXCLUDED.tenant_id,
        company_id = EXCLUDED.company_id,
        role = EXCLUDED.role;
    
    -- ⭐ ربط المستخدم بدور tenant_owner في user_role_assignments
    INSERT INTO user_role_assignments (
        user_id, role_id, tenant_id, company_id, 
        assigned_by, is_active, created_at
    )
    VALUES (
        p_user_id, v_tenant_owner_role_id, v_tenant_id, v_company_id,
        p_user_id, true, NOW()
    )
    ON CONFLICT (user_id, role_id, tenant_id, company_id) DO UPDATE SET
        is_active = true,
        updated_at = NOW();
    
    -- تحديث user_metadata في auth.users
    UPDATE auth.users
    SET raw_user_meta_data = COALESCE(raw_user_meta_data, '{}'::jsonb) || jsonb_build_object(
        'tenant_id', v_tenant_id,
        'company_id', v_company_id,
        'full_name', p_user_name,
        'registration_complete', true,
        'role', 'tenant_owner'
    )
    WHERE id = p_user_id;
    
    -- تفعيل الموديولات المضمنة في الباقة
    IF EXISTS (SELECT 1 FROM information_schema.tables WHERE table_name = 'system_modules') THEN
        INSERT INTO tenant_modules (tenant_id, module_code, is_active)
        SELECT v_tenant_id, sm.code, true
        FROM system_modules sm
        WHERE sm.code = ANY(v_included_modules)
        AND sm.is_active = true
        ON CONFLICT (tenant_id, module_code) DO UPDATE SET is_active = true;
    END IF;
    
    -- تطبيق قالب الشجرة المحاسبية
    IF p_chart_template IS NOT NULL THEN
        BEGIN
            PERFORM apply_chart_template_to_company(v_company_id, p_chart_template);
        EXCEPTION WHEN OTHERS THEN
            RAISE NOTICE 'تحذير: لم يتم تطبيق قالب الشجرة: %', SQLERRM;
        END;
    END IF;
    
    -- إرجاع النتيجة
    v_result := jsonb_build_object(
        'success', true,
        'tenant_id', v_tenant_id,
        'tenant_code', v_tenant_code,
        'company_id', v_company_id,
        'subscription_id', v_subscription_id,
        'plan_code', p_plan_code,
        'trial_days', v_trial_days,
        'trial_ends_at', NOW() + (v_trial_days || ' days')::INTERVAL,
        'currencies', v_currencies,
        'role', 'tenant_owner',
        'message', 'تم التسجيل بنجاح'
    );
    
    RETURN v_result;
    
EXCEPTION
    WHEN OTHERS THEN
        RAISE EXCEPTION 'خطأ في التسجيل: %', SQLERRM;
END;
$$;


--
-- Name: register_white_label_payment(uuid, numeric, character varying, character varying, integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.register_white_label_payment(p_agent_id uuid, p_amount numeric, p_payment_method character varying, p_payment_reference character varying, p_period_months integer DEFAULT 12) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_agent RECORD;
    v_payment_id UUID;
    v_valid_from TIMESTAMPTZ;
    v_valid_to TIMESTAMPTZ;
BEGIN
    -- التحقق من الوكيل
    SELECT * INTO v_agent FROM agents WHERE id = p_agent_id AND status = 'active';
    IF NOT FOUND THEN
        RETURN jsonb_build_object('success', false, 'error', 'الوكيل غير موجود أو غير نشط');
    END IF;
    
    -- حساب الفترة
    v_valid_from := NOW();
    v_valid_to := v_valid_from + (p_period_months || ' months')::INTERVAL;
    
    -- إنشاء سجل الدفعة
    INSERT INTO white_label_payments (
        agent_id, amount, payment_method, payment_reference,
        period_months, valid_from, valid_to, status
    ) VALUES (
        p_agent_id, p_amount, p_payment_method, p_payment_reference,
        p_period_months, v_valid_from, v_valid_to, 'pending'
    ) RETURNING id INTO v_payment_id;
    
    -- تحديث حالة الوكيل
    UPDATE agents
    SET white_label_status = 'pending'
    WHERE id = p_agent_id;
    
    -- تسجيل الحدث
    INSERT INTO agent_events (agent_id, event_type, event_data)
    VALUES (p_agent_id, 'white_label_payment_registered', jsonb_build_object(
        'payment_id', v_payment_id,
        'amount', p_amount,
        'period_months', p_period_months
    ));
    
    RETURN jsonb_build_object(
        'success', true,
        'payment_id', v_payment_id,
        'valid_from', v_valid_from,
        'valid_to', v_valid_to,
        'message', 'تم تسجيل الدفعة بنجاح - في انتظار المعالجة'
    );
END;
$$;


--
-- Name: reject_recurring_entry(uuid, uuid, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.reject_recurring_entry(p_history_id uuid, p_user_id uuid, p_reason text) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
BEGIN
    UPDATE recurring_entry_history
    SET 
        approval_status = 'rejected',
        approved_by = p_user_id,
        approved_at = NOW(),
        rejection_reason = p_reason,
        status = 'cancelled'
    WHERE id = p_history_id
      AND approval_status = 'pending';
    
    IF NOT FOUND THEN
        RETURN jsonb_build_object('success', false, 'error', 'Record not found or already processed');
    END IF;
    
    RETURN jsonb_build_object('success', true, 'message', 'Rejected successfully');
END;
$$;


--
-- Name: FUNCTION reject_recurring_entry(p_history_id uuid, p_user_id uuid, p_reason text); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION public.reject_recurring_entry(p_history_id uuid, p_user_id uuid, p_reason text) IS 'رفض قيد متكرر مع ذكر السبب';


--
-- Name: reject_review(uuid, uuid, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.reject_review(p_tenant_id uuid, p_review_id uuid, p_reason text DEFAULT NULL::text) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
BEGIN
    UPDATE product_reviews
    SET status = 'rejected',
        report_reason = p_reason,
        updated_at = NOW()
    WHERE id = p_review_id
      AND tenant_id = p_tenant_id;
    
    IF NOT FOUND THEN
        RETURN jsonb_build_object('success', false, 'error', 'التقييم غير موجود');
    END IF;
    
    RETURN jsonb_build_object('success', true, 'message', 'تم رفض التقييم');
END;
$$;


--
-- Name: FUNCTION reject_review(p_tenant_id uuid, p_review_id uuid, p_reason text); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION public.reject_review(p_tenant_id uuid, p_review_id uuid, p_reason text) IS 'رفض تقييم';


--
-- Name: remove_from_cart(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.remove_from_cart(p_item_id uuid) RETURNS boolean
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_cart_id UUID;
BEGIN
    -- حذف العنصر
    DELETE FROM shopping_cart_items
    WHERE id = p_item_id
    RETURNING cart_id INTO v_cart_id;
    
    IF NOT FOUND THEN
        RETURN false;
    END IF;
    
    -- تحديث المجاميع
    PERFORM update_cart_totals(v_cart_id);
    
    RETURN TRUE;
END;
$$;


--
-- Name: FUNCTION remove_from_cart(p_item_id uuid); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION public.remove_from_cart(p_item_id uuid) IS 'حذف منتج من السلة';


--
-- Name: remove_module_from_plan(uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.remove_module_from_plan(p_plan_id uuid, p_module_id uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_is_core BOOLEAN;
BEGIN
    -- التحقق من أن الموديول ليس أساسي
    SELECT is_core INTO v_is_core
    FROM plan_modules
    WHERE plan_id = p_plan_id AND module_id = p_module_id;
    
    IF v_is_core THEN
        RETURN jsonb_build_object(
            'success', false,
            'error', 'core_module',
            'message', 'لا يمكن إزالة موديول أساسي'
        );
    END IF;
    
    -- حذف الموديول
    DELETE FROM plan_modules
    WHERE plan_id = p_plan_id AND module_id = p_module_id;
    
    RETURN jsonb_build_object(
        'success', true,
        'message', 'تمت إزالة الموديول بنجاح'
    );
    
EXCEPTION
    WHEN OTHERS THEN
        RETURN jsonb_build_object(
            'success', false,
            'error', 'exception',
            'message', SQLERRM
        );
END;
$$;


--
-- Name: FUNCTION remove_module_from_plan(p_plan_id uuid, p_module_id uuid); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION public.remove_module_from_plan(p_plan_id uuid, p_module_id uuid) IS 'إزالة موديول من باقة (إلا إذا كان أساسي)';


--
-- Name: remove_product_image(uuid, uuid, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.remove_product_image(p_tenant_id uuid, p_product_id uuid, p_image_url text) RETURNS boolean
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_current_images JSONB;
    v_updated_images JSONB;
BEGIN
    -- 1. الحصول على الصور الحالية
    SELECT COALESCE(images, '[]'::jsonb)
    INTO v_current_images
    FROM products
    WHERE id = p_product_id AND tenant_id = p_tenant_id;
    
    -- 2. حذف الصورة المحددة
    v_updated_images := (
        SELECT jsonb_agg(img)
        FROM jsonb_array_elements(v_current_images) AS img
        WHERE img->>'url' != p_image_url
    );
    
    -- 3. تحديث المنتج
    UPDATE products
    SET images = COALESCE(v_updated_images, '[]'::jsonb),
        updated_at = NOW()
    WHERE id = p_product_id AND tenant_id = p_tenant_id;
    
    RETURN FOUND;
END;
$$;


