COMMENT ON FUNCTION public.remove_product_image(p_tenant_id uuid, p_product_id uuid, p_image_url text) IS 'حذف صورة من المنتج';


--
-- Name: renew_subscription(uuid, integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.renew_subscription(p_subscription_id uuid, p_months integer DEFAULT 1) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_subscription RECORD;
    v_new_end DATE;
    v_result JSONB;
BEGIN
    -- الحصول على الاشتراك
    SELECT * INTO v_subscription
    FROM subscriptions
    WHERE id = p_subscription_id;
    
    IF NOT FOUND THEN
        RETURN jsonb_build_object('success', false, 'error', 'subscription_not_found');
    END IF;
    
    -- حساب التاريخ الجديد
    IF v_subscription.current_period_end IS NULL OR 
       v_subscription.current_period_end < CURRENT_DATE THEN
        v_new_end := CURRENT_DATE + (p_months * INTERVAL '1 month');
    ELSE
        v_new_end := v_subscription.current_period_end + (p_months * INTERVAL '1 month');
    END IF;
    
    -- تحديث الاشتراك
    UPDATE subscriptions
    SET 
        status = 'active',
        current_period_end = v_new_end,
        locked_at = NULL,
        lock_reason = NULL,
        updated_at = NOW()
    WHERE id = p_subscription_id;
    
    -- تسجيل
    PERFORM log_audit(
        'renew',
        'subscriptions',
        p_subscription_id,
        NULL,
        NULL,
        jsonb_build_object('new_period_end', v_new_end, 'months', p_months)
    );
    
    RETURN jsonb_build_object(
        'success', true,
        'new_period_end', v_new_end,
        'months_added', p_months
    );
END;
$$;


--
-- Name: reorder_product_images(uuid, uuid, jsonb); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.reorder_product_images(p_tenant_id uuid, p_product_id uuid, p_image_orders jsonb) RETURNS boolean
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_current_images JSONB;
    v_updated_images JSONB;
    v_order_item JSONB;
BEGIN
    -- 1. الحصول على الصور الحالية
    SELECT COALESCE(images, '[]'::jsonb)
    INTO v_current_images
    FROM products
    WHERE id = p_product_id AND tenant_id = p_tenant_id;
    
    -- 2. تحديث display_order لكل صورة
    v_updated_images := (
        SELECT jsonb_agg(
            jsonb_set(
                img, 
                '{display_order}', 
                to_jsonb(
                    COALESCE(
                        (
                            SELECT (order_item->>'display_order')::int
                            FROM jsonb_array_elements(p_image_orders) AS order_item
                            WHERE order_item->>'url' = img->>'url'
                        ),
                        (img->>'display_order')::int
                    )
                )
            )
            ORDER BY 
                COALESCE(
                    (
                        SELECT (order_item->>'display_order')::int
                        FROM jsonb_array_elements(p_image_orders) AS order_item
                        WHERE order_item->>'url' = img->>'url'
                    ),
                    (img->>'display_order')::int
                )
        )
        FROM jsonb_array_elements(v_current_images) AS img
    );
    
    -- 3. تحديث المنتج
    UPDATE products
    SET images = v_updated_images,
        updated_at = NOW()
    WHERE id = p_product_id AND tenant_id = p_tenant_id;
    
    RETURN FOUND;
END;
$$;


--
-- Name: FUNCTION reorder_product_images(p_tenant_id uuid, p_product_id uuid, p_image_orders jsonb); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION public.reorder_product_images(p_tenant_id uuid, p_product_id uuid, p_image_orders jsonb) IS 'إعادة ترتيب صور المنتج';


--
-- Name: round_amount(numeric, integer, character varying); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.round_amount(p_amount numeric, p_decimal_places integer, p_rounding_method character varying DEFAULT 'half_up'::character varying) RETURNS numeric
    LANGUAGE plpgsql IMMUTABLE
    AS $$
DECLARE
    v_multiplier DECIMAL;
    v_result DECIMAL(18,6);
BEGIN
    -- حساب المضاعف
    v_multiplier := POWER(10, p_decimal_places);
    
    -- تطبيق طريقة التقريب
    CASE p_rounding_method
        -- التقريب الطبيعي (النصف للأعلى) - الطريقة الأكثر شيوعاً
        WHEN 'half_up' THEN
            v_result := ROUND(p_amount * v_multiplier) / v_multiplier;
        
        -- التقريب للأسفل دائماً
        WHEN 'down', 'floor' THEN
            v_result := FLOOR(p_amount * v_multiplier) / v_multiplier;
        
        -- التقريب للأعلى دائماً
        WHEN 'up', 'ceil' THEN
            v_result := CEIL(p_amount * v_multiplier) / v_multiplier;
        
        -- التقريب المصرفي (النصف للزوجي) - أكثر دقة إحصائياً
        WHEN 'half_even', 'banker' THEN
            -- PostgreSQL's ROUND uses half-even by default in some cases
            v_result := ROUND(p_amount::NUMERIC, p_decimal_places);
        
        -- التقريب للأسفل (النصف للأسفل)
        WHEN 'half_down' THEN
            v_result := CASE
                WHEN (p_amount * v_multiplier - FLOOR(p_amount * v_multiplier)) < 0.5
                THEN FLOOR(p_amount * v_multiplier) / v_multiplier
                ELSE CEIL(p_amount * v_multiplier) / v_multiplier
            END;
        
        -- افتراضي: half_up
        ELSE
            v_result := ROUND(p_amount * v_multiplier) / v_multiplier;
    END CASE;
    
    RETURN v_result;
END;
$$;


--
-- Name: round_amount_for_company(uuid, numeric, character varying); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.round_amount_for_company(p_company_id uuid, p_amount numeric, p_type character varying DEFAULT 'amount'::character varying) RETURNS numeric
    LANGUAGE plpgsql STABLE
    AS $$
DECLARE
    v_rounding_method VARCHAR(10);
    v_decimal_places INT;
    v_settings RECORD;
BEGIN
    -- الحصول على إعدادات التقريب
    SELECT * INTO v_settings FROM get_company_rounding_settings(p_company_id);
    
    v_rounding_method := v_settings.rounding_method;
    
    -- تحديد عدد المنازل العشرية حسب النوع
    v_decimal_places := CASE p_type
        WHEN 'tax' THEN v_settings.tax_rounding
        WHEN 'unit_price' THEN v_settings.unit_price_rounding
        WHEN 'total' THEN v_settings.total_rounding
        ELSE v_settings.amount_rounding
    END;
    
    -- تطبيق التقريب
    RETURN round_amount(p_amount, v_decimal_places, v_rounding_method);
END;
$$;


--
-- Name: save_guest_checkout(uuid, uuid, character varying, character varying, character varying, character varying, jsonb, jsonb, boolean, text, character varying, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.save_guest_checkout(p_tenant_id uuid, p_company_id uuid, p_session_id character varying, p_email character varying, p_full_name character varying, p_phone character varying, p_shipping_address jsonb, p_billing_address jsonb DEFAULT NULL::jsonb, p_same_as_shipping boolean DEFAULT true, p_notes text DEFAULT NULL::text, p_ip_address character varying DEFAULT NULL::character varying, p_user_agent text DEFAULT NULL::text) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_guest_checkout_id UUID;
    v_result JSONB;
BEGIN
    -- حفظ أو تحديث معلومات الزائر
    INSERT INTO guest_checkouts (
        tenant_id, company_id, session_id, email, full_name, phone,
        shipping_address, billing_address, same_as_shipping,
        notes, ip_address, user_agent
    )
    VALUES (
        p_tenant_id, p_company_id, p_session_id, p_email, p_full_name, p_phone,
        p_shipping_address, p_billing_address, p_same_as_shipping,
        p_notes, p_ip_address, p_user_agent
    )
    ON CONFLICT (tenant_id, session_id, email)
    DO UPDATE SET
        full_name = EXCLUDED.full_name,
        phone = EXCLUDED.phone,
        shipping_address = EXCLUDED.shipping_address,
        billing_address = EXCLUDED.billing_address,
        same_as_shipping = EXCLUDED.same_as_shipping,
        notes = EXCLUDED.notes,
        updated_at = NOW()
    RETURNING id INTO v_guest_checkout_id;
    
    -- إرجاع النتيجة
    v_result := jsonb_build_object(
        'success', true,
        'guest_checkout_id', v_guest_checkout_id,
        'message', 'تم حفظ معلومات الزائر بنجاح'
    );
    
    RETURN v_result;
END;
$$;


