-- Name: FUNCTION save_guest_checkout(p_tenant_id uuid, p_company_id uuid, p_session_id character varying, p_email character varying, p_full_name character varying, p_phone character varying, p_shipping_address jsonb, p_billing_address jsonb, p_same_as_shipping boolean, p_notes text, p_ip_address character varying, p_user_agent text); Type: COMMENT; Schema: public; Owner: -
