--
-- Name: schedule_expiry_notifications(uuid, uuid, date, text, numeric, character varying); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.schedule_expiry_notifications(p_tenant_id uuid, p_subscription_id uuid, p_end_date date, p_plan_name text DEFAULT 'الباقة'::text, p_amount_due numeric DEFAULT 0, p_currency character varying DEFAULT 'USD'::character varying) RETURNS void
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_tenant RECORD;
    v_settings RECORD;
    v_alert_day INT;
BEGIN
    -- جلب الإعدادات
    SELECT * INTO v_settings FROM saas_settings LIMIT 1;
    
    -- التحقق من تفعيل التنبيهات
    IF NOT COALESCE(v_settings.enable_alerts, true) THEN
        RAISE NOTICE '⚠️ Alerts disabled in settings';
        RETURN;
    END IF;
    
    -- جلب بيانات المستأجر
    SELECT name, email INTO v_tenant
    FROM tenants
    WHERE id = p_tenant_id;
    
    -- حذف التنبيهات القديمة غير المرسلة
    DELETE FROM subscription_alerts
    WHERE subscription_id = p_subscription_id
        AND status = 'pending';
    
    -- جدولة التنبيهات حسب الإعدادات
    FOR v_alert_day IN 
        SELECT jsonb_array_elements_text(
            COALESCE(v_settings.alert_days_before, '[7, 3, 1]'::JSONB)
        )::INT
    LOOP
        -- التحقق من أن التاريخ في المستقبل
        IF p_end_date - (v_alert_day || ' days')::INTERVAL > CURRENT_DATE THEN
            INSERT INTO subscription_alerts (
                tenant_id, subscription_id, alert_type, alert_date, days_remaining, amount_due,
                message_ar, message_en, sent_to
            ) VALUES (
                p_tenant_id, 
                p_subscription_id, 
                CASE WHEN v_alert_day = 0 THEN 'expired' ELSE 'expiry_warning' END,
                p_end_date - (v_alert_day || ' days')::INTERVAL, 
                v_alert_day,
                p_amount_due,
                CASE 
                    WHEN v_alert_day = 0 THEN '🔴 انتهى اشتراكك اليوم. يرجى التجديد فوراً لتجنب تعليق الخدمة'
                    WHEN v_alert_day <= 3 THEN format('⚠️ تنبيه عاجل: اشتراكك في %s سينتهي بعد %s أيام. المبلغ المطلوب: %s %s', 
                        p_plan_name, v_alert_day, p_amount_due, p_currency)
                    ELSE format('تنبيه: اشتراكك في %s سينتهي بعد %s أيام في تاريخ %s', 
                        p_plan_name, v_alert_day, p_end_date)
                END,
                CASE 
                    WHEN v_alert_day = 0 THEN '🔴 Your subscription expired today. Please renew immediately to avoid service suspension'
                    WHEN v_alert_day <= 3 THEN format('⚠️ Urgent: Your %s subscription expires in %s days. Amount due: %s %s',
                        p_plan_name, v_alert_day, p_amount_due, p_currency)
                    ELSE format('Notice: Your %s subscription will expire in %s days on %s',
                        p_plan_name, v_alert_day, p_end_date)
                END,
                v_tenant.email
            );
        END IF;
    END LOOP;
    
    RAISE NOTICE '📧 Scheduled notification alerts for tenant: %', v_tenant.name;
END;
$$;


--
-- Name: FUNCTION schedule_expiry_notifications(p_tenant_id uuid, p_subscription_id uuid, p_end_date date, p_plan_name text, p_amount_due numeric, p_currency character varying); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION public.schedule_expiry_notifications(p_tenant_id uuid, p_subscription_id uuid, p_end_date date, p_plan_name text, p_amount_due numeric, p_currency character varying) IS 'جدولة تنبيهات الانتهاء حسب الإعدادات';


--
-- Name: set_company_tenant_from_sample_cutting(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.set_company_tenant_from_sample_cutting() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
BEGIN
    -- إذا كان company_id أو tenant_id فارغاً و sample_cutting_id موجوداً
    IF (NEW.company_id IS NULL OR NEW.tenant_id IS NULL) AND NEW.sample_cutting_id IS NOT NULL THEN
        SELECT sc.company_id, sc.tenant_id 
        INTO NEW.company_id, NEW.tenant_id
        FROM public.sample_cuttings sc
        WHERE sc.id = NEW.sample_cutting_id;
    END IF;
    RETURN NEW;
END;
$$;


--
-- Name: set_company_tenant_from_warehouse(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.set_company_tenant_from_warehouse() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
BEGIN
    -- إذا كان company_id أو tenant_id فارغاً و warehouse_id موجوداً
    IF (NEW.company_id IS NULL OR NEW.tenant_id IS NULL) AND NEW.warehouse_id IS NOT NULL THEN
        SELECT w.company_id, c.tenant_id 
        INTO NEW.company_id, NEW.tenant_id
        FROM public.warehouses w
        JOIN public.companies c ON w.company_id = c.id
        WHERE w.id = NEW.warehouse_id;
    END IF;
    RETURN NEW;
END;
$$;


--
-- Name: set_default_currency_for_journal_entry(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.set_default_currency_for_journal_entry() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
DECLARE
    company_currency VARCHAR(3);
BEGIN
    SELECT COALESCE(default_currency, 'SAR') INTO company_currency
    FROM companies
    WHERE id = NEW.company_id;
    
    IF NEW.currency IS NULL OR NEW.currency = '' THEN
        NEW.currency := company_currency;
    END IF;
    
    IF NEW.exchange_rate IS NULL OR NEW.exchange_rate = 0 THEN
        NEW.exchange_rate := 1;
    END IF;
    
    RETURN NEW;
END;
$$;


--
-- Name: set_initial_next_execution_date(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.set_initial_next_execution_date() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
    IF NEW.next_execution_date IS NULL THEN
        NEW.next_execution_date := NEW.start_date;
    END IF;
    RETURN NEW;
END;
$$;


