--
-- Name: set_primary_language(uuid, character varying); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.set_primary_language(p_tenant_id uuid, p_language_code character varying) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
BEGIN
    -- التحقق من أن اللغة مفعلة
    IF NOT EXISTS (
        SELECT 1 FROM tenant_languages
        WHERE tenant_id = p_tenant_id
        AND language_code = p_language_code
        AND is_enabled = true
    ) THEN
        RETURN jsonb_build_object(
            'success', false,
            'error', 'Language not enabled'
        );
    END IF;
    
    -- إلغاء primary من كل اللغات
    UPDATE tenant_languages
    SET is_primary = false
    WHERE tenant_id = p_tenant_id;
    
    -- تعيين اللغة الجديدة كـ primary
    UPDATE tenant_languages
    SET is_primary = true
    WHERE tenant_id = p_tenant_id
    AND language_code = p_language_code;
    
    -- تسجيل في audit log
    PERFORM log_audit(
        'set_primary_language',
        'tenant_languages',
        p_tenant_id,
        p_language_code,
        NULL,
        jsonb_build_object('language_code', p_language_code)
    );
    
    RETURN jsonb_build_object(
        'success', true,
        'tenant_id', p_tenant_id,
        'primary_language', p_language_code
    );
END;
$$;


--
-- Name: set_primary_product_image(uuid, uuid, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.set_primary_product_image(p_tenant_id uuid, p_product_id uuid, p_image_url text) RETURNS boolean
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_current_images JSONB;
    v_updated_images JSONB;
BEGIN
    -- 1. الحصول على الصور الحالية
    SELECT COALESCE(images, '[]'::jsonb)
    INTO v_current_images
    FROM products
    WHERE id = p_product_id AND tenant_id = p_tenant_id;
    
    -- 2. تحديث جميع الصور
    v_updated_images := (
        SELECT jsonb_agg(
            CASE 
                WHEN img->>'url' = p_image_url THEN
                    jsonb_set(img, '{is_primary}', 'true'::jsonb)
                ELSE
                    jsonb_set(img, '{is_primary}', 'false'::jsonb)
            END
        )
        FROM jsonb_array_elements(v_current_images) AS img
    );
    
    -- 3. تحديث المنتج
    UPDATE products
    SET images = v_updated_images,
        updated_at = NOW()
    WHERE id = p_product_id AND tenant_id = p_tenant_id;
    
    RETURN FOUND;
END;
$$;


--
-- Name: FUNCTION set_primary_product_image(p_tenant_id uuid, p_product_id uuid, p_image_url text); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION public.set_primary_product_image(p_tenant_id uuid, p_product_id uuid, p_image_url text) IS 'تعيين صورة كصورة رئيسية';


