--
-- Name: setup_chart_templates_for_tenant(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.setup_chart_templates_for_tenant(p_tenant_id uuid) RETURNS void
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
BEGIN
    INSERT INTO chart_templates (tenant_id, template_code, template_name_ar, template_name_en, chart_type, include_demo_data, description_ar, description_en)
    VALUES (p_tenant_id, 'SIMPLE', 'الشجرة القياسية', 'Simple Chart', 'simple', false,
            'شجرة حسابات مبسطة (~52 حساب) بترقيم موحد', 'Simple chart with unified numbering (~52 accounts)')
    ON CONFLICT DO NOTHING;

    INSERT INTO chart_templates (tenant_id, template_code, template_name_ar, template_name_en, chart_type, include_demo_data, description_ar, description_en)
    VALUES (p_tenant_id, 'EXTENDED', 'الشجرة الموسعة', 'Extended Chart', 'extended', false,
            'شجرة حسابات كاملة (~82 حساب) للشركات التجارية', 'Full chart for commercial companies (~82 accounts)')
    ON CONFLICT DO NOTHING;

    RAISE NOTICE '✅ تم إعداد القوالب V5.1 (Simple + Extended) للمستأجر %', p_tenant_id;
END;
$$;


