--
-- Name: setup_super_user_by_email(character varying); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.setup_super_user_by_email(p_user_email character varying) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_user_id UUID;
    v_role_id UUID;
    v_result JSONB;
BEGIN
    -- البحث عن المستخدم بالبريد الإلكتروني
    SELECT id INTO v_user_id
    FROM auth.users
    WHERE email = p_user_email
    LIMIT 1;
    
    IF v_user_id IS NULL THEN
        SELECT jsonb_build_object(
            'success', false,
            'error', 'المستخدم غير موجود في Auth. يرجى إنشاء المستخدم أولاً من Supabase Dashboard',
            'email', p_user_email
        ) INTO v_result;
        RETURN v_result;
    END IF;
    
    -- الحصول على Super Admin Role
    SELECT id INTO v_role_id
    FROM roles
    WHERE code = 'super_admin' AND tenant_id IS NULL
    LIMIT 1;
    
    IF v_role_id IS NULL THEN
        SELECT jsonb_build_object(
            'success', false,
            'error', 'Super Admin Role غير موجود. يرجى تطبيق STEP_12 أولاً'
        ) INTO v_result;
        RETURN v_result;
    END IF;
    
    -- ربط المستخدم بالـ Role (استخدام DO UPDATE بدلاً من ON CONFLICT)
    INSERT INTO user_roles (user_id, role_id, is_active)
    VALUES (v_user_id, v_role_id, true)
    ON CONFLICT (user_id, role_id) 
    DO UPDATE SET is_active = true;
    
    -- إرجاع النتيجة
    SELECT jsonb_build_object(
        'success', true,
        'user_id', v_user_id,
        'email', p_user_email,
        'role', 'super_admin',
        'message', 'تم تعيين Super Admin بنجاح'
    ) INTO v_result;
    
    RETURN v_result;
END;
$$;


--
-- Name: setup_support_user(character varying, character varying); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.setup_support_user(p_user_email character varying, p_support_level character varying DEFAULT 'support'::character varying) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_user_id UUID;
    v_role_id UUID;
    v_role_code VARCHAR(50);
    v_result JSONB;
BEGIN
    -- تحديد Role Code
    IF p_support_level = 'senior' THEN
        v_role_code := 'support_senior';
    ELSE
        v_role_code := 'support';
    END IF;
    
    -- البحث عن المستخدم
    SELECT id INTO v_user_id
    FROM auth.users
    WHERE email = p_user_email
    LIMIT 1;
    
    IF v_user_id IS NULL THEN
        SELECT jsonb_build_object(
            'success', false,
            'error', 'المستخدم غير موجود في Auth',
            'email', p_user_email
        ) INTO v_result;
        RETURN v_result;
    END IF;
    
    -- الحصول على Support Role
    SELECT id INTO v_role_id
    FROM roles
    WHERE code = v_role_code AND tenant_id IS NULL
    LIMIT 1;
    
    IF v_role_id IS NULL THEN
        SELECT jsonb_build_object(
            'success', false,
            'error', 'Support Role غير موجود'
        ) INTO v_result;
        RETURN v_result;
    END IF;
    
    -- ربط المستخدم بالـ Role
    INSERT INTO user_roles (user_id, role_id, is_active)
    VALUES (v_user_id, v_role_id, true)
    ON CONFLICT (user_id, role_id) 
    DO UPDATE SET is_active = true;
    
    -- إرجاع النتيجة
    SELECT jsonb_build_object(
        'success', true,
        'user_id', v_user_id,
        'email', p_user_email,
        'role', v_role_code,
        'message', 'تم تعيين Support User بنجاح'
    ) INTO v_result;
    
    RETURN v_result;
END;
$$;


--
-- Name: suspend_tenant(uuid, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.suspend_tenant(p_tenant_id uuid, p_reason text DEFAULT NULL::text) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
BEGIN
    UPDATE tenants
    SET status = 'suspended',
        suspended_at = NOW(),
        suspended_reason = p_reason
    WHERE id = p_tenant_id;
    
    -- تسجيل الحدث
    INSERT INTO saas_events (tenant_id, event_type, event_data, actor_type)
    VALUES (p_tenant_id, 'tenant_suspended', jsonb_build_object('reason', p_reason), 'admin');
    
    RETURN jsonb_build_object('success', true);
END;
$$;


--
-- Name: switch_user_company(uuid, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.switch_user_company(p_user_id uuid, p_new_company_id uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
    v_tenant_id UUID;
    v_company_tenant_id UUID;
    v_company_name VARCHAR;
BEGIN
    -- التحقق من المستخدم
    IF p_user_id IS NULL OR p_user_id != auth.uid() THEN
        RETURN jsonb_build_object(
            'success', false,
            'error', 'غير مصرح'
        );
    END IF;
    
    -- الحصول على tenant_id للمستخدم
    SELECT tenant_id INTO v_tenant_id
    FROM user_profiles
    WHERE id = p_user_id;
    
    IF v_tenant_id IS NULL THEN
        RETURN jsonb_build_object(
            'success', false,
            'error', 'المستخدم غير موجود'
        );
    END IF;
    
    -- التحقق من أن الشركة الجديدة تابعة لنفس الـ tenant
    SELECT tenant_id, name INTO v_company_tenant_id, v_company_name
    FROM companies
    WHERE id = p_new_company_id;
    
    IF v_company_tenant_id IS NULL THEN
        RETURN jsonb_build_object(
            'success', false,
            'error', 'الشركة غير موجودة'
        );
    END IF;
    
    IF v_company_tenant_id != v_tenant_id THEN
        RETURN jsonb_build_object(
            'success', false,
            'error', 'الشركة غير تابعة لحسابك'
        );
    END IF;
    
    -- تحديث company_id في user_profiles
    UPDATE user_profiles
    SET 
        company_id = p_new_company_id,
        updated_at = NOW()
    WHERE id = p_user_id;
    
    RAISE NOTICE '✅ تم تبديل الشركة للمستخدم % إلى %', p_user_id, v_company_name;
    
    RETURN jsonb_build_object(
        'success', true,
        'company_id', p_new_company_id,
        'company_name', v_company_name,
        'message', 'تم تبديل الشركة بنجاح'
    );
    
EXCEPTION WHEN OTHERS THEN
    RETURN jsonb_build_object(
        'success', false,
        'error', SQLERRM
    );
END;
$$;


--
-- Name: sync_container_info_to_transaction(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.sync_container_info_to_transaction() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
    -- عند تعيين أو تغيير container_id → أجلب container_number + status
    IF NEW.container_id IS NOT NULL AND (
        OLD.container_id IS DISTINCT FROM NEW.container_id
    ) THEN
        SELECT c.container_number, c.status
        INTO NEW.container_number, NEW.container_status
        FROM containers c
        WHERE c.id = NEW.container_id;
    END IF;

    -- عند إزالة container_id → أفرّغ الحقول
    IF NEW.container_id IS NULL AND OLD.container_id IS NOT NULL THEN
        NEW.container_number := NULL;
        NEW.container_status := NULL;
    END IF;

    RETURN NEW;
END;
$$;


--
-- Name: sync_container_status_to_transactions(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.sync_container_status_to_transactions() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
    -- عند تغيير status أو container_number في containers → حدّث كل الفواتير المربوطة
    IF OLD.status IS DISTINCT FROM NEW.status 
       OR OLD.container_number IS DISTINCT FROM NEW.container_number THEN
        UPDATE purchase_transactions
        SET container_status = NEW.status,
            container_number = NEW.container_number
        WHERE container_id = NEW.id;
    END IF;
    RETURN NEW;
END;
$$;


--
-- Name: tenant_has_module(uuid, character varying); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.tenant_has_module(p_tenant_id uuid, p_module_code character varying) RETURNS boolean
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
BEGIN
    -- التحقق من حالة العميل أولاً
    IF NOT EXISTS (SELECT 1 FROM tenants WHERE id = p_tenant_id AND status = 'active') THEN
        RETURN false;
    END IF;
    
    -- التحقق من الموديول
    RETURN EXISTS (
        SELECT 1 FROM tenant_modules 
        WHERE tenant_id = p_tenant_id 
          AND module_code = p_module_code 
          AND is_active = true
          AND (expires_at IS NULL OR expires_at > NOW())
    );
END;
$$;


--
-- Name: toggle_plan_status(uuid, boolean); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.toggle_plan_status(p_plan_id uuid, p_is_active boolean) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
BEGIN
    IF NOT EXISTS (SELECT 1 FROM subscription_plans WHERE id = p_plan_id) THEN
        RETURN jsonb_build_object(
            'success', false,
            'error', 'plan_not_found'
        );
    END IF;
    
    UPDATE subscription_plans
    SET is_active = p_is_active
    WHERE id = p_plan_id;
    
    RETURN jsonb_build_object(
        'success', true,
        'plan_id', p_plan_id,
        'is_active', p_is_active
    );
END;
$$;


--
-- Name: toggle_tenant_module(uuid, character varying, boolean, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.toggle_tenant_module(p_tenant_id uuid, p_module_code character varying, p_enabled boolean, p_notes text DEFAULT NULL::text) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_current_user_id UUID;
BEGIN
    v_current_user_id := auth.uid();
    
    -- ✅ استخدام is_super_admin() الآمنة
    IF NOT is_super_admin(v_current_user_id) THEN
        RETURN jsonb_build_object(
            'success', false,
            'error', 'Unauthorized: Super Admin access required'
        );
    END IF;
    
    -- التحقق من وجود الموديول
    IF NOT EXISTS (SELECT 1 FROM system_modules WHERE code = p_module_code) THEN
        RETURN jsonb_build_object(
            'success', false,
            'error', 'Module not found'
        );
    END IF;
    
    -- إدراج أو تحديث
    INSERT INTO tenant_modules (
        tenant_id,
        module_code,
        is_active,
        enabled_by,
        enabled_at
    ) VALUES (
        p_tenant_id,
        p_module_code,
        p_enabled,
        v_current_user_id,
        CASE WHEN p_enabled THEN NOW() ELSE NULL END
    )
    ON CONFLICT (tenant_id, module_code)
    DO UPDATE SET
        is_active = p_enabled,
        enabled_by = v_current_user_id,
        enabled_at = CASE WHEN p_enabled THEN NOW() ELSE tenant_modules.enabled_at END;
    
    RETURN jsonb_build_object(
        'success', true,
        'tenant_id', p_tenant_id,
        'module_code', p_module_code,
        'enabled', p_enabled
    );
END;
$$;


--
-- Name: transfer_account_balance(uuid, uuid, numeric, text, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.transfer_account_balance(p_source_account_id uuid, p_target_account_id uuid, p_amount numeric DEFAULT NULL::numeric, p_notes text DEFAULT NULL::text, p_user_id uuid DEFAULT NULL::uuid) RETURNS uuid
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_tenant_id UUID;
    v_company_id UUID;
    v_source_account RECORD;
    v_target_account RECORD;
    v_transfer_amount DECIMAL(15, 2);
    v_source_balance DECIMAL(15, 2);
    v_journal_entry_id UUID;
    v_transfer_id UUID;
    v_description TEXT;
BEGIN
    -- Validate accounts exist and get details
    SELECT * INTO v_source_account
    FROM chart_of_accounts
    WHERE id = p_source_account_id;
    
    IF v_source_account IS NULL THEN
        RAISE EXCEPTION 'Source account not found';
    END IF;
    
    SELECT * INTO v_target_account
    FROM chart_of_accounts
    WHERE id = p_target_account_id;
    
    IF v_target_account IS NULL THEN
        RAISE EXCEPTION 'Target account not found';
    END IF;
    
    -- Validate same company
    IF v_source_account.company_id != v_target_account.company_id THEN
        RAISE EXCEPTION 'Accounts must belong to the same company';
    END IF;
    
    v_tenant_id := v_source_account.tenant_id;
    v_company_id := v_source_account.company_id;
    
    -- Validate both are detail accounts
    IF v_source_account.is_group OR v_target_account.is_group THEN
        RAISE EXCEPTION 'Cannot transfer balance from/to group accounts';
    END IF;
    
    -- Calculate source account balance
    SELECT COALESCE(SUM(debit - credit), 0) INTO v_source_balance
    FROM journal_entry_lines
    WHERE account_id = p_source_account_id;
    
    -- Determine transfer amount
    IF p_amount IS NULL THEN
        v_transfer_amount := ABS(v_source_balance);
    ELSE
        v_transfer_amount := p_amount;
    END IF;
    
    -- Validate amount
    IF v_transfer_amount <= 0 THEN
        RAISE EXCEPTION 'Transfer amount must be positive';
    END IF;
    
    IF v_transfer_amount > ABS(v_source_balance) THEN
        RAISE EXCEPTION 'Transfer amount (%) exceeds source balance (%)', v_transfer_amount, ABS(v_source_balance);
    END IF;
    
    -- Create description
    v_description := format('نقل رصيد من %s إلى %s | Balance transfer from %s to %s',
        v_source_account.name_ar,
        v_target_account.name_ar,
        v_source_account.account_code,
        v_target_account.account_code
    );
    
    -- Create journal entry
    INSERT INTO journal_entries (
        tenant_id,
        company_id,
        entry_date,
        description,
        notes,
        created_by
    ) VALUES (
        v_tenant_id,
        v_company_id,
        CURRENT_DATE,
        v_description,
        p_notes,
        p_user_id
    )
    RETURNING id INTO v_journal_entry_id;
    
    -- Create journal entry lines
    -- Debit target account
    INSERT INTO journal_entry_lines (
        journal_entry_id,
        account_id,
        debit,
        credit,
        description
    ) VALUES (
        v_journal_entry_id,
        p_target_account_id,
        v_transfer_amount,
        0,
        v_description
    );
    
    -- Credit source account
    INSERT INTO journal_entry_lines (
        journal_entry_id,
        account_id,
        debit,
        credit,
        description
    ) VALUES (
        v_journal_entry_id,
        p_source_account_id,
        0,
        v_transfer_amount,
        v_description
    );
    
    -- Record the transfer
    INSERT INTO account_transfers (
        tenant_id,
        company_id,
        source_account_id,
        target_account_id,
        transfer_type,
        amount,
        journal_entry_id,
        notes,
        created_by
    ) VALUES (
        v_tenant_id,
        v_company_id,
        p_source_account_id,
        p_target_account_id,
        'balance',
        v_transfer_amount,
        v_journal_entry_id,
        p_notes,
        p_user_id
    )
    RETURNING id INTO v_transfer_id;
    
    RAISE NOTICE 'Balance transferred: % from % to %', 
        v_transfer_amount, 
        v_source_account.account_code, 
        v_target_account.account_code;
    
    RETURN v_transfer_id;
END;
$$;


--
-- Name: FUNCTION transfer_account_balance(p_source_account_id uuid, p_target_account_id uuid, p_amount numeric, p_notes text, p_user_id uuid); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION public.transfer_account_balance(p_source_account_id uuid, p_target_account_id uuid, p_amount numeric, p_notes text, p_user_id uuid) IS 'Transfer balance from one account to another via journal entry';


