END;
$$;


--
-- Name: unpost_journal_entry(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.unpost_journal_entry(p_entry_id uuid) RETURNS boolean
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
    v_entry RECORD;
    v_line RECORD;
BEGIN
    SELECT * INTO v_entry
    FROM journal_entries
    WHERE id = p_entry_id;
    
    IF NOT FOUND THEN
        RAISE EXCEPTION 'القيد غير موجود';
    END IF;
    
    IF NOT v_entry.is_posted THEN
        RAISE EXCEPTION 'القيد غير مرحّل';
    END IF;
    
    -- Reverse: subtract Net (Dr-Cr) that was added during posting
    FOR v_line IN 
        SELECT * FROM journal_entry_lines WHERE entry_id = p_entry_id
    LOOP
        UPDATE chart_of_accounts
        SET current_balance = COALESCE(current_balance, 0) - (v_line.debit - v_line.credit),
            updated_at = NOW()
        WHERE id = v_line.account_id;
    END LOOP;
    
    UPDATE journal_entries
    SET is_posted = false,
        posted_at = NULL,
        posted_by = NULL,
        status = 'draft'
    WHERE id = p_entry_id;
    
    RETURN true;
END;
$$;


--
-- Name: update_account_balance_from_je_line(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.update_account_balance_from_je_line() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    SET search_path TO 'public'
    AS $$
DECLARE
    v_entry_status TEXT;
    v_account_id   UUID;
    v_delta        NUMERIC;
BEGIN
    -- ── INSERT ──
    IF TG_OP = 'INSERT' THEN
        SELECT status INTO v_entry_status
        FROM public.journal_entries WHERE id = NEW.entry_id;
        IF v_entry_status = 'posted' THEN
            UPDATE public.chart_of_accounts
            SET current_balance = current_balance + COALESCE(NEW.debit, 0) - COALESCE(NEW.credit, 0),
                updated_at = NOW()
            WHERE id = NEW.account_id;
        END IF;
        RETURN NEW;
    END IF;

    -- ── UPDATE ──
    IF TG_OP = 'UPDATE' THEN
        SELECT status INTO v_entry_status
        FROM public.journal_entries WHERE id = NEW.entry_id;
        IF v_entry_status = 'posted' THEN
            v_delta :=
                (COALESCE(NEW.debit,0) - COALESCE(NEW.credit,0)) -
                (COALESCE(OLD.debit,0) - COALESCE(OLD.credit,0));
            IF v_delta <> 0 THEN
                UPDATE public.chart_of_accounts
                SET current_balance = current_balance + v_delta,
                    updated_at = NOW()
                WHERE id = NEW.account_id;
            END IF;
            -- إذا تغيّر الحساب → اعكس الحساب القديم وطبّق الجديد
            IF OLD.account_id <> NEW.account_id THEN
                UPDATE public.chart_of_accounts
                SET current_balance = current_balance - (COALESCE(OLD.debit,0) - COALESCE(OLD.credit,0)),
                    updated_at = NOW()
                WHERE id = OLD.account_id;
                UPDATE public.chart_of_accounts
                SET current_balance = current_balance + (COALESCE(NEW.debit,0) - COALESCE(NEW.credit,0)),
                    updated_at = NOW()
                WHERE id = NEW.account_id;
            END IF;
        END IF;
        RETURN NEW;
    END IF;

    -- ── DELETE ──
    IF TG_OP = 'DELETE' THEN
        SELECT status INTO v_entry_status
        FROM public.journal_entries WHERE id = OLD.entry_id;
        IF v_entry_status = 'posted' THEN
            UPDATE public.chart_of_accounts
            SET current_balance = current_balance - COALESCE(OLD.debit, 0) + COALESCE(OLD.credit, 0),
                updated_at = NOW()
            WHERE id = OLD.account_id;
        END IF;
        RETURN OLD;
    END IF;

    RETURN NULL;
END;
$$;


--
-- Name: FUNCTION update_account_balance_from_je_line(); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION public.update_account_balance_from_je_line() IS 'يُحدِّث current_balance في chart_of_accounts تلقائياً عند INSERT/UPDATE/DELETE في journal_entry_lines — فقط للقيود المرحّلة (status=posted)';


--
-- Name: update_budget_actuals_from_journal(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.update_budget_actuals_from_journal() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_period VARCHAR(10);
    v_account_id UUID;
    v_amount NUMERIC;
BEGIN
    -- فقط للقيود المرحلة
    IF NEW.is_posted = true AND (OLD IS NULL OR OLD.is_posted = false) THEN
        -- تحديث كل بند في القيد
        FOR v_account_id, v_amount IN
            SELECT account_id, (debit - credit) as amount
            FROM journal_entry_lines
            WHERE entry_id = NEW.id
        LOOP
            v_period := TO_CHAR(NEW.entry_date, 'YYYY-MM');
            
            -- تحديث budget_lines إذا وجدت
            UPDATE budget_lines bl
            SET 
                actual_amount = actual_amount + v_amount,
                updated_at = NOW()
            FROM budgets b
            WHERE bl.budget_id = b.id
              AND bl.account_id = v_account_id
              AND bl.period = v_period
              AND b.status = 'active'
              AND b.company_id = NEW.company_id;
        END LOOP;
    END IF;
    
    RETURN NEW;
END;
$$;


--
-- Name: FUNCTION update_budget_actuals_from_journal(); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION public.update_budget_actuals_from_journal() IS 'تحديث المبالغ الفعلية من القيود المرحلة';


--
-- Name: update_budget_totals(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.update_budget_totals() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
    UPDATE budgets
    SET 
        total_budgeted = (
            SELECT COALESCE(SUM(budgeted_amount), 0) 
            FROM budget_lines 
            WHERE budget_id = COALESCE(NEW.budget_id, OLD.budget_id)
        ),
        total_actual = (
            SELECT COALESCE(SUM(actual_amount), 0) 
            FROM budget_lines 
            WHERE budget_id = COALESCE(NEW.budget_id, OLD.budget_id)
        ),
        updated_at = NOW()
    WHERE id = COALESCE(NEW.budget_id, OLD.budget_id);
    
    RETURN COALESCE(NEW, OLD);
END;
$$;


--
-- Name: FUNCTION update_budget_totals(); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION public.update_budget_totals() IS 'تحديث إجماليات الموازنة تلقائياً عند تغيير البنود';


--
-- Name: update_cart_item(uuid, numeric); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.update_cart_item(p_item_id uuid, p_quantity numeric) RETURNS boolean
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_cart_id UUID;
BEGIN
    -- تحديث الكمية
    UPDATE shopping_cart_items
    SET quantity = p_quantity,
        updated_at = NOW()
    WHERE id = p_item_id
    RETURNING cart_id INTO v_cart_id;
    
    IF NOT FOUND THEN
        RETURN false;
    END IF;
    
    -- تحديث المجاميع
    PERFORM update_cart_totals(v_cart_id);
    
    RETURN TRUE;
END;
$$;


--
-- Name: FUNCTION update_cart_item(p_item_id uuid, p_quantity numeric); Type: COMMENT; Schema: public; Owner: -
--

