--
-- Name: update_cart_totals(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.update_cart_totals(p_cart_id uuid) RETURNS boolean
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_subtotal DECIMAL;
BEGIN
    -- حساب المجموع الفرعي
    SELECT COALESCE(SUM(subtotal), 0)
    INTO v_subtotal
    FROM shopping_cart_items
    WHERE cart_id = p_cart_id;
    
    -- تحديث السلة
    UPDATE shopping_carts
    SET subtotal = v_subtotal,
        total_amount = v_subtotal - COALESCE(promo_discount, 0),
        updated_at = NOW()
    WHERE id = p_cart_id;
    
    RETURN TRUE;
END;
$$;


--
-- Name: FUNCTION update_cart_totals(p_cart_id uuid); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION public.update_cart_totals(p_cart_id uuid) IS 'تحديث مجاميع السلة تلقائياً';


--
-- Name: update_contact_interaction_stats(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.update_contact_interaction_stats() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
    UPDATE contacts SET 
        last_interaction_at = NEW.created_at,
        last_interaction_type = NEW.interaction_type,
        interaction_count = interaction_count + 1,
        -- تحديث إحصائيات المكالمات تحديداً
        last_call_at = CASE WHEN NEW.interaction_type = 'call' THEN NEW.created_at ELSE last_call_at END,
        total_calls = CASE WHEN NEW.interaction_type = 'call' THEN total_calls + 1 ELSE total_calls END
    WHERE id = NEW.contact_id;
    
    RETURN NEW;
END;
$$;


