--
-- Name: update_cost_center_spending(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.update_cost_center_spending() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
    -- تحديث المصاريف الحالية لمركز التكلفة
    IF NEW.cost_center_id IS NOT NULL THEN
        UPDATE cost_centers
        SET 
            current_spending = (
                SELECT COALESCE(SUM(jel.debit - jel.credit), 0)
                FROM journal_entry_lines jel
                JOIN journal_entries je ON jel.entry_id = je.id
                WHERE jel.cost_center_id = NEW.cost_center_id
                  AND je.is_posted = true
                  AND EXTRACT(YEAR FROM je.entry_date) = EXTRACT(YEAR FROM CURRENT_DATE)
            ),
            updated_at = NOW()
        WHERE id = NEW.cost_center_id;
    END IF;
    
    RETURN NEW;
END;
$$;


--
-- Name: update_customer_profile(uuid, character varying, character varying, character varying, character varying, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.update_customer_profile(p_auth_user_id uuid DEFAULT auth.uid(), p_full_name character varying DEFAULT NULL::character varying, p_phone character varying DEFAULT NULL::character varying, p_country character varying DEFAULT NULL::character varying, p_city character varying DEFAULT NULL::character varying, p_address text DEFAULT NULL::text) RETURNS boolean
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_customer_id UUID;
    v_name_parts TEXT[];
    v_first_name VARCHAR;
    v_last_name VARCHAR;
BEGIN
    -- الحصول على customer_id
    SELECT customer_id INTO v_customer_id
    FROM user_profiles
    WHERE id = p_auth_user_id;
    
    IF v_customer_id IS NULL THEN
        RAISE EXCEPTION 'Customer not found for this user';
    END IF;
    
    -- فصل الاسم إذا تم تحديثه
    IF p_full_name IS NOT NULL THEN
        v_name_parts := string_to_array(p_full_name, ' ');
        v_first_name := v_name_parts[1];
        
        IF array_length(v_name_parts, 1) > 1 THEN
            v_last_name := array_to_string(v_name_parts[2:], ' ');
        ELSE
            v_last_name := '';
        END IF;
    END IF;
    
    -- تحديث customers
    UPDATE customers
    SET 
        name_ar = COALESCE(p_full_name, name_ar),
        name_en = COALESCE(p_full_name, name_en),
        first_name = COALESCE(v_first_name, first_name),
        last_name = COALESCE(v_last_name, last_name),
        phone = COALESCE(p_phone, phone),
        mobile = COALESCE(p_phone, mobile),
        country = COALESCE(p_country, country),
        city = COALESCE(p_city, city),
        address = COALESCE(p_address, address),
        updated_at = NOW()
    WHERE id = v_customer_id;
    
    -- تحديث user_profiles
    UPDATE user_profiles
    SET 
        full_name = COALESCE(p_full_name, full_name),
        phone = COALESCE(p_phone, phone),
        updated_at = NOW()
    WHERE id = p_auth_user_id;
    
    RETURN TRUE;
END;
$$;


--
-- Name: FUNCTION update_customer_profile(p_auth_user_id uuid, p_full_name character varying, p_phone character varying, p_country character varying, p_city character varying, p_address text); Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON FUNCTION public.update_customer_profile(p_auth_user_id uuid, p_full_name character varying, p_phone character varying, p_country character varying, p_city character varying, p_address text) IS 'تحديث بيانات العميل الشخصية';


