--
-- Name: update_document_stage(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.update_document_stage() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
  IF NEW.status IN ('draft', 'requested') THEN
    NEW.document_stage := 'request';
  ELSIF NEW.status = 'quoted' THEN
    NEW.document_stage := 'quotation';
  ELSIF NEW.status IN ('ordered', 'processing', 'received', 'delivered') THEN
    NEW.document_stage := 'order';
  ELSIF NEW.status IN ('invoiced', 'posted', 'partially_paid', 'paid', 'cancelled', 'rejected') THEN
    NEW.document_stage := 'invoice';
  END IF;
  RETURN NEW;
END;
$$;


--
-- Name: update_employee_target_achievement(uuid, character varying, numeric, integer, integer, character varying, uuid, character varying, date); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.update_employee_target_achievement(p_employee_id uuid, p_target_type character varying, p_amount numeric DEFAULT 0, p_units integer DEFAULT 0, p_count integer DEFAULT 0, p_source_type character varying DEFAULT NULL::character varying, p_source_id uuid DEFAULT NULL::uuid, p_source_number character varying DEFAULT NULL::character varying, p_source_date date DEFAULT CURRENT_DATE) RETURNS uuid
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_target_id UUID;
    v_target RECORD;
    v_new_achieved_amount DECIMAL(15,2);
    v_new_achieved_units INT;
    v_new_achieved_count INT;
    v_achievement_pct DECIMAL(5,2);
BEGIN
    SELECT * INTO v_target FROM employee_targets
    WHERE employee_id = p_employee_id
      AND target_type = p_target_type
      AND status = 'active'
      AND period_year = EXTRACT(YEAR FROM p_source_date)
      AND (
          (period_type = 'monthly' AND period_month = EXTRACT(MONTH FROM p_source_date))
          OR (period_type = 'quarterly' AND period_quarter = CEIL(EXTRACT(MONTH FROM p_source_date) / 3.0))
          OR (period_type = 'yearly' AND period_month IS NULL AND period_quarter IS NULL)
      )
    LIMIT 1;
    
    IF v_target IS NULL THEN RETURN NULL; END IF;
    
    v_target_id := v_target.id;
    
    INSERT INTO target_achievement_log (
        tenant_id, target_id, source_type, source_id, source_number, source_date,
        amount, units, count_value
    )
    VALUES (
        v_target.tenant_id, v_target_id, p_source_type, p_source_id, p_source_number, p_source_date,
        p_amount, p_units, p_count
    );
    
    v_new_achieved_amount := COALESCE(v_target.achieved_amount, 0) + p_amount;
    v_new_achieved_units := COALESCE(v_target.achieved_units, 0) + p_units;
    v_new_achieved_count := COALESCE(v_target.achieved_count, 0) + p_count;
    
    IF v_target.target_amount > 0 THEN
        v_achievement_pct := (v_new_achieved_amount / v_target.target_amount) * 100;
    ELSIF v_target.target_units > 0 THEN
        v_achievement_pct := (v_new_achieved_units::DECIMAL / v_target.target_units) * 100;
    ELSIF v_target.target_count > 0 THEN
        v_achievement_pct := (v_new_achieved_count::DECIMAL / v_target.target_count) * 100;
    ELSE
        v_achievement_pct := 0;
    END IF;
    
    UPDATE employee_targets
    SET achieved_amount = v_new_achieved_amount,
        achieved_units = v_new_achieved_units,
        achieved_count = v_new_achieved_count,
        achievement_percentage = LEAST(v_achievement_pct, 999.99),
        status = CASE 
            WHEN v_achievement_pct >= 100 THEN 'achieved'
            WHEN v_achievement_pct > 0 THEN 'partial'
            ELSE 'active'
        END,
        updated_at = NOW()
    WHERE id = v_target_id;
    
    RETURN v_target_id;
END;
$$;


--
-- Name: update_entity_status_on_scan(character varying, character varying, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.update_entity_status_on_scan(p_qr_code character varying, p_new_status character varying, p_user_id uuid) RETURNS json
    LANGUAGE plpgsql SECURITY DEFINER
    AS $_$
DECLARE
    v_qr_record RECORD;
    v_prev_status VARCHAR;
    v_user_tenant UUID;
BEGIN
    -- 1. Verify user's tenant via the official helper
    v_user_tenant := get_user_tenant_id(p_user_id);
    
    IF v_user_tenant IS NULL THEN
        RETURN json_build_object(
            'success', false, 
            'message', 'User not found or has no tenant'
        );
    END IF;

    -- 2. جلب بيانات الـ QR مع التحقق من عزل المستأجر
    SELECT * INTO v_qr_record 
    FROM qr_codes 
    WHERE code = p_qr_code 
      AND tenant_id = v_user_tenant
    LIMIT 1;
    
    IF v_qr_record.id IS NULL THEN
        RETURN json_build_object(
            'success', false, 
            'message', 'QR Code not found or access denied'
        );
    END IF;

    -- 3. حفظ الحالة السابقة
    v_prev_status := v_qr_record.current_status;

    -- 4. تحديث الحالة في جدول الـ QR
    UPDATE qr_codes 
    SET current_status = p_new_status,
        updated_at = NOW()
    WHERE id = v_qr_record.id;

    -- 5. تحديث الكيان الأصلي (Dynamic SQL) — مع التحقق من tenant_id
    IF v_qr_record.entity_type = 'invoice' THEN
        EXECUTE 'UPDATE sales_invoices SET status = $1 WHERE id = $2 AND tenant_id = $3' 
        USING p_new_status, v_qr_record.entity_id, v_user_tenant;
        
    ELSIF v_qr_record.entity_type = 'entry' THEN
        EXECUTE 'UPDATE journal_entries SET status = $1 WHERE id = $2 AND tenant_id = $3' 
        USING p_new_status, v_qr_record.entity_id, v_user_tenant;
        
    ELSIF v_qr_record.entity_type = 'delivery_note' THEN
        EXECUTE 'UPDATE delivery_notes SET status = $1 WHERE id = $2 AND tenant_id = $3' 
        USING p_new_status, v_qr_record.entity_id, v_user_tenant;
    END IF;

    -- 6. تسجيل العملية في السجل (مع الحالة السابقة)
    INSERT INTO qr_scans (
        qr_code_id, scanned_by_user_id, action_type, 
        prev_status, new_status, tenant_id
    )
    VALUES (
        v_qr_record.id, p_user_id, 'update_status', 
        v_prev_status, p_new_status, v_user_tenant
    );

    RETURN json_build_object(
        'success', true, 
        'prev_status', v_prev_status,
        'new_status', p_new_status,
        'entity_type', v_qr_record.entity_type,
        'entity_id', v_qr_record.entity_id
    );
END;
$_$;


