--
-- Name: update_gold_item_value(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.update_gold_item_value() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_price DECIMAL(18,4);
BEGIN
    SELECT price_per_gram * (1 + COALESCE(markup_percentage, 0)/100) INTO v_price
    FROM gold_prices
    WHERE company_id = NEW.company_id
      AND metal_type = NEW.metal_type
      AND (karat = NEW.karat OR karat IS NULL)
      AND is_active = TRUE
    ORDER BY price_date DESC, price_time DESC NULLS LAST
    LIMIT 1;
    
    IF v_price IS NOT NULL THEN
        NEW.metal_value := NEW.net_metal_weight * v_price;
        
        IF NEW.making_charge_type = 'fixed' THEN
            NEW.making_charge_total := NEW.making_charge_value;
        ELSIF NEW.making_charge_type = 'per_gram' THEN
            NEW.making_charge_total := NEW.net_metal_weight * NEW.making_charge_value;
        ELSIF NEW.making_charge_type = 'percentage' THEN
            NEW.making_charge_total := NEW.metal_value * (NEW.making_charge_value / 100);
        END IF;
        
        NEW.total_value := NEW.metal_value + COALESCE(NEW.making_charge_total, 0) + COALESCE(NEW.stone_value, 0);
    END IF;
    
    NEW.updated_at := NOW();
    RETURN NEW;
END;
$$;


--
-- Name: update_inventory_stock(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.update_inventory_stock() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
DECLARE
    v_current_qty DECIMAL(15,3);
    v_current_cost DECIMAL(15,4);
    v_new_avg_cost DECIMAL(15,4);
    v_warehouse_id UUID;
    v_target_id UUID;
BEGIN
    -- تحديد المستودع
    v_warehouse_id := COALESCE(NEW.to_warehouse_id, NEW.from_warehouse_id);
    
    -- تحديد الهوية: هل هي مادة أم منتج؟
    v_target_id := COALESCE(NEW.material_id, NEW.product_id);

    -- 1. جلب رصيد المخزون الحالي
    SELECT quantity_on_hand, average_cost
    INTO v_current_qty, v_current_cost
    FROM inventory_stock
    WHERE 
        -- البحث سواء بمعرف المادة أو المنتج
        ((material_id IS NOT NULL AND material_id = v_target_id) 
         OR 
         (product_id IS NOT NULL AND product_id = v_target_id))
        AND warehouse_id = v_warehouse_id
    LIMIT 1;
    
    IF NOT FOUND THEN
        v_current_qty := 0;
        v_current_cost := 0;
    END IF;

    -- 2. حساب متوسط التكلفة (عند الاستلام فقط)
    IF NEW.movement_type IN ('receipt', 'purchase', 'return_in', 'adjustment_in', 'transfer_in') THEN
        -- معادلة المتوسط المرجح
        IF (v_current_qty + NEW.quantity) > 0 THEN
            v_new_avg_cost := ((v_current_qty * v_current_cost) + (NEW.quantity * COALESCE(NEW.unit_cost, v_current_cost, 0))) / (v_current_qty + NEW.quantity);
        ELSE
            v_new_avg_cost := COALESCE(NEW.unit_cost, v_current_cost, 0);
        END IF;

        -- 3. التحديث أو الإضافة
        UPDATE inventory_stock
        SET quantity_on_hand = quantity_on_hand + NEW.quantity,
            average_cost = v_new_avg_cost,
            last_cost = COALESCE(NEW.unit_cost, inventory_stock.last_cost),
            last_movement_date = NOW(),
            updated_at = NOW()
        WHERE 
            ((material_id IS NOT NULL AND material_id = v_target_id) OR (product_id IS NOT NULL AND product_id = v_target_id))
            AND warehouse_id = v_warehouse_id;

        -- إضافة سجل جديد إذا لم يوجد
        IF NOT FOUND THEN
            INSERT INTO inventory_stock (
                tenant_id, company_id, 
                product_id, material_id, 
                warehouse_id,
                quantity_on_hand, average_cost, last_cost, last_movement_date,
                batch_number
            ) VALUES (
                NEW.tenant_id, NEW.company_id, 
                NEW.product_id, NEW.material_id, 
                v_warehouse_id,
                NEW.quantity, v_new_avg_cost, COALESCE(NEW.unit_cost, 0), NOW(),
                'N/A'
            );
        END IF;

    -- 4. حالة الصرف (نقصان)
    ELSIF NEW.movement_type IN ('sale', 'issue', 'return_out', 'adjustment_out', 'transfer_out') THEN
         UPDATE inventory_stock
         SET quantity_on_hand = quantity_on_hand - NEW.quantity,
             last_movement_date = NOW(),
             updated_at = NOW()
         WHERE 
            ((material_id IS NOT NULL AND material_id = v_target_id) OR (product_id IS NOT NULL AND product_id = v_target_id))
            AND warehouse_id = v_warehouse_id;
    END IF;

    -- 5. حفظ لقطة (Snapshot) للأرصدة في سجل الحركة
    NEW.balance_after := v_current_qty + 
        CASE WHEN NEW.movement_type IN ('receipt', 'purchase', 'return_in', 'adjustment_in', 'transfer_in') THEN NEW.quantity ELSE -NEW.quantity END;
    NEW.balance_before := v_current_qty;

    RETURN NEW;
END;
$$;


