--
-- Name: update_journal_entry_totals(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.update_journal_entry_totals() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
    UPDATE journal_entries
    SET 
        total_debit = (
            SELECT COALESCE(SUM(debit), 0)
            FROM journal_entry_lines
            WHERE entry_id = COALESCE(NEW.entry_id, OLD.entry_id)  -- CORRECT: entry_id
        ),
        total_credit = (
            SELECT COALESCE(SUM(credit), 0)
            FROM journal_entry_lines
            WHERE entry_id = COALESCE(NEW.entry_id, OLD.entry_id)  -- CORRECT: entry_id
        ),
        updated_at = NOW()
    WHERE id = COALESCE(NEW.entry_id, OLD.entry_id);  -- CORRECT: entry_id
    
    RETURN COALESCE(NEW, OLD);
END;
$$;


--
-- Name: update_leave_balance_on_approval(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.update_leave_balance_on_approval() RETURNS trigger
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
BEGIN
    -- عند الموافقة: نقل من pending إلى used
    IF NEW.status = 'approved' AND OLD.status = 'pending' THEN
        UPDATE leave_balances
        SET used_days = used_days + NEW.total_days,
            pending_days = pending_days - NEW.total_days
        WHERE employee_id = NEW.employee_id
        AND leave_type_id = NEW.leave_type_id
        AND year = EXTRACT(YEAR FROM NEW.start_date);
    
    -- عند الرفض أو الإلغاء: إرجاع الأيام المعلقة
    ELSIF NEW.status IN ('rejected', 'cancelled') AND OLD.status = 'pending' THEN
        UPDATE leave_balances
        SET pending_days = pending_days - NEW.total_days
        WHERE employee_id = NEW.employee_id
        AND leave_type_id = NEW.leave_type_id
        AND year = EXTRACT(YEAR FROM NEW.start_date);
    
    -- عند تقديم الطلب: إضافة للمعلق
    ELSIF NEW.status = 'pending' AND (OLD.status IS NULL OR OLD.status = 'draft') THEN
        UPDATE leave_balances
        SET pending_days = pending_days + NEW.total_days
        WHERE employee_id = NEW.employee_id
        AND leave_type_id = NEW.leave_type_id
        AND year = EXTRACT(YEAR FROM NEW.start_date);
    END IF;
    
    RETURN NEW;
END;
$$;


