--
-- Name: update_plan_limits(uuid, integer, integer, integer, integer, integer, integer, integer, integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.update_plan_limits(p_plan_id uuid, p_max_users integer DEFAULT NULL::integer, p_max_companies integer DEFAULT NULL::integer, p_max_customers integer DEFAULT NULL::integer, p_max_products integer DEFAULT NULL::integer, p_max_documents integer DEFAULT NULL::integer, p_max_images integer DEFAULT NULL::integer, p_max_records integer DEFAULT NULL::integer, p_storage_gb integer DEFAULT NULL::integer) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
BEGIN
    -- التحقق من وجود الباقة
    IF NOT EXISTS (SELECT 1 FROM subscription_plans WHERE id = p_plan_id) THEN
        RETURN jsonb_build_object(
            'success', false,
            'error', 'plan_not_found',
            'message', 'الباقة غير موجودة'
        );
    END IF;
    
    -- تحديث الحدود (فقط القيم المرسلة)
    UPDATE subscription_plans
    SET
        max_users = COALESCE(p_max_users, max_users),
        max_companies = COALESCE(p_max_companies, max_companies),
        max_customers = COALESCE(p_max_customers, max_customers),
        max_products = COALESCE(p_max_products, max_products),
        max_documents = COALESCE(p_max_documents, max_documents),
        max_images = COALESCE(p_max_images, max_images),
        max_records = COALESCE(p_max_records, max_records),
        storage_gb = COALESCE(p_storage_gb, storage_gb)
    WHERE id = p_plan_id;
    
    RETURN jsonb_build_object(
        'success', true,
        'message', 'تم تحديث الحدود بنجاح'
    );
    
EXCEPTION
    WHEN OTHERS THEN
        RETURN jsonb_build_object(
            'success', false,
            'error', 'exception',
            'message', SQLERRM
        );
END;
$$;


