--
-- Name: update_promotional_discount(uuid, character varying, character varying, integer, timestamp with time zone, timestamp with time zone, boolean, integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.update_promotional_discount(p_discount_id uuid, p_name_ar character varying DEFAULT NULL::character varying, p_name_en character varying DEFAULT NULL::character varying, p_discount_percentage integer DEFAULT NULL::integer, p_valid_from timestamp with time zone DEFAULT NULL::timestamp with time zone, p_valid_to timestamp with time zone DEFAULT NULL::timestamp with time zone, p_is_active boolean DEFAULT NULL::boolean, p_priority integer DEFAULT NULL::integer) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
BEGIN
    IF NOT EXISTS (SELECT 1 FROM promotional_discounts WHERE id = p_discount_id) THEN
        RETURN jsonb_build_object(
            'success', false,
            'error', 'discount_not_found'
        );
    END IF;
    
    UPDATE promotional_discounts
    SET
        name_ar = COALESCE(p_name_ar, name_ar),
        name_en = COALESCE(p_name_en, name_en),
        discount_percentage = COALESCE(p_discount_percentage, discount_percentage),
        valid_from = COALESCE(p_valid_from, valid_from),
        valid_to = COALESCE(p_valid_to, valid_to),
        is_active = COALESCE(p_is_active, is_active),
        priority = COALESCE(p_priority, priority),
        updated_at = NOW()
    WHERE id = p_discount_id;
    
    RETURN jsonb_build_object(
        'success', true,
        'discount_id', p_discount_id,
        'message', 'تم تحديث الخصم بنجاح'
    );
END;
$$;


--
-- Name: update_purchase_document_status_bypass_rls(text, uuid, text, uuid, text); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.update_purchase_document_status_bypass_rls(p_table text, p_id uuid, p_status text, p_receipt_id uuid, p_receipt_number text) RETURNS void
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
BEGIN
    IF p_table = 'purchase_orders' THEN
        UPDATE purchase_orders SET status = p_status, updated_at = NOW() WHERE id = p_id;
    ELSIF p_table = 'purchase_invoices' THEN
        UPDATE purchase_invoices SET status = p_status, updated_at = NOW() WHERE id = p_id;
    END IF;
END;
$$;


