--
-- Name: update_subscription_plan(uuid, character varying, character varying, text, integer, integer, integer, integer, integer, integer, jsonb, jsonb, numeric, numeric, character varying, integer, boolean, integer, boolean); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.update_subscription_plan(p_plan_id uuid, p_name_ar character varying DEFAULT NULL::character varying, p_name_en character varying DEFAULT NULL::character varying, p_description text DEFAULT NULL::text, p_max_users integer DEFAULT NULL::integer, p_max_companies integer DEFAULT NULL::integer, p_max_branches integer DEFAULT NULL::integer, p_max_warehouses integer DEFAULT NULL::integer, p_max_products integer DEFAULT NULL::integer, p_storage_gb integer DEFAULT NULL::integer, p_included_modules jsonb DEFAULT NULL::jsonb, p_features jsonb DEFAULT NULL::jsonb, p_price_monthly numeric DEFAULT NULL::numeric, p_price_yearly numeric DEFAULT NULL::numeric, p_currency character varying DEFAULT NULL::character varying, p_trial_days integer DEFAULT NULL::integer, p_is_popular boolean DEFAULT NULL::boolean, p_display_order integer DEFAULT NULL::integer, p_is_active boolean DEFAULT NULL::boolean) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
BEGIN
    -- التحقق من وجود الباقة
    IF NOT EXISTS (SELECT 1 FROM subscription_plans WHERE id = p_plan_id) THEN
        RETURN jsonb_build_object(
            'success', false,
            'error', 'plan_not_found',
            'message', 'الباقة غير موجودة'
        );
    END IF;
    
    -- تحديث الحقول المحددة فقط
    UPDATE subscription_plans
    SET
        name_ar = COALESCE(p_name_ar, name_ar),
        name_en = COALESCE(p_name_en, name_en),
        description = COALESCE(p_description, description),
        max_users = COALESCE(p_max_users, max_users),
        max_companies = COALESCE(p_max_companies, max_companies),
        max_branches = COALESCE(p_max_branches, max_branches),
        max_warehouses = COALESCE(p_max_warehouses, max_warehouses),
        max_products = COALESCE(p_max_products, max_products),
        storage_gb = COALESCE(p_storage_gb, storage_gb),
        included_modules = COALESCE(p_included_modules, included_modules),
        features = COALESCE(p_features, features),
        price_monthly = COALESCE(p_price_monthly, price_monthly),
        price_yearly = COALESCE(p_price_yearly, price_yearly),
        currency = COALESCE(p_currency, currency),
        trial_days = COALESCE(p_trial_days, trial_days),
        is_popular = COALESCE(p_is_popular, is_popular),
        display_order = COALESCE(p_display_order, display_order),
        is_active = COALESCE(p_is_active, is_active)
    WHERE id = p_plan_id;
    
    RETURN jsonb_build_object(
        'success', true,
        'plan_id', p_plan_id,
        'message', 'تم تحديث الباقة بنجاح'
    );
    
EXCEPTION
    WHEN OTHERS THEN
        RETURN jsonb_build_object(
            'success', false,
            'error', 'exception',
            'message', SQLERRM
        );
END;
$$;


