-- Name: FUNCTION update_subscription_plan(p_plan_id uuid, p_name_ar character varying, p_name_en character varying, p_description text, p_max_users integer, p_max_companies integer, p_max_branches integer, p_max_warehouses integer, p_max_products integer, p_storage_gb integer, p_included_modules jsonb, p_features jsonb, p_price_monthly numeric, p_price_yearly numeric, p_currency character varying, p_trial_days integer, p_is_popular boolean, p_display_order integer, p_is_active boolean); Type: COMMENT; Schema: public; Owner: -
