--
-- Name: update_user_profile_on_registration(uuid, character varying, character varying, character varying, uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.update_user_profile_on_registration(p_user_id uuid, p_email character varying, p_full_name character varying, p_role character varying, p_company_id uuid) RETURNS json
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_result JSON;
BEGIN
    -- تحديث أو إدراج user_profile
    INSERT INTO public.user_profiles (
        id, email, full_name, role, company_id
    )
    VALUES (
        p_user_id, p_email, p_full_name, p_role, p_company_id
    )
    ON CONFLICT (id) 
    DO UPDATE SET
        email = EXCLUDED.email,
        full_name = EXCLUDED.full_name,
        role = EXCLUDED.role,
        company_id = EXCLUDED.company_id,
        updated_at = NOW();
    
    -- إرجاع النتيجة
    SELECT row_to_json(t) INTO v_result
    FROM (
        SELECT id, email, full_name, role, company_id, created_at, updated_at
        FROM public.user_profiles
        WHERE id = p_user_id
    ) t;
    
    RETURN v_result;
END;
$$;


