--
-- Name: verify_white_label_domain(uuid); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.verify_white_label_domain(p_domain_id uuid) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_domain RECORD;
BEGIN
    SELECT * INTO v_domain FROM white_label_domains WHERE id = p_domain_id;
    IF NOT FOUND THEN
        RETURN jsonb_build_object('success', false, 'error', 'الدومين غير موجود');
    END IF;
    
    -- TODO: إضافة منطق التحقق من DNS
    
    -- تحديث حالة الدومين
    UPDATE white_label_domains
    SET verified = true,
        verified_at = NOW(),
        status = 'active',
        activated_at = NOW()
    WHERE id = p_domain_id;
    
    RETURN jsonb_build_object(
        'success', true,
        'message', 'تم التحقق من الدومين بنجاح'
    );
END;
$$;


--
-- Name: vote_on_review(uuid, uuid, uuid, character varying); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION public.vote_on_review(p_tenant_id uuid, p_review_id uuid, p_customer_id uuid, p_vote_type character varying) RETURNS jsonb
    LANGUAGE plpgsql SECURITY DEFINER
    AS $$
DECLARE
    v_existing_vote VARCHAR;
BEGIN
    -- التحقق من التقييم
    IF NOT EXISTS (
        SELECT 1 FROM product_reviews 
        WHERE id = p_review_id AND tenant_id = p_tenant_id AND status = 'approved'
    ) THEN
        RETURN jsonb_build_object('success', false, 'error', 'التقييم غير موجود');
    END IF;
    
    -- التحقق من التصويت السابق
    SELECT vote_type INTO v_existing_vote
    FROM review_votes
    WHERE review_id = p_review_id AND customer_id = p_customer_id;
    
    IF v_existing_vote IS NOT NULL THEN
        -- تحديث التصويت
        IF v_existing_vote = 'helpful' THEN
            UPDATE product_reviews SET helpful_count = helpful_count - 1 WHERE id = p_review_id;
        ELSE
            UPDATE product_reviews SET not_helpful_count = not_helpful_count - 1 WHERE id = p_review_id;
        END IF;
        
        DELETE FROM review_votes WHERE review_id = p_review_id AND customer_id = p_customer_id;
    END IF;
    
    -- إضافة التصويت الجديد
    INSERT INTO review_votes (tenant_id, review_id, customer_id, vote_type)
    VALUES (p_tenant_id, p_review_id, p_customer_id, p_vote_type);
    
    -- تحديث العدادات
    IF p_vote_type = 'helpful' THEN
        UPDATE product_reviews SET helpful_count = helpful_count + 1 WHERE id = p_review_id;
    ELSE
        UPDATE product_reviews SET not_helpful_count = not_helpful_count + 1 WHERE id = p_review_id;
    END IF;
    
    RETURN jsonb_build_object('success', true, 'message', 'تم التصويت');
END;
$$;


