--
-- Name: admin_revenue_summary; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.admin_revenue_summary AS
 SELECT date_trunc('month'::text, (invoice_date)::timestamp with time zone) AS month,
    count(DISTINCT tenant_id) AS paying_customers,
    count(*) AS invoices_count,
    sum(total_amount) AS total_invoiced,
    sum(paid_amount) AS total_collected,
    sum(
        CASE
            WHEN ((status)::text = 'paid'::text) THEN total_amount
            ELSE (0)::numeric
        END) AS paid_invoices_amount,
    sum(
        CASE
            WHEN ((status)::text = 'overdue'::text) THEN total_amount
            ELSE (0)::numeric
        END) AS overdue_amount
   FROM public.billing_invoices bi
  GROUP BY (date_trunc('month'::text, (invoice_date)::timestamp with time zone))
  ORDER BY (date_trunc('month'::text, (invoice_date)::timestamp with time zone)) DESC;


