--

CREATE TABLE public.agent_targets (
    id uuid DEFAULT gen_random_uuid() NOT NULL,
    agent_id uuid NOT NULL,
    period_type character varying(20) NOT NULL,
    period_start date NOT NULL,
    period_end date NOT NULL,
    target_tenants integer DEFAULT 0,
    target_revenue numeric(10,2) DEFAULT 0,
    target_commissions numeric(10,2) DEFAULT 0,
    achieved_tenants integer DEFAULT 0,
    achieved_revenue numeric(10,2) DEFAULT 0,
    achieved_commissions numeric(10,2) DEFAULT 0,
    tenants_progress numeric(5,2) GENERATED ALWAYS AS (
CASE
    WHEN (target_tenants > 0) THEN LEAST((((achieved_tenants)::numeric / (target_tenants)::numeric) * (100)::numeric), (100)::numeric)
    ELSE (0)::numeric
END) STORED,
    revenue_progress numeric(5,2) GENERATED ALWAYS AS (
CASE
    WHEN (target_revenue > (0)::numeric) THEN LEAST(((achieved_revenue / target_revenue) * (100)::numeric), (100)::numeric)
    ELSE (0)::numeric
END) STORED,
    bonus_earned numeric(10,2) DEFAULT 0,
    bonus_paid boolean DEFAULT false,
    status character varying(20) DEFAULT 'active'::character varying,
    created_at timestamp with time zone DEFAULT now(),
    updated_at timestamp with time zone DEFAULT now()
);


