    CONSTRAINT contact_interactions_outcome_check CHECK (((outcome)::text = ANY ((ARRAY['answered'::character varying, 'missed'::character varying, 'voicemail'::character varying, 'busy'::character varying, 'callback_requested'::character varying, 'successful'::character varying, 'follow_up_needed'::character varying, 'no_answer'::character varying, 'completed'::character varying, NULL::character varying])::text[])))
);


