    mobile character varying(50),
    whatsapp character varying(50),
    telegram_username character varying(100),
    telegram_chat_id bigint,
    country character varying(100),
    city character varying(100),
    address text,
    source character varying(50) DEFAULT 'manual'::character varying NOT NULL,
    source_details jsonb DEFAULT '{}'::jsonb,
    contact_type character varying(30) DEFAULT 'lead'::character varying,
    lifecycle_stage character varying(30) DEFAULT 'new'::character varying,
    lost_reason character varying(200),
    priority character varying(10) DEFAULT 'medium'::character varying,
    lead_score integer DEFAULT 0,
    assigned_to uuid,
    converted_customer_id uuid,
    converted_at timestamp with time zone,
    converted_by uuid,
    last_interaction_at timestamp with time zone,
