    created_at timestamp with time zone DEFAULT now(),
    updated_at timestamp with time zone DEFAULT now(),
    CONSTRAINT contacts_contact_type_check CHECK (((contact_type)::text = ANY ((ARRAY['lead'::character varying, 'prospect'::character varying, 'wholesale_lead'::character varying, 'retail_lead'::character varying, 'partner_lead'::character varying, 'existing_contact'::character varying])::text[]))),
    CONSTRAINT contacts_lead_score_check CHECK (((lead_score >= 0) AND (lead_score <= 100))),
    CONSTRAINT contacts_lifecycle_stage_check CHECK (((lifecycle_stage)::text = ANY ((ARRAY['new'::character varying, 'contacted'::character varying, 'interested'::character varying, 'qualified'::character varying, 'negotiation'::character varying, 'converted'::character varying, 'lost'::character varying, 'archived'::character varying])::text[]))),
    CONSTRAINT contacts_priority_check CHECK (((priority)::text = ANY ((ARRAY['low'::character varying, 'medium'::character varying, 'high'::character varying, 'urgent'::character varying])::text[]))),
    CONSTRAINT contacts_source_check CHECK (((source)::text = ANY ((ARRAY['phone_inbound'::character varying, 'phone_outbound'::character varying, 'google_ads'::character varying, 'facebook_ads'::character varying, 'instagram_ads'::character varying, 'website'::character varying, 'telegram'::character varying, 'online_store'::character varying, 'referral'::character varying, 'walk_in'::character varying, 'exhibition'::character varying, 'whatsapp'::character varying, 'email_campaign'::character varying, 'manual'::character varying])::text[]))),
    CONSTRAINT contacts_status_check CHECK (((status)::text = ANY ((ARRAY['active'::character varying, 'inactive'::character varying, 'converted'::character varying, 'archived'::character varying, 'blacklisted'::character varying])::text[])))
);


