    period_id uuid,
    entry_type character varying(30) DEFAULT 'manual'::character varying,
    reference_type character varying(50),
    reference_id uuid,
    reference_number character varying(100),
    description text NOT NULL,
    currency character varying(3) DEFAULT 'USD'::character varying,
    exchange_rate numeric(18,8) DEFAULT 1,
    total_debit numeric(15,2) DEFAULT 0,
    total_credit numeric(15,2) DEFAULT 0,
    status character varying(20) DEFAULT 'draft'::character varying,
    is_posted boolean DEFAULT false,
    posted_at timestamp with time zone,
    posted_by uuid,
    is_reversed boolean DEFAULT false,
    reversed_at timestamp with time zone,
    reversed_by uuid,
    reversal_entry_id uuid,
    original_entry_id uuid,
    notes text,
    created_by uuid,
    created_at timestamp with time zone DEFAULT now(),
    updated_at timestamp with time zone DEFAULT now(),
    description_ar text,
    description_en text,
    description_ru text,
    description_uk text,
    description_ro text,
    description_pl text,
    description_tr text,
    description_de text,
    description_it text,
    marker_color character varying(20) DEFAULT NULL::character varying,
    parent_entry_id uuid,
    adjustment_reason text,
    edit_history jsonb DEFAULT '[]'::jsonb,
    activity_log jsonb DEFAULT '[]'::jsonb,
    last_edited_at timestamp with time zone,
    last_edited_by uuid,
    edit_count integer DEFAULT 0,
    CONSTRAINT chk_balanced_entry CHECK ((((status)::text <> 'posted'::text) OR (abs((total_debit - total_credit)) < 0.01)))
);


--
-- Name: COLUMN journal_entries.marker_color; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON COLUMN public.journal_entries.marker_color IS 'Color marker for visual reconciliation at entry level';


--
-- Name: COLUMN journal_entries.parent_entry_id; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON COLUMN public.journal_entries.parent_entry_id IS 'القيد الأصلي المرجعي — يُستخدم لربط قيود التسوية والعكس بالقيد الأصلي. القيد المُرحّل لا يُعدّل أبداً.';


--
-- Name: COLUMN journal_entries.adjustment_reason; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON COLUMN public.journal_entries.adjustment_reason IS 'سبب قيد التسوية — مثال: فرق كمية استلام، فرق سعر، إلخ. يظهر في التقارير والتدقيق.';


