    credit_fc numeric(15,2) DEFAULT 0,
    description text,
    cost_center_id uuid,
    party_type character varying(20),
    party_id uuid,
    reference_type character varying(50),
    reference_id uuid,
    created_at timestamp with time zone DEFAULT now(),
    marker_color character varying(20) DEFAULT NULL::character varying,
    marked_at timestamp with time zone,
    marked_by uuid,
    updated_at timestamp with time zone DEFAULT now(),
    CONSTRAINT chk_debit_or_credit CHECK ((((debit > (0)::numeric) AND (credit = (0)::numeric)) OR ((debit = (0)::numeric) AND (credit > (0)::numeric)) OR ((debit = (0)::numeric) AND (credit = (0)::numeric))))
);


