--
-- Name: mv_account_balances; Type: MATERIALIZED VIEW; Schema: public; Owner: -
--

CREATE MATERIALIZED VIEW public.mv_account_balances AS
 SELECT je.company_id,
    je.tenant_id,
    jel.account_id,
    coa.account_code,
    coa.name_ar,
    coa.name_en,
    at.code AS account_type_code,
    sum(jel.debit) AS total_debit,
    sum(jel.credit) AS total_credit,
    (sum(jel.debit) - sum(jel.credit)) AS balance,
    count(*) AS entry_count,
    max(je.entry_date) AS last_entry_date
   FROM (((public.journal_entry_lines jel
     JOIN public.journal_entries je ON ((jel.entry_id = je.id)))
     JOIN public.chart_of_accounts coa ON ((jel.account_id = coa.id)))
     LEFT JOIN public.account_types at ON ((coa.account_type_id = at.id)))
  WHERE ((je.status)::text = 'posted'::text)
  GROUP BY je.company_id, je.tenant_id, jel.account_id, coa.account_code, coa.name_ar, coa.name_en, at.code
  WITH NO DATA;


--
-- Name: mv_inventory_summary; Type: MATERIALIZED VIEW; Schema: public; Owner: -
--

CREATE MATERIALIZED VIEW public.mv_inventory_summary AS
 SELECT company_id,
    tenant_id,
    product_id,
    material_id,
    to_warehouse_id AS warehouse_id,
    sum(
        CASE
            WHEN ((movement_type)::text = ANY ((ARRAY['IN'::character varying, 'PURCHASE'::character varying, 'RETURN_IN'::character varying, 'ADJUSTMENT_IN'::character varying, 'TRANSFER_IN'::character varying])::text[])) THEN quantity
            ELSE (0)::numeric
        END) AS total_in,
    sum(
        CASE
            WHEN ((movement_type)::text = ANY ((ARRAY['OUT'::character varying, 'SALE'::character varying, 'RETURN_OUT'::character varying, 'ADJUSTMENT_OUT'::character varying, 'TRANSFER_OUT'::character varying])::text[])) THEN quantity
            ELSE (0)::numeric
        END) AS total_out,
    sum(
        CASE
            WHEN ((movement_type)::text = ANY ((ARRAY['IN'::character varying, 'PURCHASE'::character varying, 'RETURN_IN'::character varying, 'ADJUSTMENT_IN'::character varying, 'TRANSFER_IN'::character varying])::text[])) THEN quantity
            ELSE (- quantity)
        END) AS balance,
    max(movement_date) AS last_movement
   FROM public.inventory_movements im
  GROUP BY company_id, tenant_id, product_id, material_id, to_warehouse_id
  WITH NO DATA;


