    subtotal numeric(15,2) DEFAULT 0,
    discount_amount numeric(15,2) DEFAULT 0,
    taxable_amount numeric(15,2) DEFAULT 0,
    tax_amount numeric(15,2) DEFAULT 0,
    total_amount numeric(15,2) DEFAULT 0,
    currency character varying(3) DEFAULT 'SAR'::character varying,
    exchange_rate numeric(18,8) DEFAULT 1,
    journal_entry_id uuid,
    notes text,
    created_by uuid,
    created_at timestamp with time zone DEFAULT now(),
    updated_at timestamp with time zone DEFAULT now(),
    salesperson_id uuid,
    discount_percent numeric(5,2) DEFAULT 0,
    price_list_id uuid,
    confirmation_status text DEFAULT 'draft'::text,
    confirmed_at timestamp with time zone,
    confirmed_by uuid,
    approval_status text DEFAULT 'none'::text,
    approved_by uuid,
    approved_at timestamp with time zone,
    approval_notes text,
    delivery_note_id uuid,
    delivery_method character varying(30) DEFAULT 'store_pickup'::character varying,
    shipping_address_id uuid,
    shipping_address text,
    shipping_recipient character varying(200),
    shipping_phone character varying(50),
    shipping_carrier character varying(50),
    tracking_number character varying(100),
    shipping_cost numeric(12,2) DEFAULT 0,
    delivery_notes text,
    expenses jsonb DEFAULT '[]'::jsonb,
    expenses_total numeric(18,2) DEFAULT 0,
    attachments jsonb DEFAULT '[]'::jsonb,
    document_stage character varying(20) DEFAULT 'invoice'::character varying,
    order_number character varying(50),
    order_date date,
    expected_delivery_date date,
    delivery_status character varying(20) DEFAULT 'pending'::character varying,
    warehouse_id uuid,
    terms text,
    discount_type character varying(20) DEFAULT 'fixed'::character varying,
    discount_value numeric(15,2) DEFAULT 0,
    CONSTRAINT sales_invoices_status_check CHECK (((status)::text = ANY ((ARRAY['draft'::character varying, 'saved'::character varying, 'pending'::character varying, 'approved'::character varying, 'confirmed'::character varying, 'in_progress'::character varying, 'completed'::character varying, 'cancelled'::character varying, 'rejected'::character varying, 'posted'::character varying, 'paid'::character varying, 'partially_paid'::character varying, 'overdue'::character varying, 'closed'::character varying])::text[])))
);


