--
-- Name: mv_monthly_sales; Type: MATERIALIZED VIEW; Schema: public; Owner: -
--

CREATE MATERIALIZED VIEW public.mv_monthly_sales AS
 SELECT company_id,
    tenant_id,
    date_trunc('month'::text, (invoice_date)::timestamp with time zone) AS month,
    currency,
    count(*) AS invoice_count,
    sum(total_amount) AS total_amount,
    sum(COALESCE(tax_amount, (0)::numeric)) AS total_tax,
    (sum(total_amount) - sum(COALESCE(tax_amount, (0)::numeric))) AS total_net
   FROM public.sales_invoices
  WHERE ((status)::text <> ALL ((ARRAY['cancelled'::character varying, 'draft'::character varying])::text[]))
  GROUP BY company_id, tenant_id, (date_trunc('month'::text, (invoice_date)::timestamp with time zone)), currency
  WITH NO DATA;


