    receipt_no text,
    invoice_no text,
    supplier_id uuid,
    supplier_name text,
    doc_date date DEFAULT CURRENT_DATE,
    quotation_date date,
    order_date date,
    approval_date date,
    receipt_date date,
    invoice_date date,
    due_date date,
    warehouse_id uuid,
    shipment_id uuid,
    receipt_mode text DEFAULT 'direct'::text,
    currency text DEFAULT 'SAR'::text,
    exchange_rate numeric(18,6) DEFAULT 1,
    subtotal numeric(18,2) DEFAULT 0,
    discount_amount numeric(18,2) DEFAULT 0,
    discount_percent numeric(5,2) DEFAULT 0,
    tax_amount numeric(18,2) DEFAULT 0,
    expenses_total numeric(18,2) DEFAULT 0,
    total_amount numeric(18,2) DEFAULT 0,
    paid_amount numeric(18,2) DEFAULT 0,
    balance numeric(18,2) DEFAULT 0,
    payment_terms_days integer DEFAULT 30,
    supplier_invoice_number text,
    supplier_invoice_date date,
    journal_entry_id uuid,
    is_posted boolean DEFAULT false,
    created_by uuid,
    created_by_name text,
    created_at timestamp with time zone DEFAULT now(),
    quoted_by uuid,
    quoted_by_name text,
    quoted_at timestamp with time zone,
    ordered_by uuid,
    ordered_by_name text,
    ordered_at timestamp with time zone,
    approved_by uuid,
    approved_by_name text,
    approved_at timestamp with time zone,
    approval_notes text,
    received_by uuid,
    received_by_name text,
    received_at timestamp with time zone,
    invoiced_by uuid,
    invoiced_by_name text,
    invoiced_at timestamp with time zone,
    posted_by uuid,
    posted_by_name text,
    posted_at timestamp with time zone,
    cancelled_by uuid,
    cancelled_by_name text,
    cancelled_at timestamp with time zone,
    cancellation_reason text,
    updated_by uuid,
    updated_at timestamp with time zone DEFAULT now(),
    notes text,
    supplier_notes text,
    internal_notes text,
    expenses jsonb DEFAULT '[]'::jsonb,
    attachments jsonb DEFAULT '[]'::jsonb,
    tags text[],
    confirmation_status text DEFAULT 'pending'::text,
    is_active boolean DEFAULT true,
    is_locked boolean DEFAULT false,
    source_type text,
    source_id uuid,
    version integer DEFAULT 1,
    printed_count integer DEFAULT 0,
    last_printed_at timestamp with time zone,
    last_printed_by uuid,
    reminder_count integer DEFAULT 0,
    last_reminder_sent_at timestamp with time zone,
    original_transaction_id uuid,
    is_return boolean DEFAULT false,
    receipt_variance_detail jsonb,
    container_id uuid,
    container_number text,
    container_status text,
    auto_update_stock boolean DEFAULT false,
    stock_warehouse_id uuid,
    stock_movement_id uuid,
    edit_history jsonb DEFAULT '[]'::jsonb,
    activity_log jsonb DEFAULT '[]'::jsonb,
    last_edited_at timestamp with time zone,
    last_edited_by uuid,
    edit_count integer DEFAULT 0,
    CONSTRAINT purchase_transactions_confirmation_status_check CHECK ((confirmation_status = ANY (ARRAY['pending'::text, 'confirmed'::text, 'rejected'::text]))),
    CONSTRAINT purchase_transactions_receipt_mode_check CHECK ((receipt_mode = ANY (ARRAY['direct'::text, 'international'::text]))),
    CONSTRAINT purchase_transactions_stage_check CHECK ((stage = ANY (ARRAY['request'::text, 'quotation'::text, 'draft'::text, 'confirmed'::text, 'received'::text, 'posted'::text, 'cancelled'::text])))
);


--
