--
-- Name: white_label_summary_view; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW public.white_label_summary_view AS
 SELECT a.id AS agent_id,
    a.code AS agent_code,
    a.name AS agent_name,
    a.has_white_label,
    a.white_label_status,
    a.white_label_commission_percent,
    a.white_label_activated_at,
    a.white_label_expires_at,
    count(DISTINCT wld.id) AS total_domains,
    count(DISTINCT wld.id) FILTER (WHERE ((wld.status)::text = 'active'::text)) AS active_domains,
    wlc.brand_name,
    wlc.logo_url,
    wlc.primary_color,
    count(DISTINCT wlp.id) AS total_payments,
    COALESCE(sum(wlp.amount) FILTER (WHERE ((wlp.status)::text = 'completed'::text)), (0)::numeric) AS total_paid,
    COALESCE(sum(wls.total_tenants), (0)::bigint) AS total_tenants,
    COALESCE(sum(wls.total_revenue), (0)::numeric) AS total_revenue,
    COALESCE(sum(wls.agent_commission), (0)::numeric) AS total_commission
   FROM ((((public.agents a
     LEFT JOIN public.white_label_domains wld ON ((wld.agent_id = a.id)))
     LEFT JOIN public.white_label_configs wlc ON (((wlc.agent_id = a.id) AND (wlc.is_active = true))))
     LEFT JOIN public.white_label_payments wlp ON ((wlp.agent_id = a.id)))
     LEFT JOIN public.white_label_stats wls ON ((wls.agent_id = a.id)))
  WHERE (a.has_white_label = true)
  GROUP BY a.id, a.code, a.name, a.has_white_label, a.white_label_status, a.white_label_commission_percent, a.white_label_activated_at, a.white_label_expires_at, wlc.brand_name, wlc.logo_url, wlc.primary_color;


