--
-- Name: custom_statuses custom_statuses_delete; Type: POLICY; Schema: public; Owner: -
--

CREATE POLICY custom_statuses_delete ON public.custom_statuses FOR DELETE USING (((tenant_id IN ( SELECT companies.tenant_id
   FROM public.companies
