-- Name: transaction_stage_log tsl_tenant_isolation_insert; Type: POLICY; Schema: public; Owner: -
--

CREATE POLICY tsl_tenant_isolation_insert ON public.transaction_stage_log FOR INSERT WITH CHECK (((transaction_id IN ( SELECT purchase_transactions.id
   FROM public.purchase_transactions
  WHERE (purchase_transactions.tenant_id = public.get_current_user_tenant_id()))) OR (transaction_id IN ( SELECT sales_transactions.id
   FROM public.sales_transactions
  WHERE (sales_transactions.tenant_id = public.get_current_user_tenant_id()))) OR public.is_super_admin(auth.uid())));


--
-- Name: transaction_stage_log tsl_tenant_isolation_select; Type: POLICY; Schema: public; Owner: -
--

CREATE POLICY tsl_tenant_isolation_select ON public.transaction_stage_log FOR SELECT USING (((transaction_id IN ( SELECT purchase_transactions.id
   FROM public.purchase_transactions
  WHERE (purchase_transactions.tenant_id = public.get_current_user_tenant_id()))) OR (transaction_id IN ( SELECT sales_transactions.id
   FROM public.sales_transactions
  WHERE (sales_transactions.tenant_id = public.get_current_user_tenant_id()))) OR public.is_super_admin(auth.uid())));


