--

CREATE POLICY website_pages_select ON public.website_pages FOR SELECT USING (((tenant_id = ( SELECT public.get_user_tenant_id() AS get_user_tenant_id)) OR ((is_published = true) AND (site_id IN ( SELECT website_sites.id
   FROM public.website_sites
  WHERE ((website_sites.is_published = true) AND (website_sites.is_active = true)))))));


